        let _ = String(localized: "At solar noon, the sun is due south (Northern Hemisphere). The shadow therefore points due north. This is more accurate than the quick stick method.", comment: "Step Detail")
        let _ = String(localized: "Pace Bead Systems", comment: "Technique Name")
        let _ = String(localized: "Track distance accurately while walking", comment: "Technique Subtitle")
        let _ = String(localized: "Make a ranger bead system: 9 beads in one group, 4 in another on a cord.", comment: "Step Instruction")
        let _ = String(localized: "String 9 beads, tie a knot, then 4 more beads. Use any small objects: seeds, nuts, carved wood, small stones with holes.", comment: "Step Detail")
        let _ = String(localized: "Pull down one lower bead for every 100 meters walked.", comment: "Step Instruction")
        let _ = String(localized: "Based on YOUR calibrated pace count. When all 9 lower beads are pulled, you've walked 900 meters.", comment: "Step Detail")
        let _ = String(localized: "At 1000 meters (1 km), reset lower beads and pull one upper bead.", comment: "Step Instruction")
        let _ = String(localized: "Upper beads track kilometers. Four upper beads = 4 km track ability. No mental math, no forgetting counts.", comment: "Step Detail")
        let _ = String(localized: "Alternative: transfer pebbles between pockets for each 100 meters.", comment: "Step Instruction")
        let _ = String(localized: "If no beads available: 10 pebbles in right pocket. Move one to left pocket per 100m. Count left pocket pebbles = distance in hundreds of meters.", comment: "Step Detail")
        let _ = String(localized: "Shadow Tip Compass Method", comment: "Technique Name")
        let _ = String(localized: "Find cardinal directions using a stick shadow", comment: "Technique Subtitle")
        let _ = String(localized: "Celestial", comment: "Category")
        let _ = String(localized: "Place a straight stick in flat ground. Mark the tip of its shadow.", comment: "Step Instruction")
        let _ = String(localized: "Use a 2-3 foot stick in an area with good sun exposure. Place a small stone or scratch mark at the exact tip of the shadow. This is your west mark (in the Northern Hemisphere).", comment: "Step Detail")
        let _ = String(localized: "Wait 15-20 minutes. Mark the new shadow tip position.", comment: "Step Instruction")
        let _ = String(localized: "The shadow moves from west to east as the sun moves east to west. The new mark indicates east. The longer you wait, the more accurate the reading. 30 minutes is ideal.", comment: "Step Detail")
        let _ = String(localized: "Draw a line between marks: first mark = West, second = East.", comment: "Step Instruction")
        let _ = String(localized: "Stand with west on your left and east on your right — you face north (Northern Hemisphere). For the Southern Hemisphere: first mark = east, second = west, and you face south.", comment: "Step Detail")
        let _ = String(localized: "Analog Watch as Compass", comment: "Technique Name")
        let _ = String(localized: "Use an analog watch to find north/south", comment: "Technique Subtitle")
        let _ = String(localized: "Hold watch flat. Point the hour hand at the sun.", comment: "Step Instruction")
        let _ = String(localized: "Make sure the watch is set to standard time (not daylight saving). Hold it horizontal and rotate until the hour hand points directly at the sun.", comment: "Step Detail")
        let _ = String(localized: "Northern Hemisphere: bisect the angle between the hour hand and 12 o'clock. That's south.", comment: "Step Instruction")
        let _ = String(localized: "Imagine a line exactly halfway between the hour hand and the 12. That line points south. North is directly opposite. At 4pm: south is between 4 and 12 (the 2 o'clock position).", comment: "Step Detail")
        let _ = String(localized: "Southern Hemisphere: point 12 at the sun. Bisect between 12 and the hour hand. That's north.", comment: "Step Instruction")
        let _ = String(localized: "In the Southern Hemisphere, the process is reversed. Point the 12 o'clock mark at the sun instead. Digital watch: draw a clock face on paper with the current time.", comment: "Step Detail")
        let _ = String(localized: "Wind Direction Navigation", comment: "Technique Name")
        let _ = String(localized: "Use prevailing wind patterns to maintain direction", comment: "Technique Subtitle")
        let _ = String(localized: "Natural", comment: "Category")
        let _ = String(localized: "Determine wind direction at your starting point using sun or compass.", comment: "Step Instruction")
        let _ = String(localized: "Before you lose your compass or landmark reference, note which direction the wind blows. Wet a finger and hold up — the cool side faces the wind.", comment: "Step Detail")
        let _ = String(localized: "Maintain a consistent angle to the wind as you travel.", comment: "Step Instruction")
        let _ = String(localized: "If the wind is hitting your left cheek when heading east, keep it on your left cheek. Wind direction is usually consistent for 6-12 hours. Check against sun position periodically.", comment: "Step Detail")
        let _ = String(localized: "Recalibrate wind direction against other navigation cues regularly.", comment: "Step Instruction")
        let _ = String(localized: "Wind shifts throughout the day and with weather changes. Never use wind as your sole navigation method. Cross-reference with sun position, stars, terrain, or vegetation indicators.", comment: "Step Detail")
        let _ = String(localized: "Snow Environment Navigation", comment: "Technique Name")
        let _ = String(localized: "Navigate in whiteout and snow-covered terrain", comment: "Technique Subtitle")
        let _ = String(localized: "In whiteout: STOP. Moving blindly in whiteout conditions is often fatal.", comment: "Step Instruction")
        let _ = String(localized: "Whiteout eliminates all visual references. You cannot distinguish ground from sky. People walk in circles, over cliffs, or into crevasses. If possible, shelter in place until visibility improves.", comment: "Step Detail")
        let _ = String(localized: "Use sastrugi (wind-carved snow ridges) to maintain direction.", comment: "Step Instruction")
        let _ = String(localized: "Prevailing wind creates consistent parallel ridges in snow surfaces. These ridges maintain their orientation. Walk at a fixed angle to the ridges to travel a consistent direction.", comment: "Step Detail")
        let _ = String(localized: "If you must move in low visibility, probe ahead with a ski pole or stick.", comment: "Step Instruction")
        let _ = String(localized: "Probe every step for crevasses, drop-offs, or thin ice. Travel roped to partners if possible. Move slowly and deliberately. Mark your back-trail with ski poles or stakes.", comment: "Step Detail")
        let _ = String(localized: "Cloud Reading for Weather & Direction", comment: "Technique Name")
        let _ = String(localized: "Use cloud formations to predict weather and determine direction", comment: "Technique Subtitle")
        let _ = String(localized: "High, thin clouds (cirrus) moving fast indicate approaching weather change.", comment: "Step Instruction")
        let _ = String(localized: "Cirrus clouds 24-36 hours before a front. If they thicken into cirrostratus (hazy sun), rain in 12-24 hours. Clouds moving from west to east confirm you're in the westerly wind belt (mid-latitudes).", comment: "Step Detail")
        let _ = String(localized: "Cumulus clouds (puffy) over land often indicate landmasses from the sea.", comment: "Step Instruction")
        let _ = String(localized: "If you're on the ocean or a coastline, cumulus clouds form over land during daytime due to heating. Flat clouds stay over water. Navigate toward cumulus buildups to find land.", comment: "Step Detail")
        let _ = String(localized: "Cloud direction at different altitudes tells you about wind layers.", comment: "Step Instruction")
        let _ = String(localized: "Low clouds show surface wind direction. High clouds show upper-level winds. If they contradict, a weather change is coming. Clouds always move away from high pressure toward low pressure.", comment: "Step Detail")
        let _ = String(localized: "Terrain Association Navigation", comment: "Technique Name")
        let _ = String(localized: "Navigate by matching ground features to mental map", comment: "Technique Subtitle")
        let _ = String(localized: "Advanced", comment: "Category")
        let _ = String(localized: "Before moving, study visible terrain features and memorize their relative positions.", comment: "Step Instruction")
        let _ = String(localized: "Identify prominent features: mountains, valleys, rivers, ridgelines, distinct trees, rock formations. Note their direction from your position. Create a mental map.", comment: "Step Detail")
        let _ = String(localized: "As you travel, continuously match terrain to your mental map.", comment: "Step Instruction")
        let _ = String(localized: "Check: 'That mountain should be on my right' or 'I should cross a stream soon.' When reality matches your expectations, you're on track. When it doesn't, stop and reassess.", comment: "Step Detail")
        let _ = String(localized: "Use elevation changes and drainage patterns to confirm location.", comment: "Step Instruction")
        let _ = String(localized: "Water always flows downhill and collects into larger streams. If you're walking uphill, you're moving toward a ridge. Valleys and ridgelines are the most reliable terrain features for navigation.", comment: "Step Detail")
        let _ = String(localized: "Back Bearing Check", comment: "Technique Name")
        let _ = String(localized: "Look behind you regularly to remember the return route", comment: "Technique Subtitle")
        let _ = String(localized: "Basic", comment: "Category")
        let _ = String(localized: "Every few minutes, turn around and look at where you came from.", comment: "Step Instruction")
        let _ = String(localized: "Terrain looks completely different from the opposite direction. If you don't study the back view, you won't recognize your return route. This is the #1 cause of getting lost.", comment: "Step Detail")
        let _ = String(localized: "Memorize key landmarks from the return perspective.", comment: "Step Instruction")
        let _ = String(localized: "Note: 'That distinctive rock will be on my LEFT coming back' or 'I'll see that forked tree when I return.' Mental snapshots from the return direction are critical.", comment: "Step Detail")
        let _ = String(localized: "At decision points (trail forks, stream crossings), mark your route.", comment: "Step Instruction")
        let _ = String(localized: "Stack rocks (cairns), break branches to point the way, scratch arrows on trees, or stack sticks at trail junctions. Make marks visible from the return direction.", comment: "Step Detail")
        let _ = String(localized: "Position Triangulation", comment: "Technique Name")
        let _ = String(localized: "Pinpoint your location using three landmarks and a compass", comment: "Technique Subtitle")
        let _ = String(localized: "Take a compass bearing to three identifiable landmarks.", comment: "Step Instruction")
        let _ = String(localized: "Choose landmarks you can identify on your map: mountain peaks, radio towers, distinctive terrain. Take a bearing to each and record. Landmarks should be spread 60-120 degrees apart for best accuracy.", comment: "Step Detail")
        let _ = String(localized: "Convert each bearing to a back-bearing (add or subtract 180°).", comment: "Step Instruction")
        let _ = String(localized: "If your bearing TO the landmark is 045°, the back-bearing is 225° (045+180). If bearing is over 180, subtract 180 instead. Back-bearings show lines FROM the landmarks to you.", comment: "Step Detail")
        let _ = String(localized: "Draw back-bearing lines from each landmark on the map. You are where they intersect.", comment: "Step Instruction")
        let _ = String(localized: "Place protractor on each landmark, draw a line at the back-bearing angle. The three lines form a small triangle. You are inside that triangle. Smaller triangle = more accurate fix.", comment: "Step Detail")
        let _ = String(localized: "Handrail Navigation", comment: "Technique Name")
        let _ = String(localized: "Follow linear features to stay on course", comment: "Technique Subtitle")
        let _ = String(localized: "Identify a linear feature running roughly parallel to your desired direction.", comment: "Step Instruction")
        let _ = String(localized: "Handrails are long features you can follow: rivers, ridgelines, trails, power lines, roads, fences, tree lines, cliff edges. They prevent you from veering off course.", comment: "Step Detail")
        let _ = String(localized: "Keep the handrail feature on your left or right as you travel.", comment: "Step Instruction")
        let _ = String(localized: "You don't need to walk directly on the feature. Just keep it within sight or hearing distance. 'Keep the river on my right' is a simple, reliable navigation instruction.", comment: "Step Detail")
        let _ = String(localized: "When you reach your cross-feature (catching feature), leave the handrail.", comment: "Step Instruction")
        let _ = String(localized: "Plan ahead: 'I'll follow the river until I hit the power line, then turn right.' The power line is your catching feature — it tells you when to change course.", comment: "Step Detail")
        let _ = String(localized: "Deliberate Offset Navigation", comment: "Technique Name")
        let _ = String(localized: "Intentionally aim left or right of target to find it reliably", comment: "Technique Subtitle")
        let _ = String(localized: "When aiming for a target on a linear feature, deliberately aim to one side.", comment: "Step Instruction")
        let _ = String(localized: "Example: your camp is on a river. If you walk straight toward it, small navigation errors mean you don't know whether you're left or right of camp when you hit the river.", comment: "Step Detail")
        let _ = String(localized: "Aim 10-20 degrees to the LEFT of your target intentionally.", comment: "Step Instruction")
        let _ = String(localized: "When you reach the river, you KNOW you're to the left of camp. Turn right and follow the river until you reach camp. Uncertainty eliminated.", comment: "Step Detail")
        let _ = String(localized: "When you reach the linear feature, turn in the direction of your target.", comment: "Step Instruction")
        let _ = String(localized: "This technique converts a 2D search problem into a 1D problem. Instead of searching both left and right, you only search in one direction. Used extensively in military land navigation.", comment: "Step Detail")
        let _ = String(localized: "Star Steering (Night Travel)", comment: "Technique Name")
        let _ = String(localized: "Navigate at night by choosing a star to walk toward", comment: "Technique Subtitle")
        let _ = String(localized: "Select a bright star low on the horizon in your desired travel direction.", comment: "Step Instruction")
        let _ = String(localized: "Choose a star close to the horizon — high stars are harder to steer by. The star should be bright and distinctive. Walk toward it. This keeps you on a straight line.", comment: "Step Detail")
        let _ = String(localized: "Replace your steering star every 15-20 minutes as stars move.", comment: "Step Instruction")
        let _ = String(localized: "Stars move across the sky (15° per hour). After 15-20 minutes, your star has drifted noticeably. Re-confirm your direction using Polaris or the Southern Cross, then pick a new steering star.", comment: "Step Detail")
        let _ = String(localized: "Use Polaris (North Star) as a constant reference — it stays fixed.", comment: "Step Instruction")
        let _ = String(localized: "Polaris is the only star that doesn't move significantly. It always indicates true north. All other stars rotate around it. Keep Polaris in a consistent position relative to you.", comment: "Step Detail")
        let _ = String(localized: "Navigate along coastlines using tides, reefs, and landmarks", comment: "Technique Subtitle")
        let _ = String(localized: "Maritime", comment: "Category")
        let _ = String(localized: "Keep the coastline as your handrail. Note tide direction for orientation.", comment: "Step Instruction")
        let _ = String(localized: "If tide is flowing north (check with a floating stick), you know which direction is north. Tides reverse roughly every 6 hours. Track the cycle to maintain direction awareness.", comment: "Step Detail")
        let _ = String(localized: "Use headlands and bays as navigation checkpoints.", comment: "Step Instruction")
        let _ = String(localized: "Count the bays you pass. Each headland (point of land) is a landmark. Note distinctive features: rock color, cliff height, vegetation patterns. These serve as your 'mile markers.'", comment: "Step Detail")
        let _ = String(localized: "Wave patterns indicate underwater features and nearby land.", comment: "Step Instruction")
        let _ = String(localized: "Waves refract around islands and reefs. Disturbed wave patterns (confused seas) indicate shallow water or hidden obstacles. Calm water behind a headland indicates sheltered anchorage.", comment: "Step Detail")
        let _ = String(localized: "Use rivers as navigation aids to find civilization", comment: "Technique Subtitle")
        let _ = String(localized: "Follow rivers DOWNSTREAM. Rivers flow toward civilization, lakes, or the coast.", comment: "Step Instruction")
        let _ = String(localized: "Rivers grow larger downstream as tributaries join. Larger rivers are more likely to have settlements along them. This is the single most reliable lost-person strategy in most terrain.", comment: "Step Detail")
        let _ = String(localized: "Watch for signs of civilization: bridges, trash, cleared banks, power lines.", comment: "Step Instruction")
        let _ = String(localized: "Human activity leaves traces along rivers. Cut trees, livestock marks, discarded items, tire tracks, or footpaths all indicate people are nearby. Follow these signs.", comment: "Step Detail")
        let _ = String(localized: "Stay on the side with the best terrain. Don't cross rivers unnecessarily.", comment: "Step Instruction")
        let _ = String(localized: "River crossings are dangerous. Stay on whichever bank has easier walking. If the river enters a gorge, climb above it and follow the rim. Rejoin the river when terrain permits.", comment: "Step Detail")
        let _ = String(localized: "Altitude Estimation Without Tools", comment: "Technique Name")
        let _ = String(localized: "Estimate your elevation using natural indicators", comment: "Technique Subtitle")
        let _ = String(localized: "Vegetation zones indicate approximate altitude.", comment: "Step Instruction")
        let _ = String(localized: "Deciduous forest: below 3,000-4,000 ft. Conifer forest: 4,000-9,000 ft. Alpine meadow: 9,000-11,500 ft. Above treeline: 11,500+ ft (varies by latitude). These zones shift in different climates.", comment: "Step Detail")
        let _ = String(localized: "Water boiling behavior indicates altitude.", comment: "Step Instruction")
        let _ = String(localized: "Water boils at lower temperatures at altitude. If water boils noticeably faster or at lower temperature than expected, you're at significant elevation. Temperature drops roughly 3.5°F per 1,000 feet.", comment: "Step Detail")
        let _ = String(localized: "Snow line and breathing difficulty provide additional altitude clues.", comment: "Step Instruction")
        let _ = String(localized: "Permanent snow: varies by latitude (14,000+ ft at equator, sea level at poles). Breathing becomes noticeably harder above 8,000 ft. Headache and fatigue at 10,000+ ft suggest altitude sickness.", comment: "Step Detail")
        let _ = String(localized: "Weather Prediction from Nature", comment: "Technique Name")
        let _ = String(localized: "Forecast weather changes using natural signs", comment: "Technique Subtitle")
        let _ = String(localized: "Falling barometric pressure = incoming bad weather.", comment: "Step Instruction")
        let _ = String(localized: "Signs of falling pressure: campfire smoke descends instead of rising; clouds lower and thicken; sounds carry farther than normal; birds fly lower; joints ache; coffee bubbles cluster at cup center.", comment: "Step Detail")
        let _ = String(localized: "Wind shift from west to east or south often brings storms.", comment: "Step Instruction")
        let _ = String(localized: "In the Northern Hemisphere, weather systems generally move west to east. A wind shift from west to south to east often precedes a low-pressure system bringing rain.", comment: "Step Detail")
        let _ = String(localized: "Red sky at morning = weather warning. Red sky at night = fair weather.", comment: "Step Instruction")
        let _ = String(localized: "This is scientifically valid. Red sky at sunset means dust particles in the west (dry air approaching). Red sky at dawn means the dry air has passed and moisture is coming from the west.", comment: "Step Detail")
        let _ = String(localized: "Emergency Straight-Line Travel", comment: "Technique Name")
        let _ = String(localized: "Walk a straight line without a compass using landmark sighting", comment: "Technique Subtitle")
        let _ = String(localized: "Sight two objects in line with your desired direction — one near, one far.", comment: "Step Instruction")
        let _ = String(localized: "Pick a specific tree (near) and a mountain peak (far) that align with your direction. Walk toward the near object while keeping the far object aligned behind it.", comment: "Step Detail")
        let _ = String(localized: "When you reach the near object, pick a new near object aligned with the far one.", comment: "Step Instruction")
        let _ = String(localized: "Leapfrog from near object to near object, always keeping the far reference unchanged. This keeps you on an extremely straight line without any instruments.", comment: "Step Detail")
        let _ = String(localized: "When the far object is reached or lost, select two new aligned objects.", comment: "Step Instruction")
        let _ = String(localized: "Keep your travel direction consistent by always aligning two points before moving. Without this technique, humans naturally walk in circles (dominant leg takes slightly longer stride).", comment: "Step Detail")
        let _ = String(localized: "Vegetation Direction Indicators", comment: "Technique Name")
        let _ = String(localized: "Read tree growth patterns for compass direction", comment: "Technique Subtitle")
        let _ = String(localized: "In the Northern Hemisphere, heavier growth is typically on the south side of trees.", comment: "Step Instruction")
        let _ = String(localized: "Trees receive more sunlight on their south-facing side. This causes denser foliage, thicker branches, and more growth. The effect is most visible on isolated trees, not in dense forest.", comment: "Step Detail")
        let _ = String(localized: "Moss grows on the SHADED side — NOT always north.", comment: "Step Instruction")
        let _ = String(localized: "The 'moss grows on the north side' rule is unreliable. Moss grows on the shaded, moist side, which varies with terrain. Use moss only to confirm other navigation methods, never as primary.", comment: "Step Detail")
        let _ = String(localized: "Combine multiple vegetation indicators for better accuracy.", comment: "Step Instruction")
        let _ = String(localized: "Spider webs tend to face south (warmth). Flowers face the sun. Trees lean away from prevailing wind. No single indicator is reliable alone, but multiple indicators pointing the same direction increase confidence.", comment: "Step Detail")
        let _ = String(localized: "Psychology", comment: "Domain Name")
        let _ = String(localized: "Box Breathing (4-4-4-4)", comment: "Technique Name")
        let _ = String(localized: "Military-grade stress reset", comment: "Technique Subtitle")
        let _ = String(localized: "Mindset", comment: "Category")
        let _ = String(localized: "Inhale through your nose for 4 seconds.", comment: "Step Instruction")
        let _ = String(localized: "Fill your lungs completely. Breathe deep into your belly, not shallow into your chest.", comment: "Step Detail")
        let _ = String(localized: "Hold your breath for 4 seconds.", comment: "Step Instruction")
        let _ = String(localized: "Don't clamp down. Just pause. Keep your throat and chest relaxed.", comment: "Step Detail")
        let _ = String(localized: "Exhale slowly through your mouth for 4 seconds.", comment: "Step Instruction")
        let _ = String(localized: "Controlled, steady exhale. Pursed lips help slow the exhale. Empty your lungs completely.", comment: "Step Detail")
        let _ = String(localized: "Hold empty for 4 seconds. Repeat 4 cycles.", comment: "Step Instruction")
        let _ = String(localized: "The empty hold is the key differentiator. It activates the parasympathetic nervous system. Navy SEALs use this technique before operations.", comment: "Step Detail")
        let _ = String(localized: "5-4-3-2-1 Grounding", comment: "Technique Name")
        let _ = String(localized: "Pull yourself out of panic using your senses", comment: "Technique Subtitle")
        let _ = String(localized: "Name 5 things you can SEE.", comment: "Step Instruction")
        let _ = String(localized: "Look around and identify 5 specific objects. Say them out loud: 'I see a rock, a tree, my boot, the sky, a bird.'", comment: "Step Detail")
        let _ = String(localized: "Name 4 things you can TOUCH.", comment: "Step Instruction")
        let _ = String(localized: "Feel surfaces around you. 'I feel the rough bark, the cold water, the soft moss, my own heartbeat.'", comment: "Step Detail")
        let _ = String(localized: "Name 3 things you can HEAR.", comment: "Step Instruction")
        let _ = String(localized: "Close your eyes. 'I hear wind, a bird call, water flowing.' Active listening pulls you into the present.", comment: "Step Detail")
        let _ = String(localized: "Name 2 things you can SMELL.", comment: "Step Instruction")
        let _ = String(localized: "'I smell pine needles, I smell damp earth.' If you can't smell anything, remember 2 smells you like.", comment: "Step Detail")
        let _ = String(localized: "Name 1 thing you can TASTE.", comment: "Step Instruction")
        let _ = String(localized: "'I taste water.' This exercise grounds you in physical reality, breaking the panic cycle. Panic is future-focused; senses are present-focused.", comment: "Step Detail")
        let _ = String(localized: "STOP Method", comment: "Technique Name")
        let _ = String(localized: "Stop, Think, Observe, Plan", comment: "Technique Subtitle")
        let _ = String(localized: "STOP. Literally stop moving.", comment: "Step Instruction")
        let _ = String(localized: "When you realize you're lost or in danger, the worst thing you can do is keep going. Motion without direction makes everything worse.", comment: "Step Detail")
        let _ = String(localized: "THINK. What do I know? What are my resources?", comment: "Step Instruction")
        let _ = String(localized: "Assess: What time is it? How much water/food do I have? When will someone notice I'm missing? Am I injured?", comment: "Step Detail")
        let _ = String(localized: "OBSERVE. Look around. What's my environment telling me?", comment: "Step Instruction")
        let _ = String(localized: "Where is the sun? Is there shelter nearby? Water? What's the weather doing? Are there trails, roads, or sounds of civilization?", comment: "Step Detail")
        let _ = String(localized: "PLAN. Make a rational decision based on facts, not fear.", comment: "Step Instruction")
        let _ = String(localized: "Now act deliberately. Every decision should be based on the information you just gathered, not on panic or emotion.", comment: "Step Detail")
        let _ = String(localized: "Positive Self-Talk Script", comment: "Technique Name")
        let _ = String(localized: "Your inner voice determines survival", comment: "Technique Subtitle")
        let _ = String(localized: "Resilience", comment: "Category")
        let _ = String(localized: "Replace 'I can't' with 'I haven't figured out how yet.'", comment: "Step Instruction")
        let _ = String(localized: "Language shapes thought. Absolute negatives ('can't', 'never', 'impossible') shut down problem-solving. Provisional language keeps options open.", comment: "Step Detail")
        let _ = String(localized: "Break the task into the very next single step.", comment: "Step Instruction")
        let _ = String(localized: "'I need to walk 20 miles' is overwhelming. 'I need to walk to that tree' is achievable. Then the next tree. Then the next.", comment: "Step Detail")
        let _ = String(localized: "Acknowledge fear, then redirect: 'I'm scared AND I can still act.'", comment: "Step Instruction")
        let _ = String(localized: "Fear is not the enemy — paralysis is. You can be terrified and still functional. Bravery is action despite fear, not absence of it.", comment: "Step Detail")
        let _ = String(localized: "Repeat: 'I have survived every bad day so far. 100% success rate.'", comment: "Step Instruction")
        let _ = String(localized: "This is literally true. Every challenge you've faced, you've survived. That track record is unbroken. Use it.", comment: "Step Detail")
        let _ = String(localized: "Managing Sleep Deprivation", comment: "Technique Name")
        let _ = String(localized: "Strategic napping when you can't sleep normally", comment: "Technique Subtitle")
        let _ = String(localized: "Take 20-minute power naps whenever safe to do so.", comment: "Step Instruction")
        let _ = String(localized: "20 minutes is optimal — you get light sleep restoration without entering deep sleep, which causes grogginess.", comment: "Step Detail")
        let _ = String(localized: "Navy nap schedule: 20 min ON, 40 min OFF throughout the day.", comment: "Step Instruction")
        let _ = String(localized: "This sustains functional performance for days. Not ideal, but dramatically better than continuous wakefulness.", comment: "Step Detail")
        let _ = String(localized: "Recognize cognitive decline: poor decisions, irritability, hallucinations.", comment: "Step Instruction")
        let _ = String(localized: "After 24 hours: equivalent to 0.10% BAC. After 48 hours: microsleeps (involuntary 1-30 second sleep episodes). After 72 hours: psychosis-like symptoms.", comment: "Step Detail")
        let _ = String(localized: "Prioritize sleep as a survival task, not a luxury.", comment: "Step Instruction")
        let _ = String(localized: "Sleep is when your body repairs injury, consolidates memory, and restores immune function. Skipping sleep to 'push through' is false economy.", comment: "Step Detail")
        let _ = String(localized: "Strengthening the Will to Live", comment: "Technique Name")
        let _ = String(localized: "The single most important survival factor", comment: "Technique Subtitle")
        let _ = String(localized: "Identify your 'anchor' — the person or thing you are surviving FOR.", comment: "Step Instruction")
        let _ = String(localized: "Research on disaster survivors shows that people who survive for someone else last longer than those surviving for themselves. Name them. Picture their face.", comment: "Step Detail")
        let _ = String(localized: "Set micro-goals: survive the next hour. Then the next.", comment: "Step Instruction")
        let _ = String(localized: "Don't think about rescue in 3 days. Think about making it to sunset. Then to sunrise. Small horizons prevent overwhelm.", comment: "Step Detail")
        let _ = String(localized: "Maintain routines — they create normalcy in chaos.", comment: "Step Instruction")
        let _ = String(localized: "Wake up at the same time. Eat at regular intervals. Check signals at set times. Routine fights despair.", comment: "Step Detail")
        let _ = String(localized: "Stay busy. Idle hands and idle minds are your enemy.", comment: "Step Instruction")
        let _ = String(localized: "Always have a task. Improve your shelter. Gather more firewood. Set another trap. Purposeful activity prevents the downward spiral of hopelessness.", comment: "Step Detail")
        let _ = String(localized: "Group Survival Leadership", comment: "Technique Name")
        let _ = String(localized: "Organize a group for collective survival", comment: "Technique Subtitle")
        let _ = String(localized: "Group", comment: "Category")
        let _ = String(localized: "Establish a single leader immediately.", comment: "Step Instruction")
        let _ = String(localized: "Democracy slows decisions in emergencies. The group should agree on one decision-maker. This prevents confusion and infighting.", comment: "Step Detail")
        let _ = String(localized: "Assign roles based on skills: fire, water, shelter, medical, signaling.", comment: "Step Instruction")
        let _ = String(localized: "Everyone contributes. Even injured people can tend fire or signal. Assigned roles prevent free-riding and give everyone purpose.", comment: "Step Detail")
        let _ = String(localized: "Communicate openly about resources and situation.", comment: "Step Instruction")
        let _ = String(localized: "Hoarding information or resources destroys group cohesion. Share what you know — good and bad. Rumors fill information vacuums.", comment: "Step Detail")
        let _ = String(localized: "Monitor group morale. One panicking person can destroy the group.", comment: "Step Instruction")
        let _ = String(localized: "Isolate panic, address it privately. Keep the group focused on tasks. Evening check-ins help detect morale problems early.", comment: "Step Detail")
        let _ = String(localized: "Keeping Children Calm", comment: "Technique Name")
        let _ = String(localized: "Age-appropriate crisis management", comment: "Technique Subtitle")
        let _ = String(localized: "Children mirror adult emotions. Control yours first.", comment: "Step Instruction")
        let _ = String(localized: "If you're visibly panicking, they will panic harder. Take 60 seconds to compose yourself before addressing children.", comment: "Step Detail")
        let _ = String(localized: "Give them jobs — simple, achievable tasks.", comment: "Step Instruction")
        let _ = String(localized: "'Can you find me 10 sticks this big?' 'Can you count the birds?' Purpose reduces fear. Achievement builds confidence.", comment: "Step Detail")
        let _ = String(localized: "Be honest at an age-appropriate level.", comment: "Step Instruction")
        let _ = String(localized: "'We're going to be camping outside tonight while we figure out the best way to go home.' Lying destroys trust if they figure it out.", comment: "Step Detail")
        let _ = String(localized: "Physical comfort: stay close, maintain physical contact.", comment: "Step Instruction")
        let _ = String(localized: "Hugs, holding hands, keeping them in your lap at night. Physical touch is the most powerful anxiety reducer for children.", comment: "Step Detail")
        let _ = String(localized: "Combating Decision Fatigue", comment: "Technique Name")
        let _ = String(localized: "When you're too tired to think straight", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize the signs: everything feels equally important or impossible.", comment: "Step Instruction")
        let _ = String(localized: "Decision fatigue makes you either impulsive (do anything to stop thinking) or paralyzed (do nothing). Both kill.", comment: "Step Detail")
        let _ = String(localized: "Default to the survival priority list: Shelter → Water → Fire → Food.", comment: "Step Instruction")
        let _ = String(localized: "When you can't decide, work down this list. Address the first unmet need. Don't think about food if you don't have water.", comment: "Step Detail")
        let _ = String(localized: "Use the 'good enough' principle.", comment: "Step Instruction")
        let _ = String(localized: "A good enough shelter NOW is better than a perfect shelter in 3 hours — especially at dusk. Satisfice, don't optimize.", comment: "Step Detail")
        let _ = String(localized: "Eat, drink, and rest before making any major decision.", comment: "Step Instruction")
        let _ = String(localized: "Blood sugar, hydration, and fatigue all degrade judgment. If a decision can wait 30 minutes, eat and rest first.", comment: "Step Detail")
        let _ = String(localized: "Managing Specific Fears", comment: "Technique Name")
        let _ = String(localized: "Darkness, animals, isolation, death", comment: "Technique Subtitle")
        let _ = String(localized: "Name the fear specifically. Vague fear is paralyzing.", comment: "Step Instruction")
        let _ = String(localized: "'I'm scared' → 'I'm scared a bear will attack me at night.' Once named, you can address it: 'I'll hang my food 200 feet away and make noise.'", comment: "Step Detail")
        let _ = String(localized: "Separate real threats from perceived threats.", comment: "Step Instruction")
        let _ = String(localized: "Is a bear actually likely? Have you seen signs? Most nighttime noises are small animals. Knowledge replaces fear — learn what actually threatens you.", comment: "Step Detail")
        let _ = String(localized: "Take one concrete action to address the fear.", comment: "Step Instruction")
        let _ = String(localized: "Afraid of the dark? Build a brighter fire. Afraid of animals? Make a noise-maker. Afraid of being alone? Write a journal or talk out loud.", comment: "Step Detail")
        let _ = String(localized: "Accept residual fear as your ally — it keeps you alert.", comment: "Step Instruction")
        let _ = String(localized: "Complete fearlessness is dangerous. Fear is your brain's danger detection system. The goal is manageable fear, not zero fear.", comment: "Step Detail")
        let _ = String(localized: "Establishing Daily Routine", comment: "Technique Name")
        let _ = String(localized: "Routine creates purpose, purpose creates survival", comment: "Technique Subtitle")
        let _ = String(localized: "Wake at same time daily. Begin with a task immediately.", comment: "Step Instruction")
        let _ = String(localized: "Structure: water, fire, food, shelter, signaling. Same order daily.", comment: "Step Detail")
        let _ = String(localized: "Set specific goals for each day—even small ones.", comment: "Step Instruction")
        let _ = String(localized: "Improve shelter, find better firewood. Accomplishment fuels morale.", comment: "Step Detail")
        let _ = String(localized: "Maintain hygiene even when it seems pointless.", comment: "Step Instruction")
        let _ = String(localized: "Brush teeth with chewed stick. Wash hands. Prevents infection.", comment: "Step Detail")
        let _ = String(localized: "End day reviewing accomplishments and planning tomorrow.", comment: "Step Instruction")
        let _ = String(localized: "Gives sense of control. Mark days on stick calendar.", comment: "Step Detail")
        let _ = String(localized: "Pain Management Without Meds", comment: "Technique Name")
        let _ = String(localized: "Mental techniques to reduce pain perception", comment: "Technique Subtitle")
        let _ = String(localized: "Focus breathing: slow, deep—4 in, 8 out.", comment: "Step Instruction")
        let _ = String(localized: "Extended exhale activates parasympathetic system. Reduces pain signals.", comment: "Step Detail")
        let _ = String(localized: "Mental distraction: count backward from 1000 by 7s.", comment: "Step Instruction")
        let _ = String(localized: "Engaging analytical brain reduces emotional pain response.", comment: "Step Detail")
        let _ = String(localized: "Cold water on wrists and face triggers dive reflex.", comment: "Step Instruction")
        let _ = String(localized: "Slows heart rate, reduces pain. Splash or submerge wrists.", comment: "Step Detail")
        let _ = String(localized: "Accept the pain—resistance amplifies it.", comment: "Step Instruction")
        let _ = String(localized: "Acknowledge without fighting. Resistance creates tension which increases pain.", comment: "Step Detail")
        let _ = String(localized: "Managing Isolation & Loneliness", comment: "Technique Name")
        let _ = String(localized: "Your mind is your most dangerous enemy alone", comment: "Technique Subtitle")
        let _ = String(localized: "Talk out loud. Narrate your actions.", comment: "Step Instruction")
        let _ = String(localized: "Hearing a voice prevents cognitive deterioration.", comment: "Step Detail")
        let _ = String(localized: "Create a companion: name a piece of gear.", comment: "Step Instruction")
        let _ = String(localized: "Proven psychological technique. Not weakness.", comment: "Step Detail")
        let _ = String(localized: "Maintain physical appearance and camp neatness.", comment: "Step Instruction")
        let _ = String(localized: "Deterioration accelerates hopelessness. Keep order.", comment: "Step Detail")
        let _ = String(localized: "Journal with charcoal on bark. Record experience.", comment: "Step Instruction")
        let _ = String(localized: "Externalizes negative thoughts. Gives purpose.", comment: "Step Detail")
        let _ = String(localized: "OODA Loop Decision Making", comment: "Technique Name")
        let _ = String(localized: "Military decision framework for survival", comment: "Technique Subtitle")
        let _ = String(localized: "Decision", comment: "Category")
        let _ = String(localized: "OBSERVE: What is actually happening? Facts only.", comment: "Step Instruction")
        let _ = String(localized: "Strip emotion. What do senses tell you? Raw data.", comment: "Step Detail")
        let _ = String(localized: "ORIENT: What does this mean for survival?", comment: "Step Instruction")
        let _ = String(localized: "Is this threat or opportunity? What are priorities?", comment: "Step Detail")
        let _ = String(localized: "DECIDE: Choose ONE action. Commit completely.", comment: "Step Instruction")
        let _ = String(localized: "Good plan now beats perfect plan later. Indecision kills.", comment: "Step Detail")
        let _ = String(localized: "ACT: Execute, then loop back to OBSERVE.", comment: "Step Instruction")
        let _ = String(localized: "Take action, observe results. Continuous adaptation.", comment: "Step Detail")
        let _ = String(localized: "Field Sleep Hygiene", comment: "Technique Name")
        let _ = String(localized: "Maximize rest quality in harsh conditions", comment: "Technique Subtitle")
        let _ = String(localized: "Establish a consistent sleep schedule even without a clock.", comment: "Step Instruction")
        let _ = String(localized: "Use sunset and sunrise as anchors. Consistent timing regulates circadian rhythm even in extreme conditions.", comment: "Step Detail")
        let _ = String(localized: "Create a pre-sleep ritual: secure camp, bank fire, check water.", comment: "Step Instruction")
        let _ = String(localized: "Routine signals your brain that sleep is coming. Same order every night builds association.", comment: "Step Detail")
        let _ = String(localized: "Insulate from below — ground steals heat 30x faster than air.", comment: "Step Instruction")
        let _ = String(localized: "Pile leaves, grass, boughs 6 inches thick minimum. Your back loses more heat to ground contact than your front loses to air.", comment: "Step Detail")
        let _ = String(localized: "Eat something before sleeping — digestion generates internal heat.", comment: "Step Instruction")
        let _ = String(localized: "Even a small amount of food raises core temperature. Warm liquids before bed dramatically improve sleep onset.", comment: "Step Detail")
        let _ = String(localized: "Grief Management in Crisis", comment: "Technique Name")
        let _ = String(localized: "Process loss without losing function", comment: "Technique Subtitle")
        let _ = String(localized: "Acknowledge the loss — suppressing grief causes delayed breakdown.", comment: "Step Instruction")
        let _ = String(localized: "Say it out loud: 'This happened. I feel this.' Naming emotions reduces their physiological intensity by up to 50%.", comment: "Step Detail")
        let _ = String(localized: "Set a contained grief period — 10 minutes, then return to tasks.", comment: "Step Instruction")
        let _ = String(localized: "This is not denial. It is compartmentalization — a skill used by military, first responders, and surgeons to function under emotional load.", comment: "Step Detail")
        let _ = String(localized: "Channel grief into purposeful action — build, signal, improve camp.", comment: "Step Instruction")
        let _ = String(localized: "Physical work metabolizes stress hormones. Building something tangible gives a sense of control when everything feels out of control.", comment: "Step Detail")
        let _ = String(localized: "Create a memorial when safe — a cairn, carving, or moment of silence.", comment: "Step Instruction")
        let _ = String(localized: "Ritual closure is psychologically critical. It allows the brain to categorize the loss as processed rather than pending.", comment: "Step Detail")
        let _ = String(localized: "Managing Children in Survival", comment: "Technique Name")
        let _ = String(localized: "Keep kids calm, safe, and occupied", comment: "Technique Subtitle")
        let _ = String(localized: "Control YOUR reaction first — children mirror adult emotions exactly.", comment: "Step Instruction")
        let _ = String(localized: "If you panic, they panic. If you are calm and purposeful, they feel safe. Your emotional state IS their emotional state.", comment: "Step Detail")
        let _ = String(localized: "Give age-appropriate honest information. No false promises.", comment: "Step Instruction")
        let _ = String(localized: "Children detect lies. Say: 'We are in a tough spot, but I know what to do, and I need your help.' This is honest AND empowering.", comment: "Step Detail")
        let _ = String(localized: "Assign tasks — gathering sticks, counting supplies, watching for planes.", comment: "Step Instruction")
        let _ = String(localized: "Purpose prevents panic in children just as it does in adults. Make tasks real and praise completion genuinely.", comment: "Step Detail")
        let _ = String(localized: "Maintain routines — meals, stories, bedtime. Normalcy is medicine.", comment: "Step Instruction")
        let _ = String(localized: "Even fabricated routines provide psychological scaffolding. 'Breakfast at sunrise, story at sunset' creates predictability in chaos.", comment: "Step Detail")
        let _ = String(localized: "Combating Boredom and Apathy", comment: "Technique Name")
        let _ = String(localized: "The silent killer in long-term survival", comment: "Technique Subtitle")
        let _ = String(localized: "Create a daily schedule with specific time blocks.", comment: "Step Instruction")
        let _ = String(localized: "Fire maintenance 6-7am, water collection 7-8am, shelter improvement 9-11am. Structure prevents the drift into apathy that kills motivation.", comment: "Step Detail")
        let _ = String(localized: "Set improvement projects — always have something to build or refine.", comment: "Step Instruction")
        let _ = String(localized: "Better shelter, improved fire pit, carved tools, fish trap. Progress on any project generates dopamine and purpose.", comment: "Step Detail")
        let _ = String(localized: "Exercise deliberately — even simple stretching or walking circuits.", comment: "Step Instruction")
        let _ = String(localized: "Physical activity is the most reliable antidepressant known. 20 minutes of movement changes brain chemistry measurably.", comment: "Step Detail")
        let _ = String(localized: "Practice skills — knot tying, fire starting, navigation drills.", comment: "Step Instruction")
        let _ = String(localized: "Skill practice is never wasted time. It builds confidence and competence that may save your life when conditions change.", comment: "Step Detail")
        let _ = String(localized: "Conflict Resolution in Groups", comment: "Technique Name")
        let _ = String(localized: "Disputes kill groups faster than hunger", comment: "Technique Subtitle")
        let _ = String(localized: "Address conflict immediately — unresolved tension escalates exponentially.", comment: "Step Instruction")
        let _ = String(localized: "What starts as a disagreement about rationing becomes a group-splitting crisis within 48 hours if unaddressed.", comment: "Step Detail")
        let _ = String(localized: "Separate parties. Let each state their position uninterrupted.", comment: "Step Instruction")
        let _ = String(localized: "People in conflict need to feel heard more than they need to win. Active listening defuses 80% of interpersonal conflicts.", comment: "Step Detail")
        let _ = String(localized: "Reframe as 'us vs. the situation' not 'us vs. each other.'", comment: "Step Instruction")
        let _ = String(localized: "The real enemy is always the environment, not each other. Redirect competitive energy toward shared survival goals.", comment: "Step Detail")
        let _ = String(localized: "Establish fair resource-sharing rules BEFORE scarcity hits.", comment: "Step Instruction")
        let _ = String(localized: "Equal portions, rotating priority, or needs-based allocation — decide while rational. Scarcity makes fair decisions impossible.", comment: "Step Detail")
        let _ = String(localized: "Managing Night Anxiety", comment: "Technique Name")
        let _ = String(localized: "Darkness amplifies every fear", comment: "Technique Subtitle")
        let _ = String(localized: "Accept that nighttime anxiety is universal and biological.", comment: "Step Instruction")
        let _ = String(localized: "Humans are daytime creatures. We evolved to fear darkness. Every sound seems louder, every shadow seems threatening. This is normal neurology, not weakness.", comment: "Step Detail")
        let _ = String(localized: "Maintain a fire — even a small flame resets primal fear circuits.", comment: "Step Instruction")
        let _ = String(localized: "Fire is 400,000 years of human evolution saying 'you are safe.' The light it provides is less important than the psychological protection it offers.", comment: "Step Detail")
        let _ = String(localized: "Identify every sound. Named threats feel manageable; unknown ones terrify.", comment: "Step Instruction")
        let _ = String(localized: "That rustling is probably a small rodent. That crack is a branch settling. Naming sounds removes the unknown, which is what your brain actually fears.", comment: "Step Detail")
        let _ = String(localized: "Breathe slowly: 4 counts in, 7 counts hold, 8 counts out.", comment: "Step Instruction")
        let _ = String(localized: "The 4-7-8 pattern activates the parasympathetic nervous system within 2 cycles. It physically slows heart rate and reduces cortisol.", comment: "Step Detail")
        let _ = String(localized: "Motivation Anchoring", comment: "Technique Name")
        let _ = String(localized: "Attach survival drive to something bigger than yourself", comment: "Technique Subtitle")
        let _ = String(localized: "Identify your anchor — the specific person or promise pulling you home.", comment: "Step Instruction")
        let _ = String(localized: "Not 'family' in abstract. Specific: 'My daughter's piano recital on March 15.' Specificity makes it real and urgent.", comment: "Step Detail")
        let _ = String(localized: "Visualize the reunion in vivid, sensory detail every morning.", comment: "Step Instruction")
        let _ = String(localized: "See their face. Hear their voice. Feel the hug. Visualization activates the same neural reward pathways as the actual experience.", comment: "Step Detail")
        let _ = String(localized: "Make a physical token — a carved symbol, a tied knot, a scratched mark.", comment: "Step Instruction")
        let _ = String(localized: "Physical objects anchor abstract motivation. Touch it when motivation fades. Survivors consistently report that tokens kept them going.", comment: "Step Detail")
        let _ = String(localized: "State your commitment out loud daily: 'I am getting home because...'", comment: "Step Instruction")
        let _ = String(localized: "Spoken words activate different brain regions than thoughts. Saying it makes it a declaration, not just a wish.", comment: "Step Detail")
        let _ = String(localized: "Survival Journaling", comment: "Technique Name")
        let _ = String(localized: "Write to maintain sanity and aid rescue", comment: "Technique Subtitle")
        let _ = String(localized: "Use any surface — bark, dirt, stone, clothing, skin.", comment: "Step Instruction")
        let _ = String(localized: "Charcoal from fire writes on bark and stone. A sharp stick writes in dirt. The medium doesn't matter; the act of writing does.", comment: "Step Detail")
        let _ = String(localized: "Record date, weather, food/water intake, and emotional state.", comment: "Step Instruction")
        let _ = String(localized: "Tracking data gives you a sense of control and helps identify patterns. Seeing 'Day 3: found water source' provides tangible proof of progress.", comment: "Step Detail")
        let _ = String(localized: "Write observations about your environment — resources, wildlife patterns, weather.", comment: "Step Instruction")
        let _ = String(localized: "Environmental notes become actionable intelligence. 'Birds gather at south creek at dawn' = reliable water and potential food source.", comment: "Step Detail")
        let _ = String(localized: "Write messages to loved ones — even if never delivered, it helps.", comment: "Step Instruction")
        let _ = String(localized: "Expressing thoughts to an imagined audience reduces psychological isolation. If rescued, these notes become powerful personal artifacts.", comment: "Step Detail")
        let _ = String(localized: "Stages of Survival Acceptance", comment: "Technique Name")
        let _ = String(localized: "Recognize where you are mentally", comment: "Technique Subtitle")
        let _ = String(localized: "Stage 1: Denial — 'This can't be happening.' Normal. Don't fight it.", comment: "Step Instruction")
        let _ = String(localized: "Denial is a protective mechanism. It buffers the shock. But staying here is lethal. Give yourself minutes, not hours.", comment: "Step Detail")
        let _ = String(localized: "Stage 2: Anger/Blame — 'Why me?' Channel this into action.", comment: "Step Instruction")
        let _ = String(localized: "Anger is energy. The most dangerous survivors are the angry ones — in a good way. Point that rage at the environment, not yourself.", comment: "Step Detail")
        let _ = String(localized: "Stage 3: Bargaining/Planning — 'If I do X, I'll survive.' This is productive.", comment: "Step Instruction")
        let _ = String(localized: "This is where survival thinking begins. Making plans, even imperfect ones, is the turning point from victim to survivor.", comment: "Step Detail")
        let _ = String(localized: "Stage 4: Acceptance — 'This is my reality. I will work with it.'", comment: "Step Instruction")
        let _ = String(localized: "Acceptance is not giving up. It is the most powerful mental state: clear-eyed assessment of reality combined with the determination to act within it.", comment: "Step Detail")
        let _ = String(localized: "Leadership Succession", comment: "Technique Name")
        let _ = String(localized: "Prepare others to lead if you can't", comment: "Technique Subtitle")
        let _ = String(localized: "Identify the calmest, most respected group member as backup leader.", comment: "Step Instruction")
        let _ = String(localized: "Not the loudest, strongest, or most skilled. The person others naturally listen to and trust. Leadership in crisis is about trust, not authority.", comment: "Step Detail")
        let _ = String(localized: "Share all critical knowledge: water sources, fire methods, signal plans.", comment: "Step Instruction")
        let _ = String(localized: "Single points of failure kill groups. If only one person knows where the water source is, the group dies with that person.", comment: "Step Detail")
        let _ = String(localized: "Delegate gradually — give increasing responsibility while you're still able.", comment: "Step Instruction")
        let _ = String(localized: "A sudden leadership transition causes panic. A gradual one feels natural. 'You handle the fire today, I'll focus on the trap.'", comment: "Step Detail")
        let _ = String(localized: "Document the plan — scratched on bark, written in dirt, memorized by two people.", comment: "Step Instruction")
        let _ = String(localized: "Critical information must always exist in at least two minds. If the leader is injured, unconscious, or dead, the plan must survive.", comment: "Step Detail")
        let _ = String(localized: "Combat Breathing (Box Breathing)", comment: "Technique Name")
        let _ = String(localized: "Military technique to control panic and stress response", comment: "Technique Subtitle")
        let _ = String(localized: "Stress Management", comment: "Category")
        let _ = String(localized: "Inhale through nose for 4 seconds.", comment: "Step Instruction")
        let _ = String(localized: "Breathe deeply into your diaphragm, not shallow chest breathing. Feel your belly expand. This activates the parasympathetic nervous system — your body's 'calm down' system.", comment: "Step Detail")
        let _ = String(localized: "Hold breath for 4 seconds. Then exhale for 4 seconds. Hold empty for 4 seconds.", comment: "Step Instruction")
        let _ = String(localized: "4 in, 4 hold, 4 out, 4 hold = one box. Repeat 4-6 cycles. Navy SEALs use this before operations. It works because you're overriding your fight-or-flight with conscious breathing control.", comment: "Step Detail")
        let _ = String(localized: "Repeat until heart rate drops and thinking clears.", comment: "Step Instruction")
        let _ = String(localized: "You'll feel the shift within 4-6 cycles. Panic narrows your vision and thinking. This technique reverses that. Use it before any critical decision, after any fear trigger, and before sleep.", comment: "Step Detail")
        let _ = String(localized: "Cognitive Reframing", comment: "Technique Name")
        let _ = String(localized: "Change how you interpret your situation to reduce despair", comment: "Technique Subtitle")
        let _ = String(localized: "Mental Resilience", comment: "Category")
        let _ = String(localized: "Identify the negative thought: 'I'm going to die out here.'", comment: "Step Instruction")
        let _ = String(localized: "Notice the catastrophic thinking. Don't fight it — acknowledge it. 'I'm thinking that I'm going to die.' This creates distance between you and the thought.", comment: "Step Detail")
        let _ = String(localized: "Challenge it with evidence: 'People survive this. I have skills. I have resources.'", comment: "Step Instruction")
        let _ = String(localized: "List what you HAVE: shelter? Water source? Signaling capability? Knowledge? Physical health? The situation is rarely as hopeless as panic tells you it is.", comment: "Step Detail")
        let _ = String(localized: "Replace with actionable thought: 'What is the next most useful thing I can do?'", comment: "Step Instruction")
        let _ = String(localized: "Shift from passive fear to active problem-solving. The antidote to helplessness is action. Even small actions (improve shelter, gather firewood) restore a sense of control and reduce panic.", comment: "Step Detail")
        let _ = String(localized: "Sleep Discipline in Survival", comment: "Technique Name")
        let _ = String(localized: "Maintain cognitive function through structured rest", comment: "Technique Subtitle")
        let _ = String(localized: "Physical-Mental", comment: "Category")
        let _ = String(localized: "Prioritize sleep over almost everything except immediate danger.", comment: "Step Instruction")
        let _ = String(localized: "After 24 hours without sleep, cognitive function drops 25%. After 48 hours: hallucinations, paranoia, and irrational decisions. Sleep deprivation kills more people than starvation in survival situations.", comment: "Step Detail")
        let _ = String(localized: "Use power naps: 20-minute naps every 4-6 hours if continuous sleep is impossible.", comment: "Step Instruction")
        let _ = String(localized: "Military research shows that 20-minute naps restore significant function. Set a timer or have someone wake you. Even 10 minutes provides benefit. Anything over 30 minutes causes sleep inertia (grogginess).", comment: "Step Detail")
        let _ = String(localized: "Create sleep conditions: darkness, warmth, wind protection, elevated surface.", comment: "Step Instruction")
        let _ = String(localized: "Your body won't sleep well if cold, wet, or uncomfortable. Invest time in making your sleep spot warm and dry. The time spent improving your bed pays back in better decisions and physical performance.", comment: "Step Detail")
        let _ = String(localized: "Decision Fatigue Management", comment: "Technique Name")
        let _ = String(localized: "Prevent poor choices by managing mental energy", comment: "Technique Subtitle")
        let _ = String(localized: "Make critical decisions in the morning when mental energy is highest.", comment: "Step Instruction")
        let _ = String(localized: "Decision fatigue is real — each decision degrades the quality of the next. Make big decisions (travel, route, rationing) early in the day. Save routine tasks (firewood, water collection) for afternoon.", comment: "Step Detail")
        let _ = String(localized: "Establish routines to eliminate unnecessary decisions.", comment: "Step Instruction")
        let _ = String(localized: "Fixed routine = fewer decisions. Wake at dawn. Water first. Fire maintenance. Food prep. Signal checks. Shelter improvements. This autopilot for routine tasks preserves mental energy for real problems.", comment: "Step Detail")
        let _ = String(localized: "When stuck, use the 'good enough' rule — don't wait for perfect.", comment: "Step Instruction")
        let _ = String(localized: "In survival, a good decision now beats a perfect decision tomorrow. If you have two reasonable options, pick one and execute. Indecision is more dangerous than a slightly suboptimal choice.", comment: "Step Detail")
        let _ = String(localized: "Processing Grief & Loss", comment: "Technique Name")
        let _ = String(localized: "Handle loss of companions, equipment, or normalcy", comment: "Technique Subtitle")
        let _ = String(localized: "Emotional Management", comment: "Category")
        let _ = String(localized: "Acknowledge the loss. Don't suppress it or pretend it didn't happen.", comment: "Step Instruction")
        let _ = String(localized: "Suppressed grief emerges as poor decisions, risk-taking, and apathy. Allow yourself to feel the loss — set aside a specific time for it if needed. Then return to survival tasks.", comment: "Step Detail")
        let _ = String(localized: "Separate grieving from decision-making. Grieve, then decide.", comment: "Step Instruction")
        let _ = String(localized: "Don't make critical decisions while in acute grief. Handle immediate safety needs, then allow yourself to process. Grief distorts risk assessment — you may take dangerous risks or become paralyzed.", comment: "Step Detail")
        let _ = String(localized: "Channel grief into purpose: 'I will survive to honor them.'", comment: "Step Instruction")
        let _ = String(localized: "Survivors consistently report that purpose was more powerful than will. Transforming grief into motivation creates a powerful drive. 'They would want me to survive' is both healthy and effective.", comment: "Step Detail")
        let _ = String(localized: "Group Conflict Resolution", comment: "Technique Name")
        let _ = String(localized: "Resolve disputes before they become dangerous", comment: "Technique Subtitle")
        let _ = String(localized: "Group Dynamics", comment: "Category")
        let _ = String(localized: "Address conflicts immediately. They escalate rapidly under stress.", comment: "Step Instruction")
        let _ = String(localized: "In normal life, conflicts can wait. In survival, unresolved conflicts lead to group fracture, sabotage, or violence. Address disagreements within hours, not days.", comment: "Step Detail")
        let _ = String(localized: "Use structured discussion: each person states their view without interruption.", comment: "Step Instruction")
        let _ = String(localized: "Rule: speak only when holding a designated 'talking stick.' This prevents shouting matches. Each person gets 2 minutes. No interruptions. Then discuss solutions, not blame.", comment: "Step Detail")
        let _ = String(localized: "Focus on shared goals: 'We all want to survive and get home.'", comment: "Step Instruction")
        let _ = String(localized: "Reframe disputes around common interest. Not 'you vs. me' but 'us vs. the situation.' Make decisions that advance survival for all, even if imperfect for individuals.", comment: "Step Detail")
        let _ = String(localized: "Teaching as a Coping Mechanism", comment: "Technique Name")
        let _ = String(localized: "Teach others your skills to boost confidence and purpose", comment: "Technique Subtitle")
        let _ = String(localized: "Morale", comment: "Category")
        let _ = String(localized: "Teach another person a survival skill you know.", comment: "Step Instruction")
        let _ = String(localized: "Teaching does three things: reinforces your own knowledge, builds the group's capability, and gives both teacher and student a sense of purpose and competence.", comment: "Step Detail")
        let _ = String(localized: "Let beginners practice. Mastery builds confidence.", comment: "Step Instruction")
        let _ = String(localized: "Watching someone successfully start their first fire or tie their first knot transforms their self-image from 'helpless victim' to 'capable survivor.' This psychological shift is monumental.", comment: "Step Detail")
        let _ = String(localized: "Share knowledge generously. Hoarding skills creates dependency.", comment: "Step Instruction")
        let _ = String(localized: "If only one person knows how to start fire or find water, the group is fragile. Distribute skills across the group. Redundancy is resilience.", comment: "Step Detail")
        let _ = String(localized: "Survival Gratitude Practice", comment: "Technique Name")
        let _ = String(localized: "Counter negativity bias by actively noting what's going right", comment: "Technique Subtitle")
        let _ = String(localized: "Each morning and evening, identify 3 things that went right or that you're grateful for.", comment: "Step Instruction")
        let _ = String(localized: "The brain has a negativity bias — it naturally focuses on threats. Consciously noting positives counteracts this. 'The fire stayed lit. I found water. My shelter held.'", comment: "Step Detail")
        let _ = String(localized: "In a group, share these aloud at mealtimes.", comment: "Step Instruction")
        let _ = String(localized: "Group gratitude practice is powerful morale medicine. It shifts the collective focus from what's wrong to what's working. It's contagious — hearing others' gratitude amplifies your own.", comment: "Step Detail")
        let _ = String(localized: "Compare today to the worst day, not to normal life.", comment: "Step Instruction")
        let _ = String(localized: "Instead of comparing to home comforts (depressing), compare to day one or the worst day. 'At least I have fire now. At least I know where water is.' This reframe builds a sense of progress.", comment: "Step Detail")
        let _ = String(localized: "Positive Visualization", comment: "Technique Name")
        let _ = String(localized: "Use mental imagery to maintain motivation and reduce panic", comment: "Technique Subtitle")
        let _ = String(localized: "Close your eyes and vividly imagine being rescued and reuniting with loved ones.", comment: "Step Instruction")
        let _ = String(localized: "Engage all senses: see their faces, hear their voices, feel the embrace. This isn't wishful thinking — it's creating an emotional anchor that your brain will fight to achieve.", comment: "Step Detail")
        let _ = String(localized: "Visualize successfully completing your next survival task.", comment: "Step Instruction")
        let _ = String(localized: "Before starting a difficult task (fire, shelter, water), mentally rehearse success. Athletes do this to improve performance. It works for survival tasks too — you perform better when you've 'already done it' mentally.", comment: "Step Detail")
        let _ = String(localized: "Practice before sleep — this sets your subconscious working on solutions.", comment: "Step Instruction")
        let _ = String(localized: "The subconscious processes problems during sleep. By visualizing your situation before sleeping, you often wake with solutions or renewed energy. Many survivors report 'waking up knowing what to do.'", comment: "Step Detail")
        let _ = String(localized: "Humor as a Survival Tool", comment: "Technique Name")
        let _ = String(localized: "Use appropriate humor to maintain morale and reduce stress", comment: "Technique Subtitle")
        let _ = String(localized: "Find something absurd or ironic about your situation and acknowledge it.", comment: "Step Instruction")
        let _ = String(localized: "Humor is a stress release valve. Soldiers, first responders, and survival professionals all use gallows humor. Laughing at the situation reduces cortisol and restores perspective.", comment: "Step Detail")
        let _ = String(localized: "Share jokes and funny stories in the group, especially during downtime.", comment: "Step Instruction")
        let _ = String(localized: "Laughter is contagious and builds social bonds. A group that can laugh together can survive together. Named your failed fire attempt? Named the annoying crow? These moments bond the group.", comment: "Step Detail")
        let _ = String(localized: "Never use humor to dismiss real problems or someone's genuine distress.", comment: "Step Instruction")
        let _ = String(localized: "Healthy humor laughs at the situation, not at individuals. If someone is in genuine crisis, humor can feel dismissive and damage trust. Read the room — humor heals when shared, hurts when forced.", comment: "Step Detail")
        let _ = String(localized: "Establishing Normalcy & Routine", comment: "Technique Name")
        let _ = String(localized: "Create predictable structure to reduce anxiety", comment: "Technique Subtitle")
        let _ = String(localized: "Establish a daily schedule within the first 24 hours.", comment: "Step Instruction")
        let _ = String(localized: "Wake time, meal times, work periods, rest periods. Predictability reduces anxiety. Even arbitrary schedule is better than chaos. Write it out or announce it clearly to the group.", comment: "Step Detail")
        let _ = String(localized: "Assign roles and responsibilities to every group member.", comment: "Step Instruction")
        let _ = String(localized: "Everyone needs a job: fire tender, water collector, signal maintainer, cook, lookout. Purpose prevents helplessness. Even small children can sort berries or gather small sticks.", comment: "Step Detail")
        let _ = String(localized: "Maintain personal hygiene and camp organization.", comment: "Step Instruction")
        let _ = String(localized: "Hygiene matters psychologically as much as physically. Washing hands, cleaning camp, organizing gear — these create a sense of control and self-respect that prevents psychological decline.", comment: "Step Detail")
        let _ = String(localized: "Acceptance & Commitment", comment: "Technique Name")
        let _ = String(localized: "Accept what you can't change, commit to what you can", comment: "Technique Subtitle")
        let _ = String(localized: "Accept the reality of your situation without judgment.", comment: "Step Instruction")
        let _ = String(localized: "Denial wastes energy. 'This shouldn't have happened' is irrelevant — it did happen. Accept the facts: your location, your resources, your injuries, your capabilities. Acceptance is not surrender — it's clarity.", comment: "Step Detail")
        let _ = String(localized: "Identify what you CAN control. Focus exclusively on those things.", comment: "Step Instruction")
        let _ = String(localized: "Can't control: weather, terrain, when rescue comes. CAN control: your shelter, your fire, your signals, your attitude, your effort. Focusing on controllables eliminates the helplessness that kills.", comment: "Step Detail")
        let _ = String(localized: "Commit to action: 'I will do everything in my power to survive.'", comment: "Step Instruction")
        let _ = String(localized: "Commitment is the bridge between acceptance and action. You accept reality, then commit to making the best of it. This combination — realistic assessment + determined action — is found in virtually every survivor's account.", comment: "Step Detail")
        let _ = String(localized: "First Aid", comment: "Domain Name")
        let _ = String(localized: "Burn Blister Management", comment: "Technique Name")
        let _ = String(localized: "Treat minor to moderate burn blisters", comment: "Technique Subtitle")
        let _ = String(localized: "Wounds", comment: "Category")
        let _ = String(localized: "Cool the burn under cool running water for 10-20 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT use ice, butter, or toothpaste. Cool water only. This stops the burning process in deeper tissue layers.", comment: "Step Detail")
        let _ = String(localized: "Do NOT pop burn blisters — the fluid protects healing skin.", comment: "Step Instruction")
        let _ = String(localized: "The blister is a natural sterile bandage. Breaking it introduces infection risk. If it pops on its own, keep the skin flap in place.", comment: "Step Detail")
        let _ = String(localized: "Cover loosely with non-stick gauze or clean cloth.", comment: "Step Instruction")
        let _ = String(localized: "Do not wrap tightly — swelling will increase. Use non-adhesive dressing. Change dressing daily.", comment: "Step Detail")
        let _ = String(localized: "Elevate the burned area above heart level if possible.", comment: "Step Instruction")
        let _ = String(localized: "Reduces swelling and pain. Prop up arm or leg on a pack or rolled clothing.", comment: "Step Detail")
        let _ = String(localized: "Watch for infection: increasing redness, pus, fever, red streaks.", comment: "Step Instruction")
        let _ = String(localized: "Burns are very infection-prone. If signs of infection appear, clean gently and seek medical care.", comment: "Step Detail")
        let _ = String(localized: "Severe Burn (Third Degree)", comment: "Technique Name")
        let _ = String(localized: "Manage deep, charred, or full-thickness burns", comment: "Technique Subtitle")
        let _ = String(localized: "Call emergency services immediately. This is life-threatening.", comment: "Step Instruction")
        let _ = String(localized: "Third-degree burns destroy all skin layers. The skin appears white, brown, or charred. Person may not feel pain in the burned area due to nerve destruction.", comment: "Step Detail")
        let _ = String(localized: "Do NOT remove burnt clothing stuck to the skin.", comment: "Step Instruction")
        let _ = String(localized: "Pulling burned fabric off tears away skin. Cut around stuck fabric. Remove jewelry and belts near the burn before swelling starts.", comment: "Step Detail")
        let _ = String(localized: "Cover loosely with clean, dry cloth. Do NOT apply water.", comment: "Step Instruction")
        let _ = String(localized: "Large burns with cold water can cause hypothermia. Cover with clean sheet or cling wrap to protect from contamination. No creams, no butter.", comment: "Step Detail")
        let _ = String(localized: "Elevate burned area above heart level.", comment: "Step Instruction")
        let _ = String(localized: "Reduces fluid loss and swelling. If legs are burned, elevate on packs. If arms, use a sling.", comment: "Step Detail")
        let _ = String(localized: "Treat for shock: lay flat, keep warm, monitor breathing.", comment: "Step Instruction")
        let _ = String(localized: "Severe burns cause massive fluid loss leading to shock. Keep person warm with blankets. Give small sips of water if conscious. Monitor for confusion and rapid pulse.", comment: "Step Detail")
        let _ = String(localized: "Head Trauma Assessment", comment: "Technique Name")
        let _ = String(localized: "Evaluate and manage head injuries", comment: "Technique Subtitle")
        let _ = String(localized: "Medical", comment: "Category")
        let _ = String(localized: "Keep the person still. Do NOT move them unless in immediate danger.", comment: "Step Instruction")
        let _ = String(localized: "Any head injury may involve a spinal injury. Stabilize the head and neck in the position found. Do not allow them to stand up.", comment: "Step Detail")
        let _ = String(localized: "Check consciousness: ask their name, where they are, what happened.", comment: "Step Instruction")
        let _ = String(localized: "Confusion, inability to answer simple questions, or repeating the same question are red flags for serious brain injury.", comment: "Step Detail")
        let _ = String(localized: "Control any bleeding with gentle direct pressure.", comment: "Step Instruction")
        let _ = String(localized: "Scalp wounds bleed heavily even when minor. Apply firm pressure with clean cloth. Do NOT press on depressed skull fractures.", comment: "Step Detail")
        let _ = String(localized: "Check for clear fluid leaking from ears or nose.", comment: "Step Instruction")
        let _ = String(localized: "Clear, watery fluid (cerebrospinal fluid) leaking from ears or nose indicates skull fracture. Do NOT plug the leak — it needs to drain.", comment: "Step Detail")
        let _ = String(localized: "Monitor every 15 minutes: pupils, consciousness, breathing.", comment: "Step Instruction")
        let _ = String(localized: "Worsening symptoms (increasing confusion, vomiting, unequal pupils, seizures) indicate swelling. Keep head elevated slightly. Wake them every 2 hours if sleeping.", comment: "Step Detail")
        let _ = String(localized: "Concussion Management", comment: "Technique Name")
        let _ = String(localized: "Monitor and manage mild head injury", comment: "Technique Subtitle")
        let _ = String(localized: "Remove person from activity. Physical and mental rest is critical.", comment: "Step Instruction")
        let _ = String(localized: "No sports, no hiking, no heavy lifting. Mental rest too — limit screen time, reading, bright lights.", comment: "Step Detail")
        let _ = String(localized: "Apply cold pack to the impact area for 20 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Wrap ice or cold water in cloth. Apply 20 minutes on, 20 minutes off. Reduces swelling.", comment: "Step Detail")
        let _ = String(localized: "Monitor for worsening symptoms over 24-48 hours.", comment: "Step Instruction")
        let _ = String(localized: "Red flags: increasing headache, repeated vomiting, seizures, confusion getting worse, slurred speech, unequal pupils, loss of consciousness.", comment: "Step Detail")
        let _ = String(localized: "Wake the person every 2-3 hours for the first night.", comment: "Step Instruction")
        let _ = String(localized: "Ensure they can be woken up and answer simple questions (name, location). If hard to wake → Emergency.", comment: "Step Detail")
        let _ = String(localized: "No blood-thinning painkillers (aspirin/ibuprofen) for 24 hours.", comment: "Step Instruction")
        let _ = String(localized: "These thin blood and can worsen a brain bleed. Acetaminophen is safer if approved by medical advice.", comment: "Step Detail")
        let _ = String(localized: "Insect Sting Treatment", comment: "Technique Name")
        let _ = String(localized: "Bee, Wasp, Ant (Non-Allergic)", comment: "Technique Subtitle")
        let _ = String(localized: "Remove stinger immediately — scrape, don't pinch.", comment: "Step Instruction")
        let _ = String(localized: "Use credit card or fingernail to scrape it out. Pinching injects more venom.", comment: "Step Detail")
        let _ = String(localized: "Wash the area with soap and water.", comment: "Step Instruction")
        let _ = String(localized: "Prevents secondary infection at the sting site.", comment: "Step Detail")
        let _ = String(localized: "Apply cold pack or mud to reduce swelling and pain.", comment: "Step Instruction")
        let _ = String(localized: "Cooling reduces venom spread and inflammation. Mud also draws and soothes.", comment: "Step Detail")
        let _ = String(localized: "Take antihistamine if available to reduce reaction.", comment: "Step Instruction")
        let _ = String(localized: "Benadryl (diphenhydramine) or similar. Follow dosage instructions. Helps with itching and mild swelling.", comment: "Step Detail")
        let _ = String(localized: "Monitor for allergic reaction for 30 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Watch for: hives away from sting site, difficulty breathing, throat swelling, dizziness. These require EpiPen and emergency services.", comment: "Step Detail")
        let _ = String(localized: "Choking Response (Heimlich)", comment: "Technique Name")
        let _ = String(localized: "Clear airway obstruction in adults", comment: "Technique Subtitle")
        let _ = String(localized: "Ask 'Are you choking?' — if they can't speak or cough, act immediately.", comment: "Step Instruction")
        let _ = String(localized: "If they can cough forcefully or speak, encourage them to keep coughing. Only intervene if they cannot make sound or are turning blue.", comment: "Step Detail")
        let _ = String(localized: "Stand behind the person, wrap arms around their waist.", comment: "Step Instruction")
        let _ = String(localized: "Position yourself slightly to one side. Lean them forward slightly. For pregnant or obese persons, place hands higher on the chest.", comment: "Step Detail")
        let _ = String(localized: "Make a fist, place thumb side against abdomen above navel.", comment: "Step Instruction")
        let _ = String(localized: "Position below the ribcage and above the belly button. Do NOT place on the ribcage — you can fracture ribs.", comment: "Step Detail")
        let _ = String(localized: "Grasp fist with other hand. Thrust inward and upward sharply.", comment: "Step Instruction")
        let _ = String(localized: "Use a quick J-shaped motion (in and up). Each thrust should be distinct. Repeat up to 5 times.", comment: "Step Detail")
        let _ = String(localized: "If object doesn't dislodge: alternate 5 back blows with 5 thrusts.", comment: "Step Instruction")
        let _ = String(localized: "Deliver back blows between shoulder blades with heel of hand. If person becomes unconscious, lower to ground and begin CPR.", comment: "Step Detail")
        let _ = String(localized: "Emergency Tourniquet", comment: "Technique Name")
        let _ = String(localized: "Stop life-threatening limb bleeding", comment: "Technique Subtitle")
        let _ = String(localized: "Place tourniquet 2-3 inches above the wound.", comment: "Step Instruction")
        let _ = String(localized: "Never place on a joint. Place on bare skin if possible. If wound is on a limb, apply tourniquet between wound and heart.", comment: "Step Detail")
        let _ = String(localized: "Pull strap tight and secure it.", comment: "Step Instruction")
        let _ = String(localized: "The strap should be tight enough that you cannot slide a finger underneath. Pain is expected and acceptable.", comment: "Step Detail")
        let _ = String(localized: "Twist the windlass rod until bleeding stops.", comment: "Step Instruction")
        let _ = String(localized: "Turn clockwise. It will hurt. Do NOT stop until the bleeding has fully stopped. Usually 3-4 turns.", comment: "Step Detail")
        let _ = String(localized: "Lock the windlass in place and note the time.", comment: "Step Instruction")
        let _ = String(localized: "Write the time on the patient's forehead with marker or blood. Write 'TQ' and the time. Do NOT remove until hospital care.", comment: "Step Detail")
        let _ = String(localized: "Pressure Bandage", comment: "Technique Name")
        let _ = String(localized: "Control moderate bleeding", comment: "Technique Subtitle")
        let _ = String(localized: "Apply direct pressure with a clean cloth.", comment: "Step Instruction")
        let _ = String(localized: "Use gauze, a t-shirt, or any clean fabric. Press firmly. Do not lift to check — this disrupts clotting.", comment: "Step Detail")
        let _ = String(localized: "Elevate the wound above the heart if possible.", comment: "Step Instruction")
        let _ = String(localized: "Gravity reduces blood flow to the wound. Raise the limb while maintaining pressure.", comment: "Step Detail")
        let _ = String(localized: "Wrap with elastic bandage snugly but not cutting off circulation.", comment: "Step Instruction")
        let _ = String(localized: "Check fingers/toes below the bandage for warmth, color, and feeling every 15 minutes.", comment: "Step Detail")
        let _ = String(localized: "If blood soaks through, add more material on top.", comment: "Step Instruction")
        let _ = String(localized: "Never remove the first layer. Stack additional padding and re-wrap. Removing disrupts the clot.", comment: "Step Detail")
        let _ = String(localized: "Wound Irrigation & Cleaning", comment: "Technique Name")
        let _ = String(localized: "Prevent infection in cuts and scrapes", comment: "Technique Subtitle")
        let _ = String(localized: "Wash your hands thoroughly before touching the wound.", comment: "Step Instruction")
        let _ = String(localized: "Dirty hands introduce bacteria. Use soap and water, or hand sanitizer if available.", comment: "Step Detail")
        let _ = String(localized: "Flush the wound with clean running water for 5 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Use a squeeze bottle, hydration bladder, or water bottle with a pinhole in the cap to create pressure. Pressure irrigation is more effective than soaking.", comment: "Step Detail")
        let _ = String(localized: "Remove visible debris with clean tweezers.", comment: "Step Instruction")
        let _ = String(localized: "Remove dirt, gravel, splinters. Do NOT remove deeply embedded objects — stabilize them in place.", comment: "Step Detail")
        let _ = String(localized: "Apply antibiotic ointment and cover with a clean bandage.", comment: "Step Instruction")
        let _ = String(localized: "Change the dressing daily. Watch for signs of infection: increasing redness, warmth, swelling, pus, or red streaks.", comment: "Step Detail")
        let _ = String(localized: "Wound Closure Strips", comment: "Technique Name")
        let _ = String(localized: "Close gaping wounds without stitches", comment: "Technique Subtitle")
        let _ = String(localized: "Clean and dry the wound edges thoroughly.", comment: "Step Instruction")
        let _ = String(localized: "Strips won't adhere to wet or dirty skin. Pat dry the skin around the wound completely.", comment: "Step Detail")
        let _ = String(localized: "Apply tincture of benzoin to skin on both sides of the wound.", comment: "Step Instruction")
        let _ = String(localized: "This makes the adhesive stick much better. Let it get tacky (30 seconds) before applying strips.", comment: "Step Detail")
        let _ = String(localized: "Apply strips perpendicular to the wound, pulling edges together.", comment: "Step Instruction")
        let _ = String(localized: "Start at the center, then alternate sides. Space strips 3mm apart. Don't overlap them.", comment: "Step Detail")
        let _ = String(localized: "Apply reinforcing strips parallel along the strip ends.", comment: "Step Instruction")
        let _ = String(localized: "These anchor strips prevent the closure strips from peeling off. Cover with a non-stick bandage.", comment: "Step Detail")
        let _ = String(localized: "CPR (Cardiopulmonary Resuscitation)", comment: "Technique Name")
        let _ = String(localized: "Restore breathing and circulation", comment: "Technique Subtitle")
        let _ = String(localized: "Medical Emergency", comment: "Category")
        let _ = String(localized: "Check responsiveness. Tap shoulders and shout.", comment: "Step Instruction")
        let _ = String(localized: "If no response: Call for help. If alone, do 2 minutes of CPR before leaving to get help.", comment: "Step Detail")
        let _ = String(localized: "Place heel of hand on center of chest, between nipples.", comment: "Step Instruction")
        let _ = String(localized: "Interlock your other hand on top. Lock your elbows. Position shoulders directly over your hands.", comment: "Step Detail")
        let _ = String(localized: "Compress chest 2 inches deep at 100-120 beats per minute.", comment: "Step Instruction")
        let _ = String(localized: "Push hard and fast. Allow full chest recoil between compressions. Think of the beat of 'Stayin' Alive' by the Bee Gees.", comment: "Step Detail")
        let _ = String(localized: "Give 2 rescue breaths after every 30 compressions.", comment: "Step Instruction")
        let _ = String(localized: "Tilt head back, lift chin, pinch nose, seal mouth. Each breath should last 1 second. Watch for chest rise.", comment: "Step Detail")
        let _ = String(localized: "Continue 30:2 cycle without stopping until help arrives.", comment: "Step Instruction")
        let _ = String(localized: "Switch rescuers every 2 minutes if possible. Fatigue degrades compression quality rapidly.", comment: "Step Detail")
        let _ = String(localized: "Heimlich Maneuver (Choking)", comment: "Technique Name")
        let _ = String(localized: "Clear airway obstruction", comment: "Technique Subtitle")
        let _ = String(localized: "Confirm choking — person cannot speak, cough, or breathe.", comment: "Step Instruction")
        let _ = String(localized: "Universal sign is hands clutching throat. Ask 'Are you choking?' If they can speak or cough forcefully, encourage them to keep coughing.", comment: "Step Detail")
        let _ = String(localized: "Stand behind the person and wrap arms around their waist.", comment: "Step Instruction")
        let _ = String(localized: "For a pregnant person or very large person, place hands higher on the chest instead.", comment: "Step Detail")
        let _ = String(localized: "Make a fist with one hand, place thumb side against abdomen above navel.", comment: "Step Instruction")
        let _ = String(localized: "Well below the ribcage, well above the navel. This is the soft area of the upper abdomen.", comment: "Step Detail")
        let _ = String(localized: "Thrust inward and upward with quick, forceful movements.", comment: "Step Instruction")
        let _ = String(localized: "Each thrust should be a separate, distinct movement. Repeat until the object is expelled or person becomes unconscious.", comment: "Step Detail")
        let _ = String(localized: "Treating Shock", comment: "Technique Name")
        let _ = String(localized: "Prevent circulatory collapse", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize shock: pale/cool/clammy skin, rapid weak pulse, confusion.", comment: "Step Instruction")
        let _ = String(localized: "Other signs: rapid shallow breathing, nausea, thirst, dilated pupils, blue lips.", comment: "Step Detail")
        let _ = String(localized: "Lay the person flat and elevate legs 8-12 inches.", comment: "Step Instruction")
        let _ = String(localized: "This drives blood to vital organs. Do NOT elevate legs if you suspect spine, head, or leg injuries.", comment: "Step Detail")
        let _ = String(localized: "Maintain body temperature — cover with blankets or coats.", comment: "Step Instruction")
        let _ = String(localized: "Cover top AND bottom. Insulate from the ground. Shock patients lose body heat rapidly.", comment: "Step Detail")
        let _ = String(localized: "Do NOT give food or water. Moisten lips only.", comment: "Step Instruction")
        let _ = String(localized: "They may need surgery. Anything in the stomach complicates anesthesia. Moisten lips with a wet cloth.", comment: "Step Detail")
        let _ = String(localized: "Recovery Position", comment: "Technique Name")
        let _ = String(localized: "Keep unconscious breathing person safe", comment: "Technique Subtitle")
        let _ = String(localized: "Kneel beside the person. Extend near arm at right angle.", comment: "Step Instruction")
        let _ = String(localized: "Palm facing up. This prevents them from rolling onto their face.", comment: "Step Detail")
        let _ = String(localized: "Place far hand against their near cheek, hold it there.", comment: "Step Instruction")
        let _ = String(localized: "Back of their hand against their cheek. Keep holding it in place.", comment: "Step Detail")
        let _ = String(localized: "Pull the far knee up with your other hand.", comment: "Step Instruction")
        let _ = String(localized: "Foot should be flat on the ground. This creates a pivot point for rolling.", comment: "Step Detail")
        let _ = String(localized: "Roll them toward you by pulling the raised knee.", comment: "Step Instruction")
        let _ = String(localized: "They should end up on their side. Tilt head back slightly to keep airway open. Their own hand cushions their head.", comment: "Step Detail")
        let _ = String(localized: "Arm/Wrist Splint", comment: "Technique Name")
        let _ = String(localized: "Immobilize a broken arm or wrist", comment: "Technique Subtitle")
        let _ = String(localized: "Bones", comment: "Category")
        let _ = String(localized: "Do NOT attempt to realign the bone.", comment: "Step Instruction")
        let _ = String(localized: "Immobilize in the position found. Moving a fracture can sever blood vessels and nerves.", comment: "Step Detail")
        let _ = String(localized: "Find a rigid splint material: stick, cardboard, rolled magazine.", comment: "Step Instruction")
        let _ = String(localized: "Splint must be long enough to immobilize joints above and below the break.", comment: "Step Detail")
        let _ = String(localized: "Pad the splint with cloth and secure with bandages or strips.", comment: "Step Instruction")
        let _ = String(localized: "Tie at minimum 3 points: above break, below break, and at each adjacent joint. Don't tie directly over the fracture.", comment: "Step Detail")
        let _ = String(localized: "Check circulation below the splint: warmth, color, feeling, pulse.", comment: "Step Instruction")
        let _ = String(localized: "Check every 15-20 minutes. Loosen if fingers turn blue, become numb, or swell significantly.", comment: "Step Detail")
        let _ = String(localized: "Leg Splint", comment: "Technique Name")
        let _ = String(localized: "Immobilize a broken leg", comment: "Technique Subtitle")
        let _ = String(localized: "Immobilize the leg in the position found.", comment: "Step Instruction")
        let _ = String(localized: "If the foot is rotated or the leg is bent at an unnatural angle, do NOT straighten it. Splint as-is.", comment: "Step Detail")
        let _ = String(localized: "Use two long rigid objects as splints — one inside, one outside the leg.", comment: "Step Instruction")
        let _ = String(localized: "Walking sticks, branches, tent poles, rolled sleeping pads. Inner splint from groin to foot. Outer from armpit to foot for femur breaks.", comment: "Step Detail")
        let _ = String(localized: "Pad between the leg and splints generously.", comment: "Step Instruction")
        let _ = String(localized: "Use clothing, towels, or moss. Fill all gaps. Pressure points cause tissue damage over time.", comment: "Step Detail")
        let _ = String(localized: "Secure with wide bandages at 4-5 points. Avoid tying over the break.", comment: "Step Instruction")
        let _ = String(localized: "Tie at ankle, below knee, above knee, and hip. For femur fractures, include a figure-8 at the foot.", comment: "Step Detail")
        let _ = String(localized: "Arm Sling", comment: "Technique Name")
        let _ = String(localized: "Support injured arm or shoulder", comment: "Technique Subtitle")
        let _ = String(localized: "Fold a square cloth into a triangle.", comment: "Step Instruction")
        let _ = String(localized: "A bandana, shirt, or any ~40-inch square of fabric works. Cut diagonally if needed.", comment: "Step Detail")
        let _ = String(localized: "Slide the triangle under the injured arm and behind the elbow.", comment: "Step Instruction")
        let _ = String(localized: "One point at the elbow, one over the shoulder on the injured side, the other over the opposite shoulder.", comment: "Step Detail")
        let _ = String(localized: "Tie the two upper points behind the neck.", comment: "Step Instruction")
        let _ = String(localized: "The knot should sit to the side of the neck, not directly on the spine. Pad the knot if needed.", comment: "Step Detail")
        let _ = String(localized: "Pin or tie the elbow point to secure it.", comment: "Step Instruction")
        let _ = String(localized: "The forearm should be level or slightly elevated. Fingers should be visible for circulation checks.", comment: "Step Detail")
        let _ = String(localized: "Burn Treatment", comment: "Technique Name")
        let _ = String(localized: "Cool, cover, and manage pain", comment: "Technique Subtitle")
        let _ = String(localized: "Burns", comment: "Category")
        let _ = String(localized: "Remove from heat source. Remove clothing/jewelry from burn area.", comment: "Step Instruction")
        let _ = String(localized: "If clothing is stuck to the burn, cut around it. Do NOT pull stuck clothing off. Remove watches and rings before swelling.", comment: "Step Detail")
        let _ = String(localized: "Cool the burn with cool (not cold) running water for 20 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT use ice, butter, toothpaste, or any home remedy. Cool water only. 20 minutes is the evidence-based number.", comment: "Step Detail")
        let _ = String(localized: "Cover with cling wrap or a clean non-fluffy dressing.", comment: "Step Instruction")
        let _ = String(localized: "Lay cling wrap over the burn — do not wrap tightly. This keeps it clean and reduces pain from air exposure.", comment: "Step Detail")
        let _ = String(localized: "Do NOT pop blisters. They are sterile bandages.", comment: "Step Instruction")
        let _ = String(localized: "Intact blisters protect healing skin underneath. If a blister breaks on its own, gently clean and cover.", comment: "Step Detail")
        let _ = String(localized: "Chemical Burn", comment: "Technique Name")
        let _ = String(localized: "Flush immediately with water", comment: "Technique Subtitle")
        let _ = String(localized: "Brush off dry chemicals before adding water.", comment: "Step Instruction")
        let _ = String(localized: "Some dry chemicals react with water. Brush away from the body first, then flush.", comment: "Step Detail")
        let _ = String(localized: "Flush with large amounts of water for at least 20 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Use a garden hose, shower, or any source of running water. More is better. Chemical burns penetrate deeper over time.", comment: "Step Detail")
        let _ = String(localized: "Remove contaminated clothing while flushing.", comment: "Step Instruction")
        let _ = String(localized: "Clothing traps chemicals against skin. Cut clothing off if needed. Protect your own hands.", comment: "Step Detail")
        let _ = String(localized: "Do NOT try to neutralize the chemical.", comment: "Step Instruction")
        let _ = String(localized: "Neutralization reactions generate heat, making the burn worse. Water dilution is always the correct answer.", comment: "Step Detail")
        let _ = String(localized: "Snakebite Management", comment: "Technique Name")
        let _ = String(localized: "Stay calm, immobilize, evacuate", comment: "Technique Subtitle")
        let _ = String(localized: "Bites", comment: "Category")
        let _ = String(localized: "Move away from the snake. Do NOT try to catch or kill it.", comment: "Step Instruction")
        let _ = String(localized: "Note the snake's appearance for identification if possible. A photo from a safe distance helps. Most bites happen during the second encounter.", comment: "Step Detail")
        let _ = String(localized: "Keep the bitten limb below heart level and immobilize it.", comment: "Step Instruction")
        let _ = String(localized: "Remove watches, rings, tight clothing. Swelling will be rapid. Splint the limb to reduce venom spread.", comment: "Step Detail")
        let _ = String(localized: "Do NOT cut, suck, tourniquet, or apply ice to the bite.", comment: "Step Instruction")
        let _ = String(localized: "All of these cause additional damage and do not remove venom. These are myths that worsen outcomes.", comment: "Step Detail")
        let _ = String(localized: "Mark the edge of swelling and note the time.", comment: "Step Instruction")
        let _ = String(localized: "Use a pen to outline swelling every 15 minutes. This helps medical staff judge venom severity and progression.", comment: "Step Detail")
        let _ = String(localized: "Evacuate to a hospital. Antivenom is the only treatment.", comment: "Step Instruction")
        let _ = String(localized: "Carry the victim if possible — walking increases venom circulation. Time to antivenom is the most important factor.", comment: "Step Detail")
        let _ = String(localized: "Tick Removal", comment: "Technique Name")
        let _ = String(localized: "Remove without squeezing the body", comment: "Technique Subtitle")
        let _ = String(localized: "Grasp the tick as close to the skin as possible with fine-tipped tweezers.", comment: "Step Instruction")
        let _ = String(localized: "Grab the head/mouthparts, NOT the body. Squeezing the body can inject pathogens (Lyme, RMSF) into the wound.", comment: "Step Detail")
        let _ = String(localized: "Pull straight up with steady, even pressure.", comment: "Step Instruction")
        let _ = String(localized: "Do not twist, jerk, or rock. Steady tension. The tick will release in 30-60 seconds. If mouthparts break off, leave them — they'll work out naturally.", comment: "Step Detail")
        let _ = String(localized: "Clean the bite area with soap and water or alcohol.", comment: "Step Instruction")
        let _ = String(localized: "Also clean your hands and the tweezers. Apply antibiotic ointment.", comment: "Step Detail")
        let _ = String(localized: "Monitor for 30 days for a bull's-eye rash or flu symptoms.", comment: "Step Instruction")
        let _ = String(localized: "Expanding red ring = possible Lyme disease. Seek medical care immediately if symptoms appear.", comment: "Step Detail")
        let _ = String(localized: "Bee/Wasp Sting Treatment", comment: "Technique Name")
        let _ = String(localized: "Remove stinger, watch for anaphylaxis", comment: "Technique Subtitle")
        let _ = String(localized: "Scrape the stinger out sideways with a flat edge.", comment: "Step Instruction")
        let _ = String(localized: "Use a credit card, knife blade, or fingernail. Do NOT squeeze with tweezers — this injects more venom.", comment: "Step Detail")
        let _ = String(localized: "Clean with soap and water. Apply cold pack for 15 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Wrap ice in cloth — never direct ice on skin. This reduces swelling and pain.", comment: "Step Detail")
        let _ = String(localized: "Watch for anaphylaxis: facial swelling, difficulty breathing, hives.", comment: "Step Instruction")
        let _ = String(localized: "Anaphylaxis can start within minutes. If the person has an EpiPen, help them use it immediately.", comment: "Step Detail")
        let _ = String(localized: "For mild reactions: antihistamine and pain reliever.", comment: "Step Instruction")
        let _ = String(localized: "Benadryl for itching/swelling, ibuprofen for pain. Keep the area clean and monitor for infection.", comment: "Step Detail")
        let _ = String(localized: "Anaphylaxis Response", comment: "Technique Name")
        let _ = String(localized: "Epinephrine + call emergency services immediately", comment: "Technique Subtitle")
        let _ = String(localized: "Allergic Reactions", comment: "Category")
        let _ = String(localized: "Recognize: throat tightening, facial swelling, hives, wheezing, dizziness.", comment: "Step Instruction")
        let _ = String(localized: "Anaphylaxis is life-threatening. It can progress from mild to fatal in minutes. Act immediately.", comment: "Step Detail")
        let _ = String(localized: "Use epinephrine auto-injector (EpiPen) into outer thigh.", comment: "Step Instruction")
        let _ = String(localized: "Push firmly through clothing if needed. Hold for 10 seconds. Massage the site for 10 seconds after. Can be given through jeans.", comment: "Step Detail")
        let _ = String(localized: "Call emergency services immediately.", comment: "Step Instruction")
        let _ = String(localized: "Even after epinephrine, the person needs hospital monitoring. Anaphylaxis can return (biphasic reaction) hours later.", comment: "Step Detail")
        let _ = String(localized: "Place in position of comfort. Usually sitting up for breathing.", comment: "Step Instruction")
        let _ = String(localized: "If feeling faint, lay down with legs elevated. If vomiting or unconscious, recovery position. A second EpiPen dose can be given after 5 minutes if no improvement.", comment: "Step Detail")
        let _ = String(localized: "Hypothermia Treatment", comment: "Technique Name")
        let _ = String(localized: "Rewarm slowly and gently", comment: "Technique Subtitle")
        let _ = String(localized: "Environmental", comment: "Category")
        let _ = String(localized: "Get the person out of the cold and remove wet clothing.", comment: "Step Instruction")
        let _ = String(localized: "Replace wet clothes with dry layers. If no dry clothes, use any insulating material — newspaper, leaves, garbage bags.", comment: "Step Detail")
        let _ = String(localized: "Insulate from the ground and cover with multiple layers.", comment: "Step Instruction")
        let _ = String(localized: "Most heat is lost to the ground. Place sleeping pads, backpacks, branches underneath. Wrap in blankets, sleeping bags, or vapor barrier.", comment: "Step Detail")
        let _ = String(localized: "Apply warm (not hot) packs to core areas: neck, armpits, groin.", comment: "Step Instruction")
        let _ = String(localized: "Use warm water bottles, heated rocks wrapped in cloth, or warm-water-filled zip bags. Never apply heat to extremities first — this causes fatal rewarming shock.", comment: "Step Detail")
        let _ = String(localized: "Give warm sweet drinks if conscious and alert.", comment: "Step Instruction")
        let _ = String(localized: "Warm water with sugar or honey. No alcohol (it dilates blood vessels and increases heat loss). No caffeine.", comment: "Step Detail")
        let _ = String(localized: "Handle gently — a severely hypothermic heart is fragile.", comment: "Step Instruction")
        let _ = String(localized: "Rough handling can trigger cardiac arrest in severe hypothermia. Move slowly and gently. Do not rub extremities.", comment: "Step Detail")
        let _ = String(localized: "Heat Stroke Treatment", comment: "Technique Name")
        let _ = String(localized: "Cool rapidly — this is a medical emergency", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize: hot/red/dry skin, confusion, temp over 104°F, loss of consciousness.", comment: "Step Instruction")
        let _ = String(localized: "Heat stroke is NOT heat exhaustion. If they've stopped sweating and are confused/unconscious, this is a dire emergency.", comment: "Step Detail")
        let _ = String(localized: "Move to shade. Remove excess clothing.", comment: "Step Instruction")
        let _ = String(localized: "Get them out of the sun immediately. Strip to underwear if possible.", comment: "Step Detail")
        let _ = String(localized: "Cool aggressively: wet the entire body and fan.", comment: "Step Instruction")
        let _ = String(localized: "Evaporative cooling is most effective. Douse with water and fan continuously. Pack ice in armpits, neck, and groin. Immerse in cool water if a stream or pool is nearby.", comment: "Step Detail")
        let _ = String(localized: "Evacuate immediately. Call emergency services.", comment: "Step Instruction")
        let _ = String(localized: "Untreated heat stroke has a 70%+ mortality rate. Brain damage starts quickly. No home remedy suffices.", comment: "Step Detail")
        let _ = String(localized: "Altitude Sickness", comment: "Technique Name")
        let _ = String(localized: "Descend. That's the cure.", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize: headache, nausea, dizziness, fatigue above 8,000 ft.", comment: "Step Instruction")
        let _ = String(localized: "AMS (Acute Mountain Sickness) affects everyone differently. Past performance doesn't predict future occurrence.", comment: "Step Detail")
        let _ = String(localized: "Stop ascending. Rest at current altitude.", comment: "Step Instruction")
        let _ = String(localized: "If symptoms are mild: rest, hydrate, eat carbs, take ibuprofen. If symptoms are moderate: descend.", comment: "Step Detail")
        let _ = String(localized: "If symptoms worsen or don't improve in 24 hours: descend 1,000+ feet.", comment: "Step Instruction")
        let _ = String(localized: "HACE (high altitude cerebral edema): confusion, loss of coordination. HAPE (high altitude pulmonary edema): cough with pink frothy sputum. Both are fatal without descent.", comment: "Step Detail")
        let _ = String(localized: "Emergency: give supplemental oxygen if available. Descend immediately.", comment: "Step Instruction")
        let _ = String(localized: "Gamow bags simulate lower altitude. Dexamethasone for HACE, nifedipine for HAPE — but descent is the definitive treatment.", comment: "Step Detail")
        let _ = String(localized: "Dehydration Treatment", comment: "Technique Name")
        let _ = String(localized: "Oral rehydration therapy", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize: dark urine, dry mouth, headache, dizziness, rapid heart rate.", comment: "Step Instruction")
        let _ = String(localized: "Pinch test: pinch skin on back of hand — if it stays tented for more than 2 seconds, dehydration is significant.", comment: "Step Detail")
        let _ = String(localized: "Give oral rehydration solution: water + salt + sugar.", comment: "Step Instruction")
        let _ = String(localized: "Recipe: 1 liter clean water + 6 teaspoons sugar + 1/2 teaspoon salt. Sip slowly over hours. Too fast causes vomiting.", comment: "Step Detail")
        let _ = String(localized: "Small frequent sips — do not gulp.", comment: "Step Instruction")
        let _ = String(localized: "1-2 tablespoons every 5 minutes for severely dehydrated patients. Increase as tolerated. Vomiting worsens dehydration.", comment: "Step Detail")
        let _ = String(localized: "Rest in shade and minimize activity until rehydrated.", comment: "Step Instruction")
        let _ = String(localized: "Monitor urine output and color. Goal is clear to light yellow. Resume activity only when urine is light-colored.", comment: "Step Detail")
        let _ = String(localized: "Dental Emergency", comment: "Technique Name")
        let _ = String(localized: "Save a knocked-out tooth within 30 min", comment: "Technique Subtitle")
        let _ = String(localized: "Eye & Dental", comment: "Category")
        let _ = String(localized: "Pick up the tooth by the crown (white part), NEVER the root.", comment: "Step Instruction")
        let _ = String(localized: "The root has living cells that must survive. Touching the root kills cells. Handle only the crown.", comment: "Step Detail")
        let _ = String(localized: "Rinse gently with milk or saliva. Do NOT scrub.", comment: "Step Instruction")
        let _ = String(localized: "If milk is available, use it. If not, have the patient spit into a cup and rinse the tooth in their saliva.", comment: "Step Detail")
        let _ = String(localized: "Attempt to reinsert into the socket.", comment: "Step Instruction")
        let _ = String(localized: "Push firmly in and have the patient bite down on a cloth to hold it. If unable to reinsert, keep in milk or inside the patient's cheek.", comment: "Step Detail")
        let _ = String(localized: "Get to a dentist within 30 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Every minute counts. Success rate drops from 90% at 5 minutes to 5% at 60 minutes. Time is teeth.", comment: "Step Detail")
        let _ = String(localized: "Blister Prevention & Treatment", comment: "Technique Name")
        let _ = String(localized: "Stop before it starts", comment: "Technique Subtitle")
        let _ = String(localized: "Foot Care", comment: "Category")
        let _ = String(localized: "At FIRST sign of a hot spot: STOP and address it.", comment: "Step Instruction")
        let _ = String(localized: "A hot spot takes 2 minutes to fix. A blister can take you out of action for days. Never push through friction.", comment: "Step Detail")
        let _ = String(localized: "Apply moleskin or athletic tape over the hot spot.", comment: "Step Instruction")
        let _ = String(localized: "Cut a donut shape — hole over the hot spot, padding around it. This eliminates friction. Duct tape works as a last resort.", comment: "Step Detail")
        let _ = String(localized: "If a blister has formed, do NOT pop small blisters.", comment: "Step Instruction")
        let _ = String(localized: "The fluid is sterile and promotes healing. Cover with padding and reduce friction. Small = smaller than a dime.", comment: "Step Detail")
        let _ = String(localized: "For large blisters that impede walking: drain from the edge.", comment: "Step Instruction")
        let _ = String(localized: "Sterilize a needle with fire or alcohol. Puncture at the edge. Press fluid out. Do NOT remove the skin roof — it's a natural bandage. Apply antibiotic and cover.", comment: "Step Detail")
        let _ = String(localized: "Ankle Wrap (Sprain)", comment: "Technique Name")
        let _ = String(localized: "Figure-8 compression wrap", comment: "Technique Subtitle")
        let _ = String(localized: "Apply RICE: Rest, Ice, Compression, Elevation.", comment: "Step Instruction")
        let _ = String(localized: "RICE within the first hour dramatically reduces swelling and recovery time.", comment: "Step Detail")
        let _ = String(localized: "Start wrapping at the ball of the foot.", comment: "Step Instruction")
        let _ = String(localized: "Use an elastic bandage. Two wraps around the ball of the foot to anchor.", comment: "Step Detail")
        let _ = String(localized: "Wrap in a figure-8 pattern around the ankle.", comment: "Step Instruction")
        let _ = String(localized: "Go around the arch, up over the ankle, cross over the front, and repeat. Each layer should overlap the previous by half.", comment: "Step Detail")
        let _ = String(localized: "Secure the bandage. Check toe circulation.", comment: "Step Instruction")
        let _ = String(localized: "Toes should remain pink and warm. You should be able to wiggle them. If not, the wrap is too tight — loosen immediately.", comment: "Step Detail")
        let _ = String(localized: "Drowning Rescue", comment: "Technique Name")
        let _ = String(localized: "Water rescue and resuscitation", comment: "Technique Subtitle")
        let _ = String(localized: "Remove victim from water using a reaching aid.", comment: "Step Instruction")
        let _ = String(localized: "Extend a pole, rope, or branch. Never swim to a drowning person unless trained—they will grab and pull you under.", comment: "Step Detail")
        let _ = String(localized: "Lay victim flat on back. Check for breathing.", comment: "Step Instruction")
        let _ = String(localized: "Look, listen, feel for 10 seconds. Drowning victims often have water blocking airways.", comment: "Step Detail")
        let _ = String(localized: "If not breathing: give 5 rescue breaths first.", comment: "Step Instruction")
        let _ = String(localized: "Drowning protocol differs from normal CPR—start with breaths. Pinch nose, seal mouth, blow until chest rises.", comment: "Step Detail")
        let _ = String(localized: "Begin CPR: 30 compressions, 2 breaths. Continue until breathing resumes.", comment: "Step Instruction")
        let _ = String(localized: "Expect vomiting—turn head to side to clear, then continue. Do NOT press abdomen to drain water.", comment: "Step Detail")
        let _ = String(localized: "Seizure Management", comment: "Technique Name")
        let _ = String(localized: "Protect the person without restraining", comment: "Technique Subtitle")
        let _ = String(localized: "Clear area around the person of hard or sharp objects.", comment: "Step Instruction")
        let _ = String(localized: "Move furniture, rocks, anything that could cause injury. Do NOT restrain the person or hold them down.", comment: "Step Detail")
        let _ = String(localized: "Place something soft under their head.", comment: "Step Instruction")
        let _ = String(localized: "Jacket, towel, backpack—anything to prevent head injury from repeated impact.", comment: "Step Detail")
        let _ = String(localized: "Do NOT put anything in their mouth.", comment: "Step Instruction")
        let _ = String(localized: "The swallowing-tongue myth is false. Objects cause broken teeth and choking.", comment: "Step Detail")
        let _ = String(localized: "Time the seizure. Over 5 minutes is a medical emergency.", comment: "Step Instruction")
        let _ = String(localized: "After the seizure stops, place in recovery position. Stay with them—they will be confused.", comment: "Step Detail")
        let _ = String(localized: "Poison Ingestion Response", comment: "Technique Name")
        let _ = String(localized: "When someone eats or drinks something toxic", comment: "Technique Subtitle")
        let _ = String(localized: "Identify what was ingested, how much, and when.", comment: "Step Instruction")
        let _ = String(localized: "Save container, plant sample, or vomit for identification.", comment: "Step Detail")
        let _ = String(localized: "Do NOT induce vomiting unless specifically directed.", comment: "Step Instruction")
        let _ = String(localized: "Caustic substances cause more damage returning. Petroleum products can be aspirated into lungs.", comment: "Step Detail")
        let _ = String(localized: "If conscious, rinse mouth with water. Small sips only.", comment: "Step Instruction")
        let _ = String(localized: "Water dilutes the toxin. Do not give large amounts. If unconscious, do not give fluids.", comment: "Step Detail")
        let _ = String(localized: "Monitor breathing. Place unconscious person in recovery position.", comment: "Step Instruction")
        let _ = String(localized: "Some poisons cause respiratory failure. Monitor constantly.", comment: "Step Detail")
        let _ = String(localized: "Stopping a Nosebleed", comment: "Technique Name")
        let _ = String(localized: "Lean forward, pinch soft part of nose", comment: "Technique Subtitle")
        let _ = String(localized: "Sit upright and lean FORWARD slightly.", comment: "Step Instruction")
        let _ = String(localized: "Leaning back causes blood to drain down throat. Forward lets blood drain out.", comment: "Step Detail")
        let _ = String(localized: "Pinch the soft part of the nose firmly for 10-15 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Just below the bony bridge. Constant pressure—do not check early.", comment: "Step Detail")
        let _ = String(localized: "Apply cold compress to bridge of nose.", comment: "Step Instruction")
        let _ = String(localized: "Cold constricts blood vessels. Ice wrapped in cloth or cold water on bandana.", comment: "Step Detail")
        let _ = String(localized: "If bleeding persists beyond 20 minutes, seek help.", comment: "Step Instruction")
        let _ = String(localized: "May indicate posterior bleed requiring medical intervention.", comment: "Step Detail")
        let _ = String(localized: "Impaled Object Management", comment: "Technique Name")
        let _ = String(localized: "Stabilize in place — never remove", comment: "Technique Subtitle")
        let _ = String(localized: "Do NOT remove the impaled object.", comment: "Step Instruction")
        let _ = String(localized: "The object may be plugging a blood vessel. Removing can cause fatal hemorrhage.", comment: "Step Detail")
        let _ = String(localized: "Stabilize the object so it cannot move.", comment: "Step Instruction")
        let _ = String(localized: "Build padding around the object on all sides. Tape or tie padding in place.", comment: "Step Detail")
        let _ = String(localized: "Control bleeding around the object with direct pressure.", comment: "Step Instruction")
        let _ = String(localized: "Press firmly AROUND the object, not on it.", comment: "Step Detail")
        let _ = String(localized: "Immobilize the body part and transport carefully.", comment: "Step Instruction")
        let _ = String(localized: "If object is long, shorten by cutting—never pull or push.", comment: "Step Detail")
        let _ = String(localized: "Electrocution Response", comment: "Technique Name")
        let _ = String(localized: "Disconnect power before touching victim", comment: "Technique Subtitle")
        let _ = String(localized: "Do NOT touch the victim until power source is disconnected.", comment: "Step Instruction")
        let _ = String(localized: "Electricity travels through bodies. You will become a second victim. Turn off breaker, unplug, or use dry wooden stick to separate.", comment: "Step Detail")
        let _ = String(localized: "Once safe, check breathing and pulse immediately.", comment: "Step Instruction")
        let _ = String(localized: "Electricity disrupts heart rhythm. Be prepared for CPR. Lightning strike victims have best survival rates with immediate CPR.", comment: "Step Detail")
        let _ = String(localized: "Treat entry and exit burns.", comment: "Step Instruction")
        let _ = String(localized: "Electrical burns have small surface wounds but massive internal damage. Cover with sterile dressing. Do not apply ice.", comment: "Step Detail")
        let _ = String(localized: "Monitor for 24 hours — delayed cardiac arrhythmia is common.", comment: "Step Instruction")
        let _ = String(localized: "Even if the person seems fine, electrical injury can cause delayed heart problems. Keep monitoring.", comment: "Step Detail")
        let _ = String(localized: "Heart Attack Recognition", comment: "Technique Name")
        let _ = String(localized: "Chest pain, jaw pain, arm pain — act fast", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize: crushing chest pressure, left arm/jaw pain, shortness of breath, cold sweat.", comment: "Step Instruction")
        let _ = String(localized: "Women may have atypical symptoms: nausea, back pain, fatigue.", comment: "Step Detail")
        let _ = String(localized: "Sit person upright, knees bent, back supported.", comment: "Step Instruction")
        let _ = String(localized: "Sitting reduces heart workload. Do not let them lie flat or exert.", comment: "Step Detail")
        let _ = String(localized: "Give aspirin if available — have them chew it.", comment: "Step Instruction")
        let _ = String(localized: "Chewing gets it into bloodstream faster. 325mg. Thins blood.", comment: "Step Detail")
        let _ = String(localized: "If unresponsive, begin CPR immediately.", comment: "Step Instruction")
        let _ = String(localized: "Heart attacks frequently lead to cardiac arrest. Be prepared.", comment: "Step Detail")
        let _ = String(localized: "Stroke Recognition (FAST)", comment: "Technique Name")
        let _ = String(localized: "Face, Arm, Speech, Time — act immediately", comment: "Technique Subtitle")
        let _ = String(localized: "FACE: Ask them to smile. Does one side droop?", comment: "Step Instruction")
        let _ = String(localized: "Facial drooping on one side is a hallmark stroke sign.", comment: "Step Detail")
        let _ = String(localized: "ARMS: Raise both arms. Does one drift down?", comment: "Step Instruction")
        let _ = String(localized: "One-sided weakness indicates stroke.", comment: "Step Detail")
        let _ = String(localized: "SPEECH: Repeat a sentence. Is it slurred?", comment: "Step Instruction")
        let _ = String(localized: "Garbled, slurred, or confused speech is a stroke sign.", comment: "Step Detail")
        let _ = String(localized: "TIME: Note when symptoms started. Get help NOW.", comment: "Step Instruction")
        let _ = String(localized: "Every minute kills 1.9 million brain cells. Time is brain.", comment: "Step Detail")
        let _ = String(localized: "Asthma Attack Response", comment: "Technique Name")
        let _ = String(localized: "Sit upright, slow breathing, use inhaler", comment: "Technique Subtitle")
        let _ = String(localized: "Sit upright, lean slightly forward, hands on knees.", comment: "Step Instruction")
        let _ = String(localized: "Tripod position opens airways. Never lay them down.", comment: "Step Detail")
        let _ = String(localized: "Help use inhaler: shake, exhale fully, inhale while pressing.", comment: "Step Instruction")
        let _ = String(localized: "2 puffs, 30-60 sec between. No inhaler: pursed lip breathing.", comment: "Step Detail")
        let _ = String(localized: "Coach slow breathing: 4 in through nose, 6 out pursed lips.", comment: "Step Instruction")
        let _ = String(localized: "Panic worsens bronchospasm. Speak calmly.", comment: "Step Detail")
        let _ = String(localized: "Blue lips or inability to speak = emergency.", comment: "Step Instruction")
        let _ = String(localized: "Blue lips = oxygen deprivation. Cannot speak in full sentences = severe.", comment: "Step Detail")
        let _ = String(localized: "Infant Choking Response", comment: "Technique Name")
        let _ = String(localized: "Back blows and chest thrusts for babies", comment: "Technique Subtitle")
        let _ = String(localized: "Place infant face-down on forearm, head lower than chest.", comment: "Step Instruction")
        let _ = String(localized: "Support head and jaw. Forearm rests on thigh.", comment: "Step Detail")
        let _ = String(localized: "5 firm back blows between shoulder blades.", comment: "Step Instruction")
        let _ = String(localized: "Sharp deliberate blows. Angle and gravity help dislodge.", comment: "Step Detail")
        let _ = String(localized: "Flip face-up. 5 chest thrusts with two fingers on breastbone.", comment: "Step Instruction")
        let _ = String(localized: "Below nipple line. Push 1.5 inches. Sharp thrusts.", comment: "Step Detail")
        let _ = String(localized: "Repeat until expelled. If unconscious, begin infant CPR.", comment: "Step Instruction")
        let _ = String(localized: "Check mouth for visible object before each breath.", comment: "Step Detail")
        let _ = String(localized: "Dislocated Joint Management", comment: "Technique Name")
        let _ = String(localized: "Immobilize in position found — do not relocate", comment: "Technique Subtitle")
        let _ = String(localized: "Do NOT try to pop the joint back in.", comment: "Step Instruction")
        let _ = String(localized: "Field reduction risks nerve, vessel, and bone damage.", comment: "Step Detail")
        let _ = String(localized: "Immobilize in current position with splint or sling.", comment: "Step Instruction")
        let _ = String(localized: "Stabilize above and below the joint.", comment: "Step Detail")
        let _ = String(localized: "Apply cold compress. 20 minutes on, 20 off.", comment: "Step Instruction")
        let _ = String(localized: "Reduces swelling and pain.", comment: "Step Detail")
        let _ = String(localized: "Check circulation below injury: pulse, sensation, color.", comment: "Step Instruction")
        let _ = String(localized: "Cold, numb, or blue = compressed blood vessels. Urgent.", comment: "Step Detail")
        let _ = String(localized: "Hyperventilation Management", comment: "Technique Name")
        let _ = String(localized: "Coach slow breathing — no paper bag", comment: "Technique Subtitle")
        let _ = String(localized: "Reassure: they are NOT dying. It feels like it, but they are safe.", comment: "Step Instruction")
        let _ = String(localized: "Hyperventilation causes tingling, chest tightness, dizziness.", comment: "Step Detail")
        let _ = String(localized: "Coach: 4 counts in through nose, 7 counts out through mouth.", comment: "Step Instruction")
        let _ = String(localized: "Goal is to slow breathing and increase CO2 levels.", comment: "Step Detail")
        let _ = String(localized: "Do NOT use a paper bag — outdated and dangerous.", comment: "Step Instruction")
        let _ = String(localized: "Paper bag can cause oxygen depletion. Coaching is safer.", comment: "Step Detail")
        let _ = String(localized: "If not anxious, check for other causes (DKA, asthma, heart).", comment: "Step Instruction")
        let _ = String(localized: "Non-anxiety hyperventilation is a medical emergency.", comment: "Step Detail")
        let _ = String(localized: "Emergency Childbirth", comment: "Technique Name")
        let _ = String(localized: "Delivery when help is not coming", comment: "Technique Subtitle")
        let _ = String(localized: "Prepare a clean area. Wash hands and groin area.", comment: "Step Instruction")
        let _ = String(localized: "Sterility is key. Boil water if possible. Use clean cloths.", comment: "Step Detail")
        let _ = String(localized: "Support the head as it crowns. Do NOT pull.", comment: "Step Instruction")
        let _ = String(localized: "Apply gentle counter-pressure to prevent tearing. Let the baby emerge naturally.", comment: "Step Detail")
        let _ = String(localized: "Clear baby's airway. Dry and warm immediately.", comment: "Step Instruction")
        let _ = String(localized: "Wipe mouth and nose. Skin-to-skin contact with mother for warmth.", comment: "Step Detail")
        let _ = String(localized: "Do not cut cord until it stops pulsing (1-3 mins).", comment: "Step Instruction")
        let _ = String(localized: "Tie with sterile string in two places, cut between. Deliver placenta naturally — do not pull.", comment: "Step Detail")
        let _ = String(localized: "Wound Packing", comment: "Technique Name")
        let _ = String(localized: "Pack deep wounds to stop life-threatening bleeding", comment: "Technique Subtitle")
        let _ = String(localized: "Trauma", comment: "Category")
        let _ = String(localized: "Identify the wound as deep and bleeding heavily despite direct pressure.", comment: "Step Instruction")
        let _ = String(localized: "Wound packing is for deep wounds in areas where a tourniquet won't work: groin, armpit, neck, or torso. Dark red, steady flow = venous. Bright red, spurting = arterial.", comment: "Step Detail")
        let _ = String(localized: "Using gauze or clean cloth, push material INTO the wound cavity.", comment: "Step Instruction")
        let _ = String(localized: "This feels wrong but saves lives. You are applying pressure from INSIDE against the bleeding vessel. Pack tightly, filling the entire wound cavity.", comment: "Step Detail")
        let _ = String(localized: "Apply firm direct pressure on top of the packed wound for 3 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Hold continuous pressure without peeking. The clotting cascade needs uninterrupted time. If blood soaks through, pack MORE material on top — never remove the original packing.", comment: "Step Detail")
        let _ = String(localized: "Secure with a pressure bandage. Monitor for continued bleeding.", comment: "Step Instruction")
        let _ = String(localized: "Wrap firmly but check pulse below the wound to confirm you haven't cut off circulation entirely. Evacuate immediately — wound packing is a bridge to surgical care.", comment: "Step Detail")
        let _ = String(localized: "Improvised Stretcher", comment: "Technique Name")
        let _ = String(localized: "Build a stretcher from available materials", comment: "Technique Subtitle")
        let _ = String(localized: "Rescue", comment: "Category")
        let _ = String(localized: "Find two sturdy poles 7+ feet long and a large piece of fabric or clothing.", comment: "Step Instruction")
        let _ = String(localized: "Poles: straight branches, tent poles, broom handles. Fabric: blanket, tarp, jackets, sleeping bag. The poles must extend beyond the patient at both ends for carriers to grip.", comment: "Step Detail")
        let _ = String(localized: "If using jackets: zip them closed, turn inside out, and slide poles through the sleeves.", comment: "Step Instruction")
        let _ = String(localized: "Button or zip the jackets closed. Thread each pole through the sleeves of 2-3 jackets. The jacket bodies form the bed of the stretcher. This is the fastest method.", comment: "Step Detail")
        let _ = String(localized: "If using a blanket: lay the blanket flat, fold one-third over a pole, place the second pole on the fold, fold the remaining third over both.", comment: "Step Instruction")
        let _ = String(localized: "The weight of the patient locks the blanket in place. No knots needed. Test with something heavy before loading the patient.", comment: "Step Detail")
        let _ = String(localized: "Lift together on a count of three. Move in unison.", comment: "Step Instruction")
        let _ = String(localized: "Minimum 2 carriers, preferably 4 (one at each pole end). The person at the head calls commands. Move slowly and steadily. Avoid jarring or tilting.", comment: "Step Detail")
        let _ = String(localized: "Emergency Tooth Treatment", comment: "Technique Name")
        let _ = String(localized: "Handle a knocked-out or broken tooth", comment: "Technique Subtitle")
        let _ = String(localized: "Dental", comment: "Category")
        let _ = String(localized: "For a knocked-out tooth: pick it up by the crown, NEVER the root.", comment: "Step Instruction")
        let _ = String(localized: "The root surface has living cells that are critical for reimplantation. Touching the root damages these cells. Handle only the white enamel part.", comment: "Step Detail")
        let _ = String(localized: "Rinse gently with milk or saliva. Do NOT scrub or use water.", comment: "Step Instruction")
        let _ = String(localized: "Milk has the correct pH and osmolality to keep root cells alive. Tap water kills root cells. If no milk, the patient's own saliva works — have them spit into a cup.", comment: "Step Detail")
        let _ = String(localized: "Reinsert the tooth into the socket if possible. Bite on cloth to hold it.", comment: "Step Instruction")
        let _ = String(localized: "Push the tooth back in gently, correct orientation. Bite on gauze or cloth to hold. If reinsertion isn't possible, store in milk or inside the patient's cheek.", comment: "Step Detail")
        let _ = String(localized: "For broken teeth: rinse mouth, apply clove oil for pain if available.", comment: "Step Instruction")
        let _ = String(localized: "Clove oil (eugenol) is a natural dental anesthetic. Apply directly to the exposed tooth. Cover sharp edges with dental wax, gum, or soft candle wax to prevent tongue cuts.", comment: "Step Detail")
        let _ = String(localized: "Eye Injury Response", comment: "Technique Name")
        let _ = String(localized: "Protect and stabilize an injured eye", comment: "Technique Subtitle")
        let _ = String(localized: "Do NOT rub, press, or touch the injured eye.", comment: "Step Instruction")
        let _ = String(localized: "Any pressure on a punctured or lacerated eye can force fluid out and cause permanent vision loss. Even gentle rubbing worsens corneal abrasions.", comment: "Step Detail")
        let _ = String(localized: "For foreign objects: flush with clean water. Do NOT remove embedded objects.", comment: "Step Instruction")
        let _ = String(localized: "If the object is sitting on the eye surface, gentle flushing may wash it out. If it's embedded or penetrating, leave it in place — removing it causes more damage.", comment: "Step Detail")
        let _ = String(localized: "Shield the injured eye with a rigid cover (cup, cardboard cone).", comment: "Step Instruction")
        let _ = String(localized: "Tape a paper cup or cone over the eye to prevent any accidental contact. Do NOT use a patch that presses against the eye. The shield protects without pressure.", comment: "Step Detail")
        let _ = String(localized: "Cover BOTH eyes to prevent sympathetic movement.", comment: "Step Instruction")
        let _ = String(localized: "Both eyes move together. Covering both eyes prevents the injured eye from moving when the good eye tracks objects. This reduces further damage during transport.", comment: "Step Detail")
        let _ = String(localized: "Spinal Immobilization", comment: "Technique Name")
        let _ = String(localized: "Stabilize a suspected spinal injury", comment: "Technique Subtitle")
        let _ = String(localized: "Suspect spinal injury after any fall, dive, vehicle accident, or head impact.", comment: "Step Instruction")
        let _ = String(localized: "If the mechanism of injury could damage the spine, assume it did until proven otherwise. Ask the patient: can you feel your fingers and toes? Can you wiggle them?", comment: "Step Detail")
        let _ = String(localized: "Tell the patient: DO NOT MOVE. Stabilize the head and neck manually.", comment: "Step Instruction")
        let _ = String(localized: "Kneel behind the patient's head. Place your hands on both sides of their head. Hold the head in the position found — do NOT straighten or twist the neck. Your job is to prevent ALL movement.", comment: "Step Detail")
        let _ = String(localized: "Improvise a cervical collar from rolled clothing or padding.", comment: "Step Instruction")
        let _ = String(localized: "Roll a towel, jacket, or similar material into a cylinder. Wrap around the neck without moving the head. Secure with tape or strips. The collar should limit flexion and extension, not compress the airway.", comment: "Step Detail")
        let _ = String(localized: "Do NOT move the patient unless there is immediate danger.", comment: "Step Instruction")
        let _ = String(localized: "Moving a spinal injury patient incorrectly can cause permanent paralysis. Only move if fire, rising water, or structural collapse threatens their life. If you must move: log-roll technique with 3+ people.", comment: "Step Detail")
        let _ = String(localized: "Diabetic Emergency Response", comment: "Technique Name")
        let _ = String(localized: "Recognize and treat low and high blood sugar", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize symptoms: confusion, shakiness, sweating, or unresponsiveness.", comment: "Step Instruction")
        let _ = String(localized: "Low blood sugar (hypoglycemia) causes trembling, confusion, pale skin, sweating. High blood sugar (hyperglycemia) causes excessive thirst, frequent urination, fruity breath.", comment: "Step Detail")
        let _ = String(localized: "If conscious and able to swallow, give sugar immediately.", comment: "Step Instruction")
        let _ = String(localized: "Give fruit juice, candy, honey, or sugar water. About 15-20g of fast-acting sugar. Wait 15 minutes and recheck.", comment: "Step Detail")
        let _ = String(localized: "If unconscious, place in recovery position. Do NOT give food or liquid.", comment: "Step Instruction")
        let _ = String(localized: "Choking risk is high. Place them on their side with head tilted back. Check breathing every minute.", comment: "Step Detail")
        let _ = String(localized: "Look for medical ID bracelet or insulin pump.", comment: "Step Instruction")
        let _ = String(localized: "Check wrists, neck, ankles for medical alert jewelry. An insulin pump looks like a small device clipped to clothing with a tube.", comment: "Step Detail")
        let _ = String(localized: "Monitor for 30 minutes after sugar is given.", comment: "Step Instruction")
        let _ = String(localized: "Symptoms should improve within 10-15 minutes. If no improvement or person becomes unconscious, this is a medical emergency requiring professional help.", comment: "Step Detail")
        let _ = String(localized: "Drowning Rescue Response", comment: "Technique Name")
        let _ = String(localized: "Water rescue and immediate resuscitation", comment: "Technique Subtitle")
        let _ = String(localized: "Reach or throw — do NOT swim to a drowning person unless trained.", comment: "Step Instruction")
        let _ = String(localized: "Drowning victims will climb on top of rescuers, pulling them under. Extend a pole, branch, rope, or throw a flotation device. Only enter the water as last resort with a flotation aid between you.", comment: "Step Detail")
        let _ = String(localized: "Once out of water: check for breathing. Begin rescue breaths FIRST.", comment: "Step Instruction")
        let _ = String(localized: "Drowning is an AIRWAY problem. Give 5 rescue breaths before compressions — this is different from standard CPR. The lungs need air cleared and oxygen delivered before compressions help.", comment: "Step Detail")
        let _ = String(localized: "If no pulse after 5 rescue breaths, begin standard CPR (30:2).", comment: "Step Instruction")
        let _ = String(localized: "Continue CPR. Do NOT attempt to drain water from lungs — it doesn't work and wastes time. Vomiting is common during drowning CPR; turn head to side, clear mouth, continue.", comment: "Step Detail")
        let _ = String(localized: "Even after revival, seek medical care. Secondary drowning can kill hours later.", comment: "Step Instruction")
        let _ = String(localized: "Water in the lungs causes inflammation that progressively worsens. A seemingly recovered patient can deteriorate and die 1-24 hours later. Hospital observation is essential.", comment: "Step Detail")
        let _ = String(localized: "Improvised Chest Seal", comment: "Technique Name")
        let _ = String(localized: "Seal a penetrating chest wound to prevent lung collapse", comment: "Technique Subtitle")
        let _ = String(localized: "Identify the wound: look for bubbling blood or sucking sound on chest.", comment: "Step Instruction")
        let _ = String(localized: "A sucking chest wound allows air into the chest cavity when breathing. You may hear a hissing or sucking noise with each breath.", comment: "Step Detail")
        let _ = String(localized: "Expose the wound completely — remove clothing around it.", comment: "Step Instruction")
        let _ = String(localized: "Cut clothing away if needed. You must see the full wound to seal it properly. Check for exit wound on the back.", comment: "Step Detail")
        let _ = String(localized: "Cover wound with plastic (bag, wrapper, card) taped on THREE sides.", comment: "Step Instruction")
        let _ = String(localized: "Leave the bottom edge untaped. This creates a flutter valve — air can escape on exhale but cannot enter on inhale. Use duct tape, medical tape, or any adhesive.", comment: "Step Detail")
        let _ = String(localized: "Position person sitting upright, leaning toward injured side.", comment: "Step Instruction")
        let _ = String(localized: "This position helps the uninjured lung work better and lets gravity drain fluid away from the good lung.", comment: "Step Detail")
        let _ = String(localized: "Monitor breathing closely. If breathing worsens, briefly lift seal.", comment: "Step Instruction")
        let _ = String(localized: "Tension pneumothorax can develop if air builds up. If breathing suddenly gets much worse, peel back one corner of the seal to release trapped air, then reseal.", comment: "Step Detail")
        let _ = String(localized: "Crush Injury Management", comment: "Technique Name")
        let _ = String(localized: "Manage injuries from prolonged crushing under debris", comment: "Technique Subtitle")
        let _ = String(localized: "Do NOT remove the crushing object if person has been trapped over 15 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Crush syndrome: toxins build up in crushed tissue. Sudden release floods the body with potassium and can cause cardiac arrest. If trapped briefly (<15 min), remove the object.", comment: "Step Detail")
        let _ = String(localized: "If safe to release: prepare for heavy bleeding before removing weight.", comment: "Step Instruction")
        let _ = String(localized: "Have tourniquets and pressure bandages ready before lifting the object. Apply tourniquet immediately when the weight is removed if a limb.", comment: "Step Detail")
        let _ = String(localized: "Give water if the person is conscious and can swallow.", comment: "Step Instruction")
        let _ = String(localized: "Hydration helps kidneys flush toxins. Give small sips. Do NOT give if unconscious or if you suspect abdominal injury.", comment: "Step Detail")
        let _ = String(localized: "Keep crushed limb below heart level after release.", comment: "Step Instruction")
        let _ = String(localized: "This slows the flow of toxin-laden blood to the heart. Splint and immobilize the limb.", comment: "Step Detail")
        let _ = String(localized: "Monitor for shock: rapid pulse, pale skin, confusion.", comment: "Step Instruction")
        let _ = String(localized: "Crush syndrome can cause shock hours after release. Keep the person warm, lying down with legs elevated if no spinal injury suspected.", comment: "Step Detail")
        let _ = String(localized: "Heat Stroke Emergency Treatment", comment: "Technique Name")
        let _ = String(localized: "Cool a heat stroke victim rapidly to prevent organ damage", comment: "Technique Subtitle")
        let _ = String(localized: "Move person to shade or coolest available area immediately.", comment: "Step Instruction")
        let _ = String(localized: "Heat stroke is life-threatening. Core body temp has exceeded 104°F (40°C). Brain damage starts quickly. Every second counts.", comment: "Step Detail")
        let _ = String(localized: "Remove excess clothing. Expose skin to air.", comment: "Step Instruction")
        let _ = String(localized: "Strip down to underwear. Removing clothing allows maximum cooling through evaporation and air contact.", comment: "Step Detail")
        let _ = String(localized: "Cool aggressively: pour water on skin, fan vigorously.", comment: "Step Instruction")
        let _ = String(localized: "Focus cooling on neck, armpits, and groin where blood vessels are close to surface. Ice packs to these areas if available. Wet sheets draped over body work well.", comment: "Step Detail")
        let _ = String(localized: "If conscious, give small sips of cool water.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT give large amounts — vomiting risk. No alcohol, no caffeine. Electrolyte solution (salt + sugar water) is ideal.", comment: "Step Detail")
        let _ = String(localized: "Monitor mental status: confusion, seizures, unconsciousness.", comment: "Step Instruction")
        let _ = String(localized: "If person becomes unconscious, place in recovery position. If they stop breathing, begin CPR. Continue cooling efforts until body feels cool to touch.", comment: "Step Detail")
        let _ = String(localized: "Hypothermia Field Treatment", comment: "Technique Name")
        let _ = String(localized: "Rewarm a hypothermic patient safely", comment: "Technique Subtitle")
        let _ = String(localized: "Get person out of cold environment and wind.", comment: "Step Instruction")
        let _ = String(localized: "Move to shelter, vehicle, or behind a windbreak. Remove wet clothing. Hypothermia progresses rapidly in wet, windy conditions.", comment: "Step Detail")
        let _ = String(localized: "Remove ALL wet clothing. Replace with dry layers.", comment: "Step Instruction")
        let _ = String(localized: "Wet fabric conducts heat away from the body 25x faster than dry fabric. If no dry clothes available, use emergency blanket or sleeping bag.", comment: "Step Detail")
        let _ = String(localized: "Insulate from the ground. Place padding underneath.", comment: "Step Instruction")
        let _ = String(localized: "The ground steals heat faster than cold air. Use backpack, branches, closed-cell foam pad, or even thick dry leaves as insulation from below.", comment: "Step Detail")
        let _ = String(localized: "Apply heat to core: neck, armpits, groin.", comment: "Step Instruction")
        let _ = String(localized: "Use warm (not hot) water bottles, heated rocks wrapped in cloth, or another person's body heat. Never apply direct heat to extremities — this can cause cardiac arrest from cold blood rush.", comment: "Step Detail")
        let _ = String(localized: "Warm water with sugar or honey. No alcohol — it dilates blood vessels and increases heat loss. No caffeine — it dehydrates. Handle person gently — rough handling can trigger cardiac arrest in severe hypothermia.", comment: "Step Detail")
        let _ = String(localized: "Severe Allergic Reaction Response", comment: "Technique Name")
        let _ = String(localized: "Manage anaphylaxis in the field", comment: "Technique Subtitle")
        let _ = String(localized: "Identify signs: hives, swelling, difficulty breathing, dizziness.", comment: "Step Instruction")
        let _ = String(localized: "Mild: localized hives, itching. Severe (anaphylaxis): throat tightening, wheezing, swollen tongue/lips, rapid heartbeat, dizziness, nausea.", comment: "Step Detail")
        let _ = String(localized: "If EpiPen available: inject into outer thigh, hold 10 seconds.", comment: "Step Instruction")
        let _ = String(localized: "Can inject through clothing. Remove safety cap, press firmly against outer thigh (not inner), hold 10 seconds. Massage injection site.", comment: "Step Detail")
        let _ = String(localized: "Have person sit upright if breathing is difficult.", comment: "Step Instruction")
        let _ = String(localized: "Sitting upright opens airways. If they feel faint or dizzy, have them lie down with legs elevated instead.", comment: "Step Detail")
        let _ = String(localized: "Remove the allergen source if possible.", comment: "Step Instruction")
        let _ = String(localized: "Remove stinger (scrape, don't pinch). Move away from bees/wasps. Stop eating suspect food. If a contact allergen, wash skin.", comment: "Step Detail")
        let _ = String(localized: "Monitor for at least 4 hours — reactions can return.", comment: "Step Instruction")
        let _ = String(localized: "Biphasic reaction: symptoms can return 1-4 hours after initial episode even after EpiPen. Second EpiPen dose may be needed if symptoms return.", comment: "Step Detail")
        let _ = String(localized: "Emergency Wound Closure", comment: "Technique Name")
        let _ = String(localized: "Close wounds in the field when medical help is days away", comment: "Technique Subtitle")
        let _ = String(localized: "Wound Care", comment: "Category")
        let _ = String(localized: "Only close wounds that are clean, less than 6 hours old, and not from bites.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT close: animal/human bites, dirty wounds, wounds older than 6 hours, puncture wounds, or wounds over joints. These have high infection risk.", comment: "Step Detail")
        let _ = String(localized: "Clean the wound thoroughly with clean water under pressure.", comment: "Step Instruction")
        let _ = String(localized: "Use a syringe or squeeze bottle to irrigate. Use at least 500ml of clean water. Remove all visible debris and dirt.", comment: "Step Detail")
        let _ = String(localized: "Use butterfly strips or medical tape to close the wound edges.", comment: "Step Instruction")
        let _ = String(localized: "Apply strips perpendicular to the wound, pulling edges together firmly but not overlapping skin. Space strips about 3mm apart. In the field, this is preferred over actual suturing.", comment: "Step Detail")
        let _ = String(localized: "Apply antibiotic ointment if available, then cover with clean bandage.", comment: "Step Instruction")
        let _ = String(localized: "A thin layer of ointment helps prevent infection. Cover with non-stick gauze, then secure with tape or wrap.", comment: "Step Detail")
        let _ = String(localized: "Check wound daily for infection: redness spreading, pus, fever, red streaks.", comment: "Step Instruction")
        let _ = String(localized: "Remove closure strips immediately if infection develops. Open infected wounds must drain. Red streaks moving toward the heart indicate blood poisoning — a critical emergency.", comment: "Step Detail")
        let _ = String(localized: "Nerve & Circulation Check", comment: "Technique Name")
        let _ = String(localized: "Assess distal circulation, sensation, and motion after injury", comment: "Technique Subtitle")
        let _ = String(localized: "Assessment", comment: "Category")
        let _ = String(localized: "Check Circulation: feel for pulse below the injury.", comment: "Step Instruction")
        let _ = String(localized: "For arms: feel radial pulse at wrist. For legs: feel dorsalis pedis pulse on top of foot. Compare both sides. Absent pulse = critical.", comment: "Step Detail")
        let _ = String(localized: "Check Sensation: can they feel you touching fingers/toes?", comment: "Step Instruction")
        let _ = String(localized: "Gently touch each finger/toe and ask if they can feel it. Compare injured side to uninjured side. Numbness or tingling indicates nerve involvement.", comment: "Step Detail")
        let _ = String(localized: "Check Movement: can they wiggle fingers/toes?", comment: "Step Instruction")
        let _ = String(localized: "Ask them to spread fingers wide, make a fist, wiggle toes, push foot against your hand. Weakness or inability to move = nerve or tendon damage.", comment: "Step Detail")
        let _ = String(localized: "Check skin color and temperature below injury.", comment: "Step Instruction")
        let _ = String(localized: "Blue/white/cold skin means blood supply is compromised. Press fingernail — it should turn white then pink within 2 seconds (capillary refill). Longer = poor circulation.", comment: "Step Detail")
        let _ = String(localized: "Document and re-check every 30 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Write down your findings. Re-check after splinting, repositioning, or any change. Worsening circulation/sensation means the splint may be too tight or the injury is progressing.", comment: "Step Detail")
        let _ = String(localized: "Psychological First Aid", comment: "Technique Name")
        let _ = String(localized: "Support someone in acute psychological distress", comment: "Technique Subtitle")
        let _ = String(localized: "Mental Health", comment: "Category")
        let _ = String(localized: "Approach calmly. Introduce yourself. Ask if they need help.", comment: "Step Instruction")
        let _ = String(localized: "Speak in a calm, steady voice. Do not touch without permission. Let them know you are there to help and they are safe.", comment: "Step Detail")
        let _ = String(localized: "Move to a quiet, safe location away from the scene.", comment: "Step Instruction")
        let _ = String(localized: "Reduce exposure to ongoing trauma. Shield them from disturbing sights/sounds. Physical safety comes first.", comment: "Step Detail")
        let _ = String(localized: "Listen actively. Let them talk without interrupting or judging.", comment: "Step Instruction")
        let _ = String(localized: "Do not say 'I know how you feel' or 'It could be worse.' Validate their experience: 'That sounds terrifying.' Silence is okay.", comment: "Step Detail")
        let _ = String(localized: "Address immediate practical needs: water, warmth, phone.", comment: "Step Instruction")
        let _ = String(localized: "Practical help grounds people. Offer a blanket, water, help them call a loved one. Small actions restore sense of control.", comment: "Step Detail")
        let _ = String(localized: "Help them identify next steps and connect with support.", comment: "Step Instruction")
        let _ = String(localized: "Ask: 'Is there someone you can call?' Help them make a plan for the next few hours. Do not promise things you cannot deliver.", comment: "Step Detail")
        let _ = String(localized: "Abdominal Injury Management", comment: "Technique Name")
        let _ = String(localized: "Manage open or closed abdominal trauma", comment: "Technique Subtitle")
        let _ = String(localized: "Do NOT push organs back in if they are protruding.", comment: "Step Instruction")
        let _ = String(localized: "If intestines or organs are visible, do NOT touch them or try to push them back inside. This causes contamination and further damage.", comment: "Step Detail")
        let _ = String(localized: "Cover exposed organs with moist, clean cloth.", comment: "Step Instruction")
        let _ = String(localized: "Use a clean shirt, towel, or gauze dampened with clean water. Keep them moist to prevent drying. Cover loosely — do not press down.", comment: "Step Detail")
        let _ = String(localized: "Position person on their back with knees bent.", comment: "Step Instruction")
        let _ = String(localized: "This relaxes abdominal muscles and reduces pain. Place a rolled blanket or pack under the knees for support.", comment: "Step Detail")
        let _ = String(localized: "Do NOT give food, water, or medication by mouth.", comment: "Step Instruction")
        let _ = String(localized: "Surgery may be needed. Anything in the stomach increases risk during anesthesia. Moisten lips with wet cloth if they complain of thirst.", comment: "Step Detail")
        let _ = String(localized: "Treat for shock: keep warm, monitor breathing.", comment: "Step Instruction")
        let _ = String(localized: "Cover with blanket. Talk to them calmly. Monitor skin color, breathing rate, and consciousness. If they vomit, turn head to side.", comment: "Step Detail")
        let _ = String(localized: "Choking Response (Adult & Child)", comment: "Technique Name")
        let _ = String(localized: "Clear an obstructed airway using Heimlich and back blows", comment: "Technique Subtitle")
        let _ = String(localized: "Airway", comment: "Category")
        let _ = String(localized: "Determine severity: can they cough, speak, or breathe?", comment: "Step Instruction")
        let _ = String(localized: "Mild obstruction: encourage forceful coughing. Severe obstruction: no sound, no cough, may clutch throat (universal choking sign).", comment: "Step Detail")
        let _ = String(localized: "Stand behind, give 5 sharp back blows between shoulder blades.", comment: "Step Instruction")
        let _ = String(localized: "Use the heel of your hand. Lean the person forward. Each blow should be a separate, forceful strike aimed at dislodging the object.", comment: "Step Detail")
        let _ = String(localized: "If back blows fail: give 5 abdominal thrusts (Heimlich).", comment: "Step Instruction")
        let _ = String(localized: "Wrap arms around waist, fist above navel, pull sharply inward and upward. For pregnant/obese: use chest thrusts instead (fist on middle of breastbone).", comment: "Step Detail")
        let _ = String(localized: "Alternate: 5 back blows, then 5 abdominal thrusts. Repeat.", comment: "Step Instruction")
        let _ = String(localized: "Continue alternating until the object is expelled or the person becomes unconscious.", comment: "Step Detail")
        let _ = String(localized: "If person becomes unconscious: lower to ground, begin CPR.", comment: "Step Instruction")
        let _ = String(localized: "Open airway, look in mouth for visible object. If visible, sweep it out with finger. Give 2 rescue breaths. If they don't go in, give 30 chest compressions and recheck mouth.", comment: "Step Detail")
        let _ = String(localized: "Junctional Hemorrhage Control", comment: "Technique Name")
        let _ = String(localized: "Control bleeding at the neck, armpit, or groin where tourniquets can't go", comment: "Technique Subtitle")
        let _ = String(localized: "Apply direct pressure with hemostatic gauze if available.", comment: "Step Instruction")
        let _ = String(localized: "Pack hemostatic gauze (QuikClot, Celox) into the wound tightly. These contain agents that accelerate clotting. Regular gauze works if hemostatic not available.", comment: "Step Detail")
        let _ = String(localized: "For junctional wounds (neck, groin, armpit): pack tightly and hold.", comment: "Step Instruction")
        let _ = String(localized: "Tourniquets don't work in these locations. Pack gauze deep into the wound, apply maximum pressure with both hands. Hold for at least 3 minutes.", comment: "Step Detail")
        let _ = String(localized: "Maintain constant, firm pressure for minimum 3 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT lift to check. Checking disrupts the forming clot. Time it. 3 minutes minimum for venous bleeding, 10 minutes for arterial.", comment: "Step Detail")
        let _ = String(localized: "Apply pressure bandage over the packed wound.", comment: "Step Instruction")
        let _ = String(localized: "Use elastic bandage wrapped tightly. The bandage maintains pressure when you need to use your hands for other tasks.", comment: "Step Detail")
        let _ = String(localized: "Elevate the wound above heart level if possible.", comment: "Step Instruction")
        let _ = String(localized: "Elevation reduces blood pressure at the wound site. Secure the limb in elevated position with sling or padding.", comment: "Step Detail")
        let _ = String(localized: "Poisoning Emergency Response", comment: "Technique Name")
        let _ = String(localized: "Respond to ingested, inhaled, or absorbed poisons", comment: "Technique Subtitle")
        let _ = String(localized: "Identify the poison: what, how much, when, and how.", comment: "Step Instruction")
        let _ = String(localized: "Save the container, plant, or substance. Note the time of ingestion. This information is critical for treatment decisions.", comment: "Step Detail")
        let _ = String(localized: "Do NOT induce vomiting unless specifically told to by poison control.", comment: "Step Instruction")
        let _ = String(localized: "Vomiting caustic substances (acids, alkalis, petroleum products) causes double damage — going down AND coming back up. Never give ipecac.", comment: "Step Detail")
        let _ = String(localized: "If poison is on skin: remove contaminated clothing, rinse with water.", comment: "Step Instruction")
        let _ = String(localized: "Flush skin for at least 15-20 minutes with running water. Use gloves or barrier to protect yourself. Remove jewelry that may trap chemicals.", comment: "Step Detail")
        let _ = String(localized: "If poison inhaled: move to fresh air immediately.", comment: "Step Instruction")
        let _ = String(localized: "Do not enter confined spaces with potential toxic atmosphere without breathing protection. Open windows and doors.", comment: "Step Detail")
        let _ = String(localized: "Monitor for shock, breathing difficulty, or seizures.", comment: "Step Instruction")
        let _ = String(localized: "Position in recovery position if drowsy. If not breathing, begin CPR. Keep them warm. Save any vomit for medical analysis.", comment: "Step Detail")
        let _ = String(localized: "Frostbite Treatment", comment: "Technique Name")
        let _ = String(localized: "Recognize and treat frozen tissue in extremities", comment: "Technique Subtitle")
        let _ = String(localized: "Move to warm shelter. Do NOT rub or massage affected area.", comment: "Step Instruction")
        let _ = String(localized: "Rubbing causes ice crystals in tissue to tear cells, causing more damage. Protect the area from further cold exposure.", comment: "Step Detail")
        let _ = String(localized: "Remove wet clothing and constricting items from affected area.", comment: "Step Instruction")
        let _ = String(localized: "Remove rings, watches, tight boots. Swelling will increase during rewarming. Wet items accelerate heat loss.", comment: "Step Detail")
        let _ = String(localized: "Rewarm in warm (not hot) water: 98-102°F (37-39°C) for 30 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Water should feel comfortably warm on your elbow. NEVER use heating pad, fire, or hot water — frostbitten skin can't feel heat and will burn. Rewarming is extremely painful.", comment: "Step Detail")
        let _ = String(localized: "Do NOT rewarm if refreezing is possible.", comment: "Step Instruction")
        let _ = String(localized: "Thawed and refrozen tissue suffers far worse damage than tissue left frozen. Only rewarm if you can guarantee the area will stay warm.", comment: "Step Detail")
        let _ = String(localized: "Protect rewarmed tissue: wrap loosely, separate fingers/toes.", comment: "Step Instruction")
        let _ = String(localized: "Place cotton or gauze between digits. Do not pop blisters. Elevate the area. Expect significant pain during and after rewarming — this is normal.", comment: "Step Detail")
        let _ = String(localized: "Snake Bite Response", comment: "Technique Name")
        let _ = String(localized: "Manage venomous and non-venomous snake bites", comment: "Technique Subtitle")
        let _ = String(localized: "Bites & Stings", comment: "Category")
        let _ = String(localized: "Move AWAY from the snake. Do NOT try to catch or kill it.", comment: "Step Instruction")
        let _ = String(localized: "Remember the snake's appearance if possible (color, head shape, pattern) but do not risk a second bite. Most bites happen when people try to handle snakes.", comment: "Step Detail")
        let _ = String(localized: "Keep the bitten limb BELOW heart level and still.", comment: "Step Instruction")
        let _ = String(localized: "Movement increases circulation and spreads venom faster. Immobilize the limb with a splint if possible. Remove rings and watches — swelling will occur.", comment: "Step Detail")
        let _ = String(localized: "Do NOT: cut wound, suck venom, apply ice, or use tourniquet.", comment: "Step Instruction")
        let _ = String(localized: "All of these are myths and cause additional harm. Cutting introduces infection. Suction doesn't remove venom. Ice damages tissue. Tourniquets can cause limb loss.", comment: "Step Detail")
        let _ = String(localized: "Clean the bite gently with water. Mark the edge of swelling with pen.", comment: "Step Instruction")
        let _ = String(localized: "Write the time next to the swelling mark. Check every 15 minutes and mark new swelling edge. This helps medical teams assess venom spread rate.", comment: "Step Detail")
        let _ = String(localized: "Keep calm and still. Monitor for systemic symptoms.", comment: "Step Instruction")
        let _ = String(localized: "Watch for: nausea, blurred vision, difficulty breathing, numbness spreading beyond bite, metallic taste. Anxiety increases heart rate which spreads venom faster.", comment: "Step Detail")
        let _ = String(localized: "Spider & Scorpion Bite Treatment", comment: "Technique Name")
        let _ = String(localized: "Identify and manage venomous arthropod envenomation", comment: "Technique Subtitle")
        let _ = String(localized: "Clean bite with soap and water.", comment: "Step Instruction")
        let _ = String(localized: "Most spider bites are harmless. Clean thoroughly to prevent secondary infection. Note the time of bite.", comment: "Step Detail")
        let _ = String(localized: "Apply cold pack for 10 minutes on, 10 minutes off.", comment: "Step Instruction")
        let _ = String(localized: "Wrap ice in cloth — do not apply ice directly to skin. Cold reduces pain and slows venom absorption.", comment: "Step Detail")
        let _ = String(localized: "Identify dangerous signs: severe pain, muscle cramps, spreading redness.", comment: "Step Instruction")
        let _ = String(localized: "Black widow: severe abdominal cramps, sweating. Brown recluse: expanding purple/red wound after 2-8 hours. Scorpion: tingling, twitching.", comment: "Step Detail")
        let _ = String(localized: "Elevate affected limb and keep still.", comment: "Step Instruction")
        let _ = String(localized: "Reduces swelling and slows venom spread. Immobilize if possible.", comment: "Step Detail")
        let _ = String(localized: "Draw a circle around redness and note the time.", comment: "Step Instruction")
        let _ = String(localized: "If redness expands beyond the circle over hours, the venom is spreading and medical attention is needed urgently. Photograph if phone available.", comment: "Step Detail")
        let _ = String(localized: "Deep Splinter & Foreign Body Removal", comment: "Technique Name")
        let _ = String(localized: "Safely remove embedded objects from skin", comment: "Technique Subtitle")
        let _ = String(localized: "Clean the area with soap and water before removal.", comment: "Step Instruction")
        let _ = String(localized: "Cleaning first prevents pushing bacteria deeper during removal.", comment: "Step Detail")
        let _ = String(localized: "Sterilize tweezers or needle with flame or alcohol.", comment: "Step Instruction")
        let _ = String(localized: "Heat a needle tip until red-hot and cool, or wipe with alcohol. In the field, use the sharpest thin tool available.", comment: "Step Detail")
        let _ = String(localized: "Grasp the splinter near the skin and pull along the angle of entry.", comment: "Step Instruction")
        let _ = String(localized: "Pull in the same direction the splinter entered — not straight up. This prevents breaking. If too deep, use a needle to gently expose the tip.", comment: "Step Detail")
        let _ = String(localized: "Squeeze the wound gently to encourage bleeding.", comment: "Step Instruction")
        let _ = String(localized: "A small amount of bleeding helps flush bacteria from the wound channel. Do not squeeze excessively.", comment: "Step Detail")
        let _ = String(localized: "Clean again, apply antibiotic if available, and cover.", comment: "Step Instruction")
        let _ = String(localized: "Watch for signs of infection over the next 48 hours: redness, swelling, warmth, pus, or red streaks.", comment: "Step Detail")
        let _ = String(localized: "Sprain Treatment (RICE Protocol)", comment: "Technique Name")
        let _ = String(localized: "Manage ligament injuries with Rest, Ice, Compression, Elevation", comment: "Technique Subtitle")
        let _ = String(localized: "Musculoskeletal", comment: "Category")
        let _ = String(localized: "Rest: stop using the injured joint immediately.", comment: "Step Instruction")
        let _ = String(localized: "Continuing to use a sprained joint can turn a minor sprain into a complete ligament tear. If necessary to move, splint the joint first.", comment: "Step Detail")
        let _ = String(localized: "Ice: apply cold for 20 minutes every 2 hours.", comment: "Step Instruction")
        let _ = String(localized: "Use ice in a bag, cold stream water, or even cool mud wrapped in cloth. Never apply ice directly to skin. Cold reduces swelling and pain.", comment: "Step Detail")
        let _ = String(localized: "Compress: wrap with elastic bandage snugly.", comment: "Step Instruction")
        let _ = String(localized: "Start wrapping below the injury and wrap upward. Snug but not tight — you should be able to slide one finger under the wrap. Check circulation below the wrap.", comment: "Step Detail")
        let _ = String(localized: "Elevate: keep injured area above heart level.", comment: "Step Instruction")
        let _ = String(localized: "Elevation reduces blood flow to the area, limiting swelling. Prop up with a pack, log, or rolled clothing.", comment: "Step Detail")
        let _ = String(localized: "Test weight-bearing ability after 24 hours of RICE.", comment: "Step Instruction")
        let _ = String(localized: "If you can bear weight with tolerable pain, gentle movement is okay. If severe pain or instability persists, the ligament may be torn — immobilize and avoid use.", comment: "Step Detail")
        let _ = String(localized: "Knee Injury Stabilization", comment: "Technique Name")
        let _ = String(localized: "Stabilize knee injuries for safe movement", comment: "Technique Subtitle")
        let _ = String(localized: "Immobilize the knee in the position found.", comment: "Step Instruction")
        let _ = String(localized: "Do not try to straighten a locked or bent knee. Splint it in its current position using sticks, trekking poles, or sleeping pad.", comment: "Step Detail")
        let _ = String(localized: "Check circulation below the knee: pulse, warmth, sensation in foot.", comment: "Step Instruction")
        let _ = String(localized: "Feel for pulse on top of foot (dorsalis pedis). Check that toes are warm and pink. Ask if they can feel touch on each toe.", comment: "Step Detail")
        let _ = String(localized: "Apply cold to reduce swelling for 20 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Cold stream water, snow in cloth bag, or ice pack. Wrap in fabric — never direct skin contact.", comment: "Step Detail")
        let _ = String(localized: "Wrap with compression bandage in figure-8 pattern.", comment: "Step Instruction")
        let _ = String(localized: "Start below knee, cross over kneecap, wrap above knee, and repeat. This provides support while allowing some flexion.", comment: "Step Detail")
        let _ = String(localized: "Create a walking aid: trekking pole, sturdy branch, or crutch.", comment: "Step Instruction")
        let _ = String(localized: "A crutch should reach from armpit to 6 inches ahead of foot. Pad the top with cloth. Use on the uninjured side.", comment: "Step Detail")
        let _ = String(localized: "Femur Fracture Traction Splint", comment: "Technique Name")
        let _ = String(localized: "Emergency stabilization of the most dangerous long bone fracture", comment: "Technique Subtitle")
        let _ = String(localized: "Suspect femur fracture: severe thigh pain, inability to move leg, leg appears shortened.", comment: "Step Instruction")
        let _ = String(localized: "The femur is the strongest bone in the body — fracture requires significant force. Thigh may swell massively as internal bleeding can reach 1-2 liters.", comment: "Step Detail")
        let _ = String(localized: "Check for circulation, sensation, and movement in foot before splinting.", comment: "Step Instruction")
        let _ = String(localized: "Document findings: pulse at ankle, feeling in toes, ability to wiggle toes. This baseline is critical to compare after splinting.", comment: "Step Detail")
        let _ = String(localized: "Create traction splint: one long pole from armpit to past foot.", comment: "Step Instruction")
        let _ = String(localized: "Use a straight branch, ski pole, or trekking pole. Must extend from the armpit past the foot by at least 6 inches. Pad armpit contact point.", comment: "Step Detail")
        let _ = String(localized: "Secure splint at chest, hip, above knee, and at ankle.", comment: "Step Instruction")
        let _ = String(localized: "Use belts, bandages, or torn clothing strips. Tie firmly but check that ties don't cut off circulation. Never tie directly over the fracture site.", comment: "Step Detail")
        let _ = String(localized: "Apply gentle traction at ankle to realign and reduce pain.", comment: "Step Instruction")
        let _ = String(localized: "Pull gently and steadily along the long axis of the leg until the injured leg is approximately the same length as the uninjured leg. Secure ankle to the end of the splint to maintain traction.", comment: "Step Detail")
        let _ = String(localized: "Trench Foot Prevention & Treatment", comment: "Technique Name")
        let _ = String(localized: "Manage non-freezing cold injury from prolonged wet exposure", comment: "Technique Subtitle")
        let _ = String(localized: "Remove wet footwear and socks immediately.", comment: "Step Instruction")
        let _ = String(localized: "Trench foot (immersion foot) develops after 12+ hours of wet, cold conditions. The skin becomes pale, wrinkled, and numb. Early treatment prevents permanent damage.", comment: "Step Detail")
        let _ = String(localized: "Air dry feet. Do NOT rub, massage, or apply direct heat.", comment: "Step Instruction")
        let _ = String(localized: "Damaged tissue is extremely fragile. Rubbing causes further damage. Let feet air dry naturally or pat very gently with clean cloth.", comment: "Step Detail")
        let _ = String(localized: "Elevate feet to reduce swelling.", comment: "Step Instruction")
        let _ = String(localized: "Prop feet up above heart level on a pack or log. Keep them uncovered to continue drying.", comment: "Step Detail")
        let _ = String(localized: "Once dry, apply clean, dry socks loosely.", comment: "Step Instruction")
        let _ = String(localized: "Do not wear tight footwear. If available, use dry insoles. Keep feet warm but do not overheat. Place cotton between toes if skin is macerated.", comment: "Step Detail")
        let _ = String(localized: "Prevent recurrence: change socks twice daily, dry feet at every opportunity.", comment: "Step Instruction")
        let _ = String(localized: "Carry spare socks against your body to keep them dry and warm. Apply foot powder if available. Never sleep in wet socks.", comment: "Step Detail")
        let _ = String(localized: "Sprained Ankle Field Treatment", comment: "Technique Name")
        let _ = String(localized: "Manage the most common wilderness injury", comment: "Technique Subtitle")
        let _ = String(localized: "Stop walking. Remove boot and assess swelling.", comment: "Step Instruction")
        let _ = String(localized: "Continuing to walk can worsen a partial tear into a complete tear. If in the field and you must walk, leave the boot ON — it provides compression and support.", comment: "Step Detail")
        let _ = String(localized: "Apply cold for 20 minutes to reduce swelling.", comment: "Step Instruction")
        let _ = String(localized: "Submerse in cold stream, apply ice/snow wrapped in cloth, or use cold mud pack. 20 minutes on, 20 minutes off.", comment: "Step Detail")
        let _ = String(localized: "Wrap in figure-8 with elastic bandage or torn cloth.", comment: "Step Instruction")
        let _ = String(localized: "Start at the toes, wrap around the arch, cross over the ankle, loop around the lower leg, repeat. Firm but not cutting off circulation.", comment: "Step Detail")
        let _ = String(localized: "Test weight-bearing: can you walk with tolerable pain?", comment: "Step Instruction")
        let _ = String(localized: "If you can hobble with a walking stick, a field evacuation may be possible. If unable to bear any weight, the injury may be a fracture — immobilize and await help.", comment: "Step Detail")
        let _ = String(localized: "Create a walking aid and plan your evacuation.", comment: "Step Instruction")
        let _ = String(localized: "Use a sturdy Y-shaped branch as a crutch, padded with cloth at the top. Walk slowly, testing each step. Mark your trail for rescuers if you must stop.", comment: "Step Detail")
        let _ = String(localized: "Fever Management in the Field", comment: "Technique Name")
        let _ = String(localized: "Reduce fever and prevent dangerous temperature elevation", comment: "Technique Subtitle")
        let _ = String(localized: "Check temperature if thermometer available. Above 101°F (38.3°C) needs treatment.", comment: "Step Instruction")
        let _ = String(localized: "Without thermometer: hot forehead, chills, sweating, rapid heartbeat, general weakness all indicate fever. Fever itself is a defense mechanism.", comment: "Step Detail")
        let _ = String(localized: "Give ibuprofen or acetaminophen if available.", comment: "Step Instruction")
        let _ = String(localized: "Follow dosage on packaging. Alternate between both every 3-4 hours for persistent fever. Never exceed recommended doses.", comment: "Step Detail")
        let _ = String(localized: "Push fluids: water, broth, oral rehydration solution.", comment: "Step Instruction")
        let _ = String(localized: "Fever increases fluid loss. Aim for small frequent sips rather than large amounts. Add pinch of salt and sugar to water for improvised electrolyte solution.", comment: "Step Detail")
        let _ = String(localized: "Cool the body: remove excess clothing, apply cool damp cloths.", comment: "Step Instruction")
        let _ = String(localized: "Place cool wet cloths on forehead, neck, armpits. Fan the person. Do NOT use cold water immersion — shivering generates more heat.", comment: "Step Detail")
        let _ = String(localized: "Monitor for danger signs: stiff neck, confusion, rash, persistent vomiting.", comment: "Step Instruction")
        let _ = String(localized: "These may indicate meningitis, severe infection, or dehydration. Fever above 104°F (40°C) is a medical emergency requiring aggressive cooling.", comment: "Step Detail")
        let _ = String(localized: "Environments", comment: "Domain Name")
        let _ = String(localized: "Desert Travel Strategy", comment: "Technique Name")
        let _ = String(localized: "Move at night, shelter by day", comment: "Technique Subtitle")
        let _ = String(localized: "Desert", comment: "Category")
        let _ = String(localized: "Travel only at night or during dawn/dusk.", comment: "Step Instruction")
        let _ = String(localized: "Midday desert temps can exceed 130°F at ground level. You'll lose 1-2 quarts of sweat per hour walking in heat. At night, temps drop 30-50°F.", comment: "Step Detail")
        let _ = String(localized: "Stay covered — loose, light-colored clothing covering all skin.", comment: "Step Instruction")
        let _ = String(localized: "Exposed skin in direct sun dehydrates faster than covered skin. Arabic robes exist for a reason. Cover your head and neck.", comment: "Step Detail")
        let _ = String(localized: "Navigate by stars at night, compass in day.", comment: "Step Instruction")
        let _ = String(localized: "Without landmarks, people walk in circles (dominant leg push). Use celestial navigation or a compass to maintain direction.", comment: "Step Detail")
        let _ = String(localized: "Never walk without water. Ration sweat, not water.", comment: "Step Instruction")
        let _ = String(localized: "Desert survival without water: 2-3 days walking, 5-7 days resting in shade. Your water goes in you, not on you.", comment: "Step Detail")
        let _ = String(localized: "Desert Shade Shelter", comment: "Technique Name")
        let _ = String(localized: "Double-layer shade with air gap", comment: "Technique Subtitle")
        let _ = String(localized: "Create a double-layer shade with 12-inch air gap.", comment: "Step Instruction")
        let _ = String(localized: "Two layers of material (tarp over tarp) with an air gap between them reduces ground-level temperature by 30-40°F.", comment: "Step Detail")
        let _ = String(localized: "Raise the shelter 18 inches off the ground.", comment: "Step Instruction")
        let _ = String(localized: "Ground surface temperature can be 30°F hotter than air 18 inches up. A raised platform or elevated tarp helps.", comment: "Step Detail")
        let _ = String(localized: "Orient the open side away from prevailing wind.", comment: "Step Instruction")
        let _ = String(localized: "Desert winds carry sand. Open side should face the direction that provides breeze without sandblasting.", comment: "Step Detail")
        let _ = String(localized: "If no materials: dig a trench and cover with any available material.", comment: "Step Instruction")
        let _ = String(localized: "Dig 2 feet deep — subterranean temps are significantly cooler. Cover for shade. Even a backpack propped up provides head shade.", comment: "Step Detail")
        let _ = String(localized: "Finding Water in Desert", comment: "Technique Name")
        let _ = String(localized: "Follow signs to hidden sources", comment: "Technique Subtitle")
        let _ = String(localized: "Look for green vegetation — especially cottonwood, willow, and palm.", comment: "Step Instruction")
        let _ = String(localized: "These trees require consistent water. Their roots reach groundwater. Dig at the base of these trees.", comment: "Step Detail")
        let _ = String(localized: "Dig in the outside bend of dry washes and riverbeds.", comment: "Step Instruction")
        let _ = String(localized: "Water pools at the outer bend. Dig 1-3 feet. Let the hole fill over 30 minutes. If groundwater is there, it will seep in.", comment: "Step Detail")
        let _ = String(localized: "Watch for birds (especially doves) at dusk — they fly toward water.", comment: "Step Instruction")
        let _ = String(localized: "Grain-eating birds need daily water. At dusk they fly in straight lines to water sources. Follow their direction.", comment: "Step Detail")
        let _ = String(localized: "Check rock crevices and shaded north-facing cliff bases.", comment: "Step Instruction")
        let _ = String(localized: "Tinajas (natural rock pools) can hold water for weeks after rain. Check shaded depressions in rock.", comment: "Step Detail")
        let _ = String(localized: "Jungle Travel", comment: "Technique Name")
        let _ = String(localized: "Follow water, machete your path", comment: "Technique Subtitle")
        let _ = String(localized: "Jungle", comment: "Category")
        let _ = String(localized: "Follow streams downstream — they lead to rivers, rivers lead to people.", comment: "Step Instruction")
        let _ = String(localized: "99% of tropical settlements are on waterways. Walking along a stream also ensures water access.", comment: "Step Detail")
        let _ = String(localized: "Travel on ridgelines when possible — less vegetation, better visibility.", comment: "Step Instruction")
        let _ = String(localized: "Valley floors have the densest vegetation. Ridges are drier and sparser. Navigation is easier with visibility.", comment: "Step Detail")
        let _ = String(localized: "Mark your path — the jungle looks identical in every direction.", comment: "Step Instruction")
        let _ = String(localized: "Blaze trees (cut bark), break branches, tie cloth. Without markers you will loop back to where you started.", comment: "Step Detail")
        let _ = String(localized: "Watch your feet and where you grab — snakes and insects are everywhere.", comment: "Step Instruction")
        let _ = String(localized: "Never put hands or feet where you can't see. Probe ahead with a stick. Shake out boots and clothing before wearing.", comment: "Step Detail")
        let _ = String(localized: "Jungle Water Sources", comment: "Technique Name")
        let _ = String(localized: "Water is abundant but needs treatment", comment: "Technique Subtitle")
        let _ = String(localized: "Bamboo segments hold clean water between nodes.", comment: "Step Instruction")
        let _ = String(localized: "Shake green bamboo — if you hear sloshing, it contains water. Cut a small hole to access. This water is usually potable.", comment: "Step Detail")
        let _ = String(localized: "Vines can provide drinking water if cut correctly.", comment: "Step Instruction")
        let _ = String(localized: "Cut the vine HIGH first, then cut LOW. Water will flow from the bottom cut. If sap is milky or bitter, discard that vine.", comment: "Step Detail")
        let _ = String(localized: "Collect rainwater from large leaves — banana leaves are ideal.", comment: "Step Instruction")
        let _ = String(localized: "Tropical rainfall is frequent and heavy. Channel large leaves into containers. Rain is the safest water source.", comment: "Step Detail")
        let _ = String(localized: "Still purify stream water — jungle water carries parasites.", comment: "Step Instruction")
        let _ = String(localized: "Tropical waterways have the highest parasite load on Earth. Schistosomiasis from skin contact alone. Boil everything.", comment: "Step Detail")
        let _ = String(localized: "Jungle Hammock Shelter", comment: "Technique Name")
        let _ = String(localized: "Sleep off the ground away from insects and flooding", comment: "Technique Subtitle")
        let _ = String(localized: "Sleep OFF the ground. Always.", comment: "Step Instruction")
        let _ = String(localized: "Ground in tropical environments = ants, scorpions, snakes, moisture, and fungal infections. Build a raised platform or improvised hammock.", comment: "Step Detail")
        let _ = String(localized: "Use poncho or tarp as a rain fly above your sleeping area.", comment: "Step Instruction")
        let _ = String(localized: "It rains daily in the tropics. An overhead cover is critical. Angle it for runoff — water pooling causes collapse.", comment: "Step Detail")
        let _ = String(localized: "Tuck mosquito netting under your sleeping surface.", comment: "Step Instruction")
        let _ = String(localized: "Malaria, dengue, Zika — all transmitted by night-biting mosquitoes. A net is possibly the single most important piece of jungle survival gear.", comment: "Step Detail")
        let _ = String(localized: "Build a smudge fire nearby to drive away insects.", comment: "Step Instruction")
        let _ = String(localized: "Green wood and damp leaves create smoke. Keep the fire small and smoky. The smoke deters mosquitoes within a 10-foot radius.", comment: "Step Detail")
        let _ = String(localized: "Snow Shelter (Quinzhee)", comment: "Technique Name")
        let _ = String(localized: "Pile, settle, hollow — warmer than outside", comment: "Technique Subtitle")
        let _ = String(localized: "Arctic", comment: "Category")
        let _ = String(localized: "Pile snow into a mound 7-8 feet tall, 10 feet wide.", comment: "Step Instruction")
        let _ = String(localized: "The bigger the pile, the more insulation. Mixing snow of different temperatures during piling helps it harden.", comment: "Step Detail")
        let _ = String(localized: "Let the mound settle for 1-2 hours (sintering).", comment: "Step Instruction")
        let _ = String(localized: "Snow crystals bond together. This makes the structure strong enough to hollow out without collapsing. Critical step — don't skip.", comment: "Step Detail")
        let _ = String(localized: "Insert sticks 12 inches deep all over the mound.", comment: "Step Instruction")
        let _ = String(localized: "These are thickness guides. When hollowing, stop when you hit sticks. This ensures uniform wall thickness.", comment: "Step Detail")
        let _ = String(localized: "Hollow from a low entrance upward. Sleep platform above entrance.", comment: "Step Instruction")
        let _ = String(localized: "Cold air sinks. The entrance should be below the sleeping platform. Interior temp stays near 32°F even when it's -40°F outside.", comment: "Step Detail")
        let _ = String(localized: "Poke a fist-sized ventilation hole in the roof.", comment: "Step Instruction")
        let _ = String(localized: "Carbon dioxide from breathing accumulates. Without ventilation, you'll suffocate. Check the hole isn't blocked by new snowfall.", comment: "Step Detail")
        let _ = String(localized: "Arctic Travel & Navigation", comment: "Technique Name")
        let _ = String(localized: "Energy conservation is everything", comment: "Technique Subtitle")
        let _ = String(localized: "Travel during warmest hours. Shelter during extreme cold.", comment: "Step Instruction")
        let _ = String(localized: "Unlike desert (travel at night), Arctic travel should occur during midday warmth. Nighttime temps drop to unsurvivable levels.", comment: "Step Detail")
        let _ = String(localized: "Manage layers to prevent sweating.", comment: "Step Instruction")
        let _ = String(localized: "Sweating in cold = death. Wet clothing loses insulation. Remove layers BEFORE you overheat. Vent at neck and wrists.", comment: "Step Detail")
        let _ = String(localized: "Use snowshoes or improvised floatation to prevent post-holing.", comment: "Step Instruction")
        let _ = String(localized: "Walking through deep snow without snowshoes burns 3× the calorie. Tie evergreen branches to feet for improvised snowshoes.", comment: "Step Detail")
        let _ = String(localized: "Watch for thin ice: dark ice, snow-covered ice, and ice near moving water.", comment: "Step Instruction")
        let _ = String(localized: "Clear blue ice = strong. White/opaque ice = weaker (air bubbles). Snow masks thin spots. Near inlets/outlets ice is always thinner.", comment: "Step Detail")
        let _ = String(localized: "Frostbite Prevention & Treatment", comment: "Technique Name")
        let _ = String(localized: "Frozen tissue dies — prevent at all costs", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize: white/gray waxy skin, numbness, hardness.", comment: "Step Instruction")
        let _ = String(localized: "Frostbite progresses: frostnip (red, painful) → superficial (blistered, numb) → deep (hard, frozen solid). Early stages are fully reversible.", comment: "Step Detail")
        let _ = String(localized: "Rewarm in body heat: armpit, groin, stomach.", comment: "Step Instruction")
        let _ = String(localized: "Place frostbitten fingers in your armpits. Place frostbitten toes against a companion's stomach. Skin-to-skin contact is ideal.", comment: "Step Detail")
        let _ = String(localized: "If possible, rewarm in 98-102°F water for 20-30 minutes.", comment: "Step Instruction")
        let _ = String(localized: "NOT hot water — lukewarm. Rewarming is extremely painful. Give pain medication first if available. Do NOT rub or massage.", comment: "Step Detail")
        let _ = String(localized: "Thawed-then-refrozen tissue suffers far worse damage than tissue left frozen. If you can't maintain warmth, leave it frozen until you reach help.", comment: "Step Detail")
        let _ = String(localized: "Lightning Safety in Mountains", comment: "Technique Name")
        let _ = String(localized: "Get low, get small, get separate", comment: "Technique Subtitle")
        let _ = String(localized: "Mountain", comment: "Category")
        let _ = String(localized: "Get below treeline and away from peaks, ridges, and isolated trees.", comment: "Step Instruction")
        let _ = String(localized: "Lightning strikes the highest point. If you're on a ridge, you ARE the highest point. Descend immediately when storms approach.", comment: "Step Detail")
        let _ = String(localized: "Assume the lightning crouch: squat on balls of feet, arms around knees.", comment: "Step Instruction")
        let _ = String(localized: "Minimize ground contact. Ground current from nearby strikes kills more people than direct hits. The crouch keeps you small and reduces conduction path.", comment: "Step Detail")
        let _ = String(localized: "Stay away from water, metal, and wet rock.", comment: "Step Instruction")
        let _ = String(localized: "Water conducts electricity. Metal (trekking poles, camp stoves) attracts nothing but conducts well. Ditch metal and move away from lakes/streams.", comment: "Step Detail")
        let _ = String(localized: "Groups should spread 50+ feet apart.", comment: "Step Instruction")
        let _ = String(localized: "Ground current from a nearby strike can hit everyone if huddled together. Spread out so a single strike doesn't incapacitate all members.", comment: "Step Detail")
        let _ = String(localized: "Mountain Altitude Management", comment: "Technique Name")
        let _ = String(localized: "Climb high, sleep low", comment: "Technique Subtitle")
        let _ = String(localized: "Above 8,000 ft: ascend no more than 1,000 ft per day.", comment: "Step Instruction")
        let _ = String(localized: "Your body needs time to increase red blood cell production. Ascending too fast outpaces adaptation.", comment: "Step Detail")
        let _ = String(localized: "Climb high, sleep low.", comment: "Step Instruction")
        let _ = String(localized: "It's OK to climb 2,000 ft during the day for acclimatization, but return to lower camp to sleep. Your body acclimatizes best during rest at lower altitudes.", comment: "Step Detail")
        let _ = String(localized: "Hydrate aggressively — 3-4 liters per day at altitude.", comment: "Step Instruction")
        let _ = String(localized: "Altitude increases fluid loss through respiration (drier air, faster breathing). Dehydration worsens altitude sickness.", comment: "Step Detail")
        let _ = String(localized: "Golden rule: if symptoms worsen, descend immediately.", comment: "Step Instruction")
        let _ = String(localized: "AMS → HACE or HAPE can progress in hours. Altitude illness has one treatment: lower altitude. Everything else is a stopgap.", comment: "Step Detail")
        let _ = String(localized: "Open Water Survival", comment: "Technique Name")
        let _ = String(localized: "Float, signal, conserve", comment: "Technique Subtitle")
        let _ = String(localized: "Ocean", comment: "Category")
        let _ = String(localized: "Stay with the vessel or debris as long as possible.", comment: "Step Instruction")
        let _ = String(localized: "A boat, even capsized, is visible to rescuers. You are nearly invisible in open water. Climb on any floating debris.", comment: "Step Detail")
        let _ = String(localized: "HELP position: Heat Escape Lessening Position.", comment: "Step Instruction")
        let _ = String(localized: "Cross arms over chest, pull knees to chest. This protects the three highest heat loss areas: head, armpits, groin. Reduces heat loss by 50%.", comment: "Step Detail")
        let _ = String(localized: "Signal with mirror, dye marker, whistle, or bright clothing.", comment: "Step Instruction")
        let _ = String(localized: "A signal mirror is visible for 50+ miles. Wave bright clothing. Use any dye to color the water around you for aerial detection.", comment: "Step Detail")
        let _ = String(localized: "Never drink seawater. Collect rain at every opportunity.", comment: "Step Instruction")
        let _ = String(localized: "Use any fabric, life raft surfaces, or clothing to channel rainwater into containers. Your survival depends entirely on fresh water.", comment: "Step Detail")
        let _ = String(localized: "Flash Flood Survival", comment: "Technique Name")
        let _ = String(localized: "Get to high ground NOW", comment: "Technique Subtitle")
        let _ = String(localized: "Flood", comment: "Category")
        let _ = String(localized: "Move to high ground immediately. Do not wait.", comment: "Step Instruction")
        let _ = String(localized: "Flash floods can wall up to 20 feet high and arrive within minutes of rainfall. If you hear roaring water, you have seconds.", comment: "Step Detail")
        let _ = String(localized: "Never cross flowing water above your ankles.", comment: "Step Instruction")
        let _ = String(localized: "6 inches of fast-moving water can knock you down. 12 inches can carry away a vehicle. The force of flowing water is massively underestimated.", comment: "Step Detail")
        let _ = String(localized: "If swept away: float on your back, feet downstream.", comment: "Step Instruction")
        let _ = String(localized: "Use your feet to push off obstacles. Do NOT try to stand up in moving water — foot entrapment is a leading cause of drowning.", comment: "Step Detail")
        let _ = String(localized: "Never camp in dry washes, canyons, or valley floors.", comment: "Step Instruction")
        let _ = String(localized: "Flash floods can originate from storms miles away with no local rain. A dry wash can become a raging river in 15 minutes.", comment: "Step Detail")
        let _ = String(localized: "Urban Disaster Survival", comment: "Technique Name")
        let _ = String(localized: "Earthquake, building collapse, civil unrest", comment: "Technique Subtitle")
        let _ = String(localized: "Urban", comment: "Category")
        let _ = String(localized: "Earthquake: DROP, COVER, HOLD ON.", comment: "Step Instruction")
        let _ = String(localized: "Under a sturdy desk or table. Away from windows and exterior walls. In bed: stay there, cover head with pillow. Doorways are NOT safer.", comment: "Step Detail")
        let _ = String(localized: "After shaking stops: check for gas leaks, structural damage.", comment: "Step Instruction")
        let _ = String(localized: "If you smell gas, open windows and leave. Do not use flames or electrical switches. Check for cracks in walls and foundation.", comment: "Step Detail")
        let _ = String(localized: "Building collapse: protect airways, tap on pipes to signal.", comment: "Step Instruction")
        let _ = String(localized: "Cover nose and mouth with fabric. Do not use matches (gas leaks). Tap SOS on pipes or walls — sound travels through structure. Conserve energy.", comment: "Step Detail")
        let _ = String(localized: "Civil unrest: stay indoors, fill bathtubs with water, secure doors.", comment: "Step Instruction")
        let _ = String(localized: "Water supply may be disrupted. Fill every container. Stay away from windows. Identify multiple exit routes from your building.", comment: "Step Detail")
        let _ = String(localized: "Swamp & Wetland Survival", comment: "Technique Name")
        let _ = String(localized: "Navigate insects, mud, and hidden dangers", comment: "Technique Subtitle")
        let _ = String(localized: "Swamp", comment: "Category")
        let _ = String(localized: "Test each step with a pole before committing weight.", comment: "Step Instruction")
        let _ = String(localized: "Probe ahead. If sinks more than knee-deep, reroute. Travel on game trails.", comment: "Step Detail")
        let _ = String(localized: "If stuck in mud: lean forward and swim/crawl out.", comment: "Step Instruction")
        let _ = String(localized: "Struggling creates suction. Lean forward to distribute weight. Remove pack first.", comment: "Step Detail")
        let _ = String(localized: "Protect against insects: mud coating, smoke, long sleeves.", comment: "Step Instruction")
        let _ = String(localized: "Swamp insects carry disease. Cover skin with mud. Stay near smoky fire.", comment: "Step Detail")
        let _ = String(localized: "Water is abundant but contaminated—always purify.", comment: "Step Instruction")
        let _ = String(localized: "Boil, filter, or use tablets. Never drink swamp water untreated.", comment: "Step Detail")
        let _ = String(localized: "Coastal & Tidal Survival", comment: "Technique Name")
        let _ = String(localized: "Tides, rip currents, shore foraging", comment: "Technique Subtitle")
        let _ = String(localized: "Learn tide cycle—changes every ~6 hours.", comment: "Step Instruction")
        let _ = String(localized: "Note high water debris line on beach. Camp ABOVE it.", comment: "Step Detail")
        let _ = String(localized: "Rip current: swim PARALLEL to shore, not against it.", comment: "Step Instruction")
        let _ = String(localized: "Rip currents pull straight out. Swim sideways until free.", comment: "Step Detail")
        let _ = String(localized: "Forage at low tide: tidal pools have shellfish, crabs, seaweed.", comment: "Step Instruction")
        let _ = String(localized: "Mussels, clams, limpets, snails—all edible when cooked.", comment: "Step Detail")
        let _ = String(localized: "Signal from headlands—most visible from sea and air.", comment: "Step Instruction")
        let _ = String(localized: "Build signal fires on high points. Lay SOS in rocks on beach.", comment: "Step Detail")
        let _ = String(localized: "Earthquake Survival", comment: "Technique Name")
        let _ = String(localized: "Drop, Cover, Hold On — then assess", comment: "Technique Subtitle")
        let _ = String(localized: "Disaster", comment: "Category")
        let _ = String(localized: "DROP to hands and knees. COVER under furniture. HOLD ON.", comment: "Step Instruction")
        let _ = String(localized: "Under desk or table. If nothing, interior wall. Cover head.", comment: "Step Detail")
        let _ = String(localized: "Outdoors: move to open area away from buildings and lines.", comment: "Step Instruction")
        let _ = String(localized: "Falling debris kills. Get away from walls and trees.", comment: "Step Detail")
        let _ = String(localized: "After shaking: expect aftershocks. Check for injuries.", comment: "Step Instruction")
        let _ = String(localized: "Aftershocks can be strong. Stay alert for hours.", comment: "Step Detail")
        let _ = String(localized: "Check for gas leaks, structural damage, fire hazards.", comment: "Step Instruction")
        let _ = String(localized: "Gas smell = leave immediately. No flames or switches.", comment: "Step Detail")
        let _ = String(localized: "Tornado Survival", comment: "Technique Name")
        let _ = String(localized: "Get underground or lowest interior room", comment: "Technique Subtitle")
        let _ = String(localized: "Get to lowest floor. Basement ideal. Interior room.", comment: "Step Instruction")
        let _ = String(localized: "Bathroom, closet, hallway. Stay away from windows.", comment: "Step Detail")
        let _ = String(localized: "Under sturdy furniture. Cover head with arms or mattress.", comment: "Step Instruction")
        let _ = String(localized: "Flying debris kills, not wind. Protect head and vitals.", comment: "Step Detail")
        let _ = String(localized: "Outdoors: lie flat in ditch, cover head.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT shelter under overpasses. Ditch is safer.", comment: "Step Detail")
        let _ = String(localized: "Vehicle: drive perpendicular to path or park, duck, seatbelt.", comment: "Step Instruction")
        let _ = String(localized: "Do not outrun. Park, duck below windows, cover with blanket.", comment: "Step Detail")
        let _ = String(localized: "Wildfire Survival", comment: "Technique Name")
        let _ = String(localized: "Escape downhill, into wind, to burned zones", comment: "Technique Subtitle")
        let _ = String(localized: "Move downhill and into the wind.", comment: "Step Instruction")
        let _ = String(localized: "Fire travels uphill faster. Already-burned areas are safe zones.", comment: "Step Detail")
        let _ = String(localized: "Cover mouth with wet cloth. Stay low.", comment: "Step Instruction")
        let _ = String(localized: "Smoke inhalation kills faster than burns. Crawl if thick.", comment: "Step Detail")
        let _ = String(localized: "Go to water, roads, cleared areas, or burned zones.", comment: "Step Instruction")
        let _ = String(localized: "Rivers, roads, parking lots are firebreaks.", comment: "Step Detail")
        let _ = String(localized: "Trapped: clear vegetation, lie face down in depression.", comment: "Step Instruction")
        let _ = String(localized: "Clear 10-foot radius. Lie face down. Breathe ground-level air.", comment: "Step Detail")
        let _ = String(localized: "Avalanche Survival", comment: "Technique Name")
        let _ = String(localized: "Swim, air pocket, conserve oxygen", comment: "Technique Subtitle")
        let _ = String(localized: "Snow", comment: "Category")
        let _ = String(localized: "If caught: swim aggressively to stay on surface.", comment: "Step Instruction")
        let _ = String(localized: "Backstroke motion. Ditch heavy gear—it drags you down.", comment: "Step Detail")
        let _ = String(localized: "As it slows: cup hands over face for air pocket.", comment: "Step Instruction")
        let _ = String(localized: "This is your lifeline. 15-30 minutes of air.", comment: "Step Detail")
        let _ = String(localized: "When stopped: spit to determine which way is up.", comment: "Step Instruction")
        let _ = String(localized: "Gravity pulls saliva down. Dig upward.", comment: "Step Detail")
        let _ = String(localized: "Push one arm up. Stay calm — panic uses 3x oxygen.", comment: "Step Instruction")
        let _ = String(localized: "If near surface, hand may break through for rescuers.", comment: "Step Detail")
        let _ = String(localized: "Quicksand Escape", comment: "Technique Name")
        let _ = String(localized: "You will NOT sink completely — stay calm", comment: "Technique Subtitle")
        let _ = String(localized: "Stop moving. Do NOT struggle or kick.", comment: "Step Instruction")
        let _ = String(localized: "Quicksand is denser than body. Max waist-deep. Struggling worsens.", comment: "Step Detail")
        let _ = String(localized: "Drop pack and heavy items.", comment: "Step Instruction")
        let _ = String(localized: "Extra weight pushes deeper.", comment: "Step Detail")
        let _ = String(localized: "Lean back slowly. Float on your back.", comment: "Step Instruction")
        let _ = String(localized: "Spread arms wide. Increases surface area.", comment: "Step Detail")
        let _ = String(localized: "Wiggle legs to break suction. Pull out one at a time.", comment: "Step Instruction")
        let _ = String(localized: "Small movements. Pull at angle, not straight up. Slow wins.", comment: "Step Detail")
        let _ = String(localized: "Lightning Safety", comment: "Technique Name")
        let _ = String(localized: "Get low, get small, avoid tall objects", comment: "Technique Subtitle")
        let _ = String(localized: "Get off ridgelines, peaks, high ground immediately.", comment: "Step Instruction")
        let _ = String(localized: "Lightning strikes highest point. Descend if possible.", comment: "Step Detail")
        let _ = String(localized: "Avoid tall trees, metal fences, water.", comment: "Step Instruction")
        let _ = String(localized: "All excellent conductors. Group of short trees safer than one tall.", comment: "Step Detail")
        let _ = String(localized: "Lightning crouch: balls of feet, heels together, squat, ears covered.", comment: "Step Instruction")
        let _ = String(localized: "Minimizes ground contact. Heels together routes current around body.", comment: "Step Detail")
        let _ = String(localized: "Strike victim is safe to touch. Begin CPR if needed.", comment: "Step Instruction")
        let _ = String(localized: "No charge remains. Check breathing and pulse immediately.", comment: "Step Detail")
        let _ = String(localized: "Tsunami Response", comment: "Technique Name")
        let _ = String(localized: "Recognize warning signs and reach high ground", comment: "Technique Subtitle")
        let _ = String(localized: "If you feel a strong earthquake near the coast, move to high ground immediately.", comment: "Step Instruction")
        let _ = String(localized: "Do not wait for official warnings. A strong coastal earthquake IS the warning. You may have only 10-15 minutes before the first wave.", comment: "Step Detail")
        let _ = String(localized: "Watch for natural warning signs: ocean suddenly pulling far from shore.", comment: "Step Instruction")
        let _ = String(localized: "If the ocean recedes dramatically, exposing the sea floor, a tsunami is incoming. This is the ocean 'drawing back' before the wave. RUN.", comment: "Step Detail")
        let _ = String(localized: "Move inland or to elevation above 100 feet. Go UP, not just away.", comment: "Step Instruction")
        let _ = String(localized: "Tsunamis can travel miles inland on flat ground. Elevation is your only protection. Upper floors of concrete buildings work if no high ground exists.", comment: "Step Detail")
        let _ = String(localized: "Stay at high ground for hours. Tsunamis come in multiple waves.", comment: "Step Instruction")
        let _ = String(localized: "The first wave is often NOT the largest. Waves can continue for 8-12 hours. Wait for official all-clear before returning to low ground.", comment: "Step Detail")
        let _ = String(localized: "Tornado Shelter Procedure", comment: "Technique Name")
        let _ = String(localized: "Protect yourself from tornado winds and debris", comment: "Technique Subtitle")
        let _ = String(localized: "Get to the lowest interior room away from windows.", comment: "Step Instruction")
        let _ = String(localized: "Basement is best. If no basement: interior closet, bathroom, or hallway on the lowest floor. Stay away from windows, doors, and exterior walls.", comment: "Step Detail")
        let _ = String(localized: "Get under a sturdy table and cover your head and neck.", comment: "Step Instruction")
        let _ = String(localized: "Flying debris causes most tornado injuries and deaths. Use pillows, mattresses, blankets, or your arms to protect your head and neck.", comment: "Step Detail")
        let _ = String(localized: "If outdoors, lie flat in the nearest ditch or low spot.", comment: "Step Instruction")
        let _ = String(localized: "Cover your head with your arms. Do NOT try to outrun a tornado in a car. If caught driving, park, keep your seatbelt on, and duck below window level.", comment: "Step Detail")
        let _ = String(localized: "After the tornado passes, watch for downed power lines and gas leaks.", comment: "Step Instruction")
        let _ = String(localized: "Do not enter damaged buildings. Smell for gas. Avoid downed wires. Check on neighbors, especially elderly and disabled individuals.", comment: "Step Detail")
        let _ = String(localized: "Wildfire Evacuation", comment: "Technique Name")
        let _ = String(localized: "Survive and escape an approaching wildfire", comment: "Technique Subtitle")
        let _ = String(localized: "Evacuate EARLY. Do not wait for mandatory evacuation orders.", comment: "Step Instruction")
        let _ = String(localized: "Wildfires can move 6-14 mph in forest and 25+ mph in grassland. Embers travel miles ahead of the fire front. By the time you see flames, you may have minutes.", comment: "Step Detail")
        let _ = String(localized: "Drive with headlights on, windows up, vents closed.", comment: "Step Instruction")
        let _ = String(localized: "Smoke reduces visibility to near zero. Drive slowly. If road is blocked, park in a clear area, turn off the engine, close all windows, lie on the floor below window level.", comment: "Step Detail")
        let _ = String(localized: "If trapped, find a body of water, cleared area, or road.", comment: "Step Instruction")
        let _ = String(localized: "Roads, parking lots, and rocky areas have no fuel for fire. A pond or stream provides protection. Lie face-down in shallow water or cover yourself with soil.", comment: "Step Detail")
        let _ = String(localized: "Cover exposed skin and breathe through a wet cloth.", comment: "Step Instruction")
        let _ = String(localized: "Radiant heat can burn skin without direct flame contact. A wet bandana over nose and mouth filters some smoke particles. Synthetic clothing melts — natural fibers are safer.", comment: "Step Detail")
        let _ = String(localized: "Earthquake: Indoor Response", comment: "Technique Name")
        let _ = String(localized: "Drop, cover, and hold on", comment: "Technique Subtitle")
        let _ = String(localized: "DROP to your hands and knees immediately.", comment: "Step Instruction")
        let _ = String(localized: "This position prevents you from being knocked down by shaking. It also allows you to crawl to cover. Do NOT try to run outside — falling debris is the greatest danger.", comment: "Step Detail")
        let _ = String(localized: "Take COVER under a sturdy desk or table. Protect your head and neck.", comment: "Step Instruction")
        let _ = String(localized: "If no table is available, get against an interior wall and cover your head with your arms. Stay away from windows, shelves, and heavy objects.", comment: "Step Detail")
        let _ = String(localized: "HOLD ON to your shelter until the shaking stops.", comment: "Step Instruction")
        let _ = String(localized: "Strong earthquakes can last 30+ seconds. Aftershocks may follow within minutes. If your cover moves, move with it. Stay covered.", comment: "Step Detail")
        let _ = String(localized: "After shaking stops, check for injuries and exit the building carefully.", comment: "Step Instruction")
        let _ = String(localized: "Use stairs, never elevators. Check for gas leaks. Be prepared for aftershocks. Turn off utilities if you suspect damage. Do not re-enter damaged buildings.", comment: "Step Detail")
        let _ = String(localized: "Earthquake: Outdoor Response", comment: "Technique Name")
        let _ = String(localized: "Stay in the open away from structures", comment: "Technique Subtitle")
        let _ = String(localized: "Move to an open area away from buildings, trees, and power lines.", comment: "Step Instruction")
        let _ = String(localized: "Building facades, glass, and bricks fall outward during earthquakes. Get at least one building-height away from structures.", comment: "Step Detail")
        let _ = String(localized: "Drop to the ground and protect your head.", comment: "Step Instruction")
        let _ = String(localized: "Even outdoors, debris can fly. Cover your head with your arms or any available protection. Stay low and stable.", comment: "Step Detail")
        let _ = String(localized: "If driving, pull over to a clear area. Stay in the car.", comment: "Step Instruction")
        let _ = String(localized: "Avoid stopping under bridges, overpasses, or near buildings. The car provides protection from falling debris. Set the parking brake.", comment: "Step Detail")
        let _ = String(localized: "Flash Flood Response", comment: "Technique Name")
        let _ = String(localized: "React to sudden rising water", comment: "Technique Subtitle")
        let _ = String(localized: "Move to higher ground immediately. Do not wait.", comment: "Step Instruction")
        let _ = String(localized: "Flash floods rise in minutes. Even 6 inches of fast-moving water can knock you down. Don't try to save belongings — save yourself.", comment: "Step Detail")
        let _ = String(localized: "Never drive through floodwater. Turn around.", comment: "Step Instruction")
        let _ = String(localized: "12 inches of water can carry away a car. You cannot judge water depth on a flooded road. Hidden washouts can drop your vehicle into deep water instantly.", comment: "Step Detail")
        let _ = String(localized: "If swept away, float on your back with feet downstream.", comment: "Step Instruction")
        let _ = String(localized: "Your feet absorb impacts from rocks and debris. Use your arms to steer toward the bank. Grab onto anything stable when possible.", comment: "Step Detail")
        let _ = String(localized: "After floodwaters recede, avoid walking through standing water.", comment: "Step Instruction")
        let _ = String(localized: "Standing floodwater contains sewage, chemicals, snakes, and may hide downed power lines or sinkholes. Contaminated water can cause serious illness.", comment: "Step Detail")
        let _ = String(localized: "Lightning Crouch Position", comment: "Technique Name")
        let _ = String(localized: "Minimize your profile during a lightning storm", comment: "Technique Subtitle")
        let _ = String(localized: "Get off high ground, ridges, and exposed areas.", comment: "Step Instruction")
        let _ = String(localized: "Lightning strikes the highest point. Get below the tree line if on a mountain. Avoid open fields, water, and isolated tall trees.", comment: "Step Detail")
        let _ = String(localized: "Crouch low with feet together, head tucked, hands over ears.", comment: "Step Instruction")
        let _ = String(localized: "The \"lightning crouch\": minimize contact with ground and height simultaneously. Feet together reduces the voltage difference across your body if ground current strikes nearby.", comment: "Step Detail")
        let _ = String(localized: "If in a group, spread out at least 50 feet apart.", comment: "Step Instruction")
        let _ = String(localized: "This prevents a single strike from hitting multiple people via ground current. If someone is struck, others can provide aid immediately.", comment: "Step Detail")
        let _ = String(localized: "Volcanic Ashfall Protection", comment: "Technique Name")
        let _ = String(localized: "Survive falling volcanic ash and debris", comment: "Technique Subtitle")
        let _ = String(localized: "Get indoors and seal windows and doors.", comment: "Step Instruction")
        let _ = String(localized: "Volcanic ash is not like wood ash — it's pulverized rock and glass. Breathing it causes severe lung damage. Seal gaps with wet towels or tape.", comment: "Step Detail")
        let _ = String(localized: "Wear an N95 mask or breathe through a damp cloth if outdoors.", comment: "Step Instruction")
        let _ = String(localized: "Ash particles are tiny and razor-sharp. They slice lung tissue. Any filtration is better than none. Goggles protect eyes from abrasion.", comment: "Step Detail")
        let _ = String(localized: "Clear ash from roofs — wet ash can collapse structures.", comment: "Step Instruction")
        let _ = String(localized: "Volcanic ash is extremely heavy, especially when wet. As little as 4 inches of wet ash can collapse a roof. Remove it from the roof when safe to do so.", comment: "Step Detail")
        let _ = String(localized: "Avoid driving. Ash destroys engines and blocks visibility.", comment: "Step Instruction")
        let _ = String(localized: "Ash clogs air filters, abrades moving parts, and turns roads into slippery surfaces. Drive only if evacuating, at very low speed with lights on.", comment: "Step Detail")
        let _ = String(localized: "Jungle Movement & Navigation", comment: "Technique Name")
        let _ = String(localized: "Navigate dense tropical forest without trails", comment: "Technique Subtitle")
        let _ = String(localized: "Tropical", comment: "Category")
        let _ = String(localized: "Follow streams and rivers — they're natural highways in dense jungle.", comment: "Step Instruction")
        let _ = String(localized: "Dense jungle off-trail movement is ~0.5 miles/hour. Along waterways: 1-2 miles/hour. Streams lead to rivers, rivers lead to settlements. Stay near the bank, not in the water (parasites, current).", comment: "Step Detail")
        let _ = String(localized: "Use a machete or heavy stick to probe ahead. Watch for snakes.", comment: "Step Instruction")
        let _ = String(localized: "Prod vegetation before stepping. Many venomous snakes are camouflaged in leaf litter. Step ON logs, not over them — snakes rest on the far side. Always look before grabbing branches or vines.", comment: "Step Detail")
        let _ = String(localized: "Travel early morning and late afternoon. Rest during midday heat.", comment: "Step Instruction")
        let _ = String(localized: "Midday jungle heat + humidity = dangerous core temperature rise. Travel 0600-1000 and 1500-1800. Rest during the hottest hours. Dehydration rate in tropical jungle: 1-2 liters per hour of heavy movement.", comment: "Step Detail")
        let _ = String(localized: "Swamp Navigation & Safety", comment: "Technique Name")
        let _ = String(localized: "Move safely through wetland environments", comment: "Technique Subtitle")
        let _ = String(localized: "Wetland", comment: "Category")
        let _ = String(localized: "Test ground before stepping. Use a long pole to probe depth and firmness.", comment: "Step Instruction")
        let _ = String(localized: "Swamp mud can be waist-deep. Probe every step with a 6-foot pole. Solid ground often follows tree root systems. Step on root mats when possible. If you start sinking, lean forward and 'swim' to firmer ground.", comment: "Step Detail")
        let _ = String(localized: "Follow animal trails — they use the firmest paths.", comment: "Step Instruction")
        let _ = String(localized: "Deer, hogs, and other animals know the solid ground. Follow their trails. Animal trails also lead to water sources and higher ground. If a trail dead-ends at water, look for where it resumes on the other side.", comment: "Step Detail")
        let _ = String(localized: "Protect against mosquitoes, leeches, and waterborne parasites continuously.", comment: "Step Instruction")
        let _ = String(localized: "Swamp hazards: mosquitoes (malaria, dengue), leeches (infection risk), parasitic worms in water (enter through skin). Cover all exposed skin. Apply mud as insect barrier. Check for leeches every hour.", comment: "Step Detail")
        let _ = String(localized: "High Altitude Sickness Management", comment: "Technique Name")
        let _ = String(localized: "Recognize and treat altitude-related illness", comment: "Technique Subtitle")
        let _ = String(localized: "Recognize symptoms: headache, nausea, fatigue, dizziness above 8,000 feet.", comment: "Step Instruction")
        let _ = String(localized: "Acute Mountain Sickness (AMS) affects most people above 8,000 feet. Symptoms start 6-12 hours after ascending. The ONLY reliable cure is descending. Do NOT ignore symptoms — AMS can progress to fatal brain or lung swelling.", comment: "Step Detail")
        let _ = String(localized: "Descend immediately if symptoms worsen or confusion develops.", comment: "Step Instruction")
        let _ = String(localized: "Golden rule: if symptoms get worse at the same altitude, DESCEND. Even 1,000 feet of descent provides significant relief. HACE (brain swelling) and HAPE (lung fluid) kill within hours if untreated.", comment: "Step Detail")
        let _ = String(localized: "Climb high, sleep low. Ascend no more than 1,000 feet per day above 10,000 feet.", comment: "Step Instruction")
        let _ = String(localized: "Acclimatization takes 1-3 days per 1,000 feet. You can climb higher during the day but should sleep at a lower elevation. Hydrate aggressively — dehydration accelerates AMS. Avoid alcohol and sleeping pills.", comment: "Step Detail")
        let _ = String(localized: "Desert Night Travel", comment: "Technique Name")
        let _ = String(localized: "Travel at night to avoid dangerous daytime heat", comment: "Technique Subtitle")
        let _ = String(localized: "Move between sunset and sunrise. Rest during daylight in shade.", comment: "Step Instruction")
        let _ = String(localized: "Desert day temperatures can exceed 130°F. Night temperatures may drop to 40°F. You lose 0.5-1 liter of water per hour walking in day heat vs. 0.25 liters at night. Night travel doubles your range on the same water.", comment: "Step Detail")
        let _ = String(localized: "Navigate by stars, moon shadow, or pre-set landmarks visible in moonlight.", comment: "Step Instruction")
        let _ = String(localized: "Before dark, identify your direction and noting landmarks. Walk toward a star (re-check every 15 minutes as stars shift). Full moon provides enough light to navigate safely. New moon requires extreme caution.", comment: "Step Detail")
        let _ = String(localized: "Watch for temperature extremes: hypothermia is a real desert risk at night.", comment: "Step Instruction")
        let _ = String(localized: "Desert temperature swings of 60-80°F between day and night are common. Dress in layers. The same sun protection worn by day traps warmth at night. Start walking to generate body heat if cold.", comment: "Step Detail")
        let _ = String(localized: "Coastal Storm Shelter Strategy", comment: "Technique Name")
        let _ = String(localized: "Survive hurricanes, typhoons, and coastal storms", comment: "Technique Subtitle")
        let _ = String(localized: "Coastal", comment: "Category")
        let _ = String(localized: "Get to high ground immediately. Storm surge kills more than wind.", comment: "Step Instruction")
        let _ = String(localized: "Storm surge can push seawater 20+ feet above normal. Move to ground at least 30 feet above sea level and 2 miles from coast. Storm surge arrives fast — within minutes. Don't wait for official warnings.", comment: "Step Detail")
        let _ = String(localized: "Shelter in the strongest structure available. Interior rooms, lowest floor.", comment: "Step Instruction")
        let _ = String(localized: "Avoid windows. Interior rooms without exterior walls. Bathroom is often strongest (small room, plumbing reinforcement). If in open, find a ravine or depression on the lee side of a hill.", comment: "Step Detail")
        let _ = String(localized: "After the storm: beware downed power lines, contaminated water, and unstable structures.", comment: "Step Instruction")
        let _ = String(localized: "Post-storm drowning in flood water is common. Electricity in standing water is invisible and lethal. Don't drink tap water until cleared. Structural damage may cause delayed collapse. Stay alert for 48+ hours.", comment: "Step Detail")
        let _ = String(localized: "Cave Shelter & Safety", comment: "Technique Name")
        let _ = String(localized: "Use caves for shelter while avoiding their hazards", comment: "Technique Subtitle")
        let _ = String(localized: "Underground", comment: "Category")
        let _ = String(localized: "Check for animal inhabitants before entering. Look for tracks, droppings, bones.", comment: "Step Instruction")
        let _ = String(localized: "Bears, big cats, snakes, and bats use caves. Fresh droppings = occupied. Strong musky smell = recent large animal. Throw rocks inside and listen. Never enter a cave that smells of ammonia (bat guano — histoplasmosis risk).", comment: "Step Detail")
        let _ = String(localized: "Check airflow. Stale or foul air means poor ventilation — don't go deep.", comment: "Step Instruction")
        let _ = String(localized: "Caves can accumulate CO2, radon, and methane. If a flame burns dim or goes out, air is poor. Stay near the entrance where airflow is good. Never build a fire deep in a cave — smoke accumulation is lethal.", comment: "Step Detail")
        let _ = String(localized: "Build fire near the entrance, not inside. Use cave for wind protection only.", comment: "Step Instruction")
        let _ = String(localized: "Fire at cave mouth provides warmth without smoke buildup. The cave walls reflect heat. Sleep between fire and back wall. Mark your entrance clearly if exploring deeper — cave disorientation is common and deadly.", comment: "Step Detail")
        let _ = String(localized: "Recognize and escape flash flood danger", comment: "Technique Subtitle")
        let _ = String(localized: "All Environments", comment: "Category")
        let _ = String(localized: "NEVER camp in dry riverbeds, narrow canyons, or at the base of slopes.", comment: "Step Instruction")
        let _ = String(localized: "Flash floods arrive with little warning. A dry wash can fill to 10 feet deep in minutes from rain miles away that you can't even see. If you hear roaring upstream, move to high ground IMMEDIATELY.", comment: "Step Detail")
        let _ = String(localized: "Move perpendicular to the flood path — go UP, not downstream.", comment: "Step Instruction")
        let _ = String(localized: "Don't try to outrun a flood downstream — water is faster than you. Move sideways and uphill. Even 10-20 feet of elevation gain can save your life. 6 inches of moving water can knock you down.", comment: "Step Detail")
        let _ = String(localized: "If caught in water, do NOT try to stand. Float on your back feet-first.", comment: "Step Instruction")
        let _ = String(localized: "Standing in floodwater risks foot entrapment (getting stuck between underwater rocks). Float on your back, feet downstream to fend off obstacles. Grab onto anything stable (tree, rock) when possible.", comment: "Step Detail")
        let _ = String(localized: "Lightning Safety Protocol", comment: "Technique Name")
        let _ = String(localized: "Minimize lightning strike risk during thunderstorms", comment: "Technique Subtitle")
        let _ = String(localized: "30-30 Rule: if thunder follows lightning in less than 30 seconds, seek shelter.", comment: "Step Instruction")
        let _ = String(localized: "Each 5-second count between flash and thunder = 1 mile distance. 30 seconds = 6 miles = danger zone. Lightning can strike 10+ miles from its parent cloud. If you can hear thunder, you can be struck.", comment: "Step Detail")
        let _ = String(localized: "Avoid: tall trees, hilltops, open fields, water, metal objects.", comment: "Step Instruction")
        let _ = String(localized: "Lightning hits the tallest object. Don't BE the tallest object. Avoid isolated trees — seek a uniform stand of short trees. Get off ridgelines. Leave water immediately. Remove metal frame backpacks.", comment: "Step Detail")
        let _ = String(localized: "Lightning crouch: squat low, feet together, hands on knees, head down.", comment: "Step Instruction")
        let _ = String(localized: "If caught in the open: make yourself as small as possible while minimizing ground contact. Feet together reduces ground current risk. Don't lie flat — it increases ground current exposure. Space group members 50 feet apart.", comment: "Step Detail")
        let _ = String(localized: "Sandstorm Shelter-in-Place", comment: "Technique Name")
        let _ = String(localized: "Protect yourself during a desert sandstorm", comment: "Technique Subtitle")
        let _ = String(localized: "Turn your back to the wind. Cover nose and mouth immediately.", comment: "Step Instruction")
        let _ = String(localized: "Sand particles cause severe lung damage. Wrap cloth tightly over nose and mouth — breathe through the fabric. Cover eyes completely — sand abrasion can blind you. Goggles or sunglasses help but wrap with cloth too.", comment: "Step Detail")
        let _ = String(localized: "Get low. Find the lee side of a large rock, dune, or vehicle.", comment: "Step Instruction")
        let _ = String(localized: "Sand concentration is highest at 1-3 feet off the ground in moderate storms. Below that, and above 6 feet, concentration drops. Get behind a windbreak and sit with your back to the wind.", comment: "Step Detail")
        let _ = String(localized: "STAY PUT until the storm passes. Mark your direction before visibility drops.", comment: "Step Instruction")
        let _ = String(localized: "Sandstorms reduce visibility to zero. Walking blind in desert = circling, falling into gullies, or walking the wrong direction. Before the storm hits, note your compass bearing and direction to shelter. Then wait it out.", comment: "Step Detail")
        let _ = String(localized: "Tundra & Arctic Travel", comment: "Technique Name")
        let _ = String(localized: "Move safely in flat, featureless arctic environments", comment: "Technique Subtitle")
        let _ = String(localized: "Navigate by wind direction — prevailing winds are the most reliable compass in featureless terrain.", comment: "Step Instruction")
        let _ = String(localized: "Snow drifts, sastrugi (wind ridges), and vegetation lean indicate prevailing wind direction. Once established, use wind angle to maintain a bearing. Sun position helps when visible but arctic sun angles are extreme.", comment: "Step Detail")
        let _ = String(localized: "Avoid thin ice: dark ice, snow-covered ice, ice near current or outflows.", comment: "Step Instruction")
        let _ = String(localized: "Clear blue ice 4+ inches thick supports a person. White/opaque ice is weaker. Snow-covered ice hides thickness. Stream inlets, outlets, and narrows have thinner ice. Spread your weight if unsure — crawl.", comment: "Step Detail")
        let _ = String(localized: "Build snow walls or dig into snowdrifts for emergency shelter.", comment: "Step Instruction")
        let _ = String(localized: "Wind chill is the primary killer in tundra. A snow wall reduces wind by 70%. A snow trench takes 30 minutes to dig and provides immediate wind protection. Block the entrance and body heat warms the space above freezing.", comment: "Step Detail")
        let _ = String(localized: "Tropical Disease Prevention", comment: "Technique Name")
        let _ = String(localized: "Prevent malaria, dengue, and other tropical infections", comment: "Technique Subtitle")
        let _ = String(localized: "Prevent mosquito bites: cover skin, use smoke, sleep under netting or cover.", comment: "Step Instruction")
        let _ = String(localized: "Malaria and dengue are transmitted by mosquitoes. Mosquitoes are most active at dawn and dusk. Burn smoky fires near sleeping area. Smear mud on exposed skin. Tuck pants into socks, sleeves into gloves.", comment: "Step Detail")
        let _ = String(localized: "Purify ALL water. Don't wade barefoot. Cover all wounds.", comment: "Step Instruction")
        let _ = String(localized: "Tropical parasites enter through skin (schistosomiasis), mouth (giardia, ameba), and wounds (tropical ulcers). Boil all water. Wear foot covering in water. Any wound, however small, must be cleaned and covered — tropical infection is aggressive.", comment: "Step Detail")
        let _ = String(localized: "Watch for fever, shaking chills, or progressive wound redness — these are emergencies.", comment: "Step Instruction")
        let _ = String(localized: "Malaria symptoms: cyclical fever and chills starting 7-30 days after bite. Untreated falciparum malaria can kill in 24-48 hours. Red streaks from a wound = spreading infection. Both require evacuation to medical care.", comment: "Step Detail")
        let _ = String(localized: "Wildfire Entrapment Survival", comment: "Technique Name")
        let _ = String(localized: "Survive when wildfire cuts off your escape", comment: "Technique Subtitle")
        let _ = String(localized: "Move to the largest burned area (black), a road, water body, or rocky area.", comment: "Step Instruction")
        let _ = String(localized: "Already-burned areas won't burn again. Large clearings and rock fields have no fuel. Water bodies provide heat protection. Roads create fuel breaks. Running uphill from fire is deadly — fire travels uphill 4x faster than on flat ground.", comment: "Step Detail")
        let _ = String(localized: "If trapped: lie face-down in a depression, cover exposed skin.", comment: "Step Instruction")
        let _ = String(localized: "Clear vegetation around you in a 10-foot radius if possible. Lie in the lowest spot available. Cover your body with dirt. Breathe through cloth near the ground — superheated air rises. The fire front passes in 1-3 minutes.", comment: "Step Detail")
        let _ = String(localized: "After the fire passes: watch for falling trees, hidden hot spots, and unstable ground.", comment: "Step Instruction")
        let _ = String(localized: "Burned trees fall without warning. Root systems burn underground creating hidden holes. Ash conceals hot spots that can cause severe burns. Move carefully with a probing stick. Watch for rolling rocks on burned slopes.", comment: "Step Detail")
        let _ = String(localized: "Hurricane Survival", comment: "Technique Name")
        let _ = String(localized: "Survive high winds and storm surge", comment: "Technique Subtitle")
        let _ = String(localized: "Secure all windows/doors. Create a 'safe room' in interior.", comment: "Step Instruction")
        let _ = String(localized: "Board up windows if time. If not, stay in windowless room. Mattress over head protects from flying glass.", comment: "Step Detail")
        let _ = String(localized: "Fill bathtubs and containers with water BEFORE storm hits.", comment: "Step Instruction")
        let _ = String(localized: "Municipal water often fails or gets contaminated. You need 1 gallon/person/day for at least 3 days.", comment: "Step Detail")
        let _ = String(localized: "Stay inside during the 'eye' — calm is temporary.", comment: "Step Instruction")
        let _ = String(localized: "The eye passes in 10-30 mins. Winds return suddenly from opposite direction with full force. Don't go out.", comment: "Step Detail")
        let _ = String(localized: "Blizzard Survival", comment: "Technique Name")
        let _ = String(localized: "Survive whiteout and extreme cold", comment: "Technique Subtitle")
        let _ = String(localized: "Shelter immediately. Do NOT try to walk for help in whiteout.", comment: "Step Instruction")
        let _ = String(localized: "You will get lost within 50 feet. Disorientation is total. Dig a snow trench if no structure available.", comment: "Step Detail")
        let _ = String(localized: "If in car: run engine 10 mins/hour only. Clear exhaust pipe.", comment: "Step Instruction")
        let _ = String(localized: "Blocked exhaust kills via CO poisoning. Crack window slightly for air. Stay with vehicle.", comment: "Step Detail")
        let _ = String(localized: "Exercise extremities to keep blood flowing. Don't sleep if shivering stops.", comment: "Step Instruction")
        let _ = String(localized: " stopping shivering is a sign of severe hypothermia. Move fingers/toes. Huddle for warmth.", comment: "Step Detail")
        let _ = String(localized: "Volcanic Ash Protection", comment: "Technique Name")
        let _ = String(localized: "Breathing safety during eruption", comment: "Technique Subtitle")
        let _ = String(localized: "Cover mouth/nose with N95 mask or wet cloth.", comment: "Step Instruction")
        let _ = String(localized: "Volcanic ash is jagged glass, not dust. It shreds lungs. Wet cloth traps particles better than dry.", comment: "Step Detail")
        let _ = String(localized: "Wear goggles. Do NOT wear contact lenses.", comment: "Step Instruction")
        let _ = String(localized: "Ash scratches corneas. Contacts trap ash against eye.", comment: "Step Detail")
        let _ = String(localized: "Seal shelter. Tape doors/windows. Damp towels under doors.", comment: "Step Instruction")
        let _ = String(localized: "Ash is heavy and fine. It enters everywhere. Don't run AC/fans.", comment: "Step Detail")
        let _ = String(localized: "Lava & Pyroclastic Flow", comment: "Technique Name")
        let _ = String(localized: "Evacuation from eruption zone", comment: "Technique Subtitle")
        let _ = String(localized: "Evacuate laterally (perpendicular) to lava flow.", comment: "Step Instruction")
        let _ = String(localized: "Lava follows gravity (valleys). Move to ridges/high ground. Don't try to outrun pyroclastic flow (travels 100mph+).", comment: "Step Detail")
        let _ = String(localized: "Avoid low-lying areas (valleys, riverbeds).", comment: "Step Instruction")
        let _ = String(localized: "Lahars (mudflows) and lava channel into low spots. Stay high.", comment: "Step Detail")
        let _ = String(localized: "Protect against heat radiation. Cover exposed skin.", comment: "Step Instruction")
        let _ = String(localized: "Radiant heat can burn from distance. Thick clothing (cotton/wool) protects against heat pulse.", comment: "Step Detail")
        let _ = String(localized: "Tsunami Survival", comment: "Technique Name")
        let _ = String(localized: "Survive the wave train", comment: "Technique Subtitle")
        let _ = String(localized: "If you feel a quake or see water recede: RUN TO HIGH GROUND.", comment: "Step Instruction")
        let _ = String(localized: "Don't wait for sirens. Water sucking out to sea = wave incoming in minutes. Go 100ft high or 2 miles inland.", comment: "Step Detail")
        let _ = String(localized: "If caught: climb a strong concrete building or tree.", comment: "Step Instruction")
        let _ = String(localized: "Wood houses float/crush. Reinforced concrete stands. Climb to 3rd floor or roof.", comment: "Step Detail")
        let _ = String(localized: "Expect multiple waves. The first is rarely the largest.", comment: "Step Instruction")
        let _ = String(localized: "Waves arrive 10-60 mins apart. Stay high for HOURS. Water withdraws violently between waves.", comment: "Step Detail")
        let _ = String(localized: "Extreme Heat Management", comment: "Technique Name")
        let _ = String(localized: "Prevent heat stroke in emergencies", comment: "Technique Subtitle")
        let _ = String(localized: "Stop all activity. Find or build shade.", comment: "Step Instruction")
        let _ = String(localized: "Direct sun adds 15-20°F to heat load. Dig to cooler soil if necessary.", comment: "Step Detail")
        let _ = String(localized: "Wet skin/clothes if water available (not drinking water).", comment: "Step Instruction")
        let _ = String(localized: "Evaporation cools. Use urine/bad water on clothes (not skin if broken) to cool via evaporation.", comment: "Step Detail")
        let _ = String(localized: "Elevate feet. Loosen clothing. Fan yourself.", comment: "Step Instruction")
        let _ = String(localized: "Promotes circulation. Heat exhaustion leads to stroke quickly. Monitor urine color (dark = danger).", comment: "Step Detail")
        let _ = String(localized: "Escaping Rip Current", comment: "Technique Name")
        let _ = String(localized: "Swim out of ocean currents", comment: "Technique Subtitle")
        let _ = String(localized: "Water", comment: "Category")
        let _ = String(localized: "Do NOT swim against the current (toward shore). You will tire and drown.", comment: "Step Instruction")
        let _ = String(localized: "Rips move 5-8 mph. Olympic swimmers can't beat them. conserve energy.", comment: "Step Detail")
        let _ = String(localized: "Swim parallel to shore (sideways) until out of the pull.", comment: "Step Instruction")
        let _ = String(localized: "Rips are narrow (20-100 ft). Swim sideways to escape the fast water channel.", comment: "Step Detail")
        let _ = String(localized: "When current releases you, swim diagonally to shore.", comment: "Step Instruction")
        let _ = String(localized: "Waves help push you in. If tired, float to recover.", comment: "Step Detail")
        let _ = String(localized: "Self-Rescue from Ice", comment: "Technique Name")
        let _ = String(localized: "Escape after falling through ice", comment: "Technique Subtitle")
        let _ = String(localized: "Winter", comment: "Category")
        let _ = String(localized: "Control breathing. Don't panic (Cold Shock Response).", comment: "Step Instruction")
        let _ = String(localized: "You have 1 minute to control breathing, 10 minutes of movement before muscles fail. Use 1 minute to calm down.", comment: "Step Detail")
        let _ = String(localized: "Kick feet up to float horizontal. Don't climb vertical.", comment: "Step Instruction")
        let _ = String(localized: "Horizontal position distributes weight. Kick hard to push chest onto ice edge.", comment: "Step Detail")
        let _ = String(localized: "Pull with elbows/picks, kick like a seal. Roll away.", comment: "Step Instruction")
        let _ = String(localized: "Once on ice, ROLL away. Do not stand up until on thick ice/land.", comment: "Step Detail")
        let _ = String(localized: "Black Bear Encounter", comment: "Technique Name")
        let _ = String(localized: "Dealing with black bears", comment: "Technique Subtitle")
        let _ = String(localized: "Animal", comment: "Category")
        let _ = String(localized: "Stand your ground. Make noise. Look big.", comment: "Step Instruction")
        let _ = String(localized: "Black bears are timid. Wave arms. Yell 'Hey Bear'. Do NOT run.", comment: "Step Detail")
        let _ = String(localized: "If it charges: stand ground (bluff charge).", comment: "Step Instruction")
        let _ = String(localized: "They often stop feet away. Spray bear spray if within 30 ft.", comment: "Step Detail")
        let _ = String(localized: "If it attacks: FIGHT BACK vigorously.", comment: "Step Instruction")
        let _ = String(localized: "Punch eyes/nose. Use rocks/sticks. Do NOT play dead with black bears.", comment: "Step Detail")
        let _ = String(localized: "Grizzly/Brown Bear Encounter", comment: "Technique Name")
        let _ = String(localized: "Dealing with brown bears", comment: "Technique Subtitle")
        let _ = String(localized: "Do NOT run. Back away slowly. Speak calmly.", comment: "Step Instruction")
        let _ = String(localized: "Don't look in eyes (aggression). Show you are human, not prey. Prepare spray.", comment: "Step Detail")
        let _ = String(localized: "If it charges: STAND GROUND. Deploy spray.", comment: "Step Instruction")
        let _ = String(localized: "Running triggers predatory chase response. You cannot outrun a bear (35mph).", comment: "Step Detail")
        let _ = String(localized: "If it makes contact: PLAY DEAD.", comment: "Step Instruction")
        let _ = String(localized: "Drop to stomach. Hands clasped behind neck. Spread legs (harder to flip). Stay still until bear leaves (20+ mins).", comment: "Step Detail")
        let _ = String(localized: "Polar Bear Encounter", comment: "Technique Name")
        let _ = String(localized: "The only predator that actively hunts humans", comment: "Technique Subtitle")
        let _ = String(localized: "Deter immediately. Flare, warning shot, noise.", comment: "Step Instruction")
        let _ = String(localized: "Polar bears are curious/predatory. They don't bluff. If it comes toward you, it intends to eat you.", comment: "Step Detail")
        let _ = String(localized: "Fight for your life. Use any weapon.", comment: "Step Instruction")
        let _ = String(localized: "Playing dead DOES NOT WORK — they will eat you. Lethal force is usually required.", comment: "Step Detail")
        let _ = String(localized: "Cougar/Mountain Lion", comment: "Technique Name")
        let _ = String(localized: "Stalking predator defense", comment: "Technique Subtitle")
        let _ = String(localized: "Maintain eye contact. Do NOT turn back. Do NOT run.", comment: "Step Instruction")
        let _ = String(localized: "Cougars attack from behind/ambush. Stare them down.", comment: "Step Detail")
        let _ = String(localized: "Look big. Raise jacket/arms. Pick up children.", comment: "Step Instruction")
        let _ = String(localized: "Convince cat you are a threat, not prey. Yell loudly.", comment: "Step Detail")
