        let _ = String(localized: "Maintain eye contact. Rotate as it circles.", comment: "Step Instruction")
        let _ = String(localized: "Sharks ambush. Knowing it's seen deters attack.", comment: "Step Detail")
        let _ = String(localized: "Slow, rhythmic movements. Do not splash.", comment: "Step Instruction")
