        let _ = String(localized: "Neutralize venom", comment: "Technique Subtitle")
        let _ = String(localized: "Rinse with VINEGAR (or sea water). NOT fresh water.", comment: "Step Instruction")
        let _ = String(localized: "Fresh water triggers unfired nematocysts (stingers). Vinegar neutralizes them. Urine is a myth (often ineffective).", comment: "Step Detail")
