        let _ = String(localized: "Hot water soak (110°F) for pain.", comment: "Step Instruction")
        let _ = String(localized: "Heat breaks down protein venom. 20-45 minutes.", comment: "Step Detail")
        let _ = String(localized: "Monitoring Wildfire", comment: "Technique Name")
        let _ = String(localized: "Watch for wind shifts and embers", comment: "Technique Subtitle")
        let _ = String(localized: "If fire is downwind: monitor wind direction constantly.", comment: "Step Instruction")
        let _ = String(localized: "Wind shifts are the #1 killer. If wind changes 180 degrees, the flank becomes the head and you are in the path.", comment: "Step Detail")
        let _ = String(localized: "Clear 30 feet of flammable material around your location.", comment: "Step Instruction")
        let _ = String(localized: "Remove dry grass, wood piles, and furniture. Create a defensible space even if not evacuating yet.", comment: "Step Detail")
        let _ = String(localized: "Watch for spot fires started by embers.", comment: "Step Instruction")
        let _ = String(localized: "Embers can travel up to a mile ahead of the fire front. Patrol your area and extinguish small starts immediately.", comment: "Step Detail")
        let _ = String(localized: "Be ready to evacuate instantly if smoke thickens or wind changes.", comment: "Step Instruction")
        let _ = String(localized: "Have your 'go-bag' in the car. Back the car into the driveway for fast exit.", comment: "Step Detail")
        let _ = String(localized: "Trapped in Vehicle (Wildfire)", comment: "Technique Name")
        let _ = String(localized: "Last resort shelter implementation", comment: "Technique Subtitle")
        let _ = String(localized: "Park in a clear area, away from heavy vegetation.", comment: "Step Instruction")
        let _ = String(localized: "Find a rocky outcrop, plowed field, or previously burned area. Avoid parking under trees or power lines.", comment: "Step Detail")
        let _ = String(localized: "Close all windows and vents. Turn on AC to 'recirculate'.", comment: "Step Instruction")
        let _ = String(localized: "Keep smoke out. Recirculate mode prevents outside smoke from being drawn in.", comment: "Step Detail")
        let _ = String(localized: "Lie on the floor below window level. Cover with wool blanket.", comment: "Step Instruction")
        let _ = String(localized: "Radiant heat passes through glass. The floor is the coolest spot. Wool protects against heat.", comment: "Step Detail")
        let _ = String(localized: "Wait for the fire front to pass. Do not exit until safe.", comment: "Step Instruction")
        let _ = String(localized: "The main fire front often passes in 5-10 minutes. The car body protects you from radiant heat that would kill you outside.", comment: "Step Detail")
        let _ = String(localized: "Mobile Home Tornado Protocol", comment: "Technique Name")
        let _ = String(localized: "Get out immediately", comment: "Technique Subtitle")
        let _ = String(localized: "Abandon the mobile home immediately.", comment: "Step Instruction")
        let _ = String(localized: "Mobile homes offer zero protection against tornadoes. They are often destroyed even by weak tornadoes. Do not stay.", comment: "Step Detail")
        let _ = String(localized: "Seek a storm shelter or sturdy building nearby.", comment: "Step Instruction")
        let _ = String(localized: "A neighbor's house with a basement or designated community shelter is safer.", comment: "Step Detail")
        let _ = String(localized: "If no shelter: lie flat in a low-lying ditch or depression.", comment: "Step Instruction")
        let _ = String(localized: "Cover your head with your hands. Protect against flying debris, which causes most injuries.", comment: "Step Detail")
        let _ = String(localized: "Move away from the mobile home (debris hazard).", comment: "Step Instruction")
        let _ = String(localized: "Debris from the mobile home itself will become projectiles. Get distance.", comment: "Step Detail")
        let _ = String(localized: "Tornado Ditch Shelter", comment: "Technique Name")
        let _ = String(localized: "Last resort outdoor protection", comment: "Technique Subtitle")
        let _ = String(localized: "Find a low spot: ditch, ravine, or depression.", comment: "Step Instruction")
        let _ = String(localized: "You want to be below the level of the wind-blown debris. Gravity is your shield.", comment: "Step Detail")
        let _ = String(localized: "Lie face down, hands covering head and neck.", comment: "Step Instruction")
        let _ = String(localized: "Protect your skull and spine. Minimize your profile.", comment: "Step Detail")
        let _ = String(localized: "Stay away from trees, cars, and poles.", comment: "Step Instruction")
        let _ = String(localized: "These can be blown onto you. Open ground is safer than near vertical hazards.", comment: "Step Detail")
        let _ = String(localized: "Watch for flash flooding in the ditch.", comment: "Step Instruction")
        let _ = String(localized: "Tornadoes come with heavy rain. Be ready to move if the ditch fills rapidly with water.", comment: "Step Detail")
        let _ = String(localized: "Driving Near Tornado", comment: "Technique Name")
        let _ = String(localized: "Assess path and evade", comment: "Technique Subtitle")
        let _ = String(localized: "Determine the tornado's path relative to you.", comment: "Step Instruction")
        let _ = String(localized: "If it's not moving left or right, it's moving toward you. Tornadoes usually move SW to NE.", comment: "Step Detail")
        let _ = String(localized: "Drive at a right angle to the tornado's path.", comment: "Step Instruction")
        let _ = String(localized: "Do not try to outrun it straight on. Move sideways to get out of the 'bear's cage'.", comment: "Step Detail")
        let _ = String(localized: "If imminent impact: abandon car for a ditch.", comment: "Step Instruction")
        let _ = String(localized: "Cars are death traps in tornadoes (tossed like toys). If you can't drive away, get low in a ditch.", comment: "Step Detail")
        let _ = String(localized: "Do NOT hide under an overpass.", comment: "Step Instruction")
        let _ = String(localized: "Winds accelerate under bridges (Venturi effect). Debris is channeled there. It is a very dangerous spot.", comment: "Step Detail")
        let _ = String(localized: "Black Bear Avoidance", comment: "Technique Name")
        let _ = String(localized: "Intimidate and back away", comment: "Technique Subtitle")
        let _ = String(localized: "Make yourself look large.", comment: "Step Instruction")
        let _ = String(localized: "Raise arms, open jacket. Stand on a rock. Do not crouch or hide.", comment: "Step Detail")
        let _ = String(localized: "Make check noise, shout firmly: 'Hey bear! Go away!'", comment: "Step Instruction")
        let _ = String(localized: "Black bears are usually timid. Aggressive, loud human noises scare them off.", comment: "Step Detail")
        let _ = String(localized: "Back away slowly. Do NOT run.", comment: "Step Instruction")
        let _ = String(localized: "Running triggers a predatory chase instinct. Back away while facing the bear.", comment: "Step Detail")
        let _ = String(localized: "If it follows, throw rocks/sticks and get aggressive.", comment: "Step Instruction")
        let _ = String(localized: "Show you are not prey. You are a threat.", comment: "Step Detail")
        let _ = String(localized: "Grizzly Avoidance", comment: "Technique Name")
        let _ = String(localized: "De-escalate and retreat", comment: "Technique Subtitle")
        let _ = String(localized: "Stop. Do not run. Do not yell.", comment: "Step Instruction")
        let _ = String(localized: "Grizzlies are territorial. Running triggers chase. Yelling may be seen as aggression.", comment: "Step Detail")
        let _ = String(localized: "Speak softly and calmly: 'Hey bear, whoa bear'.", comment: "Step Instruction")
        let _ = String(localized: "Identify yourself as human, not prey. Keep voice low and monotonous.", comment: "Step Detail")
        let _ = String(localized: "Avoid eye contact (seen as a challenge).", comment: "Step Instruction")
        let _ = String(localized: "Look at the bear's chest or feet. Turning your head slightly shows submission.", comment: "Step Detail")
        let _ = String(localized: "Back away slowly while facing the bear.", comment: "Step Instruction")
        let _ = String(localized: "Move only when the bear is not advancing. Give it space.", comment: "Step Detail")
        let _ = String(localized: "Snake Avoidance", comment: "Technique Name")
        let _ = String(localized: "Step back and leave it alone", comment: "Technique Subtitle")
        let _ = String(localized: "Freeze. Locate the snake.", comment: "Step Instruction")
        let _ = String(localized: "Movement may trigger a strike. Find exactly where it is.", comment: "Step Detail")
        let _ = String(localized: "Identify safe escape route (away from head).", comment: "Step Instruction")
        let _ = String(localized: "Snakes can strike 1/2 their body length. Ensure your path is clear.", comment: "Step Detail")
        let _ = String(localized: "Back away slowly and deliberately.", comment: "Step Instruction")
        let _ = String(localized: "Give the snake a wide berth (at least 6 feet). Most bites happen when people try to move/kill snakes.", comment: "Step Detail")
        let _ = String(localized: "Stomp feet as you retreat (vibrations warn others).", comment: "Step Instruction")
        let _ = String(localized: "Snakes sense vibration. Heavy steps alert them to your presence.", comment: "Step Detail")
        let _ = String(localized: "Lightning Distance", comment: "Technique Name")
        let _ = String(localized: "Flash-to-Bang Calculation", comment: "Technique Subtitle")
        let _ = String(localized: "See the Flash -> Start Counting Seconds.", comment: "Step Instruction")
        let _ = String(localized: "One-Mississippi, Two-Mississippi...", comment: "Step Detail")
        let _ = String(localized: "Stop counting when you hear the Bang (Thunder).", comment: "Step Instruction")
        let _ = String(localized: "Sound travels 1 mile in 5 seconds.", comment: "Step Detail")
        let _ = String(localized: "Divide seconds by 5 = Distance in Miles.", comment: "Step Instruction")
        let _ = String(localized: "10 seconds = 2 miles. 30 seconds = 6 miles. Under 30 seconds (6 miles) is the danger zone.", comment: "Step Detail")
        let _ = String(localized: "If under 30 seconds: Seek shelter immediately.", comment: "Step Instruction")
        let _ = String(localized: "You are within striking distance. 30 minutes must pass after the last thunder before leaving shelter.", comment: "Step Detail")
        let _ = String(localized: "Fire", comment: "Domain Name")
        let _ = String(localized: "Bow Drill Fire", comment: "Technique Name")
        let _ = String(localized: "Most reliable friction fire method", comment: "Technique Subtitle")
        let _ = String(localized: "Friction", comment: "Category")
        let _ = String(localized: "Assemble 4 components: fireboard, spindle, bow, handhold.", comment: "Step Instruction")
        let _ = String(localized: "Fireboard and spindle from the same DRY softwood — willow, cottonwood, cedar, basswood. All must be dead and dry. Green wood will not work.", comment: "Step Detail")
        let _ = String(localized: "Carve a notch in the fireboard to collect ember dust.", comment: "Step Instruction")
        let _ = String(localized: "Burn in a depression first by spinning, then carve a V-notch (1/8 of the circle) from the edge to the center of the depression. This is where the ember forms.", comment: "Step Detail")
        let _ = String(localized: "Wrap the bowstring around the spindle once.", comment: "Step Instruction")
        let _ = String(localized: "The spindle goes between the string and the bow. One wrap provides enough friction to spin. The string should be taut but not guitar-tight.", comment: "Step Detail")
        let _ = String(localized: "Apply downward pressure with handhold and saw the bow back and forth.", comment: "Step Instruction")
        let _ = String(localized: "Lubricate the handhold socket (spit, oil, wax). Start slow to heat up, then increase speed. Full-length bow strokes. Smoke should build.", comment: "Step Detail")
        let _ = String(localized: "When heavy smoke pours from the notch, stop. The ember is born.", comment: "Step Instruction")
        let _ = String(localized: "Carefully lift the fireboard. A glowing coal should be sitting in the dust pile. Transfer to tinder bundle. Blow gently and steadily.", comment: "Step Detail")
        let _ = String(localized: "Hand Drill Fire", comment: "Technique Name")
        let _ = String(localized: "Simplest friction fire — just two pieces", comment: "Technique Subtitle")
        let _ = String(localized: "Find a straight, dry spindle 18-24 inches long, pencil-thick.", comment: "Step Instruction")
        let _ = String(localized: "Mullein stalks, cattail stalks, or yucca flower stalks are ideal. Must be completely dry and straight.", comment: "Step Detail")
        let _ = String(localized: "Use the same fireboard setup as bow drill with V-notch.", comment: "Step Instruction")
        let _ = String(localized: "Same softwood requirements. Burn in, carve notch. Place bark or leaf under notch to catch ember.", comment: "Step Detail")
        let _ = String(localized: "Roll the spindle between your palms while pressing down.", comment: "Step Instruction")
        let _ = String(localized: "Hands naturally migrate downward. When at bottom, quickly reposition to top. Fast spinning with strong downward pressure. This is extremely tiring.", comment: "Step Detail")
        let _ = String(localized: "Continue until ember forms in the notch dust.", comment: "Step Instruction")
        let _ = String(localized: "This method requires exceptional technique and the right materials. Many experienced practitioners consider it the hardest friction fire method.", comment: "Step Detail")
        let _ = String(localized: "Fire Saw", comment: "Technique Name")
        let _ = String(localized: "Friction fire using a sawing motion", comment: "Technique Subtitle")
        let _ = String(localized: "Split a dry bamboo or softwood piece lengthwise.", comment: "Step Instruction")
        let _ = String(localized: "Bamboo is ideal — its silica content generates excellent friction. The split piece forms your base.", comment: "Step Detail")
        let _ = String(localized: "Cut a notch across the flat inner surface.", comment: "Step Instruction")
        let _ = String(localized: "The notch catches friction dust and concentrates heat. Place tinder directly under the notch.", comment: "Step Detail")
        let _ = String(localized: "Saw a thin strip rapidly back and forth across the notch.", comment: "Step Instruction")
        let _ = String(localized: "Use another piece of bamboo or hardwood as the saw. Fast, firm strokes generate heat. Dust accumulates in the notch.", comment: "Step Detail")
        let _ = String(localized: "The accumulated dust ignites into an ember. Transfer to tinder.", comment: "Step Instruction")
        let _ = String(localized: "The bambooo fire saw is particularly effective in tropical environments where bow drill materials may be too wet.", comment: "Step Detail")
        let _ = String(localized: "Ferro Rod (Firesteel)", comment: "Technique Name")
        let _ = String(localized: "Sparks at 3,000°F in any weather", comment: "Technique Subtitle")
        let _ = String(localized: "Ignition", comment: "Category")
        let _ = String(localized: "Prepare a tinder bundle of dry, fine material.", comment: "Step Instruction")
        let _ = String(localized: "Dryer lint, birch bark, fatwood shavings, or charcloth. The finer and drier the better. Loose and fluffy catches sparks best.", comment: "Step Detail")
        let _ = String(localized: "Hold the rod against the tinder. Pull the striker BACK toward you.", comment: "Step Instruction")
        let _ = String(localized: "Don't push the striker forward — this scatters your tinder. Hold the rod still and pull the striker back. Sparks fly onto the tinder.", comment: "Step Detail")
        let _ = String(localized: "Strike firmly with fast, controlled strokes.", comment: "Step Instruction")
        let _ = String(localized: "The striker scrapes ferrocerium, creating 3,000°F sparks. Any sharp hard edge works as a striker — knife spine, broken ceramic, rock edge.", comment: "Step Detail")
        let _ = String(localized: "Once tinder catches, gently blow and transfer to fire lay.", comment: "Step Instruction")
        let _ = String(localized: "Cup the glowing tinder, blow steadily until it flames, and place in your prepared fire structure.", comment: "Step Detail")
        let _ = String(localized: "Flint & Steel", comment: "Technique Name")
        let _ = String(localized: "The original sparker — works when wet", comment: "Technique Subtitle")
        let _ = String(localized: "Find flint, quartz, or any hard glassy stone.", comment: "Step Instruction")
        let _ = String(localized: "The stone must be harder than steel. Flint, chert, jasper, agate, and quartz all work. Sharp edges throw better sparks.", comment: "Step Detail")
        let _ = String(localized: "Strike the steel (knife spine) against the sharp stone edge.", comment: "Step Instruction")
        let _ = String(localized: "The steel shaves off tiny particles that ignite from friction heat. Strike at a low angle for maximum spark shower.", comment: "Step Detail")
        let _ = String(localized: "Direct sparks onto charcloth or very fine tinder.", comment: "Step Instruction")
        let _ = String(localized: "Charcloth catches a single spark. Without charcloth, use dried fungus (amadou), birch bark dust, or very fine dried grass.", comment: "Step Detail")
        let _ = String(localized: "Transfer the glowing ember to tinder bundle and blow to flame.", comment: "Step Instruction")
        let _ = String(localized: "Charcloth holds an ember for minutes, giving you time to prepare. Nestle it in your tinder bundle and blow steadily.", comment: "Step Detail")
        let _ = String(localized: "Solar Fire (Lens Method)", comment: "Technique Name")
        let _ = String(localized: "Focus sunlight to ignite tinder", comment: "Technique Subtitle")
        let _ = String(localized: "Solar", comment: "Category")
        let _ = String(localized: "Use any convex lens: glasses, binoculars, camera lens, water-filled bag.", comment: "Step Instruction")
        let _ = String(localized: "Even a clear plastic bag filled with water, shaped into a sphere, focuses light. Eyeglasses work if farsighted (convex lenses).", comment: "Step Detail")
        let _ = String(localized: "Focus the smallest possible bright dot on dark tinder.", comment: "Step Instruction")
        let _ = String(localized: "Dark material absorbs more heat. Char, dark fabric, or blackened bark works best. The smaller the focused dot, the higher the temperature.", comment: "Step Detail")
        let _ = String(localized: "Hold steady. The tinder will begin to smoke, then glow.", comment: "Step Instruction")
        let _ = String(localized: "Patience — this can take 30 seconds to several minutes. Wind and clouds are your enemy. Shield the tinder from wind.", comment: "Step Detail")
        let _ = String(localized: "Transfer the ember to a tinder bundle and blow to flame.", comment: "Step Instruction")
        let _ = String(localized: "Works only in direct sunlight. Completely silent — useful in stealth situations. Zero consumable materials needed.", comment: "Step Detail")
        let _ = String(localized: "Fire from Ice Lens", comment: "Technique Name")
        let _ = String(localized: "Polish ice into a lens to focus sunlight", comment: "Technique Subtitle")
        let _ = String(localized: "Find or make a piece of clear ice 2-3 inches thick.", comment: "Step Instruction")
        let _ = String(localized: "Clear ice only — cloudy ice scatters light. Boil water first for clearer ice. Lake ice from slow freezing is often clear enough.", comment: "Step Detail")
        let _ = String(localized: "Shape into a lens by carving with a knife — thicker in center, thinner at edges.", comment: "Step Instruction")
        let _ = String(localized: "Convex on both sides (like a magnifying glass). Use the warmth of your hands to smooth the surfaces.", comment: "Step Detail")
        let _ = String(localized: "Polish the surfaces smooth using your warm hands.", comment: "Step Instruction")
        let _ = String(localized: "Body heat melts a thin surface layer, which refreezes smooth. Alternate hands to avoid frostbite. Surfaces must be glass-smooth.", comment: "Step Detail")
        let _ = String(localized: "Focus sunlight through the ice lens onto dark tinder.", comment: "Step Instruction")
        let _ = String(localized: "This actually works. The ice must be very clear and the surfaces very smooth. It's a last-resort method — impressive but time-consuming.", comment: "Step Detail")
        let _ = String(localized: "Teepee Fire Lay", comment: "Technique Name")
        let _ = String(localized: "The classic cone structure — great for quick heat", comment: "Technique Subtitle")
        let _ = String(localized: "Structure", comment: "Category")
        let _ = String(localized: "Place tinder bundle on the ground (dry leaves, bark shavings, grass).", comment: "Step Instruction")
        let _ = String(localized: "Ball-sized bundle of the finest, driest material. Dryer lint, birch bark, cedar bark, cattail fluff, fatwood shavings.", comment: "Step Detail")
        let _ = String(localized: "Lean small twigs (pencil-lead thin) against each other in a cone over the tinder.", comment: "Step Instruction")
        let _ = String(localized: "Leave an opening facing prevailing wind for oxygen. Start with matchstick-sized, then pencil-sized.", comment: "Step Detail")
        let _ = String(localized: "Add progressively larger sticks maintaining the cone shape.", comment: "Step Instruction")
        let _ = String(localized: "Finger-thick sticks next, then wrist-thick. Don't smother — leave gaps for airflow. The fire needs oxygen.", comment: "Step Detail")
        let _ = String(localized: "Light the tinder through the opening at the base.", comment: "Step Instruction")
        let _ = String(localized: "Flames rise upward through the cone, igniting each layer. This fire burns hot and fast — excellent for quick warmth and boiling water.", comment: "Step Detail")
        let _ = String(localized: "Log Cabin Fire Lay", comment: "Technique Name")
        let _ = String(localized: "Long-burning structure for cooking and overnight", comment: "Technique Subtitle")
        let _ = String(localized: "Lay 2 parallel sticks on the ground, 1 foot apart.", comment: "Step Instruction")
        let _ = String(localized: "Wrist-thick or larger. These are your base. Place on clean, dry ground.", comment: "Step Detail")
        let _ = String(localized: "Stack 2 more sticks perpendicular on top, forming a square.", comment: "Step Instruction")
        let _ = String(localized: "Like building a log cabin. Each layer crosses the one below. Leave the center open.", comment: "Step Detail")
        let _ = String(localized: "Continue stacking 3-4 layers high. Place tinder in the center hollow.", comment: "Step Instruction")
        let _ = String(localized: "The hollow center is your firebox. Fill with tinder and kindling. The walls will catch from the inside.", comment: "Step Detail")
        let _ = String(localized: "Light the center tinder. The structure burns inward and collapses into coals.", comment: "Step Instruction")
        let _ = String(localized: "Log cabin burns slower than teepee and produces excellent coals for cooking. The flat top surface is also good for balancing a pot.", comment: "Step Detail")
        let _ = String(localized: "Long Fire (All-Night Fire)", comment: "Technique Name")
        let _ = String(localized: "Two logs that radiate heat all night", comment: "Technique Subtitle")
        let _ = String(localized: "Find 2 green logs, 6 inches thick and as long as your body.", comment: "Step Instruction")
        let _ = String(localized: "Green (live) wood burns slowly. The longer the logs, the longer the fire lasts. This is your overnight heat source.", comment: "Step Detail")
        let _ = String(localized: "Lay them parallel, 6-8 inches apart.", comment: "Step Instruction")
        let _ = String(localized: "The gap between them is your fire channel. Tinder and kindling go in the gap.", comment: "Step Detail")
        let _ = String(localized: "Build a small teepee fire in the gap to ignite the logs.", comment: "Step Instruction")
        let _ = String(localized: "The teepee fire heats both logs simultaneously. As the logs catch, the gap radiates heat in both directions.", comment: "Step Detail")
        let _ = String(localized: "Sleep parallel to the fire, 2-3 feet away.", comment: "Step Instruction")
        let _ = String(localized: "Build a reflector wall behind the fire (stacked logs, rock wall) to direct heat toward your sleeping area. This setup provides warmth for 8+ hours.", comment: "Step Detail")
        let _ = String(localized: "Dakota Fire Hole", comment: "Technique Name")
        let _ = String(localized: "Low visibility, wind-resistant cooking fire", comment: "Technique Subtitle")
        let _ = String(localized: "Dig a hole 1 foot wide and 1 foot deep.", comment: "Step Instruction")
        let _ = String(localized: "This is your fire chamber. Wide enough to feed sticks in, deep enough to contain the fire below ground level.", comment: "Step Detail")
        let _ = String(localized: "Dig a second hole 1 foot away, connected by a tunnel.", comment: "Step Instruction")
        let _ = String(localized: "The tunnel connects the two holes underground. The second hole is your air intake — it creates a chimney effect.", comment: "Step Detail")
        let _ = String(localized: "The air tunnel should face the prevailing wind.", comment: "Step Instruction")
        let _ = String(localized: "Wind blows into the intake hole, through the tunnel, feeding the fire with forced air. This creates an extremely efficient, hot burn.", comment: "Step Detail")
        let _ = String(localized: "Build fire in the main hole. The forced air creates intense heat.", comment: "Step Instruction")
        let _ = String(localized: "Minimal smoke, nearly invisible at night, wind-protected, and excellent for cooking (place pot over the hole). Used by military for tactical fires.", comment: "Step Detail")
        let _ = String(localized: "Battery & Steel Wool Fire", comment: "Technique Name")
        let _ = String(localized: "Electrical ignition from common items", comment: "Technique Subtitle")
        let _ = String(localized: "Chemical", comment: "Category")
        let _ = String(localized: "Stretch steel wool into a thin, loose pad.", comment: "Step Instruction")
        let _ = String(localized: "Fine grade (#0000) works best. Stretch it to maximize air exposure. The thinner, the easier it ignites.", comment: "Step Detail")
        let _ = String(localized: "Touch both terminals of a 9V battery to the steel wool.", comment: "Step Instruction")
        let _ = String(localized: "A 9V battery is easiest because both terminals are on top. AA batteries work if you bridge both ends with the wool.", comment: "Step Detail")
        let _ = String(localized: "The steel wool will glow and burn rapidly.", comment: "Step Instruction")
        let _ = String(localized: "It burns fast — have your tinder bundle ready. Nest the burning steel wool in the tinder immediately.", comment: "Step Detail")
        let _ = String(localized: "Transfer to tinder bundle immediately.", comment: "Step Instruction")
        let _ = String(localized: "Steel wool burns completely in 10-15 seconds. This method also works with gum wrapper foil (fold narrow center between terminals) on AA batteries.", comment: "Step Detail")
        let _ = String(localized: "Starting Fire in Rain", comment: "Technique Name")
        let _ = String(localized: "Waterproof your fire-starting process", comment: "Technique Subtitle")
        let _ = String(localized: "Find dry tinder UNDER things: bark, overhangs, dead standing trees.", comment: "Step Instruction")
        let _ = String(localized: "The driest wood in rain is dead branches still attached to trees — they shed water. Inner bark, standing dead wood cores, and material under dense canopy.", comment: "Step Detail")
        let _ = String(localized: "Split wet wood to expose the dry interior.", comment: "Step Instruction")
        let _ = String(localized: "Even soaking wet logs are dry inside. Split them open. The inner wood ignites normally. This is the single most important wet-weather fire skill.", comment: "Step Detail")
        let _ = String(localized: "Build the fire on a platform of sticks above wet ground.", comment: "Step Instruction")
        let _ = String(localized: "Wet ground wicks moisture into your fire. A platform of sticks insulates the fire from ground moisture.", comment: "Step Detail")
        let _ = String(localized: "Use fatwood (resinous pine heartwood) — it burns even when wet.", comment: "Step Instruction")
        let _ = String(localized: "Found in the stumps and knots of dead pine trees. Saturated with flammable resin. Shave curls for tinder. Burns hot enough to dry surrounding wet wood.", comment: "Step Detail")
        let _ = String(localized: "Shield with your body and a covering while establishing the fire.", comment: "Step Instruction")
        let _ = String(localized: "Once the fire is strong enough to generate its own heat, it dries out the wet wood you feed it. The hardest part is getting started.", comment: "Step Detail")
        let _ = String(localized: "Properly Extinguishing a Fire", comment: "Technique Name")
        let _ = String(localized: "Leave no trace, prevent wildfires", comment: "Technique Subtitle")
        let _ = String(localized: "Let the fire burn down to coals — stop adding fuel well before departure.", comment: "Step Instruction")
        let _ = String(localized: "Plan ahead. A fire with large logs takes hours to burn down. Stop feeding it at least 1-2 hours before you need it out.", comment: "Step Detail")
        let _ = String(localized: "Sprinkle water on the coals — do NOT dump.", comment: "Step Instruction")
        let _ = String(localized: "Dumping water creates a steam explosion and can throw hot coals. Sprinkle, stir, sprinkle. Repeat.", comment: "Step Detail")
        let _ = String(localized: "Stir the ashes and wet every surface.", comment: "Step Instruction")
        let _ = String(localized: "Embers buried in ash can reignite hours later. Stir thoroughly and wet all surfaces.", comment: "Step Detail")
        let _ = String(localized: "Hold your hand over the ashes at 6 inches. If warm, repeat.", comment: "Step Instruction")
        let _ = String(localized: "No warmth should be detectable at 6 inches. If warm, add more water and stir again. Wildfire from abandoned campfires destroys millions of acres annually.", comment: "Step Detail")
        let _ = String(localized: "Fire Plow", comment: "Technique Name")
        let _ = String(localized: "Rub a hardwood shaft in a softwood groove", comment: "Technique Subtitle")
        let _ = String(localized: "Find a flat softwood board and a hardwood shaft.", comment: "Step Instruction")
        let _ = String(localized: "Hibiscus, sotol, or cedar board. Hardwood stick like oak for shaft.", comment: "Step Detail")
        let _ = String(localized: "Cut a groove 8 inches long in the board.", comment: "Step Instruction")
        let _ = String(localized: "Deep enough that the shaft stays in the groove when pushing.", comment: "Step Detail")
        let _ = String(localized: "Rub the shaft back and forth rapidly in the groove.", comment: "Step Instruction")
        let _ = String(localized: "Use both hands, long strokes, heavy downward pressure. Speed and pressure are critical.", comment: "Step Detail")
        let _ = String(localized: "Fine wood dust accumulates at the end—it will ignite.", comment: "Step Instruction")
        let _ = String(localized: "When dust begins smoking, blow gently and transfer to tinder bundle.", comment: "Step Detail")
        let _ = String(localized: "Potassium Permanganate Fire", comment: "Technique Name")
        let _ = String(localized: "Chemical reaction creates instant fire", comment: "Technique Subtitle")
        let _ = String(localized: "Place a small pile of potassium permanganate on dry surface.", comment: "Step Instruction")
        let _ = String(localized: "Found in some first aid kits as water purifier. Purple crystals.", comment: "Step Detail")
        let _ = String(localized: "Add a few drops of glycerin (antifreeze works too).", comment: "Step Instruction")
        let _ = String(localized: "The chemical reaction generates heat. Takes 30-90 seconds.", comment: "Step Detail")
        let _ = String(localized: "Stand back—the mixture will spontaneously ignite.", comment: "Step Instruction")
        let _ = String(localized: "Produces intense heat and flame. Have tinder ready to catch.", comment: "Step Detail")
        let _ = String(localized: "Carrying Fire / Ember Transport", comment: "Technique Name")
        let _ = String(localized: "Move a burning ember between camps", comment: "Technique Subtitle")
        let _ = String(localized: "Maintenance", comment: "Category")
        let _ = String(localized: "Place hot coal in bundle of dry punk wood or fungus.", comment: "Step Instruction")
        let _ = String(localized: "Birch polypore or rotted wood holds ember for hours.", comment: "Step Detail")
        let _ = String(localized: "Wrap in green leaves to insulate and contain.", comment: "Step Instruction")
        let _ = String(localized: "Green leaves won't catch fire. Slows oxygen flow.", comment: "Step Detail")
        let _ = String(localized: "Blow gently to feed ember when needed.", comment: "Step Instruction")
        let _ = String(localized: "Carrier keeps fire alive 12+ hours. Check periodically.", comment: "Step Detail")
        let _ = String(localized: "At new camp: place in tinder bundle, blow to flame.", comment: "Step Instruction")
        let _ = String(localized: "Surround with finest dry tinder. Blow steadily.", comment: "Step Detail")
        let _ = String(localized: "Feather Stick Making", comment: "Technique Name")
        let _ = String(localized: "Create tinder from wet wood with a knife", comment: "Technique Subtitle")
        let _ = String(localized: "Preparation", comment: "Category")
        let _ = String(localized: "Split a dead stick to expose dry interior.", comment: "Step Instruction")
        let _ = String(localized: "Even in rain, inside of dead wood is dry.", comment: "Step Detail")
        let _ = String(localized: "Shave thin curls along stick — don't cut them off.", comment: "Step Instruction")
        let _ = String(localized: "Like peeling a carrot. Curls catch fire easily.", comment: "Step Detail")
        let _ = String(localized: "Make many curls — more surface area = better.", comment: "Step Instruction")
        let _ = String(localized: "Dozens of spiral curls dramatically increase ignition chance.", comment: "Step Detail")
        let _ = String(localized: "Light the curls. They ignite even in wet conditions.", comment: "Step Instruction")
        let _ = String(localized: "Low moisture, high surface area. Catch spark and burn hot.", comment: "Step Detail")
        let _ = String(localized: "Pine Resin Torch", comment: "Technique Name")
        let _ = String(localized: "Long-burning portable light from pine resin", comment: "Technique Subtitle")
        let _ = String(localized: "Collect pine resin from wounds on pine or spruce trees.", comment: "Step Instruction")
        let _ = String(localized: "Look for amber-colored, sticky sap oozing from bark injuries. Both fresh (sticky) and dried (crystallized) resin works.", comment: "Step Detail")
        let _ = String(localized: "Wrap resin-soaked cloth or bark around the end of a green stick.", comment: "Step Instruction")
        let _ = String(localized: "Green stick won't burn. Wrap tightly with bark, cloth strips, or dried grass packed with resin chunks. More resin = longer burn.", comment: "Step Detail")
        let _ = String(localized: "Light the torch. Burns 20-40 minutes with bright flame.", comment: "Step Instruction")
        let _ = String(localized: "Pine resin is highly flammable and burns hot. Drips can cause burns — hold at arm's length, angled slightly away from you.", comment: "Step Detail")
        let _ = String(localized: "Making Charcloth", comment: "Technique Name")
        let _ = String(localized: "The best ember-catching material you can make", comment: "Technique Subtitle")
        let _ = String(localized: "Cut 100% cotton fabric (t-shirt, jeans) into 2-inch squares.", comment: "Step Instruction")
        let _ = String(localized: "MUST be natural fiber — cotton, linen, or hemp. Synthetics melt instead of charring. Old denim works excellently.", comment: "Step Detail")
        let _ = String(localized: "Place cloth in a sealed metal tin with a small hole punched in the lid.", comment: "Step Instruction")
        let _ = String(localized: "Altoids tins are perfect. The hole allows gas to escape but prevents oxygen from entering. Without the hole, pressure builds and the tin pops open.", comment: "Step Detail")
        let _ = String(localized: "Place tin in fire. Smoke will jet from the hole. When smoke stops, remove tin.", comment: "Step Instruction")
        let _ = String(localized: "The cloth is pyrolyzing — converting to carbon without burning. Takes 10-15 minutes. Do NOT open while hot — the cloth will ignite from sudden oxygen exposure.", comment: "Step Detail")
        let _ = String(localized: "Result: black, fragile cloth that catches the smallest spark.", comment: "Step Instruction")
        let _ = String(localized: "Charcloth catches sparks from flint & steel, ferro rods, and even sunlight focused through a lens. Store in a waterproof container.", comment: "Step Detail")
        let _ = String(localized: "Fire Piston", comment: "Technique Name")
        let _ = String(localized: "Compress air to ignite tinder — ancient technology", comment: "Technique Subtitle")
        let _ = String(localized: "Place a small piece of charcloth or tinder fungus in the piston cup.", comment: "Step Instruction")
        let _ = String(localized: "The tinder sits in a small concave depression at the end of the piston rod. Only a tiny piece is needed.", comment: "Step Detail")
        let _ = String(localized: "Ram the piston into the cylinder with one sharp stroke.", comment: "Step Instruction")
        let _ = String(localized: "The air compresses to roughly 1/25th its volume. This heats it to over 500°F — enough to ignite the tinder. Same principle as a diesel engine.", comment: "Step Detail")
        let _ = String(localized: "Quickly withdraw the piston. Transfer glowing ember to tinder bundle.", comment: "Step Instruction")
        let _ = String(localized: "Speed matters — the ember is tiny and cools fast. Have your tinder bundle ready. Blow gently to grow the ember.", comment: "Step Detail")
        let _ = String(localized: "Fire Plow Method", comment: "Technique Name")
        let _ = String(localized: "Friction fire with a plowing motion", comment: "Technique Subtitle")
        let _ = String(localized: "Carve a groove 6-8 inches long in a softwood base board.", comment: "Step Instruction")
        let _ = String(localized: "Hibiscus, willow, or cottonwood work best. The groove should be flat-bottomed, about half an inch wide.", comment: "Step Detail")
        let _ = String(localized: "Use a hardwood stick to rapidly push back and forth in the groove.", comment: "Step Instruction")
        let _ = String(localized: "The plow stick should be pointed. Push with firm pressure at a 30-45° angle. Speed and pressure create heat through friction.", comment: "Step Detail")
        let _ = String(localized: "Hot wood dust accumulates at the end of the groove.", comment: "Step Instruction")
        let _ = String(localized: "Brown dust turns black as temperature rises. When it begins to smoke independently, you have an ember. This method is extremely exhausting.", comment: "Step Detail")
        let _ = String(localized: "Transfer ember to tinder bundle and blow to flame.", comment: "Step Instruction")
        let _ = String(localized: "Same technique as bow drill. Gently fold tinder around ember, blow steadily. The fire plow is a backup to the bow drill — lower success rate but simpler setup.", comment: "Step Detail")
        let _ = String(localized: "Fire Saw Method", comment: "Technique Name")
        let _ = String(localized: "Tropical friction fire with bamboo", comment: "Technique Subtitle")
        let _ = String(localized: "Split a dry bamboo segment lengthwise.", comment: "Step Instruction")
        let _ = String(localized: "You need two pieces: a base piece (half-round, concave up) and a sawing piece (the edge of another half). Dry, dead bamboo works best.", comment: "Step Detail")
        let _ = String(localized: "Carve a small notch in the base piece. Place tinder underneath.", comment: "Step Instruction")
        let _ = String(localized: "The notch allows hot dust to fall through onto your tinder bundle positioned below the base piece.", comment: "Step Detail")
        let _ = String(localized: "Saw the edge of the second piece rapidly across the notch.", comment: "Step Instruction")
        let _ = String(localized: "Use long, fast strokes with heavy downward pressure. The silica in bamboo creates tremendous friction heat.", comment: "Step Detail")
        let _ = String(localized: "Hot dust falls through notch onto tinder. Blow to flame.", comment: "Step Instruction")
        let _ = String(localized: "Bamboo dust ignites at relatively low temperatures. This method is widely used in Southeast Asia and the Pacific Islands where bamboo is abundant.", comment: "Step Detail")
        let _ = String(localized: "Fire Reflector Wall", comment: "Technique Name")
        let _ = String(localized: "Double your fire's heat output with a wall", comment: "Technique Subtitle")
        let _ = String(localized: "Stack green logs or flat rocks into a wall behind your fire.", comment: "Step Instruction")
        let _ = String(localized: "Wall should be 3-4 feet tall, slightly taller than the fire. Place it opposite your shelter or sleeping position.", comment: "Step Detail")
        let _ = String(localized: "Angle the wall slightly toward your shelter for maximum heat reflection.", comment: "Step Instruction")
        let _ = String(localized: "A slight forward lean (10-15°) directs radiant heat downward toward you rather than straight up into the sky.", comment: "Step Detail")
        let _ = String(localized: "Sit or sleep between the fire and your shelter — heat from both sides.", comment: "Step Instruction")
        let _ = String(localized: "Fire radiates toward you directly AND reflects off the wall behind it. You get heat from two directions instead of one.", comment: "Step Detail")
        let _ = String(localized: "Waterproof Tinder Kit", comment: "Technique Name")
        let _ = String(localized: "Pre-prepared fire-starting materials that work wet", comment: "Technique Subtitle")
        let _ = String(localized: "Coat cotton balls in petroleum jelly (Vaseline).", comment: "Step Instruction")
        let _ = String(localized: "Pull cotton ball apart slightly, work Vaseline deep into fibers. Each ball burns 3-5 minutes. Store in waterproof container (pill bottle, ziplock).", comment: "Step Detail")
        let _ = String(localized: "Dip wooden matches in melted wax for waterproofing.", comment: "Step Instruction")
        let _ = String(localized: "Melt candle wax, dip match heads and an inch of the stick. Let dry. The wax peels off when you strike, but keeps matches dry indefinitely.", comment: "Step Detail")
        let _ = String(localized: "Store charcloth in a sealed container with your ferro rod.", comment: "Step Instruction")
        let _ = String(localized: "Charcloth absorbs moisture from air. Keep it sealed. An Altoids tin with ferro rod and charcloth is a complete waterproof fire kit.", comment: "Step Detail")
        let _ = String(localized: "Add a birthday candle — guaranteed flame for 60 seconds.", comment: "Step Instruction")
        let _ = String(localized: "A birthday candle gives you one minute of open flame to build from. Light it first, then use it to ignite your tinder bundle. Weight: nearly zero.", comment: "Step Detail")
        let _ = String(localized: "Fatwood Identification", comment: "Technique Name")
        let _ = String(localized: "Find nature's fire starter in dead conifer stumps", comment: "Technique Subtitle")
        let _ = String(localized: "Look for dead pine/spruce stumps with resin-saturated heartwood.", comment: "Step Instruction")
        let _ = String(localized: "When a conifer dies, resin concentrates in the stump and root system. The wood becomes hard, heavy, and amber-colored. It smells strongly of pine when cut.", comment: "Step Detail")
        let _ = String(localized: "Split the stump to find the resin-saturated core.", comment: "Step Instruction")
        let _ = String(localized: "The outer wood may look normal. Split or chop into the center — fatwood is darker, heavier, and has a strong turpentine smell. It feels waxy or oily.", comment: "Step Detail")
        let _ = String(localized: "Shave thin curls for tinder. Fatwood ignites with a single spark.", comment: "Step Instruction")
        let _ = String(localized: "The resins are highly flammable. Thin shavings catch from ferro rod sparks. Thicker sticks burn for 5-10 minutes with an intense flame, even when wet.", comment: "Step Detail")
        let _ = String(localized: "Birch Bark Fire Starting", comment: "Technique Name")
        let _ = String(localized: "Use birch bark's natural oils as fire starter", comment: "Technique Subtitle")
        let _ = String(localized: "Peel thin, papery bark from dead or fallen birch trees.", comment: "Step Instruction")
        let _ = String(localized: "Never strip bark from living birch trees — it kills them. Dead standing birch and fallen logs have plenty. The white papery outer bark is what you want.", comment: "Step Detail")
        let _ = String(localized: "Shred or crumple the bark into a loose nest for tinder.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark contains betulin oil, which is flammable even when wet. Crumple loosely for maximum air flow. Multiple thin layers work better than one thick piece.", comment: "Step Detail")
        let _ = String(localized: "Ignite with spark or match. Bark burns hot and long enough to light kindling.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark burns even in rain due to its oil content. It produces a smoky flame and can sustain fire for 2-3 minutes — enough to dry and ignite damp kindling above it.", comment: "Step Detail")
        let _ = String(localized: "Star Fire Configuration", comment: "Technique Name")
        let _ = String(localized: "Long-burning fire using logs as spokes", comment: "Technique Subtitle")
        let _ = String(localized: "Arrange 4-6 large logs in a star pattern with ends meeting at center.", comment: "Step Instruction")
        let _ = String(localized: "Logs radiate outward like spokes of a wheel. Only the ends burn where they meet in the middle. This is the most fuel-efficient long-burning configuration.", comment: "Step Detail")
        let _ = String(localized: "Light a small fire at the center where the logs meet.", comment: "Step Instruction")
        let _ = String(localized: "Start with tinder and kindling at the hub. Once established, the log ends catch and burn slowly inward.", comment: "Step Detail")
        let _ = String(localized: "Push logs inward as they burn. No chopping required.", comment: "Step Instruction")
        let _ = String(localized: "As the ends burn away, simply push the logs toward the center. One adjustment per hour keeps it burning all night. Minimal effort, maximum burn time.", comment: "Step Detail")
        let _ = String(localized: "Keyhole Fire (Cooking Fire)", comment: "Technique Name")
        let _ = String(localized: "Combined heating and cooking fire design", comment: "Technique Subtitle")
        let _ = String(localized: "Dig or build a keyhole shape: circle for main fire, narrow channel for cooking.", comment: "Step Instruction")
        let _ = String(localized: "The circle (12-18 inch diameter) is your main fire pit. A narrow channel (6-8 inches wide) extends from one side for cooking. Shape looks like a keyhole from above.", comment: "Step Detail")
        let _ = String(localized: "Build main fire in the circular area. Let it produce coals.", comment: "Step Instruction")
        let _ = String(localized: "The main fire is your coal factory. Burn wood down to hot coals here. This is also your warming and light fire.", comment: "Step Detail")
        let _ = String(localized: "Rake hot coals into the narrow channel for controlled cooking.", comment: "Step Instruction")
        let _ = String(localized: "The channel provides a flat, even heat surface. Place a grill or pot supports across the channel. Coals give consistent heat without flames scorching food.", comment: "Step Detail")
        let _ = String(localized: "Trench Fire", comment: "Technique Name")
        let _ = String(localized: "Wind-resistant fire in a dug trench", comment: "Technique Subtitle")
        let _ = String(localized: "Dig a narrow trench 12 inches deep, 8 inches wide, oriented into the wind.", comment: "Step Instruction")
        let _ = String(localized: "The windward end is the air inlet. The trench protects flames from wind and concentrates heat upward. Length depends on cooking needs (2-3 feet is typical).", comment: "Step Detail")
        let _ = String(localized: "Build fire at the downwind end of the trench.", comment: "Step Instruction")
        let _ = String(localized: "Wind flowing through the trench fans the fire naturally, creating a bellows effect. This makes a very hot, efficient fire that uses less fuel.", comment: "Step Detail")
        let _ = String(localized: "Lay sticks or a grill across the trench for cooking.", comment: "Step Instruction")
        let _ = String(localized: "Green wood sticks across the trench support pots. The heat rises directly onto the cooking surface. Trench fires are nearly invisible from the side — good for concealment.", comment: "Step Detail")
        let _ = String(localized: "Hand Sanitizer Fire Starter", comment: "Technique Name")
        let _ = String(localized: "Use alcohol-based gel as emergency accelerant", comment: "Technique Subtitle")
        let _ = String(localized: "Squeeze a quarter-sized amount of hand sanitizer onto your tinder bundle.", comment: "Step Instruction")
        let _ = String(localized: "Hand sanitizer is 60-70% alcohol. The gel consistency keeps it in place rather than running off like liquid alcohol. It burns with a nearly invisible blue flame.", comment: "Step Detail")
        let _ = String(localized: "Ignite with spark, match, or lighter. The gel burns for 30-60 seconds.", comment: "Step Instruction")
        let _ = String(localized: "The alcohol burns hot enough to dry and ignite damp tinder beneath it. Do NOT squeeze more onto an already-lit fire — the flame can travel up the stream into the bottle.", comment: "Step Detail")
        let _ = String(localized: "Add kindling while the gel is burning.", comment: "Step Instruction")
        let _ = String(localized: "You have 30-60 seconds of sustained flame. Use this window to build up from tinder to kindling. One application is usually enough for dry conditions.", comment: "Step Detail")
        let _ = String(localized: "Vaseline Cotton Ball Fire Starter", comment: "Technique Name")
        let _ = String(localized: "Waterproof DIY fire starter that burns 5+ minutes", comment: "Technique Subtitle")
        let _ = String(localized: "Work petroleum jelly thoroughly into a cotton ball.", comment: "Step Instruction")
        let _ = String(localized: "Saturate the cotton but leave a small dry edge for catching a spark. The petroleum jelly acts as fuel; the cotton is the wick. Each one burns for 5-8 minutes.", comment: "Step Detail")
        let _ = String(localized: "Pull the cotton ball apart slightly to expose dry fibers.", comment: "Step Instruction")
        let _ = String(localized: "Fluff the dry edge into a small nest. This is where the spark catches. The exposed fibers ignite instantly from a ferro rod spark.", comment: "Step Detail")
        let _ = String(localized: "Ignite the dry fibers. The flame will spread to the petroleum-soaked portion.", comment: "Step Instruction")
        let _ = String(localized: "Burns with a steady flame for 5-8 minutes — more than enough to start a fire in any conditions. Waterproof, lightweight, and costs almost nothing to make. Carry 10+ in a ziplock bag.", comment: "Step Detail")
        let _ = String(localized: "Fire on Snow", comment: "Technique Name")
        let _ = String(localized: "Build fire on a platform to prevent melt-through", comment: "Technique Subtitle")
        let _ = String(localized: "Build a platform of green logs laid side by side on the snow.", comment: "Step Instruction")
        let _ = String(localized: "Without a platform, fire melts into the snow and extinguishes itself. Lay 4-6 arm-thick green logs parallel, covering an area 2x2 feet. Green wood resists burning.", comment: "Step Detail")
        let _ = String(localized: "Add a second layer of logs perpendicular to the first.", comment: "Step Instruction")
        let _ = String(localized: "Two layers of green logs provide enough insulation to prevent melt-through for hours. The fire burns on top; the platform slowly chars but doesn't burn through.", comment: "Step Detail")
        let _ = String(localized: "Build your fire on top of the platform using dry dead wood.", comment: "Step Instruction")
        let _ = String(localized: "Gather dead standing wood (stays drier than ground wood). Start small, build gradually. The platform keeps the fire elevated above the snowmelt zone.", comment: "Step Detail")
        let _ = String(localized: "Fire in High Wind", comment: "Technique Name")
        let _ = String(localized: "Maintain fire when wind threatens to scatter it", comment: "Technique Subtitle")
        let _ = String(localized: "Build a windbreak from rocks, logs, or earth on the windward side.", comment: "Step Instruction")
        let _ = String(localized: "Stack rocks 18-24 inches high in a half-circle on the upwind side. The windbreak should be close enough to block wind but not so close that it smothers the fire.", comment: "Step Detail")
        let _ = String(localized: "Use a top-down fire lay: large logs on bottom, smaller fuel on top.", comment: "Step Instruction")
        let _ = String(localized: "Inverted fire structure. Large logs form a platform, medium on top, kindling and tinder on the very top. Fire burns downward, sheltered by the structure itself.", comment: "Step Detail")
        let _ = String(localized: "Feed fire from the downwind side. Keep fuel low profile.", comment: "Step Instruction")
        let _ = String(localized: "Tall flames get scattered by wind. Keep fire compact and low. Add fuel from the sheltered side. Dakota fire holes are ideal for extreme wind conditions.", comment: "Step Detail")
        let _ = String(localized: "Signal Fire Maintenance", comment: "Technique Name")
        let _ = String(localized: "Keep a signal fire ready for instant activation", comment: "Technique Subtitle")
        let _ = String(localized: "Pre-build 3 signal fire platforms in a triangle, 100 feet apart.", comment: "Step Instruction")
        let _ = String(localized: "Three fires in a triangle is the international distress signal. Build each platform with a large base of dry kindling and fuel, ready to light instantly.", comment: "Step Detail")
        let _ = String(localized: "Cover each platform with a waterproof layer (bark, tarp, or leaves).", comment: "Step Instruction")
        let _ = String(localized: "Signal fires must be ready 24/7. Cover the prepared fire lays with bark shingles or palm leaves to keep them dry. You need to light them in seconds when aircraft appear.", comment: "Step Detail")
        let _ = String(localized: "Prepare green branches or oil-soaked material for smoke production.", comment: "Step Instruction")
        let _ = String(localized: "Once lit, add green leaves, grass, or rubber for thick white/black smoke visible for miles. Have these smoke materials staged next to each fire lay, ready to throw on.", comment: "Step Detail")
        let _ = String(localized: "Concealed Fire (Low Signature)", comment: "Technique Name")
        let _ = String(localized: "Build fire that minimizes light and smoke visibility", comment: "Technique Subtitle")
        let _ = String(localized: "Use a Dakota fire hole or deep trench to hide the flame below ground.", comment: "Step Instruction")
        let _ = String(localized: "In situations where fire visibility is dangerous (hostile territory, wildfire-prone areas), underground fires hide both light and smoke from ground-level observers.", comment: "Step Detail")
        let _ = String(localized: "Burn only dry hardwood to minimize smoke.", comment: "Step Instruction")
        let _ = String(localized: "Green wood and softwood produce excessive smoke. Dry hardwood (oak, maple, hickory) burns nearly smokeless when fully combusting. Split wood into small pieces for complete combustion.", comment: "Step Detail")
        let _ = String(localized: "Use a dispersal cover (branches with leaves) above the fire pit.", comment: "Step Instruction")
        let _ = String(localized: "Elevated green branches above the fire break up the smoke column, dispersing it into invisible wisps before it rises. Keep the cover high enough to avoid ignition (4+ feet above flame).", comment: "Step Detail")
        let _ = String(localized: "Upside-Down Fire (Self-Feeding)", comment: "Technique Name")
        let _ = String(localized: "Build a fire that burns for hours unattended", comment: "Technique Subtitle")
        let _ = String(localized: "Lay largest logs on the bottom in a tight row.", comment: "Step Instruction")
        let _ = String(localized: "Place 4-5 inch diameter logs side by side as the base. These are your fuel logs that will burn last, sustaining the fire for hours.", comment: "Step Detail")
        let _ = String(localized: "Stack progressively smaller wood in layers, perpendicular to the layer below.", comment: "Step Instruction")
        let _ = String(localized: "Medium logs on top of large, then small sticks, then kindling, then tinder on the very top. Each layer is perpendicular to the one below for air flow.", comment: "Step Detail")
        let _ = String(localized: "Light the tinder on top. Fire burns downward through layers.", comment: "Step Instruction")
        let _ = String(localized: "As upper layers burn, coals fall onto lower layers, igniting them in sequence. This fire can burn 3-5 hours without any attention. Also produces an excellent coal bed for cooking.", comment: "Step Detail")
        let _ = String(localized: "Bamboo Fire Saw", comment: "Technique Name")
        let _ = String(localized: "Friction fire using split bamboo", comment: "Technique Subtitle")
        let _ = String(localized: "Split a dry bamboo section in half lengthwise.", comment: "Step Instruction")
        let _ = String(localized: "Select dead, dry bamboo about 2-3 inches diameter. Split cleanly down the center. One half becomes the base (hearth), the other becomes the saw.", comment: "Step Detail")
        let _ = String(localized: "Cut a notch in the flat side of the hearth half. Place tinder beneath.", comment: "Step Instruction")
        let _ = String(localized: "Carve a small V-notch through the wall of the hearth half. Place fine tinder (dried bamboo scrapings work) under the notch to catch the hot dust.", comment: "Step Detail")
        let _ = String(localized: "Rapidly saw the edge of the saw half back and forth across the notch.", comment: "Step Instruction")
        let _ = String(localized: "Use the sharp edge of the saw piece against the notch edge of the hearth. Saw rapidly with downward pressure. Hot bamboo dust collects and forms an ember. Transfer to tinder bundle.", comment: "Step Detail")
        let _ = String(localized: "Chocolate & Can Fire", comment: "Technique Name")
        let _ = String(localized: "Polish aluminum to a mirror for solar ignition", comment: "Technique Subtitle")
        let _ = String(localized: "Apply chocolate or toothpaste to the bottom of an aluminum can.", comment: "Step Instruction")
        let _ = String(localized: "The mild abrasive in chocolate or toothpaste polishes aluminum to a mirror finish. Use the concave bottom of a soda can — it naturally focuses light when polished.", comment: "Step Detail")
        let _ = String(localized: "Polish in circular motions for 20-30 minutes until mirror-reflective.", comment: "Step Instruction")
        let _ = String(localized: "Use a cloth, paper, or your shirt. Apply more chocolate/toothpaste as needed. The bottom must be shiny enough to see your reflection clearly.", comment: "Step Detail")
        let _ = String(localized: "Aim the polished bottom at the sun. Focus the light point onto tinder.", comment: "Step Instruction")
        let _ = String(localized: "Hold tinder at the focal point (about 1-2 inches from the can bottom). The concentrated sunlight can reach ignition temperature. Works best with dark, fine tinder like charcloth.", comment: "Step Detail")
        let _ = String(localized: "Fire Fuel Stage Management", comment: "Technique Name")
        let _ = String(localized: "Understand tinder, kindling, and fuel progression", comment: "Technique Subtitle")
        let _ = String(localized: "Gather tinder: pencil-lead thin, bone dry, catches from spark.", comment: "Step Instruction")
        let _ = String(localized: "Examples: dried grass, birch bark, cedar bark shavings, cattail fluff, dryer lint, charcloth. Must ignite from spark or small flame. You need a baseball-sized bundle.", comment: "Step Detail")
        let _ = String(localized: "Gather kindling: pencil to finger thickness, catches from tinder flame.", comment: "Step Instruction")
        let _ = String(localized: "Dry twigs, split sticks, cardboard. Kindling bridges the gap between tinder and fuel. You need twice as much kindling as you think. Most fires fail from insufficient kindling.", comment: "Step Detail")
        let _ = String(localized: "Gather fuel: wrist thickness and larger, sustains the fire.", comment: "Step Instruction")
        let _ = String(localized: "Larger logs, split wood. Hardwood burns longer and hotter. Softwood ignites easier. Mix both. Collect enough for the night BEFORE you light the fire.", comment: "Step Detail")
        let _ = String(localized: "Progress through stages: tinder → kindling → fuel. Never skip.", comment: "Step Instruction")
        let _ = String(localized: "Each stage must be fully established before adding the next size. Rushing from tinder to large fuel kills the fire. Patience in the first 5 minutes saves hours of frustration.", comment: "Step Detail")
        let _ = String(localized: "Smoky Fire for Insect Repellent", comment: "Technique Name")
        let _ = String(localized: "Use smoke to drive away mosquitoes and flies", comment: "Technique Subtitle")
        let _ = String(localized: "Build a small fire and let it burn down to coals.", comment: "Step Instruction")
        let _ = String(localized: "You don't need a large fire. A small coal bed is the foundation. The goal is sustained smoke, not flames.", comment: "Step Detail")
        let _ = String(localized: "Add green leaves, damp grass, or punky wood to produce thick smoke.", comment: "Step Instruction")
        let _ = String(localized: "Green pine needles, damp leaves, and rotting (punky) wood produce the most smoke. The smoke must be continuous and enveloping. Position yourself in the smoke path.", comment: "Step Detail")
        let _ = String(localized: "Use a smudge pot (fire in a can or container) for portable smoke.", comment: "Step Instruction")
        let _ = String(localized: "Fill a container with coals and green material. Carry it to your shelter entrance or sleeping area. One smudge pot can keep insects away from a 10-foot radius.", comment: "Step Detail")
        let _ = String(localized: "Char Rope Making", comment: "Technique Name")
        let _ = String(localized: "Make extended-burn charred cordage for fire starting", comment: "Technique Subtitle")
        let _ = String(localized: "Find natural fiber rope: cotton, jute, hemp, or sisal.", comment: "Step Instruction")
        let _ = String(localized: "Synthetic rope (nylon, polyester) melts rather than charring — it won't work. Cut 6-12 inch sections of natural fiber rope.", comment: "Step Detail")
        let _ = String(localized: "Place rope in a metal container with a small vent hole. Cook in fire.", comment: "Step Instruction")
        let _ = String(localized: "Same process as making charcloth. The rope must pyrolyze (convert to carbon) without igniting. Smoke exits the vent hole. When smoke stops, it's done. Remove from fire.", comment: "Step Detail")
        let _ = String(localized: "Test: char rope should catch a spark and glow for extended time.", comment: "Step Instruction")
        let _ = String(localized: "Good char rope glows for 2-5 minutes when sparked — much longer than charcloth. This extended burn gives more time to transfer ember to tinder bundle. It's also more wind-resistant.", comment: "Step Detail")
        let _ = String(localized: "Jute Twine Fire Starter", comment: "Technique Name")
        let _ = String(localized: "Fluff jute twine into instant tinder", comment: "Technique Subtitle")
        let _ = String(localized: "Cut 6-8 inches of jute twine and unravel the strands.", comment: "Step Instruction")
        let _ = String(localized: "Jute twine is made of natural plant fibers. Separate the individual strands and then pull apart each strand into fine fibers. The finer the fibers, the easier they ignite.", comment: "Step Detail")
        let _ = String(localized: "Fluff the separated fibers into a bird's nest shape.", comment: "Step Instruction")
        let _ = String(localized: "Create a loose, airy ball of fiber. The more surface area exposed to air, the easier ignition. Leave a small depression in the center for the spark or ember.", comment: "Step Detail")
        let _ = String(localized: "Strike a ferro rod downward into the center of the nest.", comment: "Step Instruction")
        let _ = String(localized: "Jute fibers catch ferro rod sparks reliably. Once one fiber ignites, the fire spreads rapidly through the fluffed nest. Transition immediately to kindling.", comment: "Step Detail")
        let _ = String(localized: "Fire Bundle Transport", comment: "Technique Name")
        let _ = String(localized: "Carry a live ember for miles using a bundle", comment: "Technique Subtitle")
        let _ = String(localized: "Wrap a glowing coal in dry grass, bark, or punky wood.", comment: "Step Instruction")
        let _ = String(localized: "The coal needs insulation to retain heat and slow-burning material to keep it alive. Dry grass packed loosely around the coal provides fuel and insulation.", comment: "Step Detail")
        let _ = String(localized: "Enclose the wrapped coal in green bark or large green leaves.", comment: "Step Instruction")
        let _ = String(localized: "The green outer layer prevents the bundle from burning through. Birch bark, large maple leaves, or green grasses work. Tie loosely with cordage.", comment: "Step Detail")
        let _ = String(localized: "Blow gently on the bundle every 15-20 minutes to keep the ember alive.", comment: "Step Instruction")
        let _ = String(localized: "The ember smolders inside, burning slowly through the dry material. Periodic gentle blowing feeds it oxygen. A well-made bundle can keep an ember alive for 4-8 hours.", comment: "Step Detail")
        let _ = String(localized: "Fire Safety Perimeter", comment: "Technique Name")
        let _ = String(localized: "Prevent fire spread and establish safe cooking area", comment: "Technique Subtitle")
        let _ = String(localized: "Clear all flammable material in a 10-foot circle around the fire pit.", comment: "Step Instruction")
        let _ = String(localized: "Remove dry leaves, grass, twigs, and pine needles. Scrape down to mineral soil if possible. Embers can travel 10+ feet and ignite dry debris.", comment: "Step Detail")
        let _ = String(localized: "Build a ring of rocks around the fire pit.", comment: "Step Instruction")
        let _ = String(localized: "Rocks contain the fire and reflect heat inward. NEVER use river rocks or wet rocks — trapped moisture can cause them to explode from steam pressure when heated.", comment: "Step Detail")
        let _ = String(localized: "Keep water or loose soil staged nearby for emergency extinguishing.", comment: "Step Instruction")
        let _ = String(localized: "Have a container of water or a pile of dirt within arm's reach at all times. For full extinguishing: drown with water, stir the ash, drown again. Fire should be cold to the touch before leaving.", comment: "Step Detail")
        let _ = String(localized: "Zip Tie Escape", comment: "Technique Name")
        let _ = String(localized: "Break free from illegal restraints", comment: "Technique Subtitle")
        let _ = String(localized: "Urban Evasion", comment: "Category")
        let _ = String(localized: "Bring hands high above head, knuckles touching.", comment: "Step Instruction")
        let _ = String(localized: "The locking mechanism of the zip tie should be between your hands or facing outward. Do not have the lock against your skin.", comment: "Step Detail")
        let _ = String(localized: "Explosively bring hands down into your stomach.", comment: "Step Instruction")
        let _ = String(localized: "Simultaneously flare your elbows out like chicken wings. The force breaks the locking prow.", comment: "Step Detail")
        let _ = String(localized: "Alternative: Friction Saw with shoelace.", comment: "Step Instruction")
        let _ = String(localized: "Remove shoelace, thread through tie. Loop ends on feet (bicycle motion). Saw back and forth to melt plastic.", comment: "Step Detail")
        let _ = String(localized: "Door Barricade", comment: "Technique Name")
        let _ = String(localized: "Secure a room without a lock", comment: "Technique Subtitle")
        let _ = String(localized: "Use a door wedge / shim under the door.", comment: "Step Instruction")
        let _ = String(localized: "Kick a rubber wedge or wooden shim hard under the door. This prevents opening from the outside.", comment: "Step Detail")
        let _ = String(localized: "Tie the door handle to a heavy immovable object.", comment: "Step Instruction")
        let _ = String(localized: "Use belt or cordage to tie handle to a bed frame or radiator. Reduce slack to zero.", comment: "Step Detail")
        let _ = String(localized: "Chair method: Wedge chair back under the door knob.", comment: "Step Instruction")
        let _ = String(localized: "Tilt chair so top of backrest is under the knob, legs are on floor. Pressure from opening drives chair into floor.", comment: "Step Detail")
        let _ = String(localized: "Gray Man Protocol", comment: "Technique Name")
        let _ = String(localized: "Blend into crowds and avoid attention", comment: "Technique Subtitle")
        let _ = String(localized: "Remove all tactical gear and identifying patches.", comment: "Step Instruction")
        let _ = String(localized: "No camo, no morale patches, no MOLLE packs. Look like a refugee or local commuter.", comment: "Step Detail")
        let _ = String(localized: "Adjust walking pace to match the crowd baseline.", comment: "Step Instruction")
        let _ = String(localized: "Do not run (attracts pursuit). Do not loiter (attracts security). Flow with the 'river' of people.", comment: "Step Detail")
        let _ = String(localized: "Avoid eye contact but maintain situational awareness.", comment: "Step Instruction")
        let _ = String(localized: "Scan using reflections (shop windows, phone screen). Direct eye contact is a threat signal.", comment: "Step Detail")
        let _ = String(localized: "Emergency Vehicle Entry", comment: "Technique Name")
        let _ = String(localized: "Break a window safely", comment: "Technique Subtitle")
        let _ = String(localized: "Choose the side window furthest from occupants/gear.", comment: "Step Instruction")
        let _ = String(localized: "Windshields are laminated (won't shatter). Side windows are tempered (will shatter).", comment: "Step Detail")
        let _ = String(localized: "Strike the bottom corner of the glass, not the center.", comment: "Step Instruction")
        let _ = String(localized: "The center flexes. The corners are rigid break points. Use a spark plug ceramic, center punch, or sharp rock.", comment: "Step Detail")
        let _ = String(localized: "Look away and cover eyes precisely when striking.", comment: "Step Instruction")
        let _ = String(localized: "Glass dust will explode inward. Clear remaining jagged edges with a tool before reaching in.", comment: "Step Detail")
        let _ = String(localized: "Anti-Tracking Basics", comment: "Technique Name")
        let _ = String(localized: "Minimize sign and confuse pursuers", comment: "Technique Subtitle")
        let _ = String(localized: "Walk on hard surfaces (rock, pavement) to reduce footprints.", comment: "Step Instruction")
        let _ = String(localized: "Avoid mud, soft sand, and snow. Step on rocks or logs (disturbed environment detection).", comment: "Step Detail")
        let _ = String(localized: "Fish-hook maneuver: Walk past your hide site, then loop back.", comment: "Step Instruction")
        let _ = String(localized: "Walk 100m past where you intend to hide, then circle back in a wide loop to watch your own trail.", comment: "Step Detail")
        let _ = String(localized: "Avoid breaking branches or disturbing spider webs.", comment: "Step Instruction")
        let _ = String(localized: "These are 'ground sign' indicators. Move slowly and deliberately.", comment: "Step Detail")
        let _ = String(localized: "Tools & Knots", comment: "Domain Name")
        let _ = String(localized: "Bowline Knot", comment: "Technique Name")
        let _ = String(localized: "The king of knots — a fixed loop that won't slip", comment: "Technique Subtitle")
        let _ = String(localized: "Knots", comment: "Category")
        let _ = String(localized: "Form a small loop in the standing part of the rope.", comment: "Step Instruction")
        let _ = String(localized: "The 'rabbit hole.' The standing part is the long unused end. The working end is what you're tying with.", comment: "Step Detail")
        let _ = String(localized: "Pass the working end UP through the loop.", comment: "Step Instruction")
        let _ = String(localized: "The rabbit comes out of the hole.", comment: "Step Detail")
        let _ = String(localized: "Go around behind the standing part.", comment: "Step Instruction")
        let _ = String(localized: "The rabbit goes around the tree.", comment: "Step Detail")
        let _ = String(localized: "Pass back DOWN through the same loop.", comment: "Step Instruction")
        let _ = String(localized: "The rabbit goes back in the hole. Pull tight. The bowline creates a fixed-size loop that will NOT tighten under load.", comment: "Step Detail")
        let _ = String(localized: "Clove Hitch", comment: "Technique Name")
        let _ = String(localized: "Fast tie to a post or tree", comment: "Technique Subtitle")
        let _ = String(localized: "Wrap the rope around the post once.", comment: "Step Instruction")
        let _ = String(localized: "Start by going over the post, bringing the working end across the standing part.", comment: "Step Detail")
        let _ = String(localized: "Cross over the first wrap and wrap around the post again.", comment: "Step Instruction")
        let _ = String(localized: "The second wrap should go OVER the standing part, creating an X pattern.", comment: "Step Detail")
        let _ = String(localized: "Tuck the working end under the second wrap.", comment: "Step Instruction")
        let _ = String(localized: "Pull tight. The clove hitch grips under tension. Use for ridge poles, hanging clotheslines, and temporary anchors. Not for critical loads — it can slip.", comment: "Step Detail")
        let _ = String(localized: "Taut-Line Hitch", comment: "Technique Name")
        let _ = String(localized: "Adjustable tension knot for guylines", comment: "Technique Subtitle")
        let _ = String(localized: "Loop rope around anchor (tree, stake).", comment: "Step Instruction")
        let _ = String(localized: "The working end comes back toward you with the rope going around the anchor point.", comment: "Step Detail")
        let _ = String(localized: "Make 2 wraps inside the loop around the standing part.", comment: "Step Instruction")
        let _ = String(localized: "Coil the working end around the standing part INSIDE the loop — going toward the anchor. Two full wraps.", comment: "Step Detail")
        let _ = String(localized: "Make 1 wrap outside the loop above the coils.", comment: "Step Instruction")
        let _ = String(localized: "One more wrap OUTSIDE (above) the loop around the standing part.", comment: "Step Detail")
        let _ = String(localized: "Slide the knot to adjust tension.", comment: "Step Instruction")
        let _ = String(localized: "The taut-line hitch grips when loaded but slides when unloaded. Perfect for tent guylines, tarps, and clotheslines.", comment: "Step Detail")
        let _ = String(localized: "Square Lashing", comment: "Technique Name")
        let _ = String(localized: "Join two poles at right angles", comment: "Technique Subtitle")
        let _ = String(localized: "Start with a clove hitch on the vertical pole.", comment: "Step Instruction")
        let _ = String(localized: "Tie immediately below where the horizontal pole will cross. This is your anchor.", comment: "Step Detail")
        let _ = String(localized: "Weave over and under alternately around both poles.", comment: "Step Instruction")
        let _ = String(localized: "Go over the horizontal, under the vertical, over the horizontal, under the vertical. Work in a square pattern.", comment: "Step Detail")
        let _ = String(localized: "Make 3-4 complete wrapping turns.", comment: "Step Instruction")
        let _ = String(localized: "Keep wraps tight and parallel. Each turn should be snug against the previous one.", comment: "Step Detail")
        let _ = String(localized: "Frapping: wrap tightly between the poles to tighten.", comment: "Step Instruction")
        let _ = String(localized: "Frapping turns go between the poles (perpendicular to the lashing turns) and cinch everything tight. 2-3 frapping turns.", comment: "Step Detail")
        let _ = String(localized: "Finish with a clove hitch on the horizontal pole.", comment: "Step Instruction")
        let _ = String(localized: "Square lashing is used for shelter frames, racks, bridges, ladders, and any structure requiring right-angle joints.", comment: "Step Detail")
        let _ = String(localized: "Field Knife Sharpening", comment: "Technique Name")
        let _ = String(localized: "A dull knife is a dangerous knife", comment: "Technique Subtitle")
        let _ = String(localized: "Blade", comment: "Category")
        let _ = String(localized: "Find a smooth, fine-grained stone (river rock works).", comment: "Step Instruction")
        let _ = String(localized: "Sandstone, granite, or any smooth stone. The bottom of a ceramic mug also works in civilized settings. Wet the stone.", comment: "Step Detail")
        let _ = String(localized: "Hold blade at 15-20 degree angle to the stone.", comment: "Step Instruction")
        let _ = String(localized: "Lay blade flat, then raise spine about two nickels' thickness. Maintain this angle consistently — angle consistency matters more than angle precision.", comment: "Step Detail")
        let _ = String(localized: "Sweep the blade across the stone in smooth strokes, alternating sides.", comment: "Step Instruction")
        let _ = String(localized: "Edge leading, sweeping from heel to tip. Maintain consistent pressure. 10 strokes per side, then alternate.", comment: "Step Detail")
        let _ = String(localized: "Test sharpness: slice a leaf or shave arm hair.", comment: "Step Instruction")
        let _ = String(localized: "A sharp knife should slice paper or a leaf cleanly. If it tears, continue sharpening. Finish with lighter strokes for a fine edge.", comment: "Step Detail")
        let _ = String(localized: "Flint Knapping (Stone Tools)", comment: "Technique Name")
        let _ = String(localized: "Make a cutting edge from stone", comment: "Technique Subtitle")
        let _ = String(localized: "Find flint, chert, obsidian, or quartz.", comment: "Step Instruction")
        let _ = String(localized: "These glassy, fine-grained stones fracture predictably. They're found near riverbeds, chalk deposits, and volcanic areas.", comment: "Step Detail")
        let _ = String(localized: "Strike the edge with a harder hammerstone at a 45-degree angle.", comment: "Step Instruction")
        let _ = String(localized: "Strike downward and outward. The conchoidal fracture removes thin flakes. The flakes themselves are razor-sharp cutting tools.", comment: "Step Detail")
        let _ = String(localized: "Use the sharp flakes as-is for cutting.", comment: "Step Instruction")
        let _ = String(localized: "Fresh flint flakes are sharper than surgical steel. Handle with care — wrap the non-cutting edge with bark or leather.", comment: "Step Detail")
        let _ = String(localized: "Shape a larger piece into a hand axe by removing flakes around the edges.", comment: "Step Instruction")
        let _ = String(localized: "Work from both sides, thinning and shaping. This is the oldest human technology — 2.6 million years proven. It works.", comment: "Step Detail")
        let _ = String(localized: "Natural Fiber Cordage", comment: "Technique Name")
        let _ = String(localized: "Make rope from plant fibers", comment: "Technique Subtitle")
        let _ = String(localized: "Craft", comment: "Category")
        let _ = String(localized: "Gather long, strong plant fibers: inner bark, yucca, nettle, dogbane.", comment: "Step Instruction")
        let _ = String(localized: "Peel inner bark from dead trees. Soak tough fibers to soften. The longer the fibers, the stronger the cordage.", comment: "Step Detail")
        let _ = String(localized: "Bundle 2-3 fibers and twist them tightly in one direction.", comment: "Step Instruction")
        let _ = String(localized: "Pinch the bundle at the midpoint. Twist AWAY from you. This is the 'Z-twist.'", comment: "Step Detail")
        let _ = String(localized: "Fold the twisted bundle in half and let it spin back on itself.", comment: "Step Instruction")
        let _ = String(localized: "The two halves wrap around each other in the opposite direction (S-twist). This opposing twist is what creates strength.", comment: "Step Detail")
        let _ = String(localized: "Add new fibers by overlapping 2-3 inches before the old run out.", comment: "Step Instruction")
        let _ = String(localized: "Stagger additions so splices don't align. This lets you make cordage of unlimited length. Test strength after each splice.", comment: "Step Detail")
        let _ = String(localized: "Improvised Containers", comment: "Technique Name")
        let _ = String(localized: "Carry, store, and cook without pots", comment: "Technique Subtitle")
        let _ = String(localized: "Birch bark container: fold bark into box shape, pin with thorns.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark peels easily and is waterproof. Score fold lines, fold up sides, pin corners with thorns or tie with cordage.", comment: "Step Detail")
        let _ = String(localized: "Green bamboo section: cut between nodes for natural cup.", comment: "Step Instruction")
        let _ = String(localized: "The nodes form natural sealed bottoms. Cut above one node for a cup. Save longer sections for bottles.", comment: "Step Detail")
        let _ = String(localized: "Stone bowl: find a concave rock and grind it deeper.", comment: "Step Instruction")
        let _ = String(localized: "Use a harder stone to abrade the cavity. River-smooth concave rocks are ideal starting points.", comment: "Step Detail")
        let _ = String(localized: "Woven basket: weave flexible branches in over-under pattern.", comment: "Step Instruction")
        let _ = String(localized: "Willow, reed, or split bamboo. Start with a cross base, weave outward. Line with large leaves for waterproofing.", comment: "Step Detail")
        let _ = String(localized: "Making a Survival Spear", comment: "Technique Name")
        let _ = String(localized: "Defense, hunting, and utility tool", comment: "Technique Subtitle")
        let _ = String(localized: "Weapons", comment: "Category")
        let _ = String(localized: "Find a straight hardwood pole 5-6 feet long.", comment: "Step Instruction")
        let _ = String(localized: "Green hardwood — ash, oak, hickory, or ironwood. Avoid softwoods (pine, willow) which dull quickly.", comment: "Step Detail")
        let _ = String(localized: "Carve the tip with a knife or sharp stone into a point.", comment: "Step Instruction")
        let _ = String(localized: "Long, tapering point. A wider taper is stronger; a narrow taper is sharper. Compromise based on intended use.", comment: "Step Detail")
        let _ = String(localized: "Fire-harden the tip by slowly rotating above hot coals.", comment: "Step Instruction")
        let _ = String(localized: "The heat case-hardens the wood. Rotate constantly to avoid charring. The tip should darken slightly and become extremely hard.", comment: "Step Detail")
        let _ = String(localized: "For a better spear: lash a stone or metal blade to the tip.", comment: "Step Instruction")
        let _ = String(localized: "Split the shaft, insert the blade, and lash tightly with cordage. Apply pine resin over the lashing for waterproofing and adhesion.", comment: "Step Detail")
        let _ = String(localized: "Throwing Sling", comment: "Technique Name")
        let _ = String(localized: "David's weapon — hunt and defend at range", comment: "Technique Subtitle")
        let _ = String(localized: "Cut two 24-inch lengths of cordage and a leather or woven pouch.", comment: "Step Instruction")
        let _ = String(localized: "The pouch holds the projectile. Cordage can be paracord, natural fiber, or even shoelaces. The pouch should cradle a fist-sized rock.", comment: "Step Detail")
        let _ = String(localized: "Attach cords to each side of the pouch.", comment: "Step Instruction")
        let _ = String(localized: "One cord gets a finger loop (retention cord). The other gets a simple knot at the end (release cord).", comment: "Step Detail")
        let _ = String(localized: "Load a round stone and swing overhead in a circular motion.", comment: "Step Instruction")
        let _ = String(localized: "Whirl 2-3 times overhead. Smooth, round stones fly straightest. Practice extensively before hunting.", comment: "Step Detail")
        let _ = String(localized: "Release the knotted cord at the right moment to launch the projectile.", comment: "Step Instruction")
        let _ = String(localized: "Release when the stone is aimed at target (forward position in the circle). Effective range: 30-100 meters. Accurate with practice.", comment: "Step Detail")
        let _ = String(localized: "Field Gear Repair", comment: "Technique Name")
        let _ = String(localized: "Fix equipment with natural materials", comment: "Technique Subtitle")
        let _ = String(localized: "Repair", comment: "Category")
        let _ = String(localized: "Pine resin glue: melt pine sap and mix with charcoal dust.", comment: "Step Instruction")
        let _ = String(localized: "Equal parts pine resin and crushed charcoal + a small amount of fiber (rabbit droppings or dried grass). Heat until liquid, apply while warm.", comment: "Step Detail")
        let _ = String(localized: "Patch holes in fabric with pine resin and a fabric patch.", comment: "Step Instruction")
        let _ = String(localized: "Apply warm resin to both surfaces. Press together. Let cool. This waterproof patch works on tents, packs, and clothing.", comment: "Step Detail")
        let _ = String(localized: "Splint broken tool handles with sticks and cordage lashing.", comment: "Step Instruction")
        let _ = String(localized: "Place a shorter stick alongside the break. Lash tightly above and below the break. Apply pine resin over the lashing.", comment: "Step Detail")
        let _ = String(localized: "Sew tears using a bone or thorn needle and plant fiber thread.", comment: "Step Instruction")
        let _ = String(localized: "Sharpen a thin bone fragment or use a strong thorn. Thread with inner bark fiber. Use a simple running stitch.", comment: "Step Detail")
        let _ = String(localized: "Camp Organization", comment: "Technique Name")
        let _ = String(localized: "Efficient camp layout saves time and energy", comment: "Technique Subtitle")
        let _ = String(localized: "Camp", comment: "Category")
        let _ = String(localized: "Fire pit at center, downwind from shelter.", comment: "Step Instruction")
        let _ = String(localized: "Wind should blow smoke AWAY from your sleeping area. Place fire close enough for warmth but far enough to prevent sparks igniting your shelter.", comment: "Step Detail")
        let _ = String(localized: "Food storage 200 feet from camp, hung from a tree.", comment: "Step Instruction")
        let _ = String(localized: "This prevents wildlife encounters. Hang food at least 12 feet high and 6 feet from the trunk. Use a bear bag technique.", comment: "Step Detail")
        let _ = String(localized: "Latrine 200 feet from camp, downhill from water source.", comment: "Step Instruction")
        let _ = String(localized: "Dig a cat hole 6-8 inches deep. Always downstream and downhill from your water source and camp. Cover after each use.", comment: "Step Detail")
        let _ = String(localized: "Tool and supply area organized within arm's reach of shelter.", comment: "Step Instruction")
        let _ = String(localized: "Keep knife, fire kit, water, and first aid within reach even in the dark. Establish fixed locations so you find things by feel.", comment: "Step Detail")
        let _ = String(localized: "Carving a Fish Hook", comment: "Technique Name")
        let _ = String(localized: "Bone, thorn, or wood—the oldest fishing technology", comment: "Technique Subtitle")
        let _ = String(localized: "Find a thorn, bone splinter, safety pin, or hardwood twig.", comment: "Step Instruction")
        let _ = String(localized: "Hawthorn thorns are natural hooks. Bone from a meal works.", comment: "Step Detail")
        let _ = String(localized: "Gorge hook: sharpen both ends of a 1-inch splinter, tie in middle.", comment: "Step Instruction")
        let _ = String(localized: "Fish swallows it, it turns sideways and catches.", comment: "Step Detail")
        let _ = String(localized: "Curved hook: heat and bend thorn/wire into J-shape with barb.", comment: "Step Instruction")
        let _ = String(localized: "Heat over fire to make bendable. Cut small notch for barb.", comment: "Step Detail")
        let _ = String(localized: "Attach to line with clinch knot. Test pull before fishing.", comment: "Step Instruction")
        let _ = String(localized: "Thread, wrap 5 times, pull through loop.", comment: "Step Detail")
        let _ = String(localized: "Net Making", comment: "Technique Name")
        let _ = String(localized: "Catch fish and small game with woven net", comment: "Technique Subtitle")
        let _ = String(localized: "Make cordage first—need 50-100 feet minimum.", comment: "Step Instruction")
        let _ = String(localized: "Natural fiber, paracord inner strands, or any thin strong string.", comment: "Step Detail")
        let _ = String(localized: "Tie horizontal header line between two supports.", comment: "Step Instruction")
        let _ = String(localized: "This is top edge. The net hangs from this line.", comment: "Step Detail")
        let _ = String(localized: "Tie vertical lines using sheet bend knots at intervals.", comment: "Step Instruction")
        let _ = String(localized: "1-inch for minnows, 2-3 inches for larger fish.", comment: "Step Detail")
        let _ = String(localized: "Weave horizontal rows, knotting at each intersection.", comment: "Step Instruction")
        let _ = String(localized: "Use mesh gauge stick for consistency. Sheet bend at each cross.", comment: "Step Detail")
        let _ = String(localized: "Bow & Arrow Making", comment: "Technique Name")
        let _ = String(localized: "Hunting weapon from natural materials", comment: "Technique Subtitle")
        let _ = String(localized: "Find dead, dry hardwood stave — yew, ash, hickory, oak.", comment: "Step Instruction")
        let _ = String(localized: "5-6 feet, 1.5 inches thick. No cracks. Dry and springy.", comment: "Step Detail")
        let _ = String(localized: "Carve belly for flex, leave flat back intact.", comment: "Step Instruction")
        let _ = String(localized: "Never cut into the back. Taper from thick center to thin tips.", comment: "Step Detail")
        let _ = String(localized: "Notch tips. String with cordage or sinew.", comment: "Step Instruction")
        let _ = String(localized: "String slightly shorter than bow. 6-8 inches of curve when strung.", comment: "Step Detail")
        let _ = String(localized: "Arrows: straight dry sticks with sharpened tips and feather fletching.", comment: "Step Instruction")
        let _ = String(localized: "2-3 feet, pencil thickness. Weight front more than back.", comment: "Step Detail")
        let _ = String(localized: "Stone Axe Construction", comment: "Technique Name")
        let _ = String(localized: "Splitting and chopping with stone", comment: "Technique Subtitle")
        let _ = String(localized: "Primitive", comment: "Category")
        let _ = String(localized: "Find flat, hard stone with natural edge.", comment: "Step Instruction")
        let _ = String(localized: "River rocks often pre-shaped. Flat oval, fits in hand.", comment: "Step Detail")
        let _ = String(localized: "Shape edge by pecking with harder stone.", comment: "Step Instruction")
        let _ = String(localized: "Strike along intended edge. Alternate sides. Wedge shape.", comment: "Step Detail")
        let _ = String(localized: "Split green wood handle, wedge stone inside.", comment: "Step Instruction")
        let _ = String(localized: "2-foot hardwood branch. Insert head. Bind with cordage.", comment: "Step Detail")
        let _ = String(localized: "Wrap split with wet rawhide — shrinks as it dries.", comment: "Step Instruction")
        let _ = String(localized: "Creates incredibly strong bond. Figure-8 wrap pattern.", comment: "Step Detail")
        let _ = String(localized: "Bone Needle Making", comment: "Technique Name")
        let _ = String(localized: "Sewing gear from animal bone", comment: "Technique Subtitle")
        let _ = String(localized: "Crafting", comment: "Category")
        let _ = String(localized: "Select a splinter of dense leg bone (deer/cow).", comment: "Step Instruction")
        let _ = String(localized: "Fresh bone relies on natural oils. Old bone is brittle. Shatter a leg bone to get splinters.", comment: "Step Detail")
        let _ = String(localized: "Grind on sandstone to shape and sharpen.", comment: "Step Instruction")
        let _ = String(localized: "Rub against abrasive rock. Shape into a thick needle. Constant water lubrication helps.", comment: "Step Detail")
        let _ = String(localized: "Drill the eye using a sharp flint flake or metal tip.", comment: "Step Instruction")
        let _ = String(localized: "Rotate the drill back and forth. Drill halfway from one side, then meet from the other to avoid splitting.", comment: "Step Detail")
        let _ = String(localized: "Polish smooth to prevent fraying cordage.", comment: "Step Instruction")
        let _ = String(localized: "Smooth the eye hole carefully. Any rough edge will cut your thread.", comment: "Step Detail")
        let _ = String(localized: "Bark Container / Basket", comment: "Technique Name")
        let _ = String(localized: "Carry water or berries with tree bark", comment: "Technique Subtitle")
        let _ = String(localized: "Container", comment: "Category")
        let _ = String(localized: "Cut a rectangle of flexible bark (birch, poplar, elm).", comment: "Step Instruction")
        let _ = String(localized: "Peel carefully in spring/summer when sap is running. Avoid damaging the tree if possible (use fallen log).", comment: "Step Detail")
        let _ = String(localized: "Fold the corners inward to create a tub shape.", comment: "Step Instruction")
        let _ = String(localized: "Like folding a paper box. Determine the depth.", comment: "Step Detail")
        let _ = String(localized: "Secure corners with split root or cordage stitches.", comment: "Step Instruction")
        let _ = String(localized: "Punch holes with an awl. Stitch the folds together.", comment: "Step Detail")
        let _ = String(localized: "Seal seams with pine pitch for waterproofing.", comment: "Step Instruction")
        let _ = String(localized: "Melt pine resin mixed with charcoal. Smear over seams/holes to make it water-tight.", comment: "Step Detail")
        let _ = String(localized: "Advanced Bark Container", comment: "Technique Name")
        let _ = String(localized: "Watertight folded container from tree bark", comment: "Technique Subtitle")
        let _ = String(localized: "Harvest a large rectangular sheet of fresh birch, elm, or poplar bark.", comment: "Step Instruction")
        let _ = String(localized: "Fresh bark is flexible and foldable. Dead bark cracks. Score the bark and peel carefully to avoid damaging the inner layer.", comment: "Step Detail")
        let _ = String(localized: "Score fold lines for a box shape. Fold up the sides.", comment: "Step Instruction")
        let _ = String(localized: "Mark the base rectangle and score (don't cut through) the fold lines. Fold up all four sides. Overlap corners.", comment: "Step Detail")
        let _ = String(localized: "Pin corners with wooden pegs or sew with root cordage.", comment: "Step Instruction")
        let _ = String(localized: "Spruce root makes excellent sewing material. Pre-drill holes with a bone awl, then lace the root through.", comment: "Step Detail")
        let _ = String(localized: "Seal all seams with heated pine resin mixed with charcoal.", comment: "Step Instruction")
        let _ = String(localized: "Apply resin while warm along every seam. Let cool completely. Test by filling with water. Reseal any leaks.", comment: "Step Detail")
        let _ = String(localized: "Stone Drill (Pump Drill)", comment: "Technique Name")
        let _ = String(localized: "Drill holes in wood, bone, and shell", comment: "Technique Subtitle")
        let _ = String(localized: "Weapons & Tools", comment: "Category")
        let _ = String(localized: "Knap a small, sharp stone point from flint or obsidian.", comment: "Step Instruction")
        let _ = String(localized: "The drill bit needs to be small (1/4 inch) and sharp. Pressure flaking gives the best control for small points.", comment: "Step Detail")
        let _ = String(localized: "Lash the stone point to the end of a straight, round shaft.", comment: "Step Instruction")
        let _ = String(localized: "The shaft should be 12-18 inches long and perfectly straight. Split the tip, insert the stone, and wrap tightly with sinew.", comment: "Step Detail")
        let _ = String(localized: "Attach a crossbar with string to create the pump mechanism.", comment: "Step Instruction")
        let _ = String(localized: "Drill a hole through the crossbar center, thread the shaft through. Attach strings from crossbar ends to the top of the shaft. Wind by spinning.", comment: "Step Detail")
        let _ = String(localized: "Push down on the crossbar repeatedly. The string winds and unwinds, spinning the drill.", comment: "Step Instruction")
        let _ = String(localized: "Push down smoothly — the string unwinds, spinning the shaft. Let the crossbar rise — the string rewinds. Continuous pumping drills through wood and bone.", comment: "Step Detail")
        let _ = String(localized: "Fire-Hardened Spear", comment: "Technique Name")
        let _ = String(localized: "Harden a wooden spear point with fire", comment: "Technique Subtitle")
        let _ = String(localized: "Select a straight hardwood sapling 5-7 feet long.", comment: "Step Instruction")
        let _ = String(localized: "Ash, oak, hickory, or yew are ideal. The shaft should be thumb-thick. Remove all branches and bark from the tip area.", comment: "Step Detail")
        let _ = String(localized: "Carve the tip to a sharp point using a knife or sharp stone.", comment: "Step Instruction")
        let _ = String(localized: "Carve slowly, rotating the shaft. The point should be symmetrical and gradually tapered over 4-6 inches.", comment: "Step Detail")
        let _ = String(localized: "Slowly rotate the tip over hot coals (NOT in flame).", comment: "Step Instruction")
        let _ = String(localized: "The goal is to drive out moisture and harden the wood cells without burning. Rotate constantly. The wood should darken to light brown, not blacken.", comment: "Step Detail")
        let _ = String(localized: "The hardened point is now denser and more durable than raw wood.", comment: "Step Instruction")
        let _ = String(localized: "Fire-hardened points were used for millennia before stone tools. They can penetrate fish, small game, and serve as defensive weapons.", comment: "Step Detail")
        let _ = String(localized: "Sinew Cordage", comment: "Technique Name")
        let _ = String(localized: "The strongest natural fiber from animal tendons", comment: "Technique Subtitle")
        let _ = String(localized: "Remove tendons from along the backbone or leg of a game animal.", comment: "Step Instruction")
        let _ = String(localized: "The long tendons running along the spine (backstrap sinew) are best. Leg tendons from deer, elk, or similar work well. Remove carefully in long strips.", comment: "Step Detail")
        let _ = String(localized: "Dry the sinew completely — it becomes hard and brittle.", comment: "Step Instruction")
        let _ = String(localized: "Hang sinew strips in sun and wind. Fully dried sinew looks like thin white plastic. It stores indefinitely in this state.", comment: "Step Detail")
        let _ = String(localized: "When needed, chew or soak the sinew to soften it.", comment: "Step Instruction")
        let _ = String(localized: "Chewing is traditional and effective — saliva softens sinew quickly. Once pliable, separate into thin fibers. Each fiber is incredibly strong.", comment: "Step Detail")
        let _ = String(localized: "Twist or braid fibers into cord. Sinew shrinks as it dries, tightening bindings.", comment: "Step Instruction")
        let _ = String(localized: "This shrinking property makes sinew ideal for hafting (attaching stone to handles). Wrap wet sinew around the joint — as it dries, it contracts and locks tight.", comment: "Step Detail")
        let _ = String(localized: "Primitive Clay Pot", comment: "Technique Name")
        let _ = String(localized: "Make a fireproof cooking vessel from river clay", comment: "Technique Subtitle")
        let _ = String(localized: "Collect clay from riverbanks or exposed soil cuts.", comment: "Step Instruction")
        let _ = String(localized: "Good clay is smooth, sticky when wet, and holds its shape. Test: roll a pencil-sized coil. If it doesn't crack when bent into a circle, it's usable clay.", comment: "Step Detail")
        let _ = String(localized: "Mix clay with sand or crushed shell (temper) at a 4:1 ratio.", comment: "Step Instruction")
        let _ = String(localized: "Temper prevents cracking during drying and firing. Without temper, pure clay pots will crack. Crush shell or mix fine sand into the clay.", comment: "Step Detail")
        let _ = String(localized: "Build the pot using coil method — roll ropes of clay and stack.", comment: "Step Instruction")
        let _ = String(localized: "Roll clay into finger-thick ropes. Coil in a circle for the base, then build walls by stacking coils. Smooth inside and outside surfaces as you go.", comment: "Step Detail")
        let _ = String(localized: "Dry slowly for 1-2 days, then fire in a pit fire for 2-3 hours.", comment: "Step Instruction")
        let _ = String(localized: "Rapid drying or heating causes cracking. Dry in shade first. Place in fire gradually — start at the edge, move to center. After firing, the pot can withstand direct flame for cooking.", comment: "Step Detail")
        let _ = String(localized: "Atlatl (Spear Thrower)", comment: "Technique Name")
        let _ = String(localized: "Triple your spear throwing distance and power", comment: "Technique Subtitle")
        let _ = String(localized: "Carve a flat board 18-24 inches long with a handle at one end.", comment: "Step Instruction")
        let _ = String(localized: "Hardwood works best. The board should be flat and straight. One end is your grip, the other end holds the spear.", comment: "Step Detail")
        let _ = String(localized: "Carve or attach a small spur (hook) at the far end.", comment: "Step Instruction")
        let _ = String(localized: "The spur engages a dimple in the back of the dart/spear. This is the launch point — when you swing, the spur pushes the dart forward.", comment: "Step Detail")
        let _ = String(localized: "Make lightweight darts 5-6 feet long with feather fletching.", comment: "Step Instruction")
        let _ = String(localized: "Atlatl darts are lighter and longer than hand-thrown spears. Straight, dried shafts with split-feather fletching for stable flight.", comment: "Step Detail")
        let _ = String(localized: "Practice the overhand throwing motion — flick the wrist at the end.", comment: "Step Instruction")
        let _ = String(localized: "The atlatl effectively extends your arm by 2 feet, dramatically increasing dart velocity. Early humans used atlatls to hunt mammoths. Effective range: 30-40 yards.", comment: "Step Detail")
        let _ = String(localized: "Bone Fishhook", comment: "Technique Name")
        let _ = String(localized: "Carve a functional fishhook from animal bone", comment: "Technique Subtitle")
        let _ = String(localized: "Select a thin, flat bone fragment from a rib or shoulder blade.", comment: "Step Instruction")
        let _ = String(localized: "Bird bones, fish bones, and small mammal ribs work well. The bone should be thin enough to carve but strong enough not to snap.", comment: "Step Detail")
        let _ = String(localized: "Score the hook shape with a sharp stone — J-curve with a barb.", comment: "Step Instruction")
        let _ = String(localized: "Scratch the outline deeply on both sides. The hook should be 1-2 inches total. Include a small barb near the point to prevent fish from escaping.", comment: "Step Detail")
        let _ = String(localized: "Snap away excess bone and refine the shape by grinding on stone.", comment: "Step Instruction")
        let _ = String(localized: "Carefully break along the score lines. Use a rough stone to grind the hook smooth and sharpen the point. The shank needs a notch for line attachment.", comment: "Step Detail")
        let _ = String(localized: "Lash line to the shank using a snell knot or wrapping.", comment: "Step Instruction")
        let _ = String(localized: "Wrap the line around the shank several times and tie with a secure knot. Natural cordage, fishing line, or even unraveled paracord inner strands work.", comment: "Step Detail")
        let _ = String(localized: "Bark Cloth Processing", comment: "Technique Name")
        let _ = String(localized: "Make flexible fabric from inner tree bark", comment: "Technique Subtitle")
        let _ = String(localized: "Harvest inner bark strips from paper mulberry, basswood, or elm.", comment: "Step Instruction")
        let _ = String(localized: "Peel in spring when bark separates easily. You want the inner bark (cambium layer), not the rough outer bark. Take from fallen or dead trees when possible.", comment: "Step Detail")
        let _ = String(localized: "Soak the bark strips in water for 1-2 days.", comment: "Step Instruction")
        let _ = String(localized: "Soaking softens the fibers and makes them pliable. The bark should become flexible like wet leather when ready.", comment: "Step Detail")
        let _ = String(localized: "Pound the soaked bark with a smooth stone or wooden mallet.", comment: "Step Instruction")
        let _ = String(localized: "Pound on a flat surface, rotating and folding. The fibers separate and interlock. Continue until the bark is thin, flexible, and fabric-like.", comment: "Step Detail")
        let _ = String(localized: "Dry the bark cloth in the sun. It becomes a durable, flexible fabric.", comment: "Step Instruction")
        let _ = String(localized: "Bark cloth was used worldwide before woven textiles. It can be sewn, folded, and layered. Use for clothing, bandages, cordage backing, or shelter material.", comment: "Step Detail")
        let _ = String(localized: "Bamboo Multi-Tool Construction", comment: "Technique Name")
        let _ = String(localized: "Create cutting, scraping, and stabbing tools from bamboo", comment: "Technique Subtitle")
        let _ = String(localized: "Cutting Tools", comment: "Category")
        let _ = String(localized: "Select a green bamboo section at least 1 inch diameter.", comment: "Step Instruction")
        let _ = String(localized: "Green bamboo is flexible and won't splinter as badly as dry. Cut a section between two nodes for maximum strength. Bamboo edge cuts through skin easily — handle carefully even before shaping.", comment: "Step Detail")
        let _ = String(localized: "Split lengthwise by scoring and applying pressure. Shape the edge with a rock.", comment: "Step Instruction")
        let _ = String(localized: "Score a line with a sharp rock, then apply pressure to split along the grain. The split edge is razor-sharp. For a knife: shape one end to a point. For a scraper: leave the edge wide. For a spear: fire-harden the tip.", comment: "Step Detail")
        let _ = String(localized: "Fire-harden the edge by slowly rotating over hot coals. Do not burn.", comment: "Step Instruction")
        let _ = String(localized: "Hold the working edge 4-6 inches above coals. Rotate continuously. The heat drives out moisture and hardens the fibers. The edge should darken slightly but not char. Fire-hardened bamboo holds its edge remarkably well.", comment: "Step Detail")
        let _ = String(localized: "Natural Adhesive Making", comment: "Technique Name")
        let _ = String(localized: "Create glue from pine resin, birch bark, or hide", comment: "Technique Subtitle")
        let _ = String(localized: "Adhesives", comment: "Category")
        let _ = String(localized: "Collect pine or spruce resin from tree wounds. Look for amber-colored lumps.", comment: "Step Instruction")
        let _ = String(localized: "Conifers produce sticky resin at wound sites. Collect the hardened amber lumps — they peel off easily. You need about a golf ball-sized amount for useful quantities of glue.", comment: "Step Detail")
        let _ = String(localized: "Melt resin over low heat. Mix with crushed charcoal (1:1 ratio) and optional plant fiber.", comment: "Step Instruction")
        let _ = String(localized: "Melt in a stone or shell vessel over coals. Pure resin is brittle when cool. Adding ground charcoal creates a flexible, strong adhesive. A pinch of plant fiber adds tensile strength. Stir thoroughly while hot.", comment: "Step Detail")
        let _ = String(localized: "Apply hot to the joint. It sets in 1-2 minutes as it cools.", comment: "Step Instruction")
        let _ = String(localized: "Apply to both surfaces while molten. Press together firmly and hold for 2 minutes. Can be reheated and reapplied by warming near fire. This pitch glue is waterproof and strong enough for tool hafting and waterproofing containers.", comment: "Step Detail")
        let _ = String(localized: "Torch Construction", comment: "Technique Name")
        let _ = String(localized: "Build a reliable portable light source", comment: "Technique Subtitle")
        let _ = String(localized: "Light & Fire", comment: "Category")
        let _ = String(localized: "Find a green hardwood stick 2-3 feet long and 1-2 inches thick.", comment: "Step Instruction")
        let _ = String(localized: "Green wood won't catch fire as easily as dry. Hardwood lasts longer than softwood. Split the top end into a cross pattern about 4 inches deep to create a cradle for fuel material.", comment: "Step Detail")
        let _ = String(localized: "Pack the split top with birch bark, pine resin, cloth, or fatwood shavings.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark burns bright and long. Pine resin-soaked materials burn brightest. Wrap tightly and secure with cordage. A torch wrapped with birch bark strips burns 20-30 minutes. Adding resin extends life.", comment: "Step Detail")
        let _ = String(localized: "Light from existing fire. Hold at 45-degree angle to control dripping.", comment: "Step Instruction")
        let _ = String(localized: "Angle matters: too vertical drips hot material on your hand; too horizontal burns out faster. Walk slowly — wind will extinguish a fast-moving torch. Carry backup fuel material to repack when it burns low.", comment: "Step Detail")
        let _ = String(localized: "Improvised Fishing Hooks", comment: "Technique Name")
        let _ = String(localized: "Create functional hooks from bone, wood, thorns, and wire", comment: "Technique Subtitle")
        let _ = String(localized: "Foraging Tools", comment: "Category")
        let _ = String(localized: "Gorge hook: carve a 1-inch sliver of bone or hardwood pointed at both ends.", comment: "Step Instruction")
        let _ = String(localized: "The gorge hook is the oldest fishing technology. Sharpen both ends. Tie line to the middle. Bait covers the entire hook. When the fish swallows, pull — the gorge turns sideways and lodges in the throat.", comment: "Step Detail")
        let _ = String(localized: "Thorn hook: select a strong thorn from hawthorn, honey locust, or similar tree.", comment: "Step Instruction")
        let _ = String(localized: "Natural thorns make excellent small hooks. Lash to a small twig at an angle to create the hook shape. Works best for small fish. Black locust and hawthorn thorns are ideal — strong, sharp, and curved.", comment: "Step Detail")
        let _ = String(localized: "Composite hook: lash a sharp bone point to a hardwood shank at 45 degrees.", comment: "Step Instruction")
        let _ = String(localized: "Carve a shank from hardwood with a notch for the point. Lash a sharpened bone fragment at 45 degrees. Secure with pitch glue and cordage. This style is strong enough for large fish. Barb the point with a small notch.", comment: "Step Detail")
        let _ = String(localized: "Universal Trap Trigger Mechanisms", comment: "Technique Name")
        let _ = String(localized: "Master the trigger systems used in all primitive traps", comment: "Technique Subtitle")
        let _ = String(localized: "Trapping", comment: "Category")
        let _ = String(localized: "Two-stick toggle trigger: carve two sticks with matching notches that hold under tension.", comment: "Step Instruction")
        let _ = String(localized: "Carve a hook shape on each stick that interlocks. One anchored to ground, one attached to the spring/weight. Tension holds them together. Slight movement releases. This is the basis for most snares and deadfalls.", comment: "Step Detail")
        let _ = String(localized: "Figure-4 trigger: three sticks notched to create a free-standing support.", comment: "Step Instruction")
        let _ = String(localized: "Vertical post, horizontal bait stick, and diagonal support. Notches interlock to hold weight above. When bait stick is disturbed, the system collapses. Practice assembly 20+ times before field use — timing and fit are critical.", comment: "Step Detail")
        let _ = String(localized: "Spring snare trigger: a peg-in-notch system attached to a bent sapling.", comment: "Step Instruction")
        let _ = String(localized: "Bend a sapling over the trail. Attach a trigger line to a toggle peg seated in a notched base stake. The noose loops around the peg. When an animal enters the noose and pulls, the peg releases and the sapling springs up.", comment: "Step Detail")
        let _ = String(localized: "Digging Stick & Pry Bar", comment: "Technique Name")
        let _ = String(localized: "The most fundamental and versatile primitive tool", comment: "Technique Subtitle")
        let _ = String(localized: "Multi-Purpose", comment: "Category")
        let _ = String(localized: "Select a hardwood branch 3-4 feet long, 1.5-2 inches diameter.", comment: "Step Instruction")
        let _ = String(localized: "Hardwoods (oak, maple, hickory) are strongest. Green wood is better than dead wood for initial shaping. Select straight stock with no major knots or weak points.", comment: "Step Detail")
        let _ = String(localized: "Sharpen one end to a chisel or point using a knife or sharp rock.", comment: "Step Instruction")
        let _ = String(localized: "For digging: chisel shape (flat edge) works best. For prying: wedge shape. For planting/probing: pointed tip. Shape the non-working end into a comfortable grip. Remove bark for better grip.", comment: "Step Detail")
        let _ = String(localized: "Fire-harden the working end by slowly rotating over coals.", comment: "Step Instruction")
        let _ = String(localized: "This drives out moisture, compresses fibers, and creates a much harder surface. The tip should turn golden-brown, not black. A fire-hardened digging stick can break through hard clay and frozen ground.", comment: "Step Detail")
        let _ = String(localized: "Cobble Hammer & Hammerstone", comment: "Technique Name")
        let _ = String(localized: "Create a basic impact tool for splitting, pounding, and shaping", comment: "Technique Subtitle")
        let _ = String(localized: "Impact Tools", comment: "Category")
        let _ = String(localized: "Find a dense, egg-shaped river cobble that fits comfortably in your hand.", comment: "Step Instruction")
        let _ = String(localized: "River rocks are pre-shaped by water and free of fracture lines. Granite, basalt, and quartzite are ideal. Avoid sandstone (too soft) and layered rocks (will shatter). Test by striking another rock — it should feel solid.", comment: "Step Detail")
        let _ = String(localized: "For a hafted hammer: find a stone with a natural groove or pecked groove for binding.", comment: "Step Instruction")
        let _ = String(localized: "Wrap cordage in the groove and lash to a wooden handle. Green wood handle with a split end gripping the stone is strongest. Secure with wet rawhide — it shrinks as it dries, creating an incredibly tight bond.", comment: "Step Detail")
        let _ = String(localized: "Use different faces for different tasks: flat for pounding, edge for splitting.", comment: "Step Instruction")
        let _ = String(localized: "The flat face crushes nuts and pounds stakes. An edge face splits wood. A pointed face chips other stones for tool making. One good hammerstone serves dozens of purposes — it's arguably the most versatile primitive tool.", comment: "Step Detail")
        let _ = String(localized: "Improvised Water Containers", comment: "Technique Name")
        let _ = String(localized: "Build containers to collect, carry, and store water", comment: "Technique Subtitle")
        let _ = String(localized: "Containers", comment: "Category")
        let _ = String(localized: "Birch bark container: fold bark into a box shape, secure with pins or cordage.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark is waterproof and foldable when fresh. Score fold lines, fold up sides, and pin corners with wood pegs or sew with root cordage. Seal seams with pitch glue. Holds water for days.", comment: "Step Detail")
        let _ = String(localized: "Animal stomach or bladder: turn inside out, rinse, and inflate to dry.", comment: "Step Instruction")
        let _ = String(localized: "After harvesting game, save the stomach and bladder. Rinse thoroughly, turn inside out, and inflate. Once dry, they make excellent water carriers. The stomach can hold 1-2 liters. Tie the openings with cordage.", comment: "Step Detail")
        let _ = String(localized: "Bamboo water bottle: cut a section with one node intact as the bottom.", comment: "Step Instruction")
        let _ = String(localized: "Cut bamboo at an angle just above a node (sealed end = bottom). The natural tube holds water perfectly. Carve a wooden plug for the top. A 4-inch diameter bamboo section holds about 1 liter. Carry multiple.", comment: "Step Detail")
        let _ = String(localized: "Improvised Snow Goggles", comment: "Technique Name")
        let _ = String(localized: "Prevent snow blindness with improvised eye protection", comment: "Technique Subtitle")
        let _ = String(localized: "Protective Gear", comment: "Category")
        let _ = String(localized: "Select material: birch bark, cardboard, leather, or any opaque flexible sheet.", comment: "Step Instruction")
        let _ = String(localized: "Snow blindness (UV keratitis) causes temporary but extremely painful blindness within hours of bright snow exposure. Even overcast days in snow reflect enough UV to cause damage. Prevention is critical — treatment is rest in darkness.", comment: "Step Detail")
        let _ = String(localized: "Cut a strip to cover both eyes. Cut narrow horizontal slits (1mm) at each eye position.", comment: "Step Instruction")
        let _ = String(localized: "The slits should be about 1-2 inches wide and as narrow as possible while still allowing vision. Narrower = better UV protection. You need enough vision to navigate but minimal light entry.", comment: "Step Detail")
        let _ = String(localized: "Attach cordage or elastic to wrap around the head. Blacken the inner surface.", comment: "Step Instruction")
        let _ = String(localized: "Darken the inside surface with charcoal or soot to reduce reflective glare. Secure with cordage tied behind the head. These goggles reduce UV exposure by 90%+ and are the difference between navigating and incapacitation.", comment: "Step Detail")
        let _ = String(localized: "Hand Drill Fire Optimization", comment: "Technique Name")
        let _ = String(localized: "Improve your hand drill technique for reliable fire", comment: "Technique Subtitle")
        let _ = String(localized: "Fire Tools", comment: "Category")
        let _ = String(localized: "Select spindle: dead, dry, straight, pithy stem. Mullein, cattail, or elderberry ideal.", comment: "Step Instruction")
        let _ = String(localized: "The spindle must be straight, 18-24 inches long, and 3/8 to 1/2 inch diameter. Pithy stems work best — the soft center creates more friction. Dead and dry is critical. Green wood will never produce enough heat.", comment: "Step Detail")
        let _ = String(localized: "Floating hand technique: alternate hands downward while maintaining speed and pressure.", comment: "Step Instruction")
        let _ = String(localized: "The biggest hand drill failure is losing speed while resetting hand position. Float your hands down the spindle with continuous downward pressure and rotation. When you reach the bottom, quickly snap back to the top without stopping.", comment: "Step Detail")
        let _ = String(localized: "Add friction enhancers: sand in the notch, and moisture from crushed green plants on your palms.", comment: "Step Instruction")
        let _ = String(localized: "A pinch of fine sand in the hearth board notch increases friction dramatically. Rub crushed green plantain leaves on your palms — the slight tackiness prevents slipping. These two additions make the hand drill significantly easier.", comment: "Step Detail")
        let _ = String(localized: "Figure-4 Deadfall Trap", comment: "Technique Name")
        let _ = String(localized: "Build a crushing trap for small game", comment: "Technique Subtitle")
        let _ = String(localized: "Carve three sticks: vertical post, horizontal bait bar, diagonal support.", comment: "Step Instruction")
        let _ = String(localized: "Each stick needs specific notches to interlock. Vertical: flat notch at top, square notch at bottom. Diagonal: point at bottom, flat notch at top matching vertical. Horizontal: square notch to engage vertical, bait on far end.", comment: "Step Detail")
        let _ = String(localized: "Assemble the three sticks into a figure-4 shape under a heavy flat rock.", comment: "Step Instruction")
        let _ = String(localized: "The rock must be heavy enough to kill instantly — 5x the animal's weight minimum. A 2-pound squirrel needs a 10-pound rock. Test the trigger by gently touching the bait bar — it should collapse with light touch.", comment: "Step Detail")
        let _ = String(localized: "Bait with local food sources. Place along animal trails with guide fences.", comment: "Step Instruction")
        let _ = String(localized: "Build small stick fences on either side to funnel the animal toward the bait. Smear bait on the horizontal stick. Place at trail junctions or near den entrances. Set at dusk, check at dawn. Reset daily.", comment: "Step Detail")
        let _ = String(localized: "Basic Hide Tanning", comment: "Technique Name")
        let _ = String(localized: "Preserve animal hides for clothing, cordage, and containers", comment: "Technique Subtitle")
        let _ = String(localized: "Processing", comment: "Category")
        let _ = String(localized: "Flesh the hide: scrape all meat, fat, and membrane from the inner surface.", comment: "Step Instruction")
        let _ = String(localized: "Stretch the hide on a frame or flat log. Use a scraper made from bone, rock edge, or split hardwood. Remove every trace of flesh — any remaining will rot and stink. This is the most critical and time-consuming step.", comment: "Step Detail")
        let _ = String(localized: "Brain tan: mash the animal's brain and rub into the hide thoroughly.", comment: "Step Instruction")
        let _ = String(localized: "Every animal has enough brain to tan its own hide. Mash brain with warm water into a paste. Rub into every square inch of the hide, both sides. The oils in the brain preserve and soften the leather. Let soak overnight.", comment: "Step Detail")
        let _ = String(localized: "Smoke the hide over a slow smoldering fire to set the tan.", comment: "Step Instruction")
        let _ = String(localized: "After brain tanning and drying, the leather will stiffen if it gets wet — unless smoked. Drape over a smoldering fire (punk wood, no flame) for 2-4 hours per side. The smoke locks in the oils and makes the hide permanently soft.", comment: "Step Detail")
        let _ = String(localized: "Charcoal Water Filter Construction", comment: "Technique Name")
        let _ = String(localized: "Build a gravity-fed filter from natural materials", comment: "Technique Subtitle")
        let _ = String(localized: "Water Tools", comment: "Category")
        let _ = String(localized: "Make charcoal: burn hardwood to coals, then smother. Crush into small pieces.", comment: "Step Instruction")
        let _ = String(localized: "Good charcoal is jet black, lightweight, and breaks clean. Burns to coals then cover with dirt or ash to smother. Once cool, crush to pea-sized or smaller. Charcoal absorbs chemicals, bacteria, and improves taste.", comment: "Step Detail")
        let _ = String(localized: "Layer in container: coarse gravel (bottom), fine sand, crushed charcoal, fine sand, grass (top).", comment: "Step Instruction")
        let _ = String(localized: "Use a hollow log, birch bark tube, or plastic bottle with bottom cut off. Layers from bottom: rocks → gravel → sand → charcoal → sand → grass. Each layer ~2 inches. The grass pre-filters debris, charcoal does the heavy work.", comment: "Step Detail")
        let _ = String(localized: "Pour water through top. Collect filtered water below. STILL BOIL before drinking.", comment: "Step Instruction")
        let _ = String(localized: "This filter removes sediment, improves taste, and reduces (not eliminates) bacteria. The charcoal absorbs many chemical contaminants. But it does NOT reliably kill all pathogens — always boil filtered water before drinking.", comment: "Step Detail")
        let _ = String(localized: "Improvised Cutting Tools", comment: "Technique Name")
        let _ = String(localized: "Create saws and cutting edges from found materials", comment: "Technique Subtitle")
        let _ = String(localized: "Wire saw: twist two strands of wire together. Loop handles at each end.", comment: "Step Instruction")
        let _ = String(localized: "Salvaged wire from fencing, vehicles, or electronics works. Twist two strands tight for rigidity. Loops at each end fit over sticks for handles. Draw back and forth — cuts wood surprisingly fast. Works on bone too.", comment: "Step Detail")
        let _ = String(localized: "Stone edge tool: find flint, obsidian, or fine-grained stone and strike flakes.", comment: "Step Instruction")
        let _ = String(localized: "Hard percussion (striking with a hammerstone) removes large flakes. Soft percussion (antler or hardwood baton) removes thinner, sharper flakes. A fresh flake edge is sharper than surgical steel. Handle carefully.", comment: "Step Detail")
        let _ = String(localized: "Tin can knife: cut a can in half, fold the edge over for a handle.", comment: "Step Instruction")
        let _ = String(localized: "An aluminum can edge is razor-sharp when cut. Fold one edge over several times for a grip. The working edge cuts cordage, flesh, and thin materials. Wrap the handle in cloth or bark to prevent cuts. Short lifespan but immediate results.", comment: "Step Detail")
        let _ = String(localized: "Improvised Fishing & Trapping Net", comment: "Technique Name")
        let _ = String(localized: "Construct nets from natural cordage for fishing and trapping", comment: "Technique Subtitle")
        let _ = String(localized: "Make cordage from plant fibers: dogbane, nettle, milkweed, or inner bark.", comment: "Step Instruction")
        let _ = String(localized: "Split stems lengthwise, scrape out pith, and twist the outer fibers into cordage using the reverse-twist method. You need a LOT of cordage — a small net requires 50+ feet. Start cordage production as a background task every day.", comment: "Step Detail")
        let _ = String(localized: "Tie a mesh net using sheet bend knots or overhand knots at regular intervals.", comment: "Step Instruction")
        let _ = String(localized: "Use a gauge stick to keep mesh openings consistent. Smaller mesh = smaller fish caught. 1-inch mesh for pan fish, 2-inch for larger. Work row by row, tying each new cord to the previous row's loops.", comment: "Step Detail")
        let _ = String(localized: "Attach weights (stones) to the bottom edge and floats (bark pieces) to the top.", comment: "Step Instruction")
        let _ = String(localized: "The net must hang vertically in water. Stones every 6 inches on the bottom, bark or wood floats on top. Set across a stream with stake anchors. Fish swim into the mesh and become tangled. Check every few hours.", comment: "Step Detail")
        let _ = String(localized: "Shelter", comment: "Domain Name")
        let _ = String(localized: "Lean-To Shelter", comment: "Technique Name")
        let _ = String(localized: "Quick, basic protection from wind and rain", comment: "Technique Subtitle")
        let _ = String(localized: "Forest", comment: "Category")
        let _ = String(localized: "Find two trees about 6 feet apart to support your crossbar.", comment: "Step Instruction")
        let _ = String(localized: "Trees should be sturdy enough to hold weight. Distance determines shelter length. Ensure the area between them is flat.", comment: "Step Detail")
        let _ = String(localized: "Lash a sturdy pole between the trees at waist height.", comment: "Step Instruction")
        let _ = String(localized: "This is your ridgepole. Use square lashing or a jamming knot. Ensure it is level.", comment: "Step Detail")
        let _ = String(localized: "Lean poles against the crossbar at a 45-degree angle.", comment: "Step Instruction")
        let _ = String(localized: "Place them close together on the windward side. This creates the wall that blocks the wind.", comment: "Step Detail")
        let _ = String(localized: "Weave smaller branches or vines horizontally through the leaning poles.", comment: "Step Instruction")
        let _ = String(localized: "This creates a lattice to hold the roofing material. It prevents leaves from falling through.", comment: "Step Detail")
        let _ = String(localized: "Pile debris, leaves, or boughs against the wall from bottom to top.", comment: "Step Instruction")
        let _ = String(localized: "Shingle the material so rain runs off. Thickness should be at least 1-2 feet for insulation.", comment: "Step Detail")
        let _ = String(localized: "A-Frame Debris Hut", comment: "Technique Name")
        let _ = String(localized: "High insulation value for cold nights", comment: "Technique Subtitle")
        let _ = String(localized: "Place a long ridgepole with one end on the ground and the other on a stump or tree branch.", comment: "Step Instruction")
        let _ = String(localized: "The pole should be slightly longer than your body. The elevated end should be hip-high.", comment: "Step Detail")
        let _ = String(localized: "Lean sticks against the ridgepole on both sides to form an A-frame.", comment: "Step Instruction")
        let _ = String(localized: "Leave a small opening at the high end for entry. The outcome should look like a skeletal tent.", comment: "Step Detail")
        let _ = String(localized: "Pile massive amounts of debris over the framework.", comment: "Step Instruction")
        let _ = String(localized: "Leaves, grass, pine needles. Aim for 3 feet of thickness for warmth. Don't skimp.", comment: "Step Detail")
        let _ = String(localized: "Add a final layer of bark or branches to hold the debris in place.", comment: "Step Instruction")
        let _ = String(localized: "This prevents wind from stripping away your insulation.", comment: "Step Detail")
        let _ = String(localized: "Stuff the interior with dry leaves or grass for bedding.", comment: "Step Instruction")
        let _ = String(localized: "Fill it completely, then burrow in. This creates dead air space around your body.", comment: "Step Detail")
        let _ = String(localized: "Round Debris Hut", comment: "Technique Name")
        let _ = String(localized: "Warmth for groups or sitting up", comment: "Technique Subtitle")
        let _ = String(localized: "Create a tripod base by lashing three long poles together at the top.", comment: "Step Instruction")
        let _ = String(localized: "Spread the legs wide enough for the occupants. This forms the peak of your cone.", comment: "Step Detail")
        let _ = String(localized: "Lean more poles against the tripod to close the gaps.", comment: "Step Instruction")
        let _ = String(localized: "Ideally, place them close together to support the insulation. Leave a door gap.", comment: "Step Detail")
        let _ = String(localized: "Thatch or pile debris heavily around the entire cone.", comment: "Step Instruction")
        let _ = String(localized: "Like the A-frame, thickness is key. 2-3 feet of debris is needed for real warmth.", comment: "Step Detail")
        let _ = String(localized: "Build a small door plug from tied branches.", comment: "Step Instruction")
        let _ = String(localized: "You pull this in after you to seal the entrance.", comment: "Step Detail")
        let _ = String(localized: "Tarp: A-Frame", comment: "Technique Name")
        let _ = String(localized: "Classic rain protection", comment: "Technique Subtitle")
        let _ = String(localized: "Tarp", comment: "Category")
        let _ = String(localized: "Find two anchor points 6-8 feet apart: trees, poles, or stakes.", comment: "Step Instruction")
        let _ = String(localized: "Spacing depends on tarp size. Ridgeline should be taut and about chest height. Use trees 6-8 feet apart for a standard 8x10 tarp.", comment: "Step Detail")
        let _ = String(localized: "Tie ridgeline between anchors using taut-line hitches.", comment: "Step Instruction")
        let _ = String(localized: "Run paracord or rope tight between two trees at chest height. A taut-line hitch allows you to tension the line without retying. The ridgeline is the backbone of your shelter.", comment: "Step Detail")
        let _ = String(localized: "Drape tarp over ridgeline evenly, with equal material on both sides.", comment: "Step Instruction")
        let _ = String(localized: "Center the tarp on the line. The ridgeline should run along the peak of the A-frame. In windy conditions, offset slightly so the wind side has more material.", comment: "Step Detail")
        let _ = String(localized: "Stake down each corner at 45-degree angle, pulling tarp taut.", comment: "Step Instruction")
        let _ = String(localized: "Use tent stakes, sharpened sticks, or heavy rocks. Angle stakes at 45 degrees away from the tarp for maximum hold. The tarp should be drum-tight to shed water properly.", comment: "Step Detail")
        let _ = String(localized: "Add ground insulation: leaves, pine needles, or boughs inside.", comment: "Step Instruction")
        let _ = String(localized: "The ground steals more heat than cold air. Pile at least 4 inches of material underneath your sleeping area. Compressed insulation loses effectiveness — use fluffy, dry material.", comment: "Step Detail")
        let _ = String(localized: "Tarp: Lean-To", comment: "Technique Name")
        let _ = String(localized: "Good for heat reflection from fire", comment: "Technique Subtitle")
        let _ = String(localized: "Tie ridgeline between two trees at about 4 feet high.", comment: "Step Instruction")
        let _ = String(localized: "Lower than an A-frame. One side of the tarp touches the ground, the other is elevated. Orient the high side away from wind direction.", comment: "Step Detail")
        let _ = String(localized: "Attach one long edge of tarp to the ridgeline with clips or ties.", comment: "Step Instruction")
        let _ = String(localized: "Use grommet ties, binder clips, or wrap the edge over the line and pin with sticks. Space attachment points every 12 inches for wind resistance.", comment: "Step Detail")
        let _ = String(localized: "Pull opposite edge down to ground and stake at 45-degree angle.", comment: "Step Instruction")
        let _ = String(localized: "The angle of the lean-to determines wind/rain shedding vs. interior space. Steeper angle = better rain shedding. Shallower angle = more usable space.", comment: "Step Detail")
        let _ = String(localized: "Build a reflector fire 6 feet in front of the opening.", comment: "Step Instruction")
        let _ = String(localized: "A fire in front of a lean-to radiates heat into the shelter. Build a log reflector wall behind the fire to bounce even more heat toward you. Keep fire at a safe distance.", comment: "Step Detail")
        let _ = String(localized: "Add side walls with brush or additional tarp for wind protection.", comment: "Step Instruction")
        let _ = String(localized: "Stack brush, branches, or pine boughs on the sides to block crosswind. Even a partial wind block significantly increases warmth.", comment: "Step Detail")
        let _ = String(localized: "Tarp: C-Fly", comment: "Technique Name")
        let _ = String(localized: "Ground sheet + overhead cover", comment: "Technique Subtitle")
        let _ = String(localized: "Stake one side of the tarp to the ground.", comment: "Step Instruction")
        let _ = String(localized: "This will be the bottom edge of your ground sheet.", comment: "Step Detail")
        let _ = String(localized: "Tuck 1/3 of the tarp underneath itself.", comment: "Step Instruction")
        let _ = String(localized: "This creates a floor. You explicitly sleep on this section.", comment: "Step Detail")
        let _ = String(localized: "Prop up the remaining section with poles.", comment: "Step Instruction")
        let _ = String(localized: "Use two poles at the corners and guy lines to pull it taut. It creates a wedge shape.", comment: "Step Detail")
        let _ = String(localized: "Tarp: Diamond", comment: "Technique Name")
        let _ = String(localized: "Fast setup with one tree", comment: "Technique Subtitle")
        let _ = String(localized: "Tie one corner of the tarp to a tree at head height.", comment: "Step Instruction")
        let _ = String(localized: "This is the peak. The rest of the tarp hangs loose.", comment: "Step Detail")
        let _ = String(localized: "Stake the opposite corner to the ground.", comment: "Step Instruction")
        let _ = String(localized: "Pull it taut straight back from the tree.", comment: "Step Detail")
        let _ = String(localized: "Stake the side corners out wide.", comment: "Step Instruction")
        let _ = String(localized: "This opens up the interior space. Adjust tension to remove wrinkles.", comment: "Step Detail")
        let _ = String(localized: "Snow Trench", comment: "Technique Name")
        let _ = String(localized: "Fast winter survival shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Dig a trench in the snow, slightly longer than your body.", comment: "Step Instruction")
        let _ = String(localized: "Make it deep enough to sit up in if possible, but at least 3 feet deep.", comment: "Step Detail")
        let _ = String(localized: "Line the bottom with boughs or insulation.", comment: "Step Instruction")
        let _ = String(localized: "Snow sucks heat. You need a barrier between you and the ground.", comment: "Step Detail")
        let _ = String(localized: "Roof the trench with skis, poles, or sticks.", comment: "Step Instruction")
        let _ = String(localized: "Lay them across the top to support a tarp or snow blocks.", comment: "Step Detail")
        let _ = String(localized: "Cover the roof with a tarp and snow.", comment: "Step Instruction")
        let _ = String(localized: "Snow insulates. Pile it gently on top of the tarp.", comment: "Step Detail")
        let _ = String(localized: "Quinzhee", comment: "Technique Name")
        let _ = String(localized: "Snow dome for extreme cold", comment: "Technique Subtitle")
        let _ = String(localized: "Pile snow into a large mound, 6-7 feet high.", comment: "Step Instruction")
        let _ = String(localized: "Mix different snow types. Disturbed snow hardens (sinters) as it sits.", comment: "Step Detail")
        let _ = String(localized: "Let the mound settle/harden for at least 2 hours.", comment: "Step Instruction")
        let _ = String(localized: "This step is critical. If you dig too soon, it will collapse.", comment: "Step Detail")
        let _ = String(localized: "Insert 12-inch guide sticks all over the dome.", comment: "Step Instruction")
        let _ = String(localized: "These tell you when to stop digging from the inside so walls are uniform.", comment: "Step Detail")
        let _ = String(localized: "Excavate the interior, starting from a low entrance.", comment: "Step Instruction")
        let _ = String(localized: "Throw snow out behind you. Dig until you see the ends of your guide sticks.", comment: "Step Detail")
        let _ = String(localized: "Igloo", comment: "Technique Name")
        let _ = String(localized: "Block construction for hard pack snow", comment: "Technique Subtitle")
        let _ = String(localized: "Cut firm snow blocks with a saw or knife.", comment: "Step Instruction")
        let _ = String(localized: "Blocks should be consistent size (e.g., 2ft x 1ft). Needs hard wind-packed snow.", comment: "Step Detail")
        let _ = String(localized: "Lay the first circle of blocks.", comment: "Step Instruction")
        let _ = String(localized: "Make the circle diameter appropriate for the number of people.", comment: "Step Detail")
        let _ = String(localized: "Cut a slope into the first layer.", comment: "Step Instruction")
        let _ = String(localized: "This creates a spiral ramp. Essential for the dome shape.", comment: "Step Detail")
        let _ = String(localized: "Stack subsequent blocks in a rising spiral.", comment: "Step Instruction")
        let _ = String(localized: "Lean them inward slightly. The spiral shape provides structural support.", comment: "Step Detail")
        let _ = String(localized: "Cap the top with a final keystone block.", comment: "Step Instruction")
        let _ = String(localized: "Trim it to fit the final hole perfectly from the outside.", comment: "Step Detail")
        let _ = String(localized: "Wickiup", comment: "Technique Name")
        let _ = String(localized: "Sturdy tipi-style shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Find a tripod of trees or lash three poles together.", comment: "Step Instruction")
        let _ = String(localized: "Similar to the debris hut but steeper and taller for more headroom.", comment: "Step Detail")
        let _ = String(localized: "Add many vertical poles around the frame.", comment: "Step Instruction")
        let _ = String(localized: "Create a solid wooden cone. Leave a smoke hole at top if you plan a fire.", comment: "Step Detail")
        let _ = String(localized: "Cover with mats, bark, or boughs.", comment: "Step Instruction")
        let _ = String(localized: "Layer them like shingles. Bark works excellent for rain proofing.", comment: "Step Detail")
        let _ = String(localized: "Tree Well Shelter", comment: "Technique Name")
        let _ = String(localized: "Emergency deep snow shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Find a large evergreen tree with low branches.", comment: "Step Instruction")
        let _ = String(localized: "The branches hold snow off the ground, creating a natural hollow.", comment: "Step Detail")
        let _ = String(localized: "Dig out the snow around the trunk to enlarge the space.", comment: "Step Instruction")
        let _ = String(localized: "Be careful not to knock snow off the branches above you.", comment: "Step Detail")
        let _ = String(localized: "Line the floor with boughs for insulation.", comment: "Step Instruction")
        let _ = String(localized: "Sit on branches, not snow.", comment: "Step Detail")
        let _ = String(localized: "Hammock Shelter", comment: "Technique Name")
        let _ = String(localized: "Off-ground jungle/swamp shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Find two sturdy trees 10-15 feet apart.", comment: "Step Instruction")
        let _ = String(localized: "Check for dead branches above (widowmakers).", comment: "Step Detail")
        let _ = String(localized: "Tie your hammock or improvised sheeting between them.", comment: "Step Instruction")
        let _ = String(localized: "Use strong knots like a bowline. Ensure it hangs level.", comment: "Step Detail")
        let _ = String(localized: "Rig a tarp or rain fly above the hammock.", comment: "Step Instruction")
        let _ = String(localized: "Tie a ridgeline higher up the trees and drape the cover.", comment: "Step Detail")
        let _ = String(localized: "Emergency Mylar Wrap", comment: "Technique Name")
        let _ = String(localized: "Using a space blanket correctly", comment: "Technique Subtitle")
        let _ = String(localized: "Wrap around torso and legs, keeping the shiny side facing inward.", comment: "Step Instruction")
        let _ = String(localized: "The reflective surface bounces 80-90% of your radiated body heat back to you. Shiny side faces your body. Matte side faces outward.", comment: "Step Detail")
        let _ = String(localized: "Tuck edges under body and overlap seams.", comment: "Step Instruction")
        let _ = String(localized: "Any gap allows warm air to escape using the chimney effect. Tuck the bottom edge under you when sitting or lying down. Overlap edges by at least 6 inches.", comment: "Step Detail")
        let _ = String(localized: "Cover your head — leave only face exposed for breathing.", comment: "Step Instruction")
        let _ = String(localized: "Create a hood by wrapping excess material over the top of your head. Secure with your hands or a stick clip. Leave your mouth and nose clear.", comment: "Step Detail")
        let _ = String(localized: "Get off the ground: sit on pack, logs, or pile of leaves.", comment: "Step Instruction")
        let _ = String(localized: "Mylar provides zero insulation from ground conduction. Even 2 inches of separation from cold ground makes a major difference.", comment: "Step Detail")
        let _ = String(localized: "Shield from wind. Get behind a tree, rock, or build a mound.", comment: "Step Instruction")
        let _ = String(localized: "Mylar is useless in wind — it rattles, tears, and allows convective heat loss. Even a small windbreak transforms its effectiveness.", comment: "Step Detail")
        let _ = String(localized: "Vehicle as Shelter", comment: "Technique Name")
        let _ = String(localized: "Your car is your best urban emergency shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Stay in the vehicle. It provides insulation, wind protection, visibility.", comment: "Step Instruction")
        let _ = String(localized: "Cars are visible to rescuers. Metal reflects heat. Close all windows.", comment: "Step Detail")
        let _ = String(localized: "Insulate: stuff seats, floor mats, spare clothes in gaps.", comment: "Step Instruction")
        let _ = String(localized: "Floor mats are excellent insulation. Cover windows to trap heat.", comment: "Step Detail")
        let _ = String(localized: "Run engine 10 minutes per hour for heat if safe.", comment: "Step Instruction")
        let _ = String(localized: "Check exhaust is clear of snow/blockage. Carbon monoxide kills. Crack a downwind window.", comment: "Step Detail")
        let _ = String(localized: "Signal: turn on hazard lights, tie bright cloth to antenna.", comment: "Step Instruction")
        let _ = String(localized: "Conserve battery. Periodic honking. Hazards visible from distance.", comment: "Step Detail")
        let _ = String(localized: "Emergency Bivy Sack", comment: "Technique Name")
        let _ = String(localized: "Trash bag or space blanket body wrap", comment: "Technique Subtitle")
        let _ = String(localized: "Open the bivy sack completely before getting in.", comment: "Step Instruction")
        let _ = String(localized: "Emergency bivys are thin and tear easily. Open carefully. Face the reflective side inward (toward your body) if it's a mylar-type bivy.", comment: "Step Detail")
        let _ = String(localized: "Place insulation under you before entering: leaves, grass, pack.", comment: "Step Instruction")
        let _ = String(localized: "The bivy provides zero ground insulation. Use your pack, rope, extra clothing, or natural materials underneath. This is more important than what's on top.", comment: "Step Detail")
        let _ = String(localized: "Climb in feet-first. Keep head opening partially shut but not sealed.", comment: "Step Instruction")
        let _ = String(localized: "Sealing completely causes dangerous condensation buildup inside. Leave a small opening for ventilation. Condensation on the inside will make you wet and colder.", comment: "Step Detail")
        let _ = String(localized: "Wear all available dry clothing inside the bivy.", comment: "Step Instruction")
        let _ = String(localized: "Layers trap air pockets which insulate. Cover extremities: head, hands, feet. Pull hood or shirt over your head. 40% of heat loss is from the head.", comment: "Step Detail")
        let _ = String(localized: "Draw knees up and conserve body heat.", comment: "Step Instruction")
        let _ = String(localized: "Fetal position minimizes exposed surface area. Place hands in armpits or between thighs. Tensing and relaxing muscles generates some heat.", comment: "Step Detail")
        let _ = String(localized: "Raised Platform Shelter", comment: "Technique Name")
        let _ = String(localized: "Stay above water, insects, ground cold", comment: "Technique Subtitle")
        let _ = String(localized: "Find 4 trees in rectangle, or plant 4 sturdy poles.", comment: "Step Instruction")
        let _ = String(localized: "6-8 feet apart. Platform at least 3 feet off ground.", comment: "Step Detail")
        let _ = String(localized: "Lash crossbeams between trees at same height.", comment: "Step Instruction")
        let _ = String(localized: "Square lashing. Must hold your weight.", comment: "Step Detail")
        let _ = String(localized: "Lay poles across beams for platform floor.", comment: "Step Instruction")
        let _ = String(localized: "Pack tight. Fill gaps. Cover with leaves for comfort.", comment: "Step Detail")
        let _ = String(localized: "Add A-frame roof with thatched leaves or tarp.", comment: "Step Instruction")
        let _ = String(localized: "Leaves layered like shingles from bottom up sheds rain.", comment: "Step Detail")
        let _ = String(localized: "Poncho Shelter", comment: "Technique Name")
        let _ = String(localized: "Quick military-style rain protection", comment: "Technique Subtitle")
        let _ = String(localized: "Tie ridgeline between two trees at waist height.", comment: "Step Instruction")
        let _ = String(localized: "Paracord, rope, or vine. Taut line hitch for tension.", comment: "Step Detail")
        let _ = String(localized: "Drape poncho over line. Stake corners down.", comment: "Step Instruction")
        let _ = String(localized: "Angle for rain runoff. Open side away from wind.", comment: "Step Detail")
        let _ = String(localized: "Create 4-6 inch bed of leaves underneath.", comment: "Step Instruction")
        let _ = String(localized: "Never sleep on bare ground. Ground steals heat 25x faster than air.", comment: "Step Detail")
        let _ = String(localized: "Snow Cave", comment: "Technique Name")
        let _ = String(localized: "Dig into deep snow for emergency warmth", comment: "Technique Subtitle")
        let _ = String(localized: "Cold Weather", comment: "Category")
        let _ = String(localized: "Find a deep snowdrift or hillside with at least 6 feet of packed snow.", comment: "Step Instruction")
        let _ = String(localized: "Avoid avalanche-prone slopes. The snow must be packed enough to hold its shape. Fresh powder won't work — it needs to have settled.", comment: "Step Detail")
        let _ = String(localized: "Dig a tunnel entrance angling upward into the drift.", comment: "Step Instruction")
        let _ = String(localized: "The entrance should slope UP so cold air sinks out. This is the key principle — warm air rises and is trapped in the upper chamber.", comment: "Step Detail")
        let _ = String(localized: "Hollow out a sleeping chamber above the entrance level.", comment: "Step Instruction")
        let _ = String(localized: "The sleeping platform MUST be higher than the entrance. Arch the ceiling smooth to prevent dripping. Leave walls 12+ inches thick.", comment: "Step Detail")
        let _ = String(localized: "Poke a ventilation hole in the ceiling with a stick.", comment: "Step Instruction")
        let _ = String(localized: "Critical for preventing CO2 buildup and suffocation. Make it fist-sized. If it snows, check and clear it regularly. Mark the entrance outside with a stick.", comment: "Step Detail")
        let _ = String(localized: "Vehicle Shelter", comment: "Technique Name")
        let _ = String(localized: "Use your car as emergency shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Stay with the vehicle — it is shelter, signal, and storage.", comment: "Step Instruction")
        let _ = String(localized: "A car is visible from the air. It blocks wind. It has a heater. Walking away from your car in a blizzard is how people die.", comment: "Step Detail")
        let _ = String(localized: "Run engine 10-15 minutes per hour for heat. Keep exhaust pipe clear of snow.", comment: "Step Instruction")
        let _ = String(localized: "Carbon monoxide kills silently. If the exhaust is blocked by snow, CO fills the cabin. Check and clear the tailpipe before running the engine.", comment: "Step Detail")
        let _ = String(localized: "Insulate windows with floor mats, newspapers, or clothing.", comment: "Step Instruction")
        let _ = String(localized: "Windows are the biggest heat loss. Cover them with anything available. Crack one window slightly for ventilation when engine runs.", comment: "Step Detail")
        let _ = String(localized: "Tie a bright cloth to the antenna. Turn on hazard lights periodically.", comment: "Step Instruction")
        let _ = String(localized: "Make the vehicle visible to rescuers. Hazard lights drain the battery, so use them intermittently. A bright flag on the antenna is visible even in snow.", comment: "Step Detail")
        let _ = String(localized: "Raised Tree Platform", comment: "Technique Name")
        let _ = String(localized: "Elevated sleeping platform for tropical environments", comment: "Technique Subtitle")
        let _ = String(localized: "Select 2-4 trees growing close together with strong lower branches.", comment: "Step Instruction")
        let _ = String(localized: "Trees should be 4-6 feet apart. Branches at the same height (4-5 feet) create natural support points for your platform.", comment: "Step Detail")
        let _ = String(localized: "Lash cross-poles between the trees at branch level.", comment: "Step Instruction")
        let _ = String(localized: "Use square lashing for secure right-angle joints. These main beams support everything — they must be strong and secure.", comment: "Step Detail")
        let _ = String(localized: "Lay smaller poles across the cross-beams to create the sleeping surface.", comment: "Step Instruction")
        let _ = String(localized: "Place them close together. Cover with large leaves or bark for comfort. Test by sitting on it before committing to sleeping.", comment: "Step Detail")
        let _ = String(localized: "Add a roof frame and cover with large palm or banana leaves.", comment: "Step Instruction")
        let _ = String(localized: "Tropical rain is intense. Overlap leaves from bottom to top like shingles. Make the roof extend well beyond the platform edges.", comment: "Step Detail")
        let _ = String(localized: "Rock Overhang Improvement", comment: "Technique Name")
        let _ = String(localized: "Turn a natural rock shelter into a home", comment: "Technique Subtitle")
        let _ = String(localized: "Find a rock overhang with at least 4 feet of ceiling clearance.", comment: "Step Instruction")
        let _ = String(localized: "Check for falling rock hazards. Look for existing dry ground underneath. South-facing overhangs (Northern Hemisphere) get the most sun.", comment: "Step Detail")
        let _ = String(localized: "Build a wind wall across the open side with stacked rocks or logs.", comment: "Step Instruction")
        let _ = String(localized: "Leave a gap for entry. The wall blocks wind and traps heat from a fire placed between you and the wall.", comment: "Step Detail")
        let _ = String(localized: "Create a thick bed of insulating material on the ground.", comment: "Step Instruction")
        let _ = String(localized: "Rock floors steal heat rapidly. Layer pine boughs, leaves, or grass at least 6 inches thick. Your body compresses it significantly.", comment: "Step Detail")
        let _ = String(localized: "Poncho Shelter Configurations", comment: "Technique Name")
        let _ = String(localized: "Multiple shelter designs from a single poncho", comment: "Technique Subtitle")
        let _ = String(localized: "Tarp & Poncho", comment: "Category")
        let _ = String(localized: "A-frame: drape poncho over a ridgeline and stake corners.", comment: "Step Instruction")
        let _ = String(localized: "Tie paracord between two trees at chest height. Drape poncho centered over the line. Stake or weight the corners. Simple, effective rain shelter.", comment: "Step Detail")
        let _ = String(localized: "Lean-to: tie one edge to a horizontal pole, stake the other to the ground.", comment: "Step Instruction")
        let _ = String(localized: "Face the open side away from wind. The angled surface sheds rain. Less enclosed but allows fire in front.", comment: "Step Detail")
        let _ = String(localized: "Tent: support center with a stick, stake all four corners.", comment: "Step Instruction")
        let _ = String(localized: "The stick creates a peak. This gives maximum enclosed space from a single poncho. Use the hood as a chimney vent.", comment: "Step Detail")
        let _ = String(localized: "Ground cloth: last resort — lie on the poncho to stay off wet ground.", comment: "Step Instruction")
        let _ = String(localized: "If rain isn't the threat but ground moisture is, use the poncho as a vapor barrier between you and the ground.", comment: "Step Detail")
        let _ = String(localized: "Parachute Tepee", comment: "Technique Name")
        let _ = String(localized: "Large group shelter from a parachute or large tarp", comment: "Technique Subtitle")
        let _ = String(localized: "Create a tripod of poles 12-15 feet tall. Tie at the top.", comment: "Step Instruction")
        let _ = String(localized: "Use three strong poles. Cross them at the top and lash securely. Spread the bases evenly to create a stable tripod.", comment: "Step Detail")
        let _ = String(localized: "Lean additional poles around the tripod to form a cone frame.", comment: "Step Instruction")
        let _ = String(localized: "Add 6-8 more poles to fill the cone shape. Leave a gap for the entrance. The frame should be circular at the base.", comment: "Step Detail")
        let _ = String(localized: "Drape the parachute or large tarp over the frame.", comment: "Step Instruction")
        let _ = String(localized: "Wrap around the outside, overlapping at the entrance. Stake the bottom edge. Leave the top open for smoke ventilation if using a fire inside.", comment: "Step Detail")
        let _ = String(localized: "Group Survival Shelter", comment: "Technique Name")
        let _ = String(localized: "Shelter for multiple people using shared body heat", comment: "Technique Subtitle")
        let _ = String(localized: "Build a large debris shelter wide enough for the entire group.", comment: "Step Instruction")
        let _ = String(localized: "A widened A-frame or extended lean-to. The key advantage of group sheltering is shared body heat — each person generates 100W of heat.", comment: "Step Detail")
        let _ = String(localized: "Sleep side by side — body heat is your primary warmth source.", comment: "Step Instruction")
        let _ = String(localized: "Pack closely. Put the coldest person in the middle. Spoon configuration is most efficient. Four people generate 400W — equivalent to a space heater.", comment: "Step Detail")
        let _ = String(localized: "Assign shifts for fire maintenance and security.", comment: "Step Instruction")
        let _ = String(localized: "Rotate 2-hour watch shifts. The person on watch tends the fire, monitors weather, and lets others sleep. This is critical for multi-day situations.", comment: "Step Detail")
        let _ = String(localized: "Underground Shelter", comment: "Technique Name")
        let _ = String(localized: "Dig below the surface for extreme temperature regulation", comment: "Technique Subtitle")
        let _ = String(localized: "Dig a trench 3 feet deep, body-length plus 1 foot, shoulder-width plus 6 inches.", comment: "Step Instruction")
        let _ = String(localized: "Choose well-drained soil. Sandy soil is easy to dig but may collapse. Clay holds shape but is exhausting. Avoid areas with high water table.", comment: "Step Detail")
        let _ = String(localized: "Lay poles across the top of the trench as roof beams.", comment: "Step Instruction")
        let _ = String(localized: "Poles must be strong enough to support the covering material weight. Space them 6-8 inches apart. Use the strongest wood available.", comment: "Step Detail")
        let _ = String(localized: "Cover with branches, leaves, and 6+ inches of soil.", comment: "Step Instruction")
        let _ = String(localized: "Layer: branches, then leaves/grass, then soil. The soil provides insulation and waterproofing. Leave entrance at one end.", comment: "Step Detail")
        let _ = String(localized: "Line the floor with insulating material. Create a drainage channel.", comment: "Step Instruction")
        let _ = String(localized: "Dig a small drainage trench along one wall lower than the sleeping area. Rain water channels to this trench instead of pooling under you.", comment: "Step Detail")
        let _ = String(localized: "Bough Bed Construction", comment: "Technique Name")
        let _ = String(localized: "Build an insulating sleeping surface from branches", comment: "Technique Subtitle")
        let _ = String(localized: "Collect armloads of evergreen boughs (pine, spruce, fir).", comment: "Step Instruction")
        let _ = String(localized: "You need far more than you think — the bed will compress. Plan on 4-6 inches of uncompressed boughs. Pull branches from dead/low trees when possible.", comment: "Step Detail")
        let _ = String(localized: "Lay boughs in overlapping rows like roof shingles, tips pointing toward foot end.", comment: "Step Instruction")
        let _ = String(localized: "Start at the head end, laying boughs with stems toward you, tips away. Each row overlaps the previous. This creates a smooth sleeping surface without poking stems.", comment: "Step Detail")
        let _ = String(localized: "Build up to 6+ inches for ground insulation. Test by lying on it.", comment: "Step Instruction")
        let _ = String(localized: "You lose more heat to the cold ground than to cold air. If you can feel the ground through the boughs, add more. A good bough bed is the single most important comfort improvement in a survival shelter.", comment: "Step Detail")
        let _ = String(localized: "Grass & Leaf Mattress", comment: "Technique Name")
        let _ = String(localized: "Create insulating bedding from grass and dry leaves", comment: "Technique Subtitle")
        let _ = String(localized: "Gather large quantities of dry grass, leaves, or cattail fluff.", comment: "Step Instruction")
        let _ = String(localized: "Dry materials only. Wet bedding conducts heat away from your body. Collect enough to fill a large garbage bag — you need volume because it compresses significantly.", comment: "Step Detail")
        let _ = String(localized: "Create a containing frame from logs or sticks on the shelter floor.", comment: "Step Instruction")
        let _ = String(localized: "Two parallel logs 2 feet apart define the bed edges. Without containment, loose material shifts and compresses unevenly during sleep.", comment: "Step Detail")
        let _ = String(localized: "Fill the frame 8-12 inches deep. Pile extra material on top as blanket.", comment: "Step Instruction")
        let _ = String(localized: "The goal is to not feel the ground. Also stuff material into your clothing for additional insulation. Replace bedding every 2-3 days as it compresses and absorbs moisture.", comment: "Step Detail")
        let _ = String(localized: "Heated Bed (Fire Bed)", comment: "Technique Name")
        let _ = String(localized: "Use buried coals to heat ground for warm sleeping", comment: "Technique Subtitle")
        let _ = String(localized: "Dig a trench 6 inches deep, body-width and body-length.", comment: "Step Instruction")
        let _ = String(localized: "The trench holds the heated material. Dig in a location with good drainage — you don't want water pooling in your bed trench.", comment: "Step Detail")
        let _ = String(localized: "Build a long fire in the trench and burn for 1-2 hours to heat the earth.", comment: "Step Instruction")
        let _ = String(localized: "The fire heats the soil and rocks beneath. Burn until the ground is thoroughly warm. Push aside coals and check soil temperature with your hand.", comment: "Step Detail")
        let _ = String(localized: "Rake out coals. Cover with 3-4 inches of soil, then thick bedding on top.", comment: "Step Instruction")
        let _ = String(localized: "The soil layer prevents burns and distributes heat evenly. Add boughs or grass on top of the soil. A well-heated bed stays warm for 6-8 hours. NEVER sleep directly on coals.", comment: "Step Detail")
        let _ = String(localized: "Shelter Insulation Methods", comment: "Technique Name")
        let _ = String(localized: "Add thermal mass and insulation to any shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Add dead leaves, grass, or moss to walls — minimum 12 inches thick.", comment: "Step Instruction")
        let _ = String(localized: "Insulation works by trapping dead air. Loosely packed dry material is better insulation than tightly packed material. Think loft, not density.", comment: "Step Detail")
        let _ = String(localized: "Close all gaps and drafts. Wind destroys insulation effectiveness.", comment: "Step Instruction")
        let _ = String(localized: "Find drafts by feeling with wet fingers or watching candle/match flame. Fill gaps with moss, mud, leaves, or bark. Even a tiny gap creates a wind tunnel.", comment: "Step Detail")
        let _ = String(localized: "Reduce shelter interior volume to minimum comfortable size.", comment: "Step Instruction")
        let _ = String(localized: "A smaller space heats faster and retains warmth from your body heat alone. A shelter just large enough to sit up in is warmer than a standing-height shelter.", comment: "Step Detail")
        let _ = String(localized: "Shelter Door & Entrance", comment: "Technique Name")
        let _ = String(localized: "Build a door to retain heat and block weather", comment: "Technique Subtitle")
        let _ = String(localized: "Face entrance away from prevailing wind.", comment: "Step Instruction")
        let _ = String(localized: "Wind direction is the most important shelter planning factor. Face the entrance downhill or away from wind. In the Northern Hemisphere, face south for sun warmth.", comment: "Step Detail")
        let _ = String(localized: "Build a plug door from bundled sticks, bark, or a stuffed pack.", comment: "Step Instruction")
        let _ = String(localized: "Frame a rectangle of sticks, fill with leaves and debris, bind with cordage. The plug should fit snugly in the entrance. Pull in behind you when entering.", comment: "Step Detail")
        let _ = String(localized: "Create an L-shaped entrance if possible to break wind.", comment: "Step Instruction")
        let _ = String(localized: "An L-shaped entry forces wind to turn a corner, losing most energy. The first section faces away from wind; you turn 90 degrees to enter the main shelter. This design dramatically reduces heat loss.", comment: "Step Detail")
        let _ = String(localized: "Shelter Ventilation Design", comment: "Technique Name")
        let _ = String(localized: "Prevent carbon monoxide and condensation buildup", comment: "Technique Subtitle")
        let _ = String(localized: "If using fire inside shelter, create a smoke hole at the top.", comment: "Step Instruction")
        let _ = String(localized: "Hot smoke rises. A hole at the highest point allows smoke to exit. Without ventilation, carbon monoxide accumulates and can kill you in your sleep. This is non-negotiable.", comment: "Step Detail")
        let _ = String(localized: "Create a low air inlet opposite the smoke hole.", comment: "Step Instruction")
        let _ = String(localized: "Fresh air enters low, gets heated, rises, and exits through the smoke hole. This natural convection cycle maintains fresh air flow. Even a few square inches of inlet is sufficient.", comment: "Step Detail")
        let _ = String(localized: "Monitor for condensation — it indicates insufficient ventilation.", comment: "Step Instruction")
        let _ = String(localized: "Your breath produces moisture. Without ventilation, it condenses on shelter walls, soaking insulation and dripping back on you. If walls are wet in the morning, increase ventilation holes.", comment: "Step Detail")
        let _ = String(localized: "Shelter Waterproofing", comment: "Technique Name")
        let _ = String(localized: "Keep rain and moisture out of your shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Apply debris layers at 45+ degree angle so water runs off.", comment: "Step Instruction")
        let _ = String(localized: "Like shingles on a house, layer from bottom to top so each row overlaps the one below. Water follows gravity along the overlapping surfaces. Steeper angles shed water better.", comment: "Step Detail")
        let _ = String(localized: "Apply bark shingles or large leaves over the debris layer.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark, cedar bark slabs, large palm fronds, or wide leaves create a waterproof outer shell. Overlap generously. This outer layer protects the insulating debris beneath.", comment: "Step Detail")
        let _ = String(localized: "Dig a drainage trench around the shelter perimeter.", comment: "Step Instruction")
        let _ = String(localized: "Even with a waterproof roof, ground water can flood your shelter. Dig a shallow trench (4-6 inches) around the shelter, sloping away downhill. This diverts rain runoff.", comment: "Step Detail")
        let _ = String(localized: "Storm-Proofing a Shelter", comment: "Technique Name")
        let _ = String(localized: "Reinforce shelter against high winds and heavy rain", comment: "Technique Subtitle")
        let _ = String(localized: "Add weight to the structure with rocks or additional logs.", comment: "Step Instruction")
        let _ = String(localized: "Wind lifts lightweight debris. Heavy rocks on the roof and walls anchor the shelter. Place rocks along the base perimeter to prevent walls from being pushed in.", comment: "Step Detail")
        let _ = String(localized: "Lash all structural elements with cordage or vine.", comment: "Step Instruction")
        let _ = String(localized: "Every joint that can move will move in a storm. Lash ridgepole to supports, supports to ground stakes, and cross-members to the frame. Redundant lashing = survival.", comment: "Step Detail")
        let _ = String(localized: "Lower the profile and strengthen the windward side.", comment: "Step Instruction")
        let _ = String(localized: "Tall shelters catch wind. If a storm is coming, reduce height. Double the insulation/debris on the windward side. Sleep with head toward the windward side (more protected).", comment: "Step Detail")
        let _ = String(localized: "Fallen Tree Shelter", comment: "Technique Name")
        let _ = String(localized: "Use a fallen tree as instant shelter framework", comment: "Technique Subtitle")
        let _ = String(localized: "Find a large fallen tree with the trunk 2-3 feet off the ground.", comment: "Step Instruction")
        let _ = String(localized: "The trunk forms your ridgepole. It must be stable — test by pushing hard. Avoid trees that have recently fallen and may shift. Root ball or branch supports keep it elevated.", comment: "Step Detail")
        let _ = String(localized: "Lean branches against both sides of the trunk to create walls.", comment: "Step Instruction")
        let _ = String(localized: "Thick branches first for structure, then smaller ones for coverage. Create a steep angle (60+ degrees) for water runoff. Leave one end open as entrance.", comment: "Step Detail")
        let _ = String(localized: "Cover with debris layers for insulation and waterproofing.", comment: "Step Instruction")
        let _ = String(localized: "Pile leaves, grass, ferns, and moss over the branch walls. Minimum 12 inches thick. This is essentially a lean-to shelter with the work half done by nature.", comment: "Step Detail")
        let _ = String(localized: "Stacked Rock Windbreak", comment: "Technique Name")
        let _ = String(localized: "Build a wind-blocking wall from stones", comment: "Technique Subtitle")
        let _ = String(localized: "Gather flat-sided rocks and stack into a crescent or straight wall.", comment: "Step Instruction")
        let _ = String(localized: "Flat rocks stack more stably. Build the wall on the windward side, curving around your sleeping area. Height of 3 feet blocks most ground-level wind.", comment: "Step Detail")
        let _ = String(localized: "Fill gaps between rocks with smaller stones and mud.", comment: "Step Instruction")
        let _ = String(localized: "Wind penetrates any gap. Chink the wall like a log cabin — press mud, clay, or wet earth into cracks. Let it dry for maximum windproofing.", comment: "Step Detail")
        let _ = String(localized: "Place fire between you and the wall for radiant heat reflection.", comment: "Step Instruction")
        let _ = String(localized: "Rock absorbs heat from the fire and re-radiates it toward you. Sleep between the fire and the wall. The wall acts as both windbreak and heat reflector.", comment: "Step Detail")
        let _ = String(localized: "Snow Wall Windbreak", comment: "Technique Name")
        let _ = String(localized: "Block wind with packed snow blocks", comment: "Technique Subtitle")
        let _ = String(localized: "Cut or pack snow into blocks 12x12x6 inches.", comment: "Step Instruction")
        let _ = String(localized: "Dense, wet snow holds shape best. Use a knife, shovel, saw, or even a pot lid to cut blocks. Pack loose snow into a container to form blocks if cutting isn't possible.", comment: "Step Detail")
        let _ = String(localized: "Stack blocks in a crescent shape on the windward side.", comment: "Step Instruction")
        let _ = String(localized: "Build 3-4 feet high. Stagger the blocks like bricks for stability. Angle the wall slightly inward for better wind deflection. Leave no gaps.", comment: "Step Detail")
        let _ = String(localized: "Let blocks freeze together for 30 minutes before trusting the wall.", comment: "Step Instruction")
        let _ = String(localized: "Contact between blocks melts slightly then refreezes, bonding them. Pour a small amount of water on seams to accelerate bonding. The wall becomes very solid once frozen.", comment: "Step Detail")
        let _ = String(localized: "Desert Shade Structure", comment: "Technique Name")
        let _ = String(localized: "Create life-saving shade in open desert", comment: "Technique Subtitle")
        let _ = String(localized: "Create a double-layer shade using any available material.", comment: "Step Instruction")
        let _ = String(localized: "Single layer of shade reduces temperature by 20°F. Double layer (with air gap) reduces by 40°F. Use tarp, blanket, clothing, or natural materials to create two layers 12 inches apart.", comment: "Step Detail")
        let _ = String(localized: "Elevate the shade 2-3 feet above ground to allow air circulation beneath.", comment: "Step Instruction")
        let _ = String(localized: "Ground surface temperature can be 30°F hotter than air temperature at 3 feet. Elevating the shade and lying beneath it puts you in the coolest zone.", comment: "Step Detail")
        let _ = String(localized: "Orient shade to block the sun during hottest hours (10am-4pm).", comment: "Step Instruction")
        let _ = String(localized: "The sun moves east to west. Build shade to block the south sky (Northern Hemisphere) for maximum midday protection. Adjust position as sun moves if possible.", comment: "Step Detail")
        let _ = String(localized: "Camouflaged Shelter", comment: "Technique Name")
        let _ = String(localized: "Build a shelter that blends into the environment", comment: "Technique Subtitle")
        let _ = String(localized: "Use materials that match the surrounding environment exactly.", comment: "Step Instruction")
        let _ = String(localized: "In a pine forest, use pine boughs. In a leaf-drop forest, use fallen leaves. In grassland, use grass bundles. Any material that looks out of place draws attention.", comment: "Step Detail")
        let _ = String(localized: "Keep the shelter low-profile with irregular shape.", comment: "Step Instruction")
        let _ = String(localized: "Geometric shapes (rectangles, triangles) are unnatural. Build an organic, lumpy mound shape. Keep it low — a 3-foot high mound is far less visible than a 6-foot lean-to.", comment: "Step Detail")
        let _ = String(localized: "Conceal signs of habitation: trails, fire scars, trash.", comment: "Step Instruction")
        let _ = String(localized: "The shelter itself may be hidden, but worn paths leading to it, fire-blackened ground, and scattered debris reveal your presence. Vary your approach route. Keep the area clean.", comment: "Step Detail")
        let _ = String(localized: "Urban Debris Shelter", comment: "Technique Name")
        let _ = String(localized: "Create shelter from urban rubble and materials", comment: "Technique Subtitle")
        let _ = String(localized: "Identify structurally stable areas: doorframes, concrete corners, stairwells.", comment: "Step Instruction")
        let _ = String(localized: "After earthquakes or structural collapse, these areas are most likely to remain intact. Avoid unstable walls, hanging debris, or areas with gas leaks. Listen and smell before entering.", comment: "Step Detail")
        let _ = String(localized: "Use plywood, sheet metal, doors, or mattresses as shelter walls/roof.", comment: "Step Instruction")
        let _ = String(localized: "Lean large flat materials against stable walls to create covered spaces. Mattresses provide excellent insulation. Car hoods and doors make weatherproof walls.", comment: "Step Detail")
        let _ = String(localized: "Insulate with available soft materials: carpet, clothing, paper, cardboard.", comment: "Step Instruction")
        let _ = String(localized: "Cardboard is an exceptional insulator (better than many purpose-made materials). Newspaper stuffed in clothing adds insulation. Layer carpet on floors as ground insulation.", comment: "Step Detail")
        let _ = String(localized: "Coastal Driftwood Shelter", comment: "Technique Name")
        let _ = String(localized: "Build shelter on beaches using driftwood and sand", comment: "Technique Subtitle")
        let _ = String(localized: "Build ABOVE the high tide line. Look for debris marks indicating tide reach.", comment: "Step Instruction")
        let _ = String(localized: "The high tide line is marked by seaweed, shells, and debris. Build well above this line. Check twice — storm surge can extend far beyond normal high tide.", comment: "Step Detail")
        let _ = String(localized: "Stack driftwood logs into a windbreak facing away from prevailing ocean wind.", comment: "Step Instruction")
        let _ = String(localized: "Coastal wind is constant and carries salt spray. Build a sturdy windbreak wall. Lean driftwood against a large log or rock for a lean-to structure.", comment: "Step Detail")
        let _ = String(localized: "Use seagrass, kelp, or sand to fill gaps and add insulation.", comment: "Step Instruction")
        let _ = String(localized: "Dried seagrass bundles make decent insulation. Sand piled against the base prevents wind from blowing under. DO NOT dig into sand for shelter — sand collapses and can bury you.", comment: "Step Detail")
        let _ = String(localized: "Swamp Shelter", comment: "Technique Name")
        let _ = String(localized: "Build an elevated shelter in wetland environments", comment: "Technique Subtitle")
        let _ = String(localized: "Find the driest elevated ground (hummock) in the swamp.", comment: "Step Instruction")
        let _ = String(localized: "Hummocks are raised areas around tree bases. They may only be 6-12 inches above water level, but that matters. Never sleep directly in water or mud.", comment: "Step Detail")
        let _ = String(localized: "Build a raised platform from logs lashed together.", comment: "Step Instruction")
        let _ = String(localized: "Lay parallel logs across two support logs. Lash tightly with vines or roots (plentiful in swamps). Platform should be at least 12 inches above the current water line.", comment: "Step Detail")
        let _ = String(localized: "Cover platform with thick bedding and build overhead rain cover.", comment: "Step Instruction")
        let _ = String(localized: "Swamps produce heavy mosquitoes. A smudge fire at the entrance helps. Cover the platform with as much dry material as available. Build a lean-to or A-frame overhead for rain.", comment: "Step Detail")
        let _ = String(localized: "Tarp: Plow Point", comment: "Technique Name")
        let _ = String(localized: "Maximum weather protection tarp configuration", comment: "Technique Subtitle")
        let _ = String(localized: "Stake one corner of the tarp to the ground facing into the wind.", comment: "Step Instruction")
        let _ = String(localized: "This creates the 'plow point' — like the bow of a ship cutting through wind and rain. The pointed corner deflects weather that hits it.", comment: "Step Detail")
        let _ = String(localized: "Lift the center ridgeline with a pole or ridgeline rope.", comment: "Step Instruction")
        let _ = String(localized: "The center of the tarp rises to form a peaked roof. Attach to a rope between two trees or to a center pole. Height determines interior space.", comment: "Step Detail")
        let _ = String(localized: "Stake remaining corners and edges taut.", comment: "Step Instruction")
        let _ = String(localized: "The two rear corners stake out for living space. This configuration provides excellent wind and rain protection with a dry living area. Great for long-term base camps.", comment: "Step Detail")
        let _ = String(localized: "Ground Insulation Methods", comment: "Technique Name")
        let _ = String(localized: "Prevent heat loss to cold ground while sleeping", comment: "Technique Subtitle")
        let _ = String(localized: "Gather DRY material: leaves, pine needles, grass, ferns.", comment: "Step Instruction")
        let _ = String(localized: "Wet material conducts heat away from your body. Prioritize dry material even if you have to walk farther to find it. Test by squeezing — if water drips out, it's too wet.", comment: "Step Detail")
        let _ = String(localized: "Pile material at least 4-6 inches thick — it will compress.", comment: "Step Instruction")
        let _ = String(localized: "Under body weight, 6 inches of loose leaves compresses to about 2 inches. You need several armloads. Pine boughs compress less and provide better insulation.", comment: "Step Detail")
        let _ = String(localized: "Create a body-shaped depression in the center of the pile.", comment: "Step Instruction")
        let _ = String(localized: "This cradles your body and prevents rolling off the insulation. Push material up on the sides to reduce exposure.", comment: "Step Detail")
        let _ = String(localized: "Add a top layer: cover yourself with more material for a blanket.", comment: "Step Instruction")
        let _ = String(localized: "Insulation works both ways — underneath stops conduction, on top stops convection and radiation. Pile loose material over your body up to 12 inches thick.", comment: "Step Detail")
        let _ = String(localized: "Check and replace material that becomes damp overnight.", comment: "Step Instruction")
        let _ = String(localized: "Body moisture makes insulation damp by morning. Rotate and fluff material. Gather fresh dry material when possible. Damp insulation is worse than none.", comment: "Step Detail")
        let _ = String(localized: "Elevated Food Cache", comment: "Technique Name")
        let _ = String(localized: "Store food above ground to protect from animals", comment: "Technique Subtitle")
        let _ = String(localized: "Select a tree with a strong branch 10-12 feet high.", comment: "Step Instruction")
        let _ = String(localized: "The cache must be high enough that bears can't reach it (10+ feet) and far enough from the trunk that they can't climb to it (4+ feet out on a branch).", comment: "Step Detail")
        let _ = String(localized: "Place food in a bag and hoist it using a rope over the branch.", comment: "Step Instruction")
        let _ = String(localized: "Throw a weighted line over the branch. Attach your food bag and hoist. The bag should hang at least 4 feet from the trunk and 4 feet below the branch.", comment: "Step Detail")
        let _ = String(localized: "Tie off the rope securely. Cache should be 100+ feet from shelter.", comment: "Step Instruction")
        let _ = String(localized: "Bears follow food smells. If they find the cache, you want them far from your shelter. Cook 100 feet from shelter, cache 100 feet in a different direction. Triangle arrangement.", comment: "Step Detail")
        let _ = String(localized: "Thermal Mass Shelter", comment: "Technique Name")
        let _ = String(localized: "Use earth and rock to regulate shelter temperature", comment: "Technique Subtitle")
        let _ = String(localized: "Build or dig shelter into or against earth, rock, or hillside.", comment: "Step Instruction")
        let _ = String(localized: "Earth and rock absorb heat during the day and release it at night. Underground temperature is roughly 55°F (13°C) year-round. A partially underground shelter stays cool in summer, warm in winter.", comment: "Step Detail")
        let _ = String(localized: "Incorporate heated rocks for nighttime warmth.", comment: "Step Instruction")
        let _ = String(localized: "Heat large flat rocks in the fire, then move them inside the shelter. Rocks the size of footballs retain heat for 4-8 hours. Place near sleeping area but NOT in direct contact with skin.", comment: "Step Detail")
        let _ = String(localized: "Seal shelter tightly and use the thermal mass to maintain temperature.", comment: "Step Instruction")
        let _ = String(localized: "The combination of earth insulation and heated rock thermal mass creates a stable temperature environment. This is the principle behind traditional earth lodges that maintained comfort in extreme climates.", comment: "Step Detail")
        let _ = String(localized: "Desert Trench Shelter", comment: "Technique Name")
        let _ = String(localized: "Sub-surface cooling and warmth", comment: "Technique Subtitle")
        let _ = String(localized: "Arid", comment: "Category")
        let _ = String(localized: "Dig a trench 1-2 feet deep, large enough to lie in.", comment: "Step Instruction")
        let _ = String(localized: "The smooth sand 1 foot down can be 10-20 degrees cooler than the surface air in daytime. Pile the dug sand around the edges as a windbreak.", comment: "Step Detail")
        let _ = String(localized: "Cover with a tarp or cloth, weighting edges with sand.", comment: "Step Instruction")
        let _ = String(localized: "Leave a 6-inch air gap between the cover and the ground to allow airflow. Double-layering (two tarps with air gap) provides significantly better insulation from the sun.", comment: "Step Detail")
        let _ = String(localized: "At night, lower the roof or add insulation.", comment: "Step Instruction")
        let _ = String(localized: "The desert gets freezing at night. Lowering the tarp traps your body heat in the trench. The sand retains some day heat.", comment: "Step Detail")
        let _ = String(localized: "Swamp Bed", comment: "Technique Name")
        let _ = String(localized: "Elevated sleeping platform", comment: "Technique Subtitle")
        let _ = String(localized: "Wetlands", comment: "Category")
        let _ = String(localized: "Gather 4 sturdy forked posts or utilize smooth trees.", comment: "Step Instruction")
        let _ = String(localized: "Drive them into the mud or use existing trees. The goal is to create a rectangular frame at least 18 inches off the ground/water.", comment: "Step Detail")
        let _ = String(localized: "Lash cross-beams to the posts.", comment: "Step Instruction")
        let _ = String(localized: "Use vines or cordage. Ensure they are strong enough to hold your weight.", comment: "Step Detail")
        let _ = String(localized: "Lay a deck of poles across the frame.", comment: "Step Instruction")
        let _ = String(localized: "Cover the deck with palm fronds, grass, or leaves for cushioning. This keeps you dry and away from ground dwelling insects/snakes.", comment: "Step Detail")
        let _ = String(localized: "Fire Reflector", comment: "Technique Name")
        let _ = String(localized: "Maximize fire warmth", comment: "Technique Subtitle")
        let _ = String(localized: "General", comment: "Category")
        let _ = String(localized: "Locate spot opposite your shelter entrance, behind the fire.", comment: "Step Instruction")
        let _ = String(localized: "The fire should be between you and the reflector. Distance: about 3 feet from fire.", comment: "Step Detail")
        let _ = String(localized: "Drive stakes or stack rocks/logs to create a wall.", comment: "Step Instruction")
        let _ = String(localized: "The wall should be at least as wide and tall as the fire. Green logs work best (less fire risk).", comment: "Step Detail")
        let _ = String(localized: "Use mud or earth to shield wooden reflectors.", comment: "Step Instruction")
        let _ = String(localized: "This prevents them from catching fire and adds thermal mass to radiate heat back at you.", comment: "Step Detail")
        let _ = String(localized: "Tarp Plow Point", comment: "Technique Name")
        let _ = String(localized: "Fast, 1-tie setup", comment: "Technique Subtitle")
        let _ = String(localized: "Tie one corner of the tarp to a tree at waist height.", comment: "Step Instruction")
        let _ = String(localized: "Or use a hiking pole/stick if no tree is available.", comment: "Step Detail")
        let _ = String(localized: "PULL the opposite corner tight and stake it to the ground.", comment: "Step Instruction")
        let _ = String(localized: "This creates the spine ridge.", comment: "Step Detail")
        let _ = String(localized: "Stake the remaining two corners.", comment: "Step Instruction")
        let _ = String(localized: "Creates a triangular wedge shape. Very wind resistant if the low point faces the wind. Good for shedding rain.", comment: "Step Detail")
        let _ = String(localized: "Tarp Flying V", comment: "Technique Name")
        let _ = String(localized: "Ventilated sun/rain cover", comment: "Technique Subtitle")
        let _ = String(localized: "Tie a ridgeline between two trees.", comment: "Step Instruction")
        let _ = String(localized: "Height should be reachable but high enough to sit under.", comment: "Step Detail")
        let _ = String(localized: "Drape tarp over line diagonally.", comment: "Step Instruction")
        let _ = String(localized: "Two opposite corners hang down, two are on the line.", comment: "Step Detail")
        let _ = String(localized: "Guy out the two hanging corners significantly.", comment: "Step Instruction")
        let _ = String(localized: "This lifts the 'wings' up, creating a V shape that catches breeze but blocks sun/rain from above. Excellent for hot weather.", comment: "Step Detail")
        let _ = String(localized: "Rock Overhang", comment: "Technique Name")
        let _ = String(localized: "Natural shelter improvement", comment: "Technique Subtitle")
        let _ = String(localized: "Check overhang stability and look for animal signs.", comment: "Step Instruction")
        let _ = String(localized: "Ensure rocks aren't loose. Check for droppings/nests (caves are popular dens).", comment: "Step Detail")
        let _ = String(localized: "Build sidewalls with stones or branches.", comment: "Step Instruction")
        let _ = String(localized: "Enclose the open sides to block wind and retain heat.", comment: "Step Detail")
        let _ = String(localized: "Build a fire near the opening (not deep inside).", comment: "Step Instruction")
        let _ = String(localized: "Use a reflector wall to bounce heat in. A fire too deep inside can smoke you out or heat cracks in the roof rock.", comment: "Step Detail")
        let _ = String(localized: "Tarp Lean-To", comment: "Technique Name")
        let _ = String(localized: "Open front, heating shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Poncho Tent", comment: "Technique Name")
        let _ = String(localized: "Minimalist gear shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Gear", comment: "Category")
        let _ = String(localized: "Hood must be tied off/sealed tightly.", comment: "Step Instruction")
        let _ = String(localized: "This is the main leak point. Tie it authorized or use a pebble and cordage to seal it.", comment: "Step Detail")
        let _ = String(localized: "Stake the four corners to the ground.", comment: "Step Instruction")
        let _ = String(localized: "Or two corners to ground, two to low branches for a low lean-to.", comment: "Step Detail")
        let _ = String(localized: "Use a stick in the center to prop it up (if flat pitching).", comment: "Step Instruction")
        let _ = String(localized: "Creates a small pyramid tent. Very tight space but decent storm protection.", comment: "Step Detail")
        let _ = String(localized: "Natural Hollow / Depression", comment: "Technique Name")
        let _ = String(localized: "Quick emergency cover", comment: "Technique Subtitle")
        let _ = String(localized: "Find a natural depression, root ball hole, or fallen log.", comment: "Step Instruction")
        let _ = String(localized: "Ensure it's not a drainage path for water.", comment: "Step Detail")
        let _ = String(localized: "Roof over the top with branches and debris.", comment: "Step Instruction")
        let _ = String(localized: "You only need to build a roof, saving 50% of the work.", comment: "Step Detail")
        let _ = String(localized: "Insulate the bottom heavily.", comment: "Step Instruction")
        let _ = String(localized: "Hollows can be damp and cold sinks. Use extra bedding.", comment: "Step Detail")
        let _ = String(localized: "Debris Hut (Standard)", comment: "Technique Name")
        let _ = String(localized: "The ultimate survival shelter", comment: "Technique Subtitle")
        let _ = String(localized: "Set a ridgepole against a tree or rock.", comment: "Step Instruction")
        let _ = String(localized: "Pole must be longer than your body. Height at opening should sit just above your waist.", comment: "Step Detail")
        let _ = String(localized: "Line sides with 'rib' sticks.", comment: "Step Instruction")
        let _ = String(localized: "Place sticks closely against the ridgepole to form an A-frame ribcage.", comment: "Step Detail")
        let _ = String(localized: "Pile 3 feet of debris (leaves, grass) on top.", comment: "Step Instruction")
        let _ = String(localized: "Compressed weight is insulation. If you think you have enough, add more. It should shed water like shingles.", comment: "Step Detail")
        let _ = String(localized: "Food", comment: "Domain Name")
        let _ = String(localized: "Heavy rock triggered by bait stick", comment: "Technique Subtitle")
        let _ = String(localized: "Trap", comment: "Category")
        let _ = String(localized: "Find a flat heavy rock (5-20 lbs depending on target).", comment: "Step Instruction")
        let _ = String(localized: "Rock must be heavy enough to kill the animal instantly. A suffering animal will escape. Test weight by imagining it dropped on prey.", comment: "Step Detail")
        let _ = String(localized: "Carve 3 sticks: vertical post, diagonal bait stick, horizontal trigger.", comment: "Step Instruction")
        let _ = String(localized: "Each stick has notches that interlock. The figure-4 shape is critical — it converts light trigger force into total collapse.", comment: "Step Detail")
        let _ = String(localized: "Assemble under the rock: vertical stick supports horizontal trigger, diagonal holds bait.", comment: "Step Instruction")
        let _ = String(localized: "The bait stick angles toward the ground under the rock. When the animal pulls the bait, it releases the trigger, dropping the rock.", comment: "Step Detail")
        let _ = String(localized: "Place bait on the end of the diagonal stick.", comment: "Step Instruction")
        let _ = String(localized: "Use peanut butter, berries, seeds, or meat scraps. Set on game trails. Check twice daily — trapped animals attract predators.", comment: "Step Detail")
        let _ = String(localized: "Simple Wire Snare", comment: "Technique Name")
        let _ = String(localized: "Noose trap for small game", comment: "Technique Subtitle")
        let _ = String(localized: "Make a noose loop from wire, paracord, or strong cordage.", comment: "Step Instruction")
        let _ = String(localized: "Wire snares are most effective — animals can't chew through. The loop should be fist-sized for rabbits, head-sized for larger game.", comment: "Step Detail")
        let _ = String(localized: "Secure the free end to a stake, tree, or spring pole.", comment: "Step Instruction")
        let _ = String(localized: "A spring pole (bent sapling) lifts the catch off the ground, preventing escape and keeping it from other predators.", comment: "Step Detail")
        let _ = String(localized: "Set at head height on an active game trail.", comment: "Step Instruction")
        let _ = String(localized: "Position the bottom of the loop 2-3 inches off the ground for rabbits. Look for droppings, tracks, and worn paths.", comment: "Step Detail")
        let _ = String(localized: "Set 10-12 snares to increase your odds.", comment: "Step Instruction")
        let _ = String(localized: "One snare has maybe a 10% chance. Twelve snares give you a reasonable chance of catching something. Set and forget — check morning and evening.", comment: "Step Detail")
        let _ = String(localized: "Ojibwa Bird Snare", comment: "Technique Name")
        let _ = String(localized: "Perch-triggered snare for birds", comment: "Technique Subtitle")
        let _ = String(localized: "Drive a pole into the ground near a bird-frequented area.", comment: "Step Instruction")
        let _ = String(localized: "Near water sources, berry bushes, or open fields where birds land. The pole should be about 4 feet tall.", comment: "Step Detail")
        let _ = String(localized: "Drill a hole near the top for a perch toggle.", comment: "Step Instruction")
        let _ = String(localized: "The toggle is a short stick inserted through the hole. It must be loose enough to release when weight is applied.", comment: "Step Detail")
        let _ = String(localized: "Attach a snare loop to the toggle, hanging down.", comment: "Step Instruction")
        let _ = String(localized: "The loop lies flat on top of the perch. When a bird lands, its weight pulls the toggle, tightening the snare around its feet.", comment: "Step Detail")
        let _ = String(localized: "Attach a weight or spring to the snare line.", comment: "Step Instruction")
        let _ = String(localized: "A rock weight pulling the snare tight ensures the bird can't escape. The weight also swings the bird off the perch.", comment: "Step Detail")
        let _ = String(localized: "Fish Spear (Gig)", comment: "Technique Name")
        let _ = String(localized: "Pronged spear for shallow water fishing", comment: "Technique Subtitle")
        let _ = String(localized: "Fish", comment: "Category")
        let _ = String(localized: "Find a straight pole 6-8 feet long.", comment: "Step Instruction")
        let _ = String(localized: "Green hardwood is best — dry wood splits too easily. The pole should be about 1-inch diameter.", comment: "Step Detail")
        let _ = String(localized: "Split the tip into 4 prongs, 6-8 inches deep.", comment: "Step Instruction")
        let _ = String(localized: "Cross-split the end. Insert small sticks to spread the prongs apart. Sharpen each prong to a point.", comment: "Step Detail")
        let _ = String(localized: "Harden the tips in fire.", comment: "Step Instruction")
        let _ = String(localized: "Rotate the tips above coals (not in flames) until they darken. This case-hardens the wood. Don't burn them.", comment: "Step Detail")
        let _ = String(localized: "Aim BELOW the fish — refraction makes fish appear higher than they are.", comment: "Step Instruction")
        let _ = String(localized: "Water bends light. The fish is actually 25% deeper than it looks. Aim at its shadow on the bottom if visible.", comment: "Step Detail")
        let _ = String(localized: "Fish Basket Trap", comment: "Technique Name")
        let _ = String(localized: "Passive trap that catches fish 24/7", comment: "Technique Subtitle")
        let _ = String(localized: "Weave a funnel-shaped basket from flexible branches or vines.", comment: "Step Instruction")
        let _ = String(localized: "Willow, reed, or any pliable material. The funnel narrows inward — fish swim in but can't find the exit.", comment: "Step Detail")
        let _ = String(localized: "Create an inner funnel that points inward.", comment: "Step Instruction")
        let _ = String(localized: "The opening should be 3-4 inches wide at the entrance, narrowing to 1-2 inches. Fish follow the funnel in but bump against the walls trying to get out.", comment: "Step Detail")
        let _ = String(localized: "Bait with bread, berries, or fish guts inside the trap.", comment: "Step Instruction")
        let _ = String(localized: "Place bait at the far end. The smell draws fish in through the funnel.", comment: "Step Detail")
        let _ = String(localized: "Set in streams facing upstream or in tidal areas.", comment: "Step Instruction")
        let _ = String(localized: "Fish swim upstream naturally and enter the funnel. Weight with rocks to keep in place. Check twice daily.", comment: "Step Detail")
        let _ = String(localized: "Improvised Hook & Line", comment: "Technique Name")
        let _ = String(localized: "Fishing with found materials", comment: "Technique Subtitle")
        let _ = String(localized: "Make hooks from thorns, bones, safety pins, or carved wood.", comment: "Step Instruction")
        let _ = String(localized: "Gorge hooks (straight sharp sticks) work on large fish. Bend paperclips, wire, or use strong thorns. Bone fragments can be carved into hooks.", comment: "Step Detail")
        let _ = String(localized: "Use any strong thin material for line.", comment: "Step Instruction")
        let _ = String(localized: "Paracord inner strands, dental floss, thread from clothing, plant fibers twisted into cordage. Test strength before using.", comment: "Step Detail")
        let _ = String(localized: "Bait with insects, worms, berries, or bright material.", comment: "Step Instruction")
        let _ = String(localized: "Turn over rocks for insects. Dig for worms. Small pieces of bright cloth or feather can serve as lures.", comment: "Step Detail")
        let _ = String(localized: "Set multiple passive lines to maximize chance.", comment: "Step Instruction")
        let _ = String(localized: "Tie lines to overhanging branches with bait in the water. Check periodically. This is more efficient than active fishing.", comment: "Step Detail")
        let _ = String(localized: "Edible Insects", comment: "Technique Name")
        let _ = String(localized: "The most abundant protein source on Earth", comment: "Technique Subtitle")
        let _ = String(localized: "Insects", comment: "Category")
        let _ = String(localized: "Target: ants, grasshoppers, crickets, grubs, termites.", comment: "Step Instruction")
        let _ = String(localized: "These are safe worldwide. Avoid brightly colored insects (warning coloration), hairy caterpillars, and anything that stinks.", comment: "Step Detail")
        let _ = String(localized: "Always cook insects if possible.", comment: "Step Instruction")
        let _ = String(localized: "Roasting kills parasites. Dry-roast in a pan, on a hot rock, or skewer and hold over flame. Removes legs and wings for easier eating.", comment: "Step Detail")
        let _ = String(localized: "Remove legs, wings, and heads before eating.", comment: "Step Instruction")
        let _ = String(localized: "Legs have barbs that irritate the throat. Wings are indigestible. Heads can be bitter.", comment: "Step Detail")
        let _ = String(localized: "Collect in quantity — you need volume for meaningful nutrition.", comment: "Step Instruction")
        let _ = String(localized: "100g of crickets has more protein than 100g of beef. But you need to eat a LOT. Set light traps at night or shake them from vegetation in the morning when cold.", comment: "Step Detail")
        let _ = String(localized: "Universal Edibility Test", comment: "Technique Name")
        let _ = String(localized: "Test unknown plants before eating", comment: "Technique Subtitle")
        let _ = String(localized: "Forage", comment: "Category")
        let _ = String(localized: "Test only ONE plant part at a time (leaf, root, fruit, stem).", comment: "Step Instruction")
        let _ = String(localized: "Each part may have different toxicity. Do not test more than one part simultaneously. Different parts of the same plant can range from edible to lethal.", comment: "Step Detail")
        let _ = String(localized: "Rub on inner wrist for 15 minutes. Wait 45 minutes for reaction.", comment: "Step Instruction")
        let _ = String(localized: "If rash, burning, or swelling occurs — reject this plant. No reaction = proceed to next step.", comment: "Step Detail")
        let _ = String(localized: "Touch to lip corner for 3 minutes. Then tongue tip for 15 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Any tingling, burning, or numbness = stop. Spit out and rinse mouth. Wait 15 minutes between each step.", comment: "Step Detail")
        let _ = String(localized: "Chew a small piece for 15 minutes without swallowing.", comment: "Step Instruction")
        let _ = String(localized: "If no burning, bitterness, or soapy taste, swallow. Wait 8 hours monitoring for stomach pain, nausea, or diarrhea.", comment: "Step Detail")
        let _ = String(localized: "If no ill effects after 8 hours, eat 1/4 cup. Wait another 8 hours.", comment: "Step Instruction")
        let _ = String(localized: "If still no effects, the plant part is likely safe. This test takes 24+ hours. Do NOT shortcut. Poisoning in a survival situation can be fatal.", comment: "Step Detail")
        let _ = String(localized: "Commonly Edible Wild Plants", comment: "Technique Name")
        let _ = String(localized: "Widely distributed safe plants", comment: "Technique Subtitle")
        let _ = String(localized: "Dandelion: entire plant is edible — leaves, flowers, roots.", comment: "Step Instruction")
        let _ = String(localized: "Young leaves raw in salad, older leaves boiled to reduce bitterness. Roots roasted as coffee substitute. Grows worldwide.", comment: "Step Detail")
        let _ = String(localized: "Cattail: the 'supermarket of the swamp.'", comment: "Step Instruction")
        let _ = String(localized: "Young shoots raw or cooked (taste like cucumber). Pollen as flour. Roots pounded for starch. Found at water edges worldwide.", comment: "Step Detail")
        let _ = String(localized: "Pine: inner bark is edible, needles make vitamin C tea.", comment: "Step Instruction")
        let _ = String(localized: "Scrape the white/cream layer between bark and wood. Eat raw or dried and pounded into flour. Pine needle tea prevents scurvy.", comment: "Step Detail")
        let _ = String(localized: "Clover: flowers and leaves are edible raw or cooked.", comment: "Step Instruction")
        let _ = String(localized: "White and red clover are safe. High in protein for a plant. Dry and crumble for flour substitute.", comment: "Step Detail")
        let _ = String(localized: "Plantain (broadleaf): common lawn weed, edible and medicinal.", comment: "Step Instruction")
        let _ = String(localized: "Young leaves raw in salads. Older leaves cooked like spinach. Crushed leaf poultice for insect bites and stings.", comment: "Step Detail")
        let _ = String(localized: "Plants to Avoid", comment: "Technique Name")
        let _ = String(localized: "Recognition of dangerous plants", comment: "Technique Subtitle")
        let _ = String(localized: "Avoid: white or yellow berries. 90% are poisonous.", comment: "Step Instruction")
        let _ = String(localized: "Exception: some white mulberries. But in a survival situation, skip ALL white/yellow berries. The risk is not worth it.", comment: "Step Detail")
        let _ = String(localized: "Avoid: plants with milky sap (except dandelion and coconut).", comment: "Step Instruction")
        let _ = String(localized: "Milky sap often indicates toxic alkaloids. Even skin contact can cause blistering with some species.", comment: "Step Detail")
        let _ = String(localized: "Avoid: umbrella-shaped flower clusters (parsley family).", comment: "Step Instruction")
        let _ = String(localized: "Water hemlock and poison hemlock are among the most lethal plants in North America. They look like carrots and parsley.", comment: "Step Detail")
        let _ = String(localized: "Avoid: almond/peach scent in leaves or bark.", comment: "Step Instruction")
        let _ = String(localized: "This smell indicates cyanogenic glycosides — cyanide precursors. Cherry laurel, elderberry leaves, and wild almonds.", comment: "Step Detail")
        let _ = String(localized: "Avoid: mushrooms unless you are an expert.", comment: "Step Instruction")
        let _ = String(localized: "Many deadly mushrooms look identical to edible ones. Amanita species kill 95% of people who eat them. No edibility test works for mushrooms. Experts only.", comment: "Step Detail")
        let _ = String(localized: "Cooking Over Open Fire", comment: "Technique Name")
        let _ = String(localized: "Methods for cooking without pots", comment: "Technique Subtitle")
        let _ = String(localized: "Cooking", comment: "Category")
        let _ = String(localized: "Spit roasting: skewer meat on a green stick over coals.", comment: "Step Instruction")
        let _ = String(localized: "Use COALS, not flames. Flames char the outside while leaving the inside raw. Keep 6-8 inches above coals. Turn frequently.", comment: "Step Detail")
        let _ = String(localized: "Rock cooking: heat flat rocks and cook directly on them.", comment: "Step Instruction")
        let _ = String(localized: "Use dry, non-porous rocks. WET or RIVER rocks can EXPLODE when heated — they contain trapped moisture. Heat gradually.", comment: "Step Detail")
        let _ = String(localized: "Clay baking: coat meat in thick clay and bake in coals.", comment: "Step Instruction")
        let _ = String(localized: "The clay seals in moisture and creates an oven. When cracked open, skin/feathers peel off with the clay. Works great for birds and fish.", comment: "Step Detail")
        let _ = String(localized: "Leaf wrapping: wrap food in large non-toxic leaves and place on coals.", comment: "Step Instruction")
        let _ = String(localized: "Banana leaves, burdock, grape leaves. Creates a steaming packet. Food cooks evenly and stays moist.", comment: "Step Detail")
        let _ = String(localized: "Stone Boiling", comment: "Technique Name")
        let _ = String(localized: "Boil water in non-fireproof containers", comment: "Technique Subtitle")
        let _ = String(localized: "Fill a bark container, skin bag, or hollowed log with water.", comment: "Step Instruction")
        let _ = String(localized: "These containers can't go on fire but can hold boiling water. Even a plastic bag works if filled with water (the water prevents it from melting).", comment: "Step Detail")
        let _ = String(localized: "Heat rocks in a fire until glowing hot.", comment: "Step Instruction")
        let _ = String(localized: "Use DRY rocks only. River rocks or wet rocks can shatter explosively. Heat for 20-30 minutes until glowing.", comment: "Step Detail")
        let _ = String(localized: "Transfer hot rocks to the water with sticks or tongs.", comment: "Step Instruction")
        let _ = String(localized: "Brush ash off rocks before transferring. Drop carefully to avoid splashing boiling water.", comment: "Step Detail")
        let _ = String(localized: "Continue adding rocks until water reaches a rolling boil.", comment: "Step Instruction")
        let _ = String(localized: "2-3 fist-sized rocks will boil 1 liter. Remove cooled rocks with sticks and add newly heated ones to maintain the boil.", comment: "Step Detail")
        let _ = String(localized: "Meat Preservation (Smoking/Drying)", comment: "Technique Name")
        let _ = String(localized: "Make meat last for weeks", comment: "Technique Subtitle")
        let _ = String(localized: "Preservation", comment: "Category")
        let _ = String(localized: "Cut meat into thin strips — 1/4 inch thick.", comment: "Step Instruction")
        let _ = String(localized: "Cut WITH the grain for jerky. Thinner strips dry faster and spoil less. Remove all fat — fat goes rancid.", comment: "Step Detail")
        let _ = String(localized: "For smoking: build a low smoky fire in an enclosed space.", comment: "Step Instruction")
        let _ = String(localized: "Use green wood or wet wood to create dense smoke. Build a tripod or rack 2-3 feet above the fire. Smoke for 6-12 hours.", comment: "Step Detail")
        let _ = String(localized: "For drying: hang strips in direct sun and wind.", comment: "Step Instruction")
        let _ = String(localized: "Hot, dry, windy conditions are ideal. Hang on a line or rack. Protect from flies with thin cloth. Sun-dry for 1-2 days.", comment: "Step Detail")
        let _ = String(localized: "Meat is done when it cracks but doesn't break when bent.", comment: "Step Instruction")
        let _ = String(localized: "Properly dried meat can last 2-4 weeks without refrigeration. Store in breathable cloth or bark containers. Mold means it's too moist.", comment: "Step Detail")
        let _ = String(localized: "Pemmican", comment: "Technique Name")
        let _ = String(localized: "High-calorie survival super food", comment: "Technique Subtitle")
        let _ = String(localized: "Pound dried meat into powder.", comment: "Step Instruction")
        let _ = String(localized: "Use rocks as mortar and pestle. Meat should be completely dry — any moisture causes spoilage. Pound until fibrous powder.", comment: "Step Detail")
        let _ = String(localized: "Mix meat powder with rendered fat (50/50 ratio).", comment: "Step Instruction")
        let _ = String(localized: "Melt animal fat slowly. Strain out solids. Mix warm liquid fat with meat powder until it holds together.", comment: "Step Detail")
        let _ = String(localized: "Add dried berries or nuts if available.", comment: "Step Instruction")
        let _ = String(localized: "Crushed dried berries add vitamins and flavor. Nuts add additional fat and calories. These are optional.", comment: "Step Detail")
        let _ = String(localized: "Form into bars or balls and let cool.", comment: "Step Instruction")
        let _ = String(localized: "Pemmican stores for months at room temperature and years if kept cool. One pound provides 3,500 calories — a full day's rations.", comment: "Step Detail")
        let _ = String(localized: "Catching Crayfish", comment: "Technique Name")
        let _ = String(localized: "Freshwater lobsters found in most streams", comment: "Technique Subtitle")
        let _ = String(localized: "Look under rocks in shallow streams and rivers.", comment: "Step Instruction")
        let _ = String(localized: "Crayfish hide under rocks during the day. Grab behind the head to avoid pincers.", comment: "Step Detail")
        let _ = String(localized: "Bait trap: container with small opening and bait inside.", comment: "Step Instruction")
        let _ = String(localized: "Cut plastic bottle with top inverted makes a trap. Bait with fish guts or bread.", comment: "Step Detail")
        let _ = String(localized: "Boil 5-7 minutes until bright red. Eat tail meat.", comment: "Step Instruction")
        let _ = String(localized: "Never eat raw—parasites. Discard any dead before cooking.", comment: "Step Detail")
        let _ = String(localized: "Edible Seaweed Harvesting", comment: "Technique Name")
        let _ = String(localized: "The ocean's most nutritious free food", comment: "Technique Subtitle")
        let _ = String(localized: "Harvest seaweed attached to rocks, not floating loose.", comment: "Step Instruction")
        let _ = String(localized: "Floating seaweed may be decomposing. Most attached seaweed is edible.", comment: "Step Detail")
        let _ = String(localized: "Rinse in fresh water if available to reduce salt.", comment: "Step Instruction")
        let _ = String(localized: "High salt worsens dehydration. Eat in small amounts if no fresh water.", comment: "Step Detail")
        let _ = String(localized: "Eat raw, dried, or add to soups. Rich in iodine and vitamins.", comment: "Step Instruction")
        let _ = String(localized: "Kelp, nori, dulse, sea lettuce all edible. Sun-dry for preservation.", comment: "Step Detail")
        let _ = String(localized: "Cattail Harvesting", comment: "Technique Name")
        let _ = String(localized: "Survival supermarket — every part is edible", comment: "Technique Subtitle")
        let _ = String(localized: "Identify: tall reeds with brown cigar-shaped seed heads.", comment: "Step Instruction")
        let _ = String(localized: "Found in marshes, ponds, wet areas worldwide. One of safest wild foods.", comment: "Step Detail")
        let _ = String(localized: "Root: dig rhizome, peel and eat raw or roast. Starchy.", comment: "Step Instruction")
        let _ = String(localized: "Potato-like. Can be dried and ground into flour. Available year-round.", comment: "Step Detail")
        let _ = String(localized: "Young shoots: peel outer leaves, inner core is edible raw.", comment: "Step Instruction")
        let _ = String(localized: "Called Cossack asparagus. Crisp, mild flavor. Spring harvest.", comment: "Step Detail")
        let _ = String(localized: "Pollen: shake from flower head. High-protein flour substitute.", comment: "Step Instruction")
        let _ = String(localized: "Mix with water for pancakes. Summer harvest only.", comment: "Step Detail")
        let _ = String(localized: "Pine Needle Tea", comment: "Technique Name")
        let _ = String(localized: "Vitamin C from any pine tree", comment: "Technique Subtitle")
        let _ = String(localized: "Gather green pine needles. Avoid yew (flat needles, red berries—toxic).", comment: "Step Instruction")
        let _ = String(localized: "True pines with needles in bundles of 2-5 are safe.", comment: "Step Detail")
        let _ = String(localized: "Chop or bruise needles to release oils.", comment: "Step Instruction")
        let _ = String(localized: "Cut into small pieces or crush with rock.", comment: "Step Detail")
        let _ = String(localized: "Steep in hot (not boiling) water for 10-15 minutes.", comment: "Step Instruction")
        let _ = String(localized: "Boiling destroys vitamin C. Strain before drinking.", comment: "Step Detail")
        let _ = String(localized: "5x more vitamin C than orange juice. Prevents scurvy.", comment: "Step Instruction")
        let _ = String(localized: "Also contains vitamin A. Pleasant forest taste.", comment: "Step Detail")
        let _ = String(localized: "Smoking Meat for Preservation", comment: "Technique Name")
        let _ = String(localized: "Preserve meat for weeks without refrigeration", comment: "Technique Subtitle")
        let _ = String(localized: "Cut meat into thin strips — 1/4 inch maximum.", comment: "Step Instruction")
        let _ = String(localized: "Thinner strips smoke faster and more evenly. Cut against grain.", comment: "Step Detail")
        let _ = String(localized: "Build smoking rack 2-3 feet above small, smoky fire.", comment: "Step Instruction")
        let _ = String(localized: "Green wood tripod with cross-sticks. Smoke, not flame.", comment: "Step Detail")
        let _ = String(localized: "Use hardwood: oak, hickory, maple, apple. Never pine.", comment: "Step Instruction")
        let _ = String(localized: "Resin from pine makes meat toxic. Green hardwood = most smoke.", comment: "Step Detail")
        let _ = String(localized: "Smoke 6-12 hours until dry and dark. Should snap, not fold.", comment: "Step Instruction")
        let _ = String(localized: "Properly smoked jerky lasts 2-4 weeks unrefrigerated.", comment: "Step Detail")
        let _ = String(localized: "Animal Skinning & Butchering", comment: "Technique Name")
        let _ = String(localized: "Field dress game safely", comment: "Technique Subtitle")
        let _ = String(localized: "Hunting", comment: "Category")
        let _ = String(localized: "Shallow cut from pelvis to ribcage — do not puncture organs.", comment: "Step Instruction")
        let _ = String(localized: "Use knife tip only. Lift skin, cut outward. Organ puncture contaminates meat.", comment: "Step Detail")
        let _ = String(localized: "Remove organs in one mass. Save heart, liver, kidneys.", comment: "Step Instruction")
        let _ = String(localized: "Cut windpipe and esophagus at top. These organs are nutrient-dense.", comment: "Step Detail")
        let _ = String(localized: "Skin by pulling hide away, cutting connective tissue.", comment: "Step Instruction")
        let _ = String(localized: "Start at legs, work toward spine. Keep blade against hide.", comment: "Step Detail")
        let _ = String(localized: "Separate meat along muscle groups. Cook or preserve immediately.", comment: "Step Instruction")
        let _ = String(localized: "Hindquarters = most meat. Backstrap along spine = best cut.", comment: "Step Detail")
        let _ = String(localized: "Shellfish & Mussel Gathering", comment: "Technique Name")
        let _ = String(localized: "Tidal zone protein available twice daily", comment: "Technique Subtitle")
        let _ = String(localized: "Gather at low tide. Mussels on rocks, clams in sand.", comment: "Step Instruction")
        let _ = String(localized: "Look for small holes that squirt water for clams.", comment: "Step Detail")
        let _ = String(localized: "Discard any that are open and don't close when tapped.", comment: "Step Instruction")
        let _ = String(localized: "Open shells = dead = bacterial contamination.", comment: "Step Detail")
        let _ = String(localized: "Boil until shells open, 5-10 minutes. Discard unopened.", comment: "Step Instruction")
        let _ = String(localized: "Raw shellfish carry parasites and bacteria.", comment: "Step Detail")
        let _ = String(localized: "Avoid during red tide or warm months in tropics.", comment: "Step Instruction")
        let _ = String(localized: "Paralytic shellfish poisoning is fatal. No field treatment.", comment: "Step Detail")
        let _ = String(localized: "Wild Onion & Garlic ID", comment: "Technique Name")
        let _ = String(localized: "Smells like onion = safe. No smell = death camas", comment: "Technique Subtitle")
        let _ = String(localized: "Crush leaf or bulb. MUST smell of onion or garlic.", comment: "Step Instruction")
        let _ = String(localized: "Death camas looks identical but has NO onion smell. Fatal if eaten.", comment: "Step Detail")
        let _ = String(localized: "Check for onion-like bulb with papery skin.", comment: "Step Instruction")
        let _ = String(localized: "Layered bulbs like store-bought. Round with dry outer layers.", comment: "Step Detail")
        let _ = String(localized: "Leaves should be grass-like, from the base.", comment: "Step Instruction")
        let _ = String(localized: "Long, flat or tubular. All from ground level.", comment: "Step Detail")
        let _ = String(localized: "Eat raw, roasted, or in soups. Entire plant edible.", comment: "Step Instruction")
        let _ = String(localized: "Bulb, leaves, flowers all edible. Roasting sweetens.", comment: "Step Detail")
        let _ = String(localized: "Frog Catching", comment: "Technique Name")
        let _ = String(localized: "Night hunting with a light source", comment: "Technique Subtitle")
        let _ = String(localized: "Hunt at night near water with light. Frogs freeze in light.", comment: "Step Instruction")
        let _ = String(localized: "Walk along stream banks and pond edges. Eyes reflect light.", comment: "Step Detail")
        let _ = String(localized: "Grab quickly from behind. They are fast and slippery.", comment: "Step Instruction")
        let _ = String(localized: "Approach slowly, grab with fast swoop. Pin to ground.", comment: "Step Detail")
        let _ = String(localized: "Avoid brightly colored frogs — many are toxic.", comment: "Step Instruction")
        let _ = String(localized: "Red, blue, yellow, orange = poison. Stick to green/brown.", comment: "Step Detail")
        let _ = String(localized: "Remove skin, cook legs thoroughly. Discard organs.", comment: "Step Instruction")
        let _ = String(localized: "Skin may have irritants. Legs are the meat. Taste like chicken.", comment: "Step Detail")
        let _ = String(localized: "Pine Bark Flour", comment: "Technique Name")
        let _ = String(localized: "Emergency starch from inner pine bark", comment: "Technique Subtitle")
        let _ = String(localized: "Strip the outer bark from a pine tree to expose the inner bark.", comment: "Step Instruction")
        let _ = String(localized: "The cambium layer — thin, moist, whitish layer between the rough outer bark and the wood. Peel in vertical strips. Take from multiple trees to avoid killing any one tree.", comment: "Step Detail")
        let _ = String(localized: "Scrape off the inner bark (cambium) in thin strips.", comment: "Step Instruction")
        let _ = String(localized: "Use a knife edge to scrape. You want the soft, moist inner bark, not the hard outer bark or the wood underneath. It tastes slightly sweet and resinous.", comment: "Step Detail")
        let _ = String(localized: "Dry the strips and grind into flour. Mix with water for porridge.", comment: "Step Instruction")
        let _ = String(localized: "Dried pine bark flour contains 500-600 calories per 100g. It can be eaten raw, boiled into porridge, or mixed with other flours. It kept Scandinavian populations alive through famine.", comment: "Step Detail")
        let _ = String(localized: "Every part of the cattail is edible year-round", comment: "Technique Subtitle")
        let _ = String(localized: "Identify cattails by their distinctive brown cigar-shaped seed head.", comment: "Step Instruction")
        let _ = String(localized: "Cattails grow in wetlands, ponds, and ditches worldwide. CAUTION: Iris leaves look similar but are toxic. Cattail leaves wrap around the stalk; iris leaves grow from the base in a fan.", comment: "Step Detail")
        let _ = String(localized: "Spring: eat young shoots and stalk bases raw or cooked.", comment: "Step Instruction")
        let _ = String(localized: "The white base of young shoots tastes like cucumber. Pull the inner stalk out and eat the tender white portion. Called 'Cossack asparagus' by Russian settlers.", comment: "Step Detail")
        let _ = String(localized: "Summer: harvest pollen from the male flower for protein-rich flour.", comment: "Step Instruction")
        let _ = String(localized: "Shake the yellow male flower (top spike) into a bag. The pollen is high in protein and can be mixed with regular flour for bread or added to soups.", comment: "Step Detail")
        let _ = String(localized: "Fall/Winter: dig up the root rhizomes for starchy food.", comment: "Step Instruction")
        let _ = String(localized: "Wash and peel the roots. The starchy core can be eaten raw, boiled, or dried and ground to flour. Rhizomes are the highest calorie part of the plant.", comment: "Step Detail")
        let _ = String(localized: "Crayfish Trapping", comment: "Technique Name")
        let _ = String(localized: "Easy protein from streams and ponds", comment: "Technique Subtitle")
        let _ = String(localized: "Fishing", comment: "Category")
        let _ = String(localized: "Look for crayfish in shallow, rocky streams and pond edges.", comment: "Step Instruction")
        let _ = String(localized: "Turn over rocks — crayfish hide underneath during the day. Active at night. Found on every continent except Antarctica.", comment: "Step Detail")
        let _ = String(localized: "Build a simple funnel trap from sticks or a plastic bottle.", comment: "Step Instruction")
        let _ = String(localized: "Cut a bottle in half, invert the top into the bottom to create a funnel entrance. Or weave a cone from flexible sticks.", comment: "Step Detail")
        let _ = String(localized: "Bait with fish scraps, meat, or strong-smelling food. Place in shallow water.", comment: "Step Instruction")
        let _ = String(localized: "Crayfish are scavengers attracted to strong smells. Anchor the trap with rocks so it doesn't drift. Set in the evening for best results.", comment: "Step Detail")
        let _ = String(localized: "Boil crayfish in water for 5 minutes. Eat the tail meat.", comment: "Step Instruction")
        let _ = String(localized: "MUST be cooked — crayfish carry parasites when raw. Twist the tail from the body, peel the shell, eat the meat.", comment: "Step Detail")
        let _ = String(localized: "Ojibwe Bird Snare", comment: "Technique Name")
        let _ = String(localized: "Traditional bird snare using a bent sapling", comment: "Technique Subtitle")
        let _ = String(localized: "Find a flexible sapling near bird feeding areas.", comment: "Step Instruction")
        let _ = String(localized: "Look for areas where birds feed on the ground — berry bushes, seed heads, water edges.", comment: "Step Detail")
        let _ = String(localized: "Bend the sapling down and secure it with a trigger mechanism.", comment: "Step Instruction")
        let _ = String(localized: "Carve a simple figure-4 trigger or use a toggle and notch system. The trigger holds the sapling down under tension.", comment: "Step Detail")
        let _ = String(localized: "Attach a snare loop made from cordage to the trigger.", comment: "Step Instruction")
        let _ = String(localized: "The snare loop should be slightly larger than the bird's foot. Lay it flat around bait.", comment: "Step Detail")
        let _ = String(localized: "Place bait (berries, seeds, insects) around the trigger.", comment: "Step Instruction")
        let _ = String(localized: "Set multiple snares in a line for better odds. Check every few hours.", comment: "Step Detail")
        let _ = String(localized: "Pemmican Making", comment: "Technique Name")
        let _ = String(localized: "The ultimate survival food: meat, fat, and berries", comment: "Technique Subtitle")
        let _ = String(localized: "Dry lean meat into jerky, then pound into powder.", comment: "Step Instruction")
        let _ = String(localized: "Any lean meat works. Slice thin and dry completely over smoke or in the sun. Once bone-dry, pound between rocks until it's a fine, fluffy powder.", comment: "Step Detail")
        let _ = String(localized: "Render fat by slowly heating it until it's liquid.", comment: "Step Instruction")
        let _ = String(localized: "Cut fat into small pieces, heat slowly. Strain the liquid fat through cloth. Pure rendered fat stores for months.", comment: "Step Detail")
        let _ = String(localized: "Mix powdered meat with warm rendered fat at a 1:1 ratio.", comment: "Step Instruction")
        let _ = String(localized: "The fat should be warm but not hot. Mix thoroughly. Optionally add dried, crushed berries for nutrition and flavor.", comment: "Step Detail")
        let _ = String(localized: "Press into bars. Stores for months without refrigeration.", comment: "Step Instruction")
        let _ = String(localized: "Pemmican is the most calorie-dense survival food: 3,000+ calories per pound. Keeps for years if stored dry.", comment: "Step Detail")
        let _ = String(localized: "Jerky Without Salt", comment: "Technique Name")
        let _ = String(localized: "Preserve meat when you have no salt", comment: "Technique Subtitle")
        let _ = String(localized: "Cut meat into thin strips (1/4 inch) along the grain.", comment: "Step Instruction")
        let _ = String(localized: "Thinner strips dry faster. Remove ALL fat — fat does not dry, it goes rancid. Lean meat only.", comment: "Step Detail")
        let _ = String(localized: "Build a drying rack over a smoky fire.", comment: "Step Instruction")
        let _ = String(localized: "Use green wood for more smoke (hickory, oak, mesquite). The smoke is antimicrobial and adds flavor.", comment: "Step Detail")
        let _ = String(localized: "Hang strips on the rack 6-12 inches above the smoke.", comment: "Step Instruction")
        let _ = String(localized: "Don't let strips touch each other. Air must circulate. Flip every few hours.", comment: "Step Detail")
        let _ = String(localized: "Dry until strips crack when bent but don't break.", comment: "Step Instruction")
        let _ = String(localized: "Takes 6-12 hours over smoke. Without salt, keeps 1-2 weeks. Eat it fast or make pemmican.", comment: "Step Detail")
        let _ = String(localized: "Mushroom Safety Rules", comment: "Technique Name")
        let _ = String(localized: "Critical rules for mushroom identification and consumption", comment: "Technique Subtitle")
        let _ = String(localized: "Foraging", comment: "Category")
        let _ = String(localized: "NEVER eat a mushroom you cannot 100% identify. No exceptions.", comment: "Step Instruction")
        let _ = String(localized: "Many deadly mushrooms look almost identical to edible ones. Death cap (Amanita phalloides) kills more people than any other mushroom and initially looks like several edible species. There is NO universal test for edibility.", comment: "Step Detail")
        let _ = String(localized: "Learn and focus ONLY on a few easily-identified safe species.", comment: "Step Instruction")
        let _ = String(localized: "Beginner-safe species with few lookalikes: chicken of the woods (orange shelf mushroom), giant puffball (must be pure white inside), morels (honeycomb pattern). Learn these from an expert, not a book alone.", comment: "Step Detail")
        let _ = String(localized: "When in doubt, skip mushrooms. The caloric value isn't worth the risk.", comment: "Step Instruction")
        let _ = String(localized: "Most mushrooms are low in calories (20-30 cal per cup). A misidentification can cause liver failure and death. The risk/reward ratio is terrible. Focus caloric foraging on plants, insects, and animals instead.", comment: "Step Detail")
        let _ = String(localized: "Seaweed & Kelp Harvesting", comment: "Technique Name")
        let _ = String(localized: "Harvest nutritious seaweed from coastal environments", comment: "Technique Subtitle")
        let _ = String(localized: "Harvest seaweed from clean water, attached to rocks (not free-floating).", comment: "Step Instruction")
        let _ = String(localized: "Free-floating seaweed may be decomposing. Harvest from rocks in clean, moving water. Avoid areas near sewage outlets, harbors, or industrial sites. Best at low tide when more is exposed.", comment: "Step Detail")
        let _ = String(localized: "Rinse thoroughly and dry in sun or near fire to preserve.", comment: "Step Instruction")
        let _ = String(localized: "Fresh seaweed spoils within 24 hours. Dried seaweed lasts months. Spread thin on rocks or hang on cord in sun. Can also eat fresh — most edible seaweed can be eaten raw or lightly boiled.", comment: "Step Detail")
        let _ = String(localized: "Avoid blue-green algae (cyanobacteria) — it's toxic.", comment: "Step Instruction")
        let _ = String(localized: "Blue-green algae looks like green paint in water. It produces neurotoxins and liver toxins. Real seaweed is brown, green, or red and has a plant-like structure. If it looks like scum or slime, avoid it.", comment: "Step Detail")
        let _ = String(localized: "Rich vitamin C source from any pine tree", comment: "Technique Subtitle")
        let _ = String(localized: "Gather a handful of fresh green pine needles. Avoid yew (toxic).", comment: "Step Instruction")
        let _ = String(localized: "Most pine species are safe: white pine, scotch pine, ponderosa. AVOID yew (flat needles, red berries) and Norfolk Island pine. Choose young, bright green needles for best flavor and nutrition.", comment: "Step Detail")
        let _ = String(localized: "Chop needles into small pieces and steep in hot (not boiling) water.", comment: "Step Instruction")
        let _ = String(localized: "Chopping releases oils. Use hot water just below boiling — boiling destroys vitamin C. Steep 5-10 minutes until water turns light yellow-green. Longer steeping = stronger flavor.", comment: "Step Detail")
        let _ = String(localized: "Drink as tea. Contains 5x the vitamin C of lemons by weight.", comment: "Step Instruction")
        let _ = String(localized: "Pine needle tea prevents scurvy and provides immune support. Pleasant, mild taste. Can be re-steeped 2-3 times. Also works cold-steeped overnight. The inner bark is also edible and calorie-dense.", comment: "Step Detail")
        let _ = String(localized: "Acorn Processing & Cooking", comment: "Technique Name")
        let _ = String(localized: "Leach tannins from acorns to make edible flour", comment: "Technique Subtitle")
        let _ = String(localized: "Collect fallen acorns. Discard any with holes (insect larvae inside).", comment: "Step Instruction")
        let _ = String(localized: "White oak acorns are less bitter than red oak. All acorns are edible after processing. Crack shells and remove nutmeat. Brown, intact nutmeat is good. Black or moldy = discard.", comment: "Step Detail")
        let _ = String(localized: "Crush nutmeat and soak in running water or change water repeatedly.", comment: "Step Instruction")
        let _ = String(localized: "Tannins make raw acorns bitter and cause stomach problems. Leaching methods: place crushed acorn in mesh bag in running stream for 24-48 hours, OR boil in multiple changes of water (5-7 changes until water runs clear).", comment: "Step Detail")
        let _ = String(localized: "Dry leached acorn meal and grind into flour for cooking.", comment: "Step Instruction")
        let _ = String(localized: "Dried acorn flour can be used for flatbread, porridge, or thickening. 100g of acorn flour = 500+ calories. Acorns were a staple food for indigenous peoples worldwide. An oak tree produces 10,000-20,000 acorns per year.", comment: "Step Detail")
        let _ = String(localized: "Bird Snare Construction", comment: "Technique Name")
        let _ = String(localized: "Build simple snares for catching birds", comment: "Technique Subtitle")
        let _ = String(localized: "Build an Ojibwa bird pole: tall pole with perch and snare.", comment: "Step Instruction")
        let _ = String(localized: "Drill a hole near top of a 6-foot pole. Insert a short perch stick. Tie a small noose of cordage around the perch. When a bird lands, its weight pulls the perch, tightening the noose around its feet.", comment: "Step Detail")
        let _ = String(localized: "Place in open area near water or food sources where birds congregate.", comment: "Step Instruction")
        let _ = String(localized: "Birds prefer the highest perch available. Place your pole taller than surrounding vegetation. Near water is ideal — birds landing to drink will use your perch. Set multiple poles for better odds.", comment: "Step Detail")
        let _ = String(localized: "Check snares frequently. Process caught birds immediately.", comment: "Step Instruction")
        let _ = String(localized: "Pluck feathers while still warm (easier). Gut immediately. Small birds can be roasted whole on a spit. All birds are edible — there are no poisonous birds (though some taste terrible). Cook thoroughly for food safety.", comment: "Step Detail")
        let _ = String(localized: "Small Game Field Dressing", comment: "Technique Name")
        let _ = String(localized: "Clean and prepare small animals for cooking", comment: "Technique Subtitle")
        let _ = String(localized: "Make a small cut through the belly skin (avoid puncturing organs).", comment: "Step Instruction")
        let _ = String(localized: "Pinch belly skin and make a small cut. Insert two fingers under the skin to lift it away from organs, then cut between your fingers. Puncturing the intestines contaminates the meat.", comment: "Step Detail")
        let _ = String(localized: "Remove intestines, stomach, and bladder. Keep liver, heart, and kidneys.", comment: "Step Instruction")
        let _ = String(localized: "Reach in and pull organs out in one mass. Heart, liver, and kidneys are the most nutritious parts — eat them first. Liver is extremely nutrient-dense. Check liver for spots (parasites) — discard if spotted.", comment: "Step Detail")
        let _ = String(localized: "Skin by pulling hide off like removing a sock.", comment: "Step Instruction")
        let _ = String(localized: "For rabbits: cut around all four feet. Cut from foot to belly cut on each leg. Pull skin off like peeling a banana. Rinse carcass with clean water. Cook thoroughly — all wild game must be fully cooked.", comment: "Step Detail")
        let _ = String(localized: "Fish Spearing", comment: "Technique Name")
        let _ = String(localized: "Improvise a spear and catch fish in shallow water", comment: "Technique Subtitle")
        let _ = String(localized: "Create a multi-pronged spear by splitting a sapling tip into 4 prongs.", comment: "Step Instruction")
        let _ = String(localized: "Choose a straight pole 6-8 feet long. Split the tip into 4 equal sections using your knife. Wedge a small stone between the prongs to spread them. Sharpen each prong. Bind below the split to prevent further splitting.", comment: "Step Detail")
        let _ = String(localized: "Stand still in shallow water. Wait for fish to come to you.", comment: "Step Instruction")
        let _ = String(localized: "Patience is essential. Stand downstream and remain motionless. Fish will approach within minutes. Muddy your feet's scent by rubbing with mud before entering. Dawn and dusk are best times.", comment: "Step Detail")
        let _ = String(localized: "Aim below the fish to compensate for water refraction.", comment: "Step Instruction")
        let _ = String(localized: "Light bends at the water surface, making the fish appear higher than it actually is. Aim at the bottom of the fish's shadow, not the fish itself. Thrust quickly and pin against the bottom.", comment: "Step Detail")
        let _ = String(localized: "Easy, reliable protein from freshwater streams", comment: "Technique Subtitle")
        let _ = String(localized: "Build a simple funnel trap from a plastic bottle or woven sticks.", comment: "Step Instruction")
        let _ = String(localized: "Bottle trap: cut top off plastic bottle, invert it into the bottom half, staple/tie edges. Crayfish enter funnel but can't find the exit. Stick trap: weave a cone-shaped basket with narrow entrance.", comment: "Step Detail")
        let _ = String(localized: "Bait with fish scraps, meat, or rotten food. Place in rocky stream areas.", comment: "Step Instruction")
        let _ = String(localized: "Crayfish are scavengers attracted to strong-smelling bait. Place trap in 1-3 feet of water near rocks (crayfish habitat). Weight trap with rocks so it stays submerged. Set in evening, check in morning.", comment: "Step Detail")
        let _ = String(localized: "Boil crayfish alive for 3-5 minutes until bright red. Eat tail meat.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT eat dead crayfish (toxin buildup). Twist tail from body, peel shell, eat tail meat. Claw meat is also edible on larger specimens. 100g of crayfish = 80 calories and 16g protein.", comment: "Step Detail")
        let _ = String(localized: "Finding & Eating Grubs", comment: "Technique Name")
        let _ = String(localized: "High-calorie protein from rotting wood", comment: "Technique Subtitle")
        let _ = String(localized: "Look inside rotting logs and under bark for beetle larvae (grubs).", comment: "Step Instruction")
        let _ = String(localized: "Break apart soft, rotting wood. White or cream-colored larvae are beetle grubs. They're common in dead trees worldwide. Also check under rocks and in soil near rotting vegetation.", comment: "Step Detail")
        let _ = String(localized: "Squeeze grubs gently to expel gut contents (optional but improves taste).", comment: "Step Instruction")
        let _ = String(localized: "Pinch behind the head and squeeze toward the tail to expel digestive contents. This removes bitter flavors. Not strictly necessary for safety — just preference.", comment: "Step Detail")
        let _ = String(localized: "Roast on a stick near fire, or skewer and fry. Cook thoroughly.", comment: "Step Instruction")
        let _ = String(localized: "Roasted grubs taste nutty and buttery. A single large grub can contain 50+ calories — mostly fat and protein. 10 large grubs = a small meal. Can also be dried for storage.", comment: "Step Detail")
        let _ = String(localized: "Bone Broth for Maximum Nutrition", comment: "Technique Name")
        let _ = String(localized: "Extract every calorie and mineral from animal bones", comment: "Technique Subtitle")
        let _ = String(localized: "Crack or smash bones to expose marrow before boiling.", comment: "Step Instruction")
        let _ = String(localized: "Marrow is the most calorie-dense part of an animal (80% fat). Use rocks to crack long bones. Marrow can also be roasted and eaten directly — push it out of the split bone with a stick.", comment: "Step Detail")
        let _ = String(localized: "Boil cracked bones in water for 4-12 hours, keeping water level up.", comment: "Step Instruction")
        let _ = String(localized: "Long boiling extracts calcium, phosphorus, magnesium, and collagen from bones. The longer you boil, the more nutrition extracted. If possible, add acidic ingredients (wild berries) to extract more minerals.", comment: "Step Detail")
        let _ = String(localized: "Drink broth hot. Skim fat from surface for cooking or calories.", comment: "Step Instruction")
        let _ = String(localized: "The fat floating on top is pure energy. Save it for cooking other foods. The broth provides minerals, electrolytes, and gelatin. Bones can be reboiled 2-3 times for diminishing but real returns.", comment: "Step Detail")
        let _ = String(localized: "Wild Garlic & Onion Identification", comment: "Technique Name")
        let _ = String(localized: "Find wild alliums for nutrition and flavor", comment: "Technique Subtitle")
        let _ = String(localized: "Look for grass-like leaves with a strong garlic or onion smell when crushed.", comment: "Step Instruction")
        let _ = String(localized: "Wild garlic (ramps), wild onion, and wild leeks all have edible bulbs and leaves. The SMELL is the key identifier. If it doesn't smell like garlic or onion, DO NOT eat it — similar-looking plants (death camas) are deadly.", comment: "Step Detail")
        let _ = String(localized: "Dig up the bulb. It should look like a small onion or garlic clove.", comment: "Step Instruction")
        let _ = String(localized: "The bulb should have layers (like an onion) or be solid (like garlic). If the bulb has no onion smell, it is NOT wild allium. Death camas has a similar leaf but no allium smell and its bulb has no layers.", comment: "Step Detail")
        let _ = String(localized: "Eat raw, add to cooking, or dry for preservation.", comment: "Step Instruction")
        let _ = String(localized: "All parts are edible: bulbs, leaves, flowers. Excellent addition to bland survival food. Contains vitamin C, selenium, and has antimicrobial properties. Dry and crush leaves for seasoning that stores well.", comment: "Step Detail")
        let _ = String(localized: "Dandelion: Complete Edible Plant", comment: "Technique Name")
        let _ = String(localized: "Every part of the dandelion is edible and nutritious", comment: "Technique Subtitle")
        let _ = String(localized: "Identify: jagged leaves, hollow stem with milky sap, yellow flower.", comment: "Step Instruction")
        let _ = String(localized: "Dandelions are found on every continent. Leaves form a rosette at ground level. Stem is hollow and produces white latex when broken. Flower is a single composite yellow head. No poisonous lookalikes.", comment: "Step Detail")
        let _ = String(localized: "Harvest leaves (youngest are least bitter), flowers, and roots.", comment: "Step Instruction")
        let _ = String(localized: "Young leaves: eat raw in salads or boil to reduce bitterness. Flowers: eat raw or fry (remove green parts — they're bitter). Roots: roast until dark and grind for coffee substitute, or boil as root vegetable.", comment: "Step Detail")
        let _ = String(localized: "Rich in vitamins A, C, K, and minerals. More nutritious than spinach.", comment: "Step Instruction")
        let _ = String(localized: "Dandelion greens contain more vitamin A than carrots, more iron than spinach, and more calcium than milk per gram. Harvest away from roads (lead contamination) and lawns (herbicides).", comment: "Step Detail")
        let _ = String(localized: "Clay Pot Construction & Cooking", comment: "Technique Name")
        let _ = String(localized: "Make a cooking vessel from natural clay", comment: "Technique Subtitle")
        let _ = String(localized: "Find clay near stream banks — it holds shape when squeezed and doesn't crumble.", comment: "Step Instruction")
        let _ = String(localized: "Good clay is smooth, sticky when wet, and holds its form. Test: roll a pencil-thin coil. If it bends without cracking, the clay is suitable. Remove stones and roots. Knead thoroughly to remove air bubbles.", comment: "Step Detail")
        let _ = String(localized: "Build pot using coil method: roll long snakes of clay and stack in circles.", comment: "Step Instruction")
        let _ = String(localized: "Roll clay into ropes the thickness of your thumb. Coil upward from a flat base, smoothing each coil into the one below. Keep walls even thickness (1/2 inch). Smooth inside and out. Make walls thicker at the base.", comment: "Step Detail")
        let _ = String(localized: "Dry slowly for 24-48 hours, then fire in a hot campfire for 2-3 hours.", comment: "Step Instruction")
        let _ = String(localized: "Fast drying causes cracking. Place near fire for gentle drying first. Then bury in hot coals for 2-3 hours. Let cool slowly in the ashes. The pot will be fragile but functional for boiling water and cooking stews.", comment: "Step Detail")
        let _ = String(localized: "Earth Oven (Ground Pit Cooking)", comment: "Technique Name")
        let _ = String(localized: "Cook large quantities of food using heated stones underground", comment: "Technique Subtitle")
        let _ = String(localized: "Dig a pit 2-3 feet deep and wide. Build a large fire in it with stones.", comment: "Step Instruction")
        let _ = String(localized: "Use dense, non-porous stones (river rocks can explode from trapped water). Burn a hot fire for 2-3 hours until stones are glowing. Scrape out coals but leave hot stones in the pit.", comment: "Step Detail")
        let _ = String(localized: "Layer: hot stones, wet leaves/grass, food, wet leaves/grass, more hot stones.", comment: "Step Instruction")
        let _ = String(localized: "The wet vegetation creates steam for cooking. Wrap food in large green leaves to protect from ash. Layer food that takes longest on the bottom (root vegetables) and fastest on top (greens, fish).", comment: "Step Detail")
        let _ = String(localized: "Cover with earth and let cook 4-8 hours. The earth insulates the heat.", comment: "Step Instruction")
        let _ = String(localized: "Seal edges with packed dirt so steam can't escape. This method slow-cooks everything evenly. Root vegetables become soft and sweet. Meat falls off the bone. Can cook for a large group efficiently.", comment: "Step Detail")
        let _ = String(localized: "Emergency Rationing Strategy", comment: "Technique Name")
        let _ = String(localized: "How to eat when food is scarce", comment: "Technique Subtitle")
        let _ = String(localized: "Strategy", comment: "Category")
        let _ = String(localized: "Inventory EVERYTHING edible immediately.", comment: "Step Instruction")
        let _ = String(localized: "Count every bar, cracker, and candy. Divide total calories by days until rescue (estimated). Goal: 500+ cal/day.", comment: "Step Detail")
        let _ = String(localized: "Do NOT eat for the first 24 hours.", comment: "Step Instruction")
        let _ = String(localized: "Your body has reserves. Eating triggers digestion which uses water. Save food for when hunger pangs stabilize.", comment: "Step Detail")
        let _ = String(localized: "Eat small amounts during activity peaks.", comment: "Step Instruction")
        let _ = String(localized: "Eat before heavy exertion (hiking/building) or before sleep (to stay warm). Don't graze all day.", comment: "Step Detail")
        let _ = String(localized: "Wild Fruit Identification", comment: "Technique Name")
        let _ = String(localized: "Identify safe edible wild fruits", comment: "Technique Subtitle")
        let _ = String(localized: "Use the Universal Edibility Test: test ONE plant part at a time.", comment: "Step Instruction")
        let _ = String(localized: "Never eat unknown plants without testing. Test only one plant and one part (fruit, leaf, stem) at a time. If you react to any part, discard the entire plant.", comment: "Step Detail")
        let _ = String(localized: "Avoid: white/yellow berries, umbrella-shaped flowers, milky sap.", comment: "Step Instruction")
        let _ = String(localized: "General rule: 90% of white and yellow berries are poisonous. Plants with milky sap or umbrella flower clusters (like poison hemlock) are dangerous. Red berries are 50/50.", comment: "Step Detail")
        let _ = String(localized: "Safe bets: blackberries, raspberries, blueberries, rose hips.", comment: "Step Instruction")
        let _ = String(localized: "These are widely distributed and easy to identify. Blackberries/raspberries have compound berries on bramble bushes. Rose hips are the red fruit below rose flowers.", comment: "Step Detail")
        let _ = String(localized: "Smell test: crush a small amount and smell. Reject if bitter or almond-like.", comment: "Step Instruction")
        let _ = String(localized: "Bitter almond smell indicates cyanide compounds. Soapy smell indicates saponins. Both are toxic. A pleasant, fruity smell is a good sign but not conclusive.", comment: "Step Detail")
        let _ = String(localized: "Skin test: rub on inner wrist, wait 15 minutes for reaction.", comment: "Step Instruction")
        let _ = String(localized: "If no rash, burning, or numbness, place a small amount on your lip. Wait 15 minutes. Then on tongue. Wait 15 minutes. Then chew and spit. If no reaction after 8 hours, eat a small amount.", comment: "Step Detail")
        let _ = String(localized: "Boiling Water", comment: "Technique Name")
        let _ = String(localized: "The gold standard of purification", comment: "Technique Subtitle")
        let _ = String(localized: "Purification", comment: "Category")
        let _ = String(localized: "Bring water to a rolling boil.", comment: "Step Instruction")
        let _ = String(localized: "A rolling boil means large bubbles breaking the surface continuously — not just small bubbles on the bottom.", comment: "Step Detail")
        let _ = String(localized: "Maintain the boil for 1 minute (3 minutes above 6,500 ft).", comment: "Step Instruction")
        let _ = String(localized: "Boiling kills bacteria, viruses, and parasites. At altitude, water boils at a lower temperature so extra time compensates.", comment: "Step Detail")
        let _ = String(localized: "Let cool before drinking.", comment: "Step Instruction")
        let _ = String(localized: "Store in a clean container. Do not add untreated water to the clean water. Boiled water tastes flat — pour between containers to add air.", comment: "Step Detail")
        let _ = String(localized: "Iodine Treatment", comment: "Technique Name")
        let _ = String(localized: "Chemical purification for clear water", comment: "Technique Subtitle")
        let _ = String(localized: "Add 5 drops of 2% iodine tincture per quart of clear water.", comment: "Step Instruction")
        let _ = String(localized: "Double the dose for cloudy water. Triple for very cold water (below 40°F).", comment: "Step Detail")
        let _ = String(localized: "Wait 30 minutes before drinking.", comment: "Step Instruction")
        let _ = String(localized: "Iodine needs contact time. Longer wait = more effective. 30 minutes is the minimum.", comment: "Step Detail")
        let _ = String(localized: "Add vitamin C powder after wait time to improve taste.", comment: "Step Instruction")
        let _ = String(localized: "Vitamin C neutralizes iodine taste. Add AFTER the treatment period, not before. Lemon juice also works.", comment: "Step Detail")
        let _ = String(localized: "UV Light Purification (SODIS)", comment: "Technique Name")
        let _ = String(localized: "Use sunlight to kill pathogens", comment: "Technique Subtitle")
        let _ = String(localized: "Fill clear PET plastic bottles with clear water.", comment: "Step Instruction")
        let _ = String(localized: "Water must be clear — pre-filter if turbid. Only works with PET bottles (recycling number 1). Glass and colored plastic block UV.", comment: "Step Detail")
        let _ = String(localized: "Lay bottles on dark surface in direct sunlight for 6 hours.", comment: "Step Instruction")
        let _ = String(localized: "On a dark rock, corrugated metal roof, or any heat-absorbing surface. Lay horizontally for maximum UV exposure.", comment: "Step Detail")
        let _ = String(localized: "In cloudy weather, extend to 2 full days.", comment: "Step Instruction")
        let _ = String(localized: "UV-A radiation kills bacteria and viruses. Combined with heat, it's highly effective. Does NOT remove chemical contaminants.", comment: "Step Detail")
        let _ = String(localized: "Improvised Sock Filter", comment: "Technique Name")
        let _ = String(localized: "Remove sediment from turbid water", comment: "Technique Subtitle")
        let _ = String(localized: "Layer materials inside a sock or pant leg: charcoal, sand, gravel.", comment: "Step Instruction")
        let _ = String(localized: "Bottom (outlet): fine sand or crushed charcoal. Middle: sand. Top: gravel and grass. Each layer should be 2-3 inches.", comment: "Step Detail")
        let _ = String(localized: "Pour water through slowly and collect from the bottom.", comment: "Step Instruction")
        let _ = String(localized: "First few runs will be cloudy. Discard the first 2-3 batches. The filter improves with use as it develops a biofilm.", comment: "Step Detail")
        let _ = String(localized: "STILL PURIFY the filtered water by boiling or chemical treatment.", comment: "Step Instruction")
        let _ = String(localized: "This filter removes sediment and some bacteria but does NOT guarantee safe water. It's a pre-treatment step.", comment: "Step Detail")
        let _ = String(localized: "Charcoal Water Filter", comment: "Technique Name")
        let _ = String(localized: "Activated charcoal removes chemicals and taste", comment: "Technique Subtitle")
        let _ = String(localized: "Make charcoal from hardwood burned down to coals.", comment: "Step Instruction")
        let _ = String(localized: "Let a hot fire burn to glowing coals, then smother with dirt. Once cool, crush into small pieces. This is NOT activated carbon but still useful.", comment: "Step Detail")
        let _ = String(localized: "Crush charcoal into fine granules.", comment: "Step Instruction")
        let _ = String(localized: "The finer the better — more surface area means better filtration. Remove any large chunks.", comment: "Step Detail")
        let _ = String(localized: "Build a filter: container with hole → grass → charcoal → sand → gravel.", comment: "Step Instruction")
        let _ = String(localized: "Use a cut bottle, bark funnel, or bamboo section. The tight-packed charcoal layer should be the thickest — at least 4 inches.", comment: "Step Detail")
        let _ = String(localized: "Run water through multiple times for clearer results.", comment: "Step Instruction")
        let _ = String(localized: "Each pass improves clarity. Even so, boil or chemically treat afterward. Charcoal improves taste significantly.", comment: "Step Detail")
        let _ = String(localized: "Solar Still", comment: "Technique Name")
        let _ = String(localized: "Extract water from the ground using sun", comment: "Technique Subtitle")
        let _ = String(localized: "Finding Water", comment: "Category")
        let _ = String(localized: "Dig a hole 3 feet wide and 2 feet deep.", comment: "Step Instruction")
        let _ = String(localized: "Choose a sunny spot with moist soil. Near vegetation is better — plant roots indicate moisture.", comment: "Step Detail")
        let _ = String(localized: "Place a collection container in the center of the hole.", comment: "Step Instruction")
        let _ = String(localized: "A cup, can, water bottle — anything that can collect drips. If you have a drinking tube, run it from the container up out of the hole.", comment: "Step Detail")
        let _ = String(localized: "Cover the hole with clear plastic sheeting.", comment: "Step Instruction")
        let _ = String(localized: "Seal edges with dirt or rocks. Make it airtight. A garbage bag or poncho works.", comment: "Step Detail")
        let _ = String(localized: "Place a small rock on the plastic directly above the container.", comment: "Step Instruction")
        let _ = String(localized: "This creates a cone shape. Evaporated moisture condenses on the plastic and drips into the container. Expect 1-2 cups per day.", comment: "Step Detail")
        let _ = String(localized: "Transpiration Bag", comment: "Technique Name")
        let _ = String(localized: "Collect water from living plants", comment: "Technique Subtitle")
        let _ = String(localized: "Place a clear plastic bag over a leafy tree branch.", comment: "Step Instruction")
        let _ = String(localized: "Choose a branch with lots of green leaves in direct sunlight. Non-poisonous trees only — avoid oleander, yew, rhododendron.", comment: "Step Detail")
        let _ = String(localized: "Tie the bag opening tightly around the branch.", comment: "Step Instruction")
        let _ = String(localized: "Make it airtight. Weight the bottom corner so water collects there.", comment: "Step Detail")
        let _ = String(localized: "Collect water from the lowest corner after several hours.", comment: "Step Instruction")
        let _ = String(localized: "A single bag can produce 1-3 cups per day. Set up multiple bags. Move to new branches daily as leaves deplete.", comment: "Step Detail")
        let _ = String(localized: "Dew Collection", comment: "Technique Name")
        let _ = String(localized: "Gather morning moisture from grass", comment: "Technique Subtitle")
        let _ = String(localized: "Wrap absorbent cloth around your ankles and walk through grass at dawn.", comment: "Step Instruction")
        let _ = String(localized: "T-shirts, bandanas, or any absorbent fabric. Walk through tall grass, meadows, or low brush.", comment: "Step Detail")
        let _ = String(localized: "Wring the cloth into a container when saturated.", comment: "Step Instruction")
        let _ = String(localized: "Repeat multiple passes. In heavy dew conditions, you can collect over a liter per hour.", comment: "Step Detail")
        let _ = String(localized: "Purify if possible — dew from grass may contain contaminants.", comment: "Step Instruction")
        let _ = String(localized: "Dew is condensed atmospheric moisture and is usually clean, but plant surfaces may harbor bacteria.", comment: "Step Detail")
        let _ = String(localized: "Rain Collection", comment: "Technique Name")
        let _ = String(localized: "The cleanest natural water source", comment: "Technique Subtitle")
        let _ = String(localized: "Spread any waterproof material to maximize collection area.", comment: "Step Instruction")
        let _ = String(localized: "Tarps, ponchos, garbage bags, large leaves. Angle toward a collection point.", comment: "Step Detail")
        let _ = String(localized: "Use any available containers — bottles, pots, carved wood, pits lined with plastic.", comment: "Step Instruction")
        let _ = String(localized: "Set out every container you have. A 1-hour moderate rain on a 6x6 tarp can yield 5+ gallons.", comment: "Step Detail")
        let _ = String(localized: "Let the first few minutes of rain wash the collection surface.", comment: "Step Instruction")
        let _ = String(localized: "Initial runoff picks up dirt and contaminants from the collection surface. Discard the first accumulation.", comment: "Step Detail")
        let _ = String(localized: "Finding Water by Vegetation", comment: "Technique Name")
        let _ = String(localized: "Plants tell you where water is", comment: "Technique Subtitle")
        let _ = String(localized: "Look for green vegetation in dry terrain.", comment: "Step Instruction")
        let _ = String(localized: "Cottonwoods, willows, sycamores, and cattails indicate water at or near the surface.", comment: "Step Detail")
        let _ = String(localized: "Follow animal trails that converge — they lead to water.", comment: "Step Instruction")
        let _ = String(localized: "Trails from multiple directions meeting indicate a water source. Follow them downhill.", comment: "Step Detail")
        let _ = String(localized: "Watch birds at dawn and dusk — grain-eating birds fly toward water.", comment: "Step Instruction")
        let _ = String(localized: "Pigeons, doves, and finches need daily water. They fly in straight lines toward sources. Follow their flight path.", comment: "Step Detail")
        let _ = String(localized: "Dig in the outside bend of dry riverbeds.", comment: "Step Instruction")
        let _ = String(localized: "Water pools on the outside of bends. Dig 1-3 feet and wait. Seepage indicates groundwater.", comment: "Step Detail")
        let _ = String(localized: "Desalinating Seawater", comment: "Technique Name")
        let _ = String(localized: "Remove salt through evaporation", comment: "Technique Subtitle")
        let _ = String(localized: "NEVER drink seawater directly — it accelerates dehydration.", comment: "Step Instruction")
        let _ = String(localized: "Salt concentration in seawater requires your kidneys to use more water than the drink provides. Drinking seawater kills.", comment: "Step Detail")
        let _ = String(localized: "Build a solar still using seawater as the source.", comment: "Step Instruction")
        let _ = String(localized: "Dig a pit, pour seawater in, cover with plastic. Evaporated water is salt-free. The salt remains in the pit.", comment: "Step Detail")
        let _ = String(localized: "Or boil seawater and collect condensation.", comment: "Step Instruction")
        let _ = String(localized: "Boil in a covered pot with a tube running from the lid to a collection container. The steam condenses as fresh water.", comment: "Step Detail")
        let _ = String(localized: "Even small amounts of fresh water are worth the effort.", comment: "Step Instruction")
        let _ = String(localized: "A solar still may only give 1-2 cups per day but that's enough to survive. Set up multiple stills.", comment: "Step Detail")
        let _ = String(localized: "Melting Snow & Ice for Water", comment: "Technique Name")
        let _ = String(localized: "Never eat snow directly", comment: "Technique Subtitle")
        let _ = String(localized: "Never eat snow directly — it lowers core body temp.", comment: "Step Instruction")
        let _ = String(localized: "The energy cost of melting snow in your mouth is significant. In a cold environment, this accelerates hypothermia.", comment: "Step Detail")
        let _ = String(localized: "Melt snow or ice in a dark container in the sun.", comment: "Step Instruction")
        let _ = String(localized: "Black or dark containers absorb heat. Pack loosely — compressed snow takes longer to melt and can scorch the container.", comment: "Step Detail")
        let _ = String(localized: "Prefer ice over snow — ice yields more water per volume.", comment: "Step Instruction")
        let _ = String(localized: "Snow is 90% air. You need roughly 10 gallons of snow to get 1 gallon of water. Old sea ice (blue/clear) is desalinated.", comment: "Step Detail")
        let _ = String(localized: "If using fire: add a small amount of water first to prevent scorching.", comment: "Step Instruction")
        let _ = String(localized: "Snow in a dry pot over flame scorches before melting. Add a splash of water first, then gradually add snow.", comment: "Step Detail")
        let _ = String(localized: "Water Storage & Transport", comment: "Technique Name")
        let _ = String(localized: "Carry more, lose less", comment: "Technique Subtitle")
        let _ = String(localized: "Storage", comment: "Category")
        let _ = String(localized: "Improvise containers: bamboo sections, animal stomachs, bark vessels.", comment: "Step Instruction")
        let _ = String(localized: "Green bamboo sections sealed with mud hold water well. Birch bark can be folded into watertight containers.", comment: "Step Detail")
        let _ = String(localized: "Line pits with plastic, large leaves, or clay for ground storage.", comment: "Step Instruction")
        let _ = String(localized: "A tarp-lined hole can store 10+ gallons. Cover to prevent evaporation and contamination.", comment: "Step Detail")
        let _ = String(localized: "Keep stored water covered and cool.", comment: "Step Instruction")
        let _ = String(localized: "Bacteria multiply rapidly in warm exposed water. Store in shade and cover to keep insects out.", comment: "Step Detail")
        let _ = String(localized: "Seal containers to prevent spilling during travel.", comment: "Step Instruction")
        let _ = String(localized: "Use cork, carved wood plugs, or bunched cloth to seal improvised containers.", comment: "Step Detail")
        let _ = String(localized: "Water Rationing Strategy", comment: "Technique Name")
        let _ = String(localized: "Ration sweat, not water", comment: "Technique Subtitle")
        let _ = String(localized: "Drink when thirsty. Do NOT ration your water.", comment: "Step Instruction")
        let _ = String(localized: "Your body needs water now, not later. Rationing leads to inefficiency — you become too weak to get more water. Many people have died with water in their canteen.", comment: "Step Detail")
        let _ = String(localized: "Ration your SWEAT instead.", comment: "Step Instruction")
        let _ = String(localized: "Stay in shade. Move at night. Minimize exertion. Breathe through your nose. Keep covered with loose clothing.", comment: "Step Detail")
        let _ = String(localized: "Know your needs: minimum 1 quart/day resting in shade, 1 gallon/day with activity.", comment: "Step Instruction")
        let _ = String(localized: "In hot desert conditions, you can lose 1-2 quarts per HOUR of heavy exertion. Monitor urine color.", comment: "Step Detail")
        let _ = String(localized: "Condensation Trap", comment: "Technique Name")
        let _ = String(localized: "Collect moisture from air using temperature difference", comment: "Technique Subtitle")
        let _ = String(localized: "Find a metal surface—car hood, sheet metal, or large flat rock.", comment: "Step Instruction")
        let _ = String(localized: "Metal cools faster than air at night, causing condensation. Bigger surface = more water.", comment: "Step Detail")
        let _ = String(localized: "Angle the surface so condensation runs to a collection point.", comment: "Step Instruction")
        let _ = String(localized: "Even slight angle causes droplets to run downhill. Place container at low end.", comment: "Step Detail")
        let _ = String(localized: "Best results at dawn when temperature difference is greatest.", comment: "Step Instruction")
        let _ = String(localized: "Desert nights are ideal due to extreme temperature swings. Can yield 1-2 cups overnight.", comment: "Step Detail")
        let _ = String(localized: "Bamboo Water Collection", comment: "Technique Name")
        let _ = String(localized: "Green bamboo stores water naturally", comment: "Technique Subtitle")
        let _ = String(localized: "Find green bamboo with thick stems. Shake—hear water inside.", comment: "Step Instruction")
        let _ = String(localized: "Old dry bamboo is empty. Look for green, thick-stemmed living bamboo.", comment: "Step Detail")
        let _ = String(localized: "Bend a tall stalk and cut the top. Water drains out.", comment: "Step Instruction")
        let _ = String(localized: "Position a container underneath. Each stem segment holds water independently.", comment: "Step Detail")
        let _ = String(localized: "Alternatively, punch a hole just above each node.", comment: "Step Instruction")
        let _ = String(localized: "Punch, drain, move to next node. Each compartment is separate.", comment: "Step Detail")
        let _ = String(localized: "Birch Tree Tapping", comment: "Technique Name")
        let _ = String(localized: "Birch sap is drinkable water with nutrients", comment: "Technique Subtitle")
        let _ = String(localized: "Find a birch tree with trunk at least 10 inches diameter.", comment: "Step Instruction")
        let _ = String(localized: "Works in spring when sap flows. Birch, maple, walnut all produce drinkable sap.", comment: "Step Detail")
        let _ = String(localized: "Carve a small hole 2 inches deep, angled slightly upward.", comment: "Step Instruction")
        let _ = String(localized: "About 2-3 feet from ground. Use knife point or sharp stick.", comment: "Step Detail")
        let _ = String(localized: "Insert a tube or hollow stick into the hole.", comment: "Step Instruction")
        let _ = String(localized: "Hollowed elderberry branch works. Directs sap into container.", comment: "Step Detail")
        let _ = String(localized: "Collect sap. Drinkable immediately—slightly sweet.", comment: "Step Instruction")
        let _ = String(localized: "A large birch produces 1-2 gallons per day in spring. Contains water, sugars, minerals.", comment: "Step Detail")
        let _ = String(localized: "Rock Seepage Collection", comment: "Technique Name")
        let _ = String(localized: "Collect water seeping from rock faces", comment: "Technique Subtitle")
        let _ = String(localized: "Look for wet rock faces—dark stains, moss, fern growth.", comment: "Step Instruction")
        let _ = String(localized: "Limestone and sandstone are porous. Water seeps through naturally.", comment: "Step Detail")
        let _ = String(localized: "Press absorbent cloth against wet rock, wring into container.", comment: "Step Instruction")
        let _ = String(localized: "Bandana works. Slow but reliable. Leave container overnight.", comment: "Step Detail")
        let _ = String(localized: "Create channel with clay or mud to direct trickle flow.", comment: "Step Instruction")
        let _ = String(localized: "Even small trickles add up over time. Leave collection overnight.", comment: "Step Detail")
        let _ = String(localized: "Solar Desalination", comment: "Technique Name")
        let _ = String(localized: "Convert seawater to drinkable water using sunlight", comment: "Technique Subtitle")
        let _ = String(localized: "Fill a dark container with seawater. Place a smaller empty container inside.", comment: "Step Instruction")
        let _ = String(localized: "The outer container holds saltwater. The inner container catches condensation. The inner container must be shorter than the outer.", comment: "Step Detail")
        let _ = String(localized: "Cover with clear plastic wrap. Seal edges tightly.", comment: "Step Instruction")
        let _ = String(localized: "The cover must be airtight. Use tape, clay, or wet sand to seal edges. Any leak lets moisture escape.", comment: "Step Detail")
        let _ = String(localized: "Place a small weight on the plastic above the inner container.", comment: "Step Instruction")
        let _ = String(localized: "This creates a low point where condensation drips into the collection container. A small stone works perfectly.", comment: "Step Detail")
        let _ = String(localized: "Place in direct sunlight. Collect fresh water from inner container.", comment: "Step Instruction")
        let _ = String(localized: "Sun heats saltwater, evaporation condenses on plastic, drips into inner container. Yield: 500ml-1L per day in strong sun.", comment: "Step Detail")
        let _ = String(localized: "Birch Bark Water Container", comment: "Technique Name")
        let _ = String(localized: "Waterproof container from tree bark", comment: "Technique Subtitle")
        let _ = String(localized: "Harvest a large sheet of birch bark without damaging the tree.", comment: "Step Instruction")
        let _ = String(localized: "Cut horizontally around the trunk, then vertically to peel. Take bark from dead or fallen trees when possible to avoid harming living trees.", comment: "Step Detail")
        let _ = String(localized: "Fold into a box or cone shape. Secure with cordage or wooden pegs.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark is naturally waterproof due to betulin compounds. Fold with the white side OUT. Corners can be folded and pinned.", comment: "Step Detail")
        let _ = String(localized: "Seal seams with heated pine resin.", comment: "Step Instruction")
        let _ = String(localized: "Mix pine resin with charcoal dust for a strong waterproof sealant. Apply warm, it hardens as it cools.", comment: "Step Detail")
        let _ = String(localized: "You can even boil water in birch bark directly over fire.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark containers can go directly over flame. The water inside prevents the bark from burning. The bark ignites at 450°F but water keeps it below 212°F.", comment: "Step Detail")
        let _ = String(localized: "Water Vine Extraction", comment: "Technique Name")
        let _ = String(localized: "Cut tropical vines for immediate drinking water", comment: "Technique Subtitle")
        let _ = String(localized: "Identify thick, woody vines in tropical or subtropical forest.", comment: "Step Instruction")
        let _ = String(localized: "Water vines are 1-3 inches thick with rough bark. Common species: grape vine, rattan, and various lianas. Avoid milky or colored sap — these are toxic.", comment: "Step Detail")
        let _ = String(localized: "Cut the vine HIGH first, then cut low.", comment: "Step Instruction")
        let _ = String(localized: "Critical: cut the top first to break the capillary seal. If you cut the bottom first, water retreats upward and you get nothing.", comment: "Step Detail")
        let _ = String(localized: "Hold the cut section over your mouth. Water drips from the bottom cut.", comment: "Step Instruction")
        let _ = String(localized: "Clear, tasteless water is safe. If the liquid is colored, milky, or bitter, spit it out immediately — that vine is not a water source.", comment: "Step Detail")
        let _ = String(localized: "Fog Collection", comment: "Technique Name")
        let _ = String(localized: "Harvest water from fog and mist", comment: "Technique Subtitle")
        let _ = String(localized: "Stretch fabric or mesh between two poles at a 90° angle to prevailing wind.", comment: "Step Instruction")
        let _ = String(localized: "The mesh catches fog droplets which coalesce and run down. Position on a ridge or exposed hillside where fog flows across.", comment: "Step Detail")
        let _ = String(localized: "Channel the bottom edge into a collection container.", comment: "Step Instruction")
        let _ = String(localized: "Create a V-shaped trough at the bottom of the mesh using bark, plastic, or folded fabric to funnel water into your container.", comment: "Step Detail")
        let _ = String(localized: "Leave overnight. Fog is heaviest from midnight to dawn.", comment: "Step Instruction")
        let _ = String(localized: "In coastal areas with regular fog, yields of 1-5 liters per square meter per night are common. This is used as primary water supply in some coastal deserts.", comment: "Step Detail")
        let _ = String(localized: "Digging a Water Well", comment: "Technique Name")
        let _ = String(localized: "Access groundwater in low-lying areas", comment: "Technique Subtitle")
        let _ = String(localized: "Choose a location: outside bends of dry riverbeds, valley bottoms, base of hills.", comment: "Step Instruction")
        let _ = String(localized: "Water collects at the lowest accessible point. The outside bend of a river channel has deeper water table. Green vegetation in dry terrain marks subsurface water.", comment: "Step Detail")
        let _ = String(localized: "Dig a hole 1-3 feet deep. Widen as you go for stability.", comment: "Step Instruction")
        let _ = String(localized: "Start with a small hole. If soil becomes damp, you're close. If dry after 3 feet, try a different location.", comment: "Step Detail")
        let _ = String(localized: "Wait 30 minutes for water to seep in from surrounding soil.", comment: "Step Instruction")
        let _ = String(localized: "The first water will be muddy. Let it settle, then scoop the clearest water from the top into your container.", comment: "Step Detail")
        let _ = String(localized: "Filter and purify before drinking — groundwater still needs treatment.", comment: "Step Instruction")
        let _ = String(localized: "Groundwater is usually cleaner than surface water but can contain bacteria and parasites. Always boil or chemically treat.", comment: "Step Detail")
        let _ = String(localized: "Snow Melting Best Practices", comment: "Technique Name")
        let _ = String(localized: "Convert snow to water without losing body heat", comment: "Technique Subtitle")
        let _ = String(localized: "Never eat snow directly — it lowers core body temperature dangerously.", comment: "Step Instruction")
        let _ = String(localized: "Eating snow uses body heat to melt it. In cold conditions, this accelerates hypothermia. It takes 1 calorie to melt 1 gram of snow.", comment: "Step Detail")
        let _ = String(localized: "Melt snow in a dark container in sunlight, or near (not on) fire.", comment: "Step Instruction")
        let _ = String(localized: "A dark bottle in the sun melts snow with zero energy cost to you. Near a fire is next best. Pack snow tightly for more water per volume.", comment: "Step Detail")
        let _ = String(localized: "Start with a small amount of water in the container, then add snow gradually.", comment: "Step Instruction")
        let _ = String(localized: "If you put a container of dry snow directly on heat, the bottom burns before the top melts. A water base conducts heat evenly.", comment: "Step Detail")
        let _ = String(localized: "Use ice instead of snow when available — it yields more water per volume.", comment: "Step Instruction")
        let _ = String(localized: "Snow is 90% air. A liter of snow yields only ~100ml water. Ice yields ~900ml. Always prefer ice to snow.", comment: "Step Detail")
        let _ = String(localized: "Water Safety Assessment", comment: "Technique Name")
        let _ = String(localized: "Evaluate unknown water sources before drinking", comment: "Technique Subtitle")
        let _ = String(localized: "Check clarity — hold water up to light. Clear is better than cloudy.", comment: "Step Instruction")
        let _ = String(localized: "Turbidity indicates suspended particles. These particles can harbor bacteria and interfere with chemical treatment. Always filter turbid water first.", comment: "Step Detail")
        let _ = String(localized: "Smell the water — chemical or sulfur odors mean contamination.", comment: "Step Instruction")
        let _ = String(localized: "Clean water has no smell. Rotten egg smell = hydrogen sulfide. Chemical smell = industrial contamination. Sweet smell = algae blooms (some toxic).", comment: "Step Detail")
        let _ = String(localized: "Look at the surroundings — dead animals, algae blooms, or industrial runoff.", comment: "Step Instruction")
        let _ = String(localized: "Dead fish or animals near water = toxins. Blue-green algae mats = cyanobacteria (potentially fatal). Upstream mines or farms = chemical contamination.", comment: "Step Detail")
        let _ = String(localized: "When in doubt, purify. The cost of purification is always less than the cost of illness.", comment: "Step Instruction")
        let _ = String(localized: "Even clear, odorless water from a pristine stream can contain Giardia or Crypto. Always purify unless collecting direct rainfall.", comment: "Step Detail")
        let _ = String(localized: "Enhanced Transpiration Bag", comment: "Technique Name")
        let _ = String(localized: "Maximize water output from vegetation bags", comment: "Technique Subtitle")
        let _ = String(localized: "Select a sun-facing branch with the most leafy growth.", comment: "Step Instruction")
        let _ = String(localized: "South-facing branches (Northern Hemisphere) transpire most. More leaves = more water. Avoid toxic plants (oleander, rhododendron).", comment: "Step Detail")
        let _ = String(localized: "Enclose the leafy end in a clear plastic bag. Seal airtight around the branch.", comment: "Step Instruction")
        let _ = String(localized: "Use string, tape, or twisted plastic to seal. Any air leak wastes moisture. The bag should balloon with trapped air.", comment: "Step Detail")
        let _ = String(localized: "Place a small rock in the bottom corner to create a collection point.", comment: "Step Instruction")
        let _ = String(localized: "Water condenses on the inside of the bag and runs down to the lowest point. The rock creates a pool you can access.", comment: "Step Detail")
        let _ = String(localized: "Set up multiple bags — each yields only 60-200ml per day.", comment: "Step Instruction")
        let _ = String(localized: "One bag is not enough. Set 5-10 bags to get meaningful water. Replace branches daily as transpiration declines after cutting.", comment: "Step Detail")
        let _ = String(localized: "Cactus Water Extraction", comment: "Technique Name")
        let _ = String(localized: "Extract moisture from desert cacti (with caution)", comment: "Technique Subtitle")
        let _ = String(localized: "Identify barrel cactus (Ferocactus) — the only safe species for water.", comment: "Step Instruction")
        let _ = String(localized: "NOT all cacti contain drinkable water. Many contain toxic alkaloids that cause vomiting (which accelerates dehydration). Barrel cactus is the safest option. Prickly pear fruit is also safe.", comment: "Step Detail")
        let _ = String(localized: "Cut off the top of the cactus and mash the pulp inside.", comment: "Step Instruction")
        let _ = String(localized: "Use a knife or rock to slice the top. The interior pulp is moist and fibrous. Mash it to release moisture. Do NOT drink the liquid directly — chew the pulp and spit out the fiber.", comment: "Step Detail")
        let _ = String(localized: "Squeeze pulp through cloth to extract moisture. Drink in small amounts.", comment: "Step Instruction")
        let _ = String(localized: "Yield is small: a large barrel cactus may give 1-2 cups. The liquid may taste bitter. Drink slowly. If it causes nausea, stop — you have the wrong species.", comment: "Step Detail")
        let _ = String(localized: "Coconut Water Safety", comment: "Technique Name")
        let _ = String(localized: "Use green coconuts for hydration — avoid mature ones", comment: "Technique Subtitle")
        let _ = String(localized: "Select GREEN coconuts (young). Avoid brown mature coconuts.", comment: "Step Instruction")
        let _ = String(localized: "Green coconut water is sterile, isotonic, and safe to drink in quantity. Brown coconut water is higher in oil and can act as a laxative, causing dehydration if consumed in large amounts.", comment: "Step Detail")
        let _ = String(localized: "Pierce the soft eye of the coconut with a sharp point or knife.", comment: "Step Instruction")
        let _ = String(localized: "Each coconut has 2-3 'eyes' (dark spots) at one end. One eye is softer than the others — test each with your knife tip. Pierce through this soft eye to access the water inside.", comment: "Step Detail")
        let _ = String(localized: "Drink directly or pour into container. Limit mature coconut to 2-3 per day.", comment: "Step Instruction")
        let _ = String(localized: "Green coconuts: drink freely. Mature coconuts: limit to 2-3 daily to avoid digestive issues. Coconut water contains electrolytes (potassium, sodium) making it superior to plain water for rehydration.", comment: "Step Detail")
        let _ = String(localized: "Banana Plant Water", comment: "Technique Name")
        let _ = String(localized: "Extract water from banana plant trunks", comment: "Technique Subtitle")
        let _ = String(localized: "Cut a banana plant trunk down to a 6-inch stump.", comment: "Step Instruction")
        let _ = String(localized: "Banana 'trunks' are actually tightly rolled leaf sheaths, not wood. They cut easily. Choose a mature plant for maximum water content.", comment: "Step Detail")
        let _ = String(localized: "Scoop out the center of the stump to create a bowl shape.", comment: "Step Instruction")
        let _ = String(localized: "Hollow out the core of the stump. Within 10-15 minutes, water will seep up from the root system and fill the bowl. The plant acts as a natural pump.", comment: "Step Detail")
        let _ = String(localized: "Scoop water every 30 minutes. The stump refills 3-4 times.", comment: "Step Instruction")
        let _ = String(localized: "Each filling yields about 1 cup. Scoop out the first fill (may be bitter) and drink subsequent fills. A single plant can provide 2-3 cups of water over several hours.", comment: "Step Detail")
        let _ = String(localized: "Clay Pot Filter (Ceramic)", comment: "Technique Name")
        let _ = String(localized: "Make a ceramic filter that removes bacteria", comment: "Technique Subtitle")
        let _ = String(localized: "Mix clay with fine sawdust or rice husks (60% clay, 40% organic).", comment: "Step Instruction")
        let _ = String(localized: "The organic material burns out during firing, leaving microscopic pores in the clay. These pores are small enough to filter bacteria (0.5-2 microns). The ratio is critical.", comment: "Step Detail")
        let _ = String(localized: "Shape into a pot or bowl and let dry completely (1-2 days).", comment: "Step Instruction")
        let _ = String(localized: "Form a bowl shape with walls about 1 inch thick. It must dry completely before firing or it will crack. Keep in shade and turn periodically for even drying.", comment: "Step Detail")
        let _ = String(localized: "Fire in a hot fire for 6-8 hours. The organic material burns out leaving pores.", comment: "Step Instruction")
        let _ = String(localized: "Maintain high heat. The sawdust vaporizes, leaving a network of micropores. After firing and cooling, test: water should seep through slowly (1-2 liters per hour). Too fast = pores too large.", comment: "Step Detail")
        let _ = String(localized: "Bio-Sand Filter", comment: "Technique Name")
        let _ = String(localized: "Build a biological filtration system for long-term use", comment: "Technique Subtitle")
        let _ = String(localized: "Fill a large container with layers: gravel (bottom), coarse sand, fine sand (top).", comment: "Step Instruction")
        let _ = String(localized: "Use a 5-gallon bucket or similar. Bottom 4 inches: gravel (pea-sized). Middle 4 inches: coarse sand. Top 8 inches: fine sand. Each layer filters progressively smaller particles.", comment: "Step Detail")
        let _ = String(localized: "Create an outlet at the bottom for filtered water to exit.", comment: "Step Instruction")
        let _ = String(localized: "Drill or punch a hole near the bottom. Insert a tube or bamboo section. Water enters the top, filters through layers, and exits clean at the bottom. Flow rate should be slow: 1 liter per 15-20 minutes.", comment: "Step Detail")
        let _ = String(localized: "Use daily for 2 weeks. A biological layer (schmutzdecke) forms and filters bacteria.", comment: "Step Instruction")
        let _ = String(localized: "The magic is the biofilm that forms on the top sand layer after 2 weeks of regular use. This living layer consumes pathogens. Once established, the filter removes 96-99% of bacteria. Never let it dry out.", comment: "Step Detail")
        let _ = String(localized: "Morning Dew Collection (Cloth Drag)", comment: "Technique Name")
        let _ = String(localized: "Collect dew by dragging cloth through wet grass", comment: "Technique Subtitle")
        let _ = String(localized: "Before sunrise, tie absorbent cloth around your ankles and legs.", comment: "Step Instruction")
        let _ = String(localized: "T-shirts, towels, bandanas — any absorbent cotton material. Wrap around lower legs and feet. Walk through tall, dew-covered grass in the early morning.", comment: "Step Detail")
        let _ = String(localized: "Walk through tall grass, collecting dew on the cloth.", comment: "Step Instruction")
        let _ = String(localized: "Walk slowly through areas with heavy dew. The cloth absorbs moisture from the grass. Each pass through a 50-foot stretch saturates the cloth significantly.", comment: "Step Detail")
        let _ = String(localized: "Wring the cloth into a container. Repeat until enough water is collected.", comment: "Step Instruction")
        let _ = String(localized: "Each wringing yields 1-4 ounces depending on dew intensity and cloth size. In heavy dew conditions, you can collect 1+ liters in an hour. The water is generally clean but filter if possible.", comment: "Step Detail")
        let _ = String(localized: "Seawater Ice Desalination", comment: "Technique Name")
        let _ = String(localized: "Freeze seawater to separate salt from ice", comment: "Technique Subtitle")
        let _ = String(localized: "In freezing conditions, collect seawater in shallow containers.", comment: "Step Instruction")
        let _ = String(localized: "Shallow containers freeze faster. The physics: when seawater freezes, salt is excluded from the ice crystal structure and concentrates in the remaining liquid brine.", comment: "Step Detail")
        let _ = String(localized: "Let water freeze partially. Pour off the unfrozen brine (concentrated salt).", comment: "Step Instruction")
        let _ = String(localized: "The liquid remaining is super-salty brine. Pour it off. The ice that formed is significantly less salty than the original seawater. This is the desalinated portion.", comment: "Step Detail")
        let _ = String(localized: "Melt the ice. Taste test — repeat freeze/pour if still salty.", comment: "Step Instruction")
        let _ = String(localized: "First freeze removes about 70% of salt. A second freeze-pour cycle gets it close to drinkable. Old sea ice (multi-year) found in Arctic regions is naturally fresh — it has a blue tint.", comment: "Step Detail")
        let _ = String(localized: "Tarp Rain Catchment", comment: "Technique Name")
        let _ = String(localized: "Maximize rain collection with a tarp funnel", comment: "Technique Subtitle")
        let _ = String(localized: "Spread tarp with edges elevated and center dipped to form a funnel.", comment: "Step Instruction")
        let _ = String(localized: "Tie corners to trees or stakes at waist height. The center should sag to collect water. A 6x8 foot tarp can collect 25+ gallons in 1 inch of rain.", comment: "Step Detail")
        let _ = String(localized: "Place a container under the lowest point of the tarp.", comment: "Step Instruction")
        let _ = String(localized: "Poke a small hole or create a channel at the lowest point. Water drains down the funnel shape and into your container. Angle the tarp slightly for continuous drainage.", comment: "Step Detail")
        let _ = String(localized: "Pre-rinse the tarp if dirty. First flush may contain debris.", comment: "Step Instruction")
        let _ = String(localized: "Let the first 30 seconds of rain wash dirt off the tarp before collecting. Rain water collected on a clean surface is safe to drink without treatment in most environments.", comment: "Step Detail")
        let _ = String(localized: "Activated Charcoal Making", comment: "Technique Name")
        let _ = String(localized: "Create filtering charcoal for water purification", comment: "Technique Subtitle")
        let _ = String(localized: "Make regular charcoal by burning hardwood in a low-oxygen fire.", comment: "Step Instruction")
        let _ = String(localized: "Burn hardwood in a covered pit or sealed container with a vent hole. The wood converts to charcoal (carbon) without burning to ash. Cool completely before handling.", comment: "Step Detail")
        let _ = String(localized: "Crush charcoal into small granules (pea-sized to sand-sized).", comment: "Step Instruction")
        let _ = String(localized: "Smaller pieces have more surface area for adsorption. Crush with rocks between two flat surfaces. Remove any unburned wood — it should be uniformly black and lightweight.", comment: "Step Detail")
        let _ = String(localized: "Layer crushed charcoal in filter between sand layers.", comment: "Step Instruction")
        let _ = String(localized: "Charcoal adsorbs chemical contaminants, chlorine, and some organic toxins. It does NOT reliably kill bacteria or viruses — still boil or treat chemically after charcoal filtering. Replace charcoal weekly.", comment: "Step Detail")
        let _ = String(localized: "Spring Identification", comment: "Technique Name")
        let _ = String(localized: "Find natural spring water sources", comment: "Technique Subtitle")
        let _ = String(localized: "Look for unusually green vegetation on hillsides in dry areas.", comment: "Step Instruction")
        let _ = String(localized: "Springs create strips or patches of green plants in otherwise dry terrain. The vegetation line often follows the underground water flow path. Willows, cattails, and reeds almost always indicate nearby water.", comment: "Step Detail")
        let _ = String(localized: "Check the base of cliffs, rock outcrops, and where geology changes.", comment: "Step Instruction")
        let _ = String(localized: "Springs form where permeable rock (sandstone, limestone) meets impermeable rock (clay, granite). Water travels through porous rock until it hits a barrier and seeps out. These geological boundaries are spring sites.", comment: "Step Detail")
        let _ = String(localized: "Test: spring water is typically cold, clear, and flowing.", comment: "Step Instruction")
        let _ = String(localized: "Good springs produce clear, cold water (ground temperature, ~55°F). If the water is warm, cloudy, or has an odor, it may be surface runoff, not a true spring. True spring water is generally safe but still filter if possible.", comment: "Step Detail")
        let _ = String(localized: "Underground Seep Location", comment: "Technique Name")
        let _ = String(localized: "Find subsurface water by reading terrain clues", comment: "Technique Subtitle")
        let _ = String(localized: "Dig at the outside bend of a dry streambed.", comment: "Step Instruction")
        let _ = String(localized: "Water flows underground in the same path as the surface stream. The outside of a bend has the deepest water table. Dig 1-3 feet deep. Water seeps in from the sides and bottom.", comment: "Step Detail")
        let _ = String(localized: "Dig at the base of a sand dune facing the valley.", comment: "Step Instruction")
        let _ = String(localized: "Dunes collect and concentrate rainwater. The valley-facing (concave) side often has water closer to the surface. Dig where the dune meets the valley floor.", comment: "Step Detail")
        let _ = String(localized: "Wait for the hole to fill. Filter and purify the seep water.", comment: "Step Instruction")
        let _ = String(localized: "Seep water may take 15-60 minutes to collect. Let sediment settle before scooping. The water has been naturally filtered through soil but may still contain pathogens — purify before drinking.", comment: "Step Detail")
        let _ = String(localized: "Altitude Boiling Adjustments", comment: "Technique Name")
        let _ = String(localized: "Understand how altitude affects water purification", comment: "Technique Subtitle")
        let _ = String(localized: "At sea level, water boils at 212°F (100°C). At altitude, it boils at lower temperatures.", comment: "Step Instruction")
        let _ = String(localized: "For every 1,000 feet of elevation, the boiling point drops about 2°F. At 10,000 feet, water boils at 193°F. At 14,000 feet: 187°F. This matters for purification.", comment: "Step Detail")
        let _ = String(localized: "Good news: pathogens die well below boiling temperature.", comment: "Step Instruction")
        let _ = String(localized: "Most waterborne pathogens die at 160°F (71°C). Even at extreme altitude (Everest base camp at 17,600 feet), water boils at 179°F — still hot enough to kill all common pathogens.", comment: "Step Detail")
        let _ = String(localized: "Bring water to a rolling boil for 1 minute (3 minutes above 6,500 feet).", comment: "Step Instruction")
        let _ = String(localized: "CDC recommendation. At sea level, 1 minute is sufficient. Above 6,500 feet, boil for 3 minutes to compensate for the lower temperature. Rolling boil means large, vigorous bubbles.", comment: "Step Detail")
        let _ = String(localized: "Animal Indicators for Water", comment: "Technique Name")
        let _ = String(localized: "Follow animal behavior to find water sources", comment: "Technique Subtitle")
        let _ = String(localized: "Follow grazing animals (deer, cattle) at dawn and dusk — they head to water.", comment: "Step Instruction")
        let _ = String(localized: "Grazing animals drink at dawn and dusk. Their trails converge toward water sources. Fresh tracks in dry areas always lead to water if you follow them long enough.", comment: "Step Detail")
        let _ = String(localized: "Watch birds: grain-eaters fly toward water at dusk, away at dawn.", comment: "Step Instruction")
        let _ = String(localized: "Seed-eating birds (finches, pigeons, doves) must drink daily. In the evening, they fly fast and low toward water. In the morning, they fly away from water. Follow their evening flight path.", comment: "Step Detail")
        let _ = String(localized: "Listen for frogs and insects at night — they indicate water nearby.", comment: "Step Instruction")
        let _ = String(localized: "Frog calls mean standing water within earshot. Dense insect swarms (mosquitoes, midges) often hover over or near water sources. Bees are rarely more than 3 miles from water.", comment: "Step Detail")
        let _ = String(localized: "Water from Wild Fruits & Plants", comment: "Technique Name")
        let _ = String(localized: "Extract moisture from edible plants and fruits", comment: "Technique Subtitle")
        let _ = String(localized: "Identify water-rich wild fruits: berries, wild grapes, prickly pear.", comment: "Step Instruction")
        let _ = String(localized: "Many wild fruits are 80-90% water. Prickly pear pads and fruit, wild grapes, blackberries, blueberries, and even dandelion stems contain usable moisture.", comment: "Step Detail")
        let _ = String(localized: "Eat water-rich plants: cattail shoots, wild lettuce, clover.", comment: "Step Instruction")
        let _ = String(localized: "Young cattail shoots taste like cucumber and are mostly water. Wild lettuce, chickweed, and sorrel are high in moisture. Only eat plants you can positively identify.", comment: "Step Detail")
        let _ = String(localized: "Chew but do not swallow fibrous plants to extract moisture.", comment: "Step Instruction")
        let _ = String(localized: "Green grass, sugar cane, and young bark can be chewed to extract moisture. Chew thoroughly, swallow the juice, spit out the fiber. This provides small but meaningful amounts of hydration.", comment: "Step Detail")
        let _ = String(localized: "Emergency Urban Water Sources", comment: "Technique Name")
        let _ = String(localized: "Find drinkable water in buildings and vehicles after disaster", comment: "Technique Subtitle")
        let _ = String(localized: "Hot water heater: 30-80 gallons of safe, stored water.", comment: "Step Instruction")
        let _ = String(localized: "Turn off power/gas to heater. Open the drain valve at the bottom into a container. The water is pre-heated and essentially sterile. One heater can sustain a person for weeks.", comment: "Step Detail")
        let _ = String(localized: "Toilet tanks (NOT bowls): contain 1-2 gallons of clean water.", comment: "Step Instruction")
        let _ = String(localized: "The TANK (upper portion) holds clean water, same as tap water. Do NOT use water from the bowl. Do NOT use if chemical cleaning tablets are in the tank (blue/green water).", comment: "Step Detail")
        let _ = String(localized: "Pipe drainage: open the lowest faucet to drain remaining water from pipes.", comment: "Step Instruction")
        let _ = String(localized: "After water supply stops, pipes still contain residual water. Open the lowest faucet in the building. Gravity drains water from upper pipes down. May yield 1-5 gallons.", comment: "Step Detail")
        let _ = String(localized: "Poncho Rain Collection", comment: "Technique Name")
        let _ = String(localized: "Use a poncho or garbage bag as rain catchment", comment: "Technique Subtitle")
        let _ = String(localized: "Tie corners of poncho to trees or stakes at waist height.", comment: "Step Instruction")
        let _ = String(localized: "Create a basin shape with the center lower than the edges. A garbage bag can be cut open to create a flat sheet. Even a jacket opened and stretched works for small amounts.", comment: "Step Detail")
        let _ = String(localized: "Place a small rock in the center to create a funnel point.", comment: "Step Instruction")
        let _ = String(localized: "The rock weighs down the center, creating a natural funnel. All water flows toward this low point. Punch or cut a small hole and place your container below for automatic collection.", comment: "Step Detail")
        let _ = String(localized: "In light rain, maximize catchment area. Move to open ground.", comment: "Step Instruction")
        let _ = String(localized: "Tree canopy intercepts significant rainfall. Move catchment to the most open area available. A 3x3 foot poncho in moderate rain collects about 1 gallon per hour.", comment: "Step Detail")
        let _ = String(localized: "Improvised Oral Rehydration Solution", comment: "Technique Name")
        let _ = String(localized: "Make WHO-standard rehydration fluid from basic ingredients", comment: "Technique Subtitle")
        let _ = String(localized: "Mix: 1 liter clean water + 6 teaspoons sugar + ½ teaspoon salt.", comment: "Step Instruction")
        let _ = String(localized: "This is the WHO oral rehydration formula. The precise ratio matters — too much sugar causes diarrhea; too much salt causes vomiting. Measure carefully.", comment: "Step Detail")
        let _ = String(localized: "Stir thoroughly until fully dissolved. Taste should be like tears.", comment: "Step Instruction")
        let _ = String(localized: "The solution should taste mildly salty, similar to tears or slightly salted water. If it tastes very salty, add more water. If too sweet, add a pinch more salt.", comment: "Step Detail")
        let _ = String(localized: "Sip slowly over 4-6 hours. Do not gulp.", comment: "Step Instruction")
        let _ = String(localized: "Rapid drinking can trigger vomiting in dehydrated individuals. Small, frequent sips allow maximum absorption. This solution treats dehydration 10x more effectively than plain water because of electrolyte replacement.", comment: "Step Detail")
        let _ = String(localized: "Rescue & Signaling", comment: "Domain Name")
        let _ = String(localized: "Signal Fire", comment: "Technique Name")
        let _ = String(localized: "Three fires in a triangle = universal distress", comment: "Technique Subtitle")
        let _ = String(localized: "Signal", comment: "Category")
        let _ = String(localized: "Build 3 fires in a triangle, 100 feet apart.", comment: "Step Instruction")
        let _ = String(localized: "Three of anything in a triangle is the international distress signal. Place on high ground, clearings, or near open water for maximum visibility.", comment: "Step Detail")
        let _ = String(localized: "Prepare each fire with dry tinder and kindling, ready to light.", comment: "Step Instruction")
        let _ = String(localized: "Have them pre-built so you can light quickly when you hear/see aircraft. Keep fire-starting materials dry and ready.", comment: "Step Detail")
        let _ = String(localized: "Add green branches or wet material for heavy smoke.", comment: "Step Instruction")
        let _ = String(localized: "Smoke is visible from much greater distance than flame. Green leaves, wet grass, or rubber produce thick white/black smoke.", comment: "Step Detail")
        let _ = String(localized: "At night, flames are more visible than smoke.", comment: "Step Instruction")
        let _ = String(localized: "At night, keep fires burning with dry wood for bright flames. During day, switch to smoky materials.", comment: "Step Detail")
        let _ = String(localized: "Signal Mirror", comment: "Technique Name")
        let _ = String(localized: "Visible 50+ miles on a clear day", comment: "Technique Subtitle")
        let _ = String(localized: "Any reflective surface works: mirror, CD, phone screen, metal.", comment: "Step Instruction")
        let _ = String(localized: "Commercial signal mirrors are the best but ANY reflective object can work. Even a belt buckle or aluminum foil.", comment: "Step Detail")
        let _ = String(localized: "Hold the mirror near your eye and extend your other hand toward the target.", comment: "Step Instruction")
        let _ = String(localized: "The target is the aircraft, boat, or distant point you want to signal.", comment: "Step Detail")
        let _ = String(localized: "Reflect sunlight onto your extended hand, then move hand to align flash with target.", comment: "Step Instruction")
        let _ = String(localized: "The bright spot on your hand tells you where the reflection is pointing. Move it until it's on the target. Sweep back and forth across the target.", comment: "Step Detail")
        let _ = String(localized: "Flash in sets of three (SOS pattern) — three short, three long, three short.", comment: "Step Instruction")
        let _ = String(localized: "Keep signaling even if you think the aircraft hasn't seen you. Pilots scan with binoculars and may see you long before you realize it.", comment: "Step Detail")
        let _ = String(localized: "Ground-to-Air Signals", comment: "Technique Name")
        let _ = String(localized: "Large visible markers for aircraft", comment: "Technique Subtitle")
        let _ = String(localized: "Create symbols at least 10 feet tall, 3 feet wide.", comment: "Step Instruction")
        let _ = String(localized: "Bigger is always better. Use contrasting materials against the ground — dark rocks on light sand, light clothing on dark soil.", comment: "Step Detail")
        let _ = String(localized: "Standard signals: V = need assistance, X = need medical help, → = traveling this direction.", comment: "Step Instruction")
        let _ = String(localized: "I = need medical supplies. F = need food and water. LL = all is well. These are ICAO standard ground-to-air visual signals.", comment: "Step Detail")
        let _ = String(localized: "Place in open areas visible from above — clearings, hilltops, beaches.", comment: "Step Instruction")
        let _ = String(localized: "Avoid placing under tree canopy. Signals must be visible from directly above and at angles.", comment: "Step Detail")
        let _ = String(localized: "Add shadow-casting height for visibility from low angles.", comment: "Step Instruction")
        let _ = String(localized: "Stack rocks, logs, or mound dirt to create 3D signals that cast shadows. Shadows dramatically increase visibility.", comment: "Step Detail")
        let _ = String(localized: "Whistle Signal", comment: "Technique Name")
        let _ = String(localized: "Three blasts = help needed", comment: "Technique Subtitle")
        let _ = String(localized: "Three sharp blasts = universal distress signal.", comment: "Step Instruction")
        let _ = String(localized: "Three of anything (blasts, fires, signals) means 'help needed.' Pause 30 seconds between sets. Repeat every 5 minutes.", comment: "Step Detail")
        let _ = String(localized: "Blow in short, sharp bursts — not long continuous blows.", comment: "Step Instruction")
        let _ = String(localized: "Short blasts carry farther and are easier to distinguish from natural sounds. Each blast should last about 1 second.", comment: "Step Detail")
        let _ = String(localized: "Point the whistle toward open areas, valleys, or potential rescuer direction.", comment: "Step Instruction")
        let _ = String(localized: "Sound travels farther down valleys and across water. Face the most likely direction of help. Avoid blowing into dense forest — trees absorb sound.", comment: "Step Detail")
        let _ = String(localized: "Conserve energy: blow every 5 minutes, not continuously.", comment: "Step Instruction")
        let _ = String(localized: "Continuous blowing wastes energy and can cause hyperventilation. Set a schedule: 3 blasts, wait 5 minutes, repeat.", comment: "Step Detail")
        let _ = String(localized: "If no whistle: use two rocks struck together or a metal object.", comment: "Step Instruction")
        let _ = String(localized: "Banging rocks creates a sharp, carrying sound unnatural to the wilderness. A metal pot or cup struck with a rock is even louder. Three strikes = distress.", comment: "Step Detail")
        let _ = String(localized: "SOS in Morse Code", comment: "Technique Name")
        let _ = String(localized: "· · · — — — · · · (3 short, 3 long, 3 short)", comment: "Technique Subtitle")
        let _ = String(localized: "SOS = 3 short, 3 long, 3 short. Any medium: light, sound, flag.", comment: "Step Instruction")
        let _ = String(localized: "Short = quick flash/tap. Long = 3× the duration of short. This is the most universally recognized distress signal.", comment: "Step Detail")
        let _ = String(localized: "With a flashlight: quick-quick-quick, looong-looong-looong, quick-quick-quick.", comment: "Step Instruction")
        let _ = String(localized: "Aim at aircraft, boats, or distant camps. Repeat continuously. Even a phone screen works.", comment: "Step Detail")
        let _ = String(localized: "Write SOS in sand, snow, or any visible surface.", comment: "Step Instruction")
        let _ = String(localized: "Make letters as large as possible. Use contrasting materials. SOS is understood in every language worldwide.", comment: "Step Detail")
        let _ = String(localized: "Maximizing Phone Battery in Emergency", comment: "Technique Name")
        let _ = String(localized: "Get the most from your dying phone", comment: "Technique Subtitle")
        let _ = String(localized: "Technology", comment: "Category")
        let _ = String(localized: "Turn on airplane mode immediately.", comment: "Step Instruction")
        let _ = String(localized: "The #1 battery drain is your phone searching for cell signal. In wilderness with no signal, it searches continuously, killing the battery.", comment: "Step Detail")
        let _ = String(localized: "Turn off airplane mode ONLY to attempt calls/texts, then back on.", comment: "Step Instruction")
        let _ = String(localized: "Climb to high ground, turn off airplane mode, attempt contact, then turn it back on. Each attempt should be deliberate.", comment: "Step Detail")
        let _ = String(localized: "Send texts instead of calling — texts use far less power.", comment: "Step Instruction")
        let _ = String(localized: "Texts also retry automatically and can get through with weaker signals than voice calls.", comment: "Step Detail")
        let _ = String(localized: "Emergency numbers (112, 911, 999, etc.) work on any network and often without a SIM.", comment: "Step Instruction")
        let _ = String(localized: "Emergency calls route through ANY available carrier, not just yours. 112 works in most countries worldwide. Check your local number in this app's Emergency Directory.", comment: "Step Detail")
        let _ = String(localized: "Before battery dies: text your GPS coordinates to someone.", comment: "Step Instruction")
        let _ = String(localized: "Open maps app, copy coordinates, text to contact. Even if the text doesn't send immediately, it will queue and send when signal is found.", comment: "Step Detail")
        let _ = String(localized: "Reading & Sharing GPS Coordinates", comment: "Technique Name")
        let _ = String(localized: "Your exact location in numbers", comment: "Technique Subtitle")
        let _ = String(localized: "On iPhone: Open Compass app — coordinates shown at bottom.", comment: "Step Instruction")
        let _ = String(localized: "GPS works WITHOUT cell service or WiFi. It uses satellites directly. Your phone can always determine your position.", comment: "Step Detail")
        let _ = String(localized: "On Android: Open Google Maps, tap the blue dot, coordinates appear.", comment: "Step Instruction")
        let _ = String(localized: "Or download an offline GPS app before your trip. Offline maps + GPS = full navigation without service.", comment: "Step Detail")
        let _ = String(localized: "Share coordinates as decimal degrees: e.g., 37.7749, -122.4194.", comment: "Step Instruction")
        let _ = String(localized: "Decimal degrees are the most universal and least error-prone format. Include the negative sign for south/west coordinates.", comment: "Step Detail")
        let _ = String(localized: "What3Words: every 3m×3m square has a unique 3-word address.", comment: "Step Instruction")
        let _ = String(localized: "The app works offline. Example: ///filled.count.soap. Emergency services in many countries accept What3Words addresses.", comment: "Step Detail")
        let _ = String(localized: "Self-Rescue Decision Making", comment: "Technique Name")
        let _ = String(localized: "Stay or go? The critical decision.", comment: "Technique Subtitle")
        let _ = String(localized: "Self-Rescue", comment: "Category")
        let _ = String(localized: "Stop. Breathe. Think before acting.", comment: "Step Instruction")
        let _ = String(localized: "Panic is the leading cause of drowning in capable swimmers. Take 10 seconds to assess: how far is shore? What direction is the current? Do you have anything that floats?", comment: "Step Detail")
        let _ = String(localized: "Float on your back to rest and conserve energy.", comment: "Step Instruction")
        let _ = String(localized: "Roll onto your back, spread arms wide, arch your back slightly. Even non-swimmers can float this way. Breathe slowly and deeply — full lungs increase buoyancy.", comment: "Step Detail")
        let _ = String(localized: "Remove heavy items: shoes, backpack, heavy jacket.", comment: "Step Instruction")
        let _ = String(localized: "Heavy clothing and gear drag you down. Remove boots and heavy outer layers. Keep lightweight clothing on — it provides some insulation and doesn't weigh much when swimming.", comment: "Step Detail")
        let _ = String(localized: "Swim at 45-degree angle to current toward nearest shore.", comment: "Step Instruction")
        let _ = String(localized: "Do NOT fight current directly. Swim diagonally. Use sidestroke or breaststroke (most energy efficient). Rest on your back between efforts.", comment: "Step Detail")
        let _ = String(localized: "If exhausted, switch to survival floating: face down, lift head to breathe.", comment: "Step Instruction")
        let _ = String(localized: "Hang vertically with face in water, arms and legs dangling. Lift head to breathe every 10-15 seconds. This uses almost zero energy and you can last for hours.", comment: "Step Detail")
        let _ = String(localized: "Leaving a Trail for Rescuers", comment: "Technique Name")
        let _ = String(localized: "Breadcrumbs that save your life", comment: "Technique Subtitle")
        let _ = String(localized: "Build rock cairns (stacked stones) at regular intervals.", comment: "Step Instruction")
        let _ = String(localized: "3 rocks stacked is unnatural enough to catch a searcher's eye. Place at decision points (trail junctions, river crossings).", comment: "Step Detail")
        let _ = String(localized: "Break branches at eye level pointing your direction.", comment: "Step Instruction")
        let _ = String(localized: "Snap a branch so it dangles without falling off. The broken end points your direction of travel.", comment: "Step Detail")
        let _ = String(localized: "Tie bright cloth strips to vegetation.", comment: "Step Instruction")
        let _ = String(localized: "Cut strips from clothing. Tie at eye level. Use the brightest material available. Space every 100-200 yards.", comment: "Step Detail")
        let _ = String(localized: "Drag a stick or mark the ground in soft terrain.", comment: "Step Instruction")
        let _ = String(localized: "In mud, sand, or snow — drag a line or make arrows. These are visible from the air and ground.", comment: "Step Detail")
        let _ = String(localized: "Helicopter Landing Zone Prep", comment: "Technique Name")
        let _ = String(localized: "Clear a safe landing area", comment: "Technique Subtitle")
        let _ = String(localized: "Clear a flat area at least 60×60 feet (20×20 meters).", comment: "Step Instruction")
        let _ = String(localized: "Remove loose debris, branches, and anything that could blow into the rotor. Mark the perimeter with rocks or logs.", comment: "Step Detail")
        let _ = String(localized: "Remove all overhead obstructions — trees, wires, branches.", comment: "Step Instruction")
        let _ = String(localized: "Helicopter rotors extend beyond the fuselage. Any overhead contact is catastrophic. Clear completely.", comment: "Step Detail")
        let _ = String(localized: "Mark wind direction with a flag, smoke, or streamers.", comment: "Step Instruction")
        let _ = String(localized: "Helicopters prefer to land into the wind. Hang a cloth strip or light a small smoky fire at the edge of the landing zone.", comment: "Step Detail")
        let _ = String(localized: "Stay upwind and crouch when helicopter approaches.", comment: "Step Instruction")
        let _ = String(localized: "The downwash is extreme — loose items become projectiles. Shield your eyes. Never approach from the tail rotor side. Wait for pilot signal.", comment: "Step Detail")
        let _ = String(localized: "Morse Code SOS", comment: "Technique Name")
        let _ = String(localized: "Universal distress: ... --- ...", comment: "Technique Subtitle")
        let _ = String(localized: "SOS: three short, three long, three short.", comment: "Step Instruction")
        let _ = String(localized: "... --- ... (dit dit dit / dah dah dah / dit dit dit). Universal distress.", comment: "Step Detail")
        let _ = String(localized: "Signal with flashlight, mirror, whistle, or tapping.", comment: "Step Instruction")
        let _ = String(localized: "Short = quick flash/tap. Long = 3x duration of short.", comment: "Step Detail")
        let _ = String(localized: "Repeat with 1-minute pauses between sets.", comment: "Step Instruction")
        let _ = String(localized: "Signal 1 minute, rest 1 minute. Conserve energy.", comment: "Step Detail")
        let _ = String(localized: "Helicopter Landing Zone", comment: "Technique Name")
        let _ = String(localized: "Clear 100-foot zone for helicopter rescue", comment: "Technique Subtitle")
        let _ = String(localized: "Clear a flat area at least 100x100 feet.", comment: "Step Instruction")
        let _ = String(localized: "Remove loose debris. Rotor wash launches objects at lethal speed.", comment: "Step Detail")
        let _ = String(localized: "Mark with bright material. H = need helicopter. V = need help.", comment: "Step Instruction")
        let _ = String(localized: "X means cannot move. Use clothing, tarp, or signal panels.", comment: "Step Detail")
        let _ = String(localized: "Indicate wind direction with smoke or flag.", comment: "Step Instruction")
        let _ = String(localized: "Helicopters land into wind. Light smoky fire upwind of LZ.", comment: "Step Detail")
        let _ = String(localized: "Stand upwind, crouch when approaching. Never approach from rear.", comment: "Step Instruction")
        let _ = String(localized: "Tail rotor kills. Approach front/side only when pilot signals. Stay low.", comment: "Step Detail")
        let _ = String(localized: "Trail Blazing Markers", comment: "Technique Name")
        let _ = String(localized: "Leave a trail others can follow", comment: "Technique Subtitle")
        let _ = String(localized: "Break branches at shoulder height pointing your direction.", comment: "Step Instruction")
        let _ = String(localized: "Pale broken wood visible from distance. Point break in travel direction.", comment: "Step Detail")
        let _ = String(localized: "Stack 3 rocks (cairn) at every turn or decision point.", comment: "Step Instruction")
        let _ = String(localized: "Three stacked rocks is universal trail marker.", comment: "Step Detail")
        let _ = String(localized: "Scratch arrows on trees or dirt at junctions.", comment: "Step Instruction")
        let _ = String(localized: "Use knife, sharp rock, or stick. Eye level on trees.", comment: "Step Detail")
        let _ = String(localized: "Tie bright cloth strips to branches every 50-100 feet.", comment: "Step Instruction")
        let _ = String(localized: "Tear clothing if needed. Visible in both directions.", comment: "Step Detail")
        let _ = String(localized: "International Ground Signal Codes", comment: "Technique Name")
        let _ = String(localized: "V, X, I — pilot-readable from 1000 feet", comment: "Technique Subtitle")
        let _ = String(localized: "V = Need Help. X = Need Medical. I = Need Supplies.", comment: "Step Instruction")
        let _ = String(localized: "ICAO standard signals. Make at least 10 feet tall.", comment: "Step Detail")
        let _ = String(localized: "Arrow = traveling this direction. Y = Yes. N = No.", comment: "Step Instruction")
        let _ = String(localized: "Answer air queries with Y and N on ground.", comment: "Step Detail")
        let _ = String(localized: "Build with rocks, logs, clothing, or trenches.", comment: "Step Instruction")
        let _ = String(localized: "Maximum contrast with ground color.", comment: "Step Detail")
        let _ = String(localized: "Minimum 10 feet long, 3 feet wide. Bigger is better.", comment: "Step Instruction")
        let _ = String(localized: "3-foot letters invisible from 1000 feet. Think highway-scale.", comment: "Step Detail")
        let _ = String(localized: "Colored Smoke Signals", comment: "Technique Name")
        let _ = String(localized: "Daytime signaling with combustion", comment: "Technique Subtitle")
        let _ = String(localized: "Build a standard fire and get it burning hot.", comment: "Step Instruction")
        let _ = String(localized: "You need a strong updraft to carry the smoke high.", comment: "Step Detail")
        let _ = String(localized: "add GREEN vegetation for WHITE smoke.", comment: "Step Instruction")
        let _ = String(localized: "Green leaves, moss, or grass produce thick white smoke. Good against dark backgrounds (trees).", comment: "Step Detail")
        let _ = String(localized: "Add OIL, RUBBER, or PLASTIC for BLACK smoke.", comment: "Step Instruction")
        let _ = String(localized: "Tires, oil-soaked rags, or plastic produce black smoke. Good against light backgrounds (snow, sand).", comment: "Step Detail")
        let _ = String(localized: "Create 3 distinct puffs (cover/uncover) for SOS.", comment: "Step Instruction")
        let _ = String(localized: "Use a blanket or coat. Cover the fire, let smoke build, release. Three puffs is the international distress signal.", comment: "Step Detail")
        let _ = String(localized: "Personal Locator Beacon (PLB)", comment: "Technique Name")
        let _ = String(localized: "One button sends your GPS to rescue coordination", comment: "Technique Subtitle")
        let _ = String(localized: "Deploy the antenna fully and activate the beacon.", comment: "Step Instruction")
        let _ = String(localized: "Most PLBs have a spring-loaded antenna and a protected activation button. Remove the cover, extend antenna, press and hold for 1 second.", comment: "Step Detail")
        let _ = String(localized: "Place beacon with clear sky view — no canopy, no overhangs.", comment: "Step Instruction")
        let _ = String(localized: "PLBs transmit on 406 MHz to COSPAS-SARSAT satellites. Signal needs unobstructed path to sky. Even partial canopy degrades signal.", comment: "Step Detail")
        let _ = String(localized: "Leave activated for minimum 24 hours. Do not turn off and on.", comment: "Step Instruction")
        let _ = String(localized: "Multiple satellite passes improve position accuracy from 5km to 100m. Intermittent activation confuses the system.", comment: "Step Detail")
        let _ = String(localized: "Stay near the beacon. Rescuers will come to the signal location.", comment: "Step Instruction")
        let _ = String(localized: "If you move, carry the beacon. Response times: 1-4 hours in populated areas, 8-24 hours in remote wilderness.", comment: "Step Detail")
        let _ = String(localized: "VHF Radio Distress Call", comment: "Technique Name")
        let _ = String(localized: "Channel 16: international distress frequency", comment: "Technique Subtitle")
        let _ = String(localized: "Tune to Channel 16 (156.800 MHz) — monitored by Coast Guard worldwide.", comment: "Step Instruction")
        let _ = String(localized: "Channel 16 is the international calling and distress frequency. All marine vessels and coast guard stations monitor it 24/7.", comment: "Step Detail")
        let _ = String(localized: "Press transmit and say: MAYDAY MAYDAY MAYDAY, this is [your name/vessel].", comment: "Step Instruction")
        let _ = String(localized: "MAYDAY = life-threatening emergency. PAN-PAN = urgent but not life-threatening. SECURITE = safety information. Use MAYDAY for survival situations.", comment: "Step Detail")
        let _ = String(localized: "State: position, nature of emergency, number of people, assistance needed.", comment: "Step Instruction")
        let _ = String(localized: "Example: 'Position 37.7749 north, 122.4194 west. Party of 3, one injured. Need helicopter evacuation. Over.'", comment: "Step Detail")
        let _ = String(localized: "Release transmit button and listen for response. Repeat every 2 minutes.", comment: "Step Instruction")
        let _ = String(localized: "VHF range is line-of-sight: 5-25 miles depending on terrain and antenna height. Move to high ground to extend range.", comment: "Step Detail")
        let _ = String(localized: "Night Signaling Techniques", comment: "Technique Name")
        let _ = String(localized: "Be visible when darkness hides everything", comment: "Technique Subtitle")
        let _ = String(localized: "Maintain a bright fire on the highest accessible point.", comment: "Step Instruction")
        let _ = String(localized: "A hilltop fire is visible for 20+ miles on a clear night. Use dry hardwood for sustained bright flames, not smoldering coals.", comment: "Step Detail")
        let _ = String(localized: "Use flashlight or phone flash in SOS pattern.", comment: "Step Instruction")
        let _ = String(localized: "Three short flashes, three long flashes, three short flashes. Repeat. Even a dim light is visible for miles at night.", comment: "Step Detail")
        let _ = String(localized: "Create a torch from resinous wood or cloth soaked in fat.", comment: "Step Instruction")
        let _ = String(localized: "Birch bark, pine fatwood, or any cloth with animal fat/oil burns brightly. Wave the torch in a figure-8 pattern for attention.", comment: "Step Detail")
        let _ = String(localized: "Use reflective material to catch any light source.", comment: "Step Instruction")
        let _ = String(localized: "Emergency blankets, foil, even wet metal surfaces reflect moonlight and starlight. Hang them at angles facing likely rescue directions.", comment: "Step Detail")
        let _ = String(localized: "Vehicle-Based Signaling", comment: "Technique Name")
        let _ = String(localized: "Turn your vehicle into a rescue beacon", comment: "Technique Subtitle")
        let _ = String(localized: "Stay with the vehicle — it is more visible than you are.", comment: "Step Instruction")
        let _ = String(localized: "A car is visible from aircraft. A person in the wilderness is nearly invisible. Your vehicle is your best signal, shelter, and resource.", comment: "Step Detail")
        let _ = String(localized: "Open hood and trunk — this signals distress to aircraft.", comment: "Step Instruction")
        let _ = String(localized: "An open hood is a recognized distress signal. Tie bright fabric to the antenna or mirror. Arrange floor mats on the roof as signals.", comment: "Step Detail")
        let _ = String(localized: "Use mirrors, headlights, horn for active signaling.", comment: "Step Instruction")
        let _ = String(localized: "Side mirrors angle sunlight. Headlights flash at night. Horn blasts carry far. Conserve battery — use in bursts when rescue is likely.", comment: "Step Detail")
        let _ = String(localized: "Burn oil or tires for thick black smoke (extreme emergency only).", comment: "Step Instruction")
        let _ = String(localized: "Drain oil onto dirt, ignite with battery spark. Black smoke is visible for miles against any sky. Use only when rescue is imminent.", comment: "Step Detail")
        let _ = String(localized: "Improvised Flag Signaling", comment: "Technique Name")
        let _ = String(localized: "Attract attention with movement and color", comment: "Technique Subtitle")
        let _ = String(localized: "Tie the brightest fabric you have to a long pole or branch.", comment: "Step Instruction")
        let _ = String(localized: "Orange, red, or yellow are most visible against natural backgrounds. Even a white undershirt works against dark terrain.", comment: "Step Detail")
        let _ = String(localized: "Wave in large, slow arcs — both arms overhead means 'need help.'", comment: "Step Instruction")
        let _ = String(localized: "Both arms raised and waving is the international ground-to-air distress gesture. One arm raised means 'all okay.'", comment: "Step Detail")
        let _ = String(localized: "Plant the flag on the highest visible point when not actively waving.", comment: "Step Instruction")
        let _ = String(localized: "Wind keeps it moving, which catches attention. Moving objects are detected 10x faster than static ones by human vision.", comment: "Step Detail")
        let _ = String(localized: "Drone Search Awareness", comment: "Technique Name")
        let _ = String(localized: "Modern SAR uses drones — know how to be found", comment: "Technique Subtitle")
        let _ = String(localized: "Maximize thermal contrast — drones often use infrared cameras.", comment: "Step Instruction")
        let _ = String(localized: "Your body heat stands out against cold ground. Clear surroundings of insulating debris. Lie in an open area if you hear a drone.", comment: "Step Detail")
        let _ = String(localized: "Create large, clear ground signals visible from directly above.", comment: "Step Instruction")
        let _ = String(localized: "Drones fly lower than aircraft but look straight down. Make signals at least 6 feet in any dimension with maximum color contrast.", comment: "Step Detail")
        let _ = String(localized: "Wave reflective materials — drones detect moving objects and reflections.", comment: "Step Instruction")
        let _ = String(localized: "Emergency blankets, phone screens, anything shiny. Movement triggers drone operator attention faster than static signals.", comment: "Step Detail")
        let _ = String(localized: "Satellite Messenger Usage", comment: "Technique Name")
        let _ = String(localized: "Two-way emergency communication anywhere on Earth", comment: "Technique Subtitle")
        let _ = String(localized: "Activate SOS function — press and hold the dedicated SOS button.", comment: "Step Instruction")
        let _ = String(localized: "Garmin inReach, SPOT, Zoleo all have dedicated SOS buttons. This connects to GEOS International Emergency Response Center.", comment: "Step Detail")
        let _ = String(localized: "Send a preset message with your GPS coordinates.", comment: "Step Instruction")
        let _ = String(localized: "Pre-configure emergency contacts and messages before your trip. Include medical conditions, group size, and planned route.", comment: "Step Detail")
        let _ = String(localized: "Use two-way messaging to communicate situation details.", comment: "Step Instruction")
        let _ = String(localized: "Unlike PLBs, satellite messengers allow back-and-forth communication. You can describe injuries, conditions, and accessibility for rescue teams.", comment: "Step Detail")
        let _ = String(localized: "Conserve battery — turn off tracking, reduce message frequency.", comment: "Step Instruction")
        let _ = String(localized: "Most satellite messengers last 24-100 hours. Turn off interval tracking. Send messages only when needed. Keep warm to preserve battery.", comment: "Step Detail")
        let _ = String(localized: "Throw Bag River Rescue", comment: "Technique Name")
        let _ = String(localized: "Reach a person in moving water", comment: "Technique Subtitle")
        let _ = String(localized: "Yell to victim: 'GRAB THE BAG!' Get their attention first.", comment: "Step Instruction")
        let _ = String(localized: "A person in panic may not see or hear you. Make eye contact. Use sharp whistle blasts. Wave arms. They need to be ready to grab.", comment: "Step Detail")
        let _ = String(localized: "Open the bag, hold the end of the rope.", comment: "Step Instruction")
        let _ = String(localized: "Keep one foot on the rope tail or tie it to your wrist. If you throw the bag without holding the rope end, you've lost your rescue tool.", comment: "Step Detail")
        let _ = String(localized: "Throw underhanded PAST the victim, so rope drapes across them.", comment: "Step Instruction")
        let _ = String(localized: "Aim beyond and slightly upstream of the victim. Throwing past them means the rope will drape across their body — easier to grab than catching a bag.", comment: "Step Detail")
        let _ = String(localized: "Once they grab the rope, brace yourself and pull.", comment: "Step Instruction")
        let _ = String(localized: "Sit down, dig heels in, lean back. The current will push them toward you as you maintain tension. Do NOT tie rope to yourself — you could be pulled in.", comment: "Step Detail")
        let _ = String(localized: "If first throw misses: re-stuff bag quickly or throw loose coils.", comment: "Step Instruction")
        let _ = String(localized: "Quickly stuff rope back into bag (doesn't need to be neat). Or gather rope in loose coils and throw the coils. Speed matters more than technique on the second throw.", comment: "Step Detail")
        let _ = String(localized: "Cliff and Canyon Signaling", comment: "Technique Name")
        let _ = String(localized: "Signal from terrain that blocks normal methods", comment: "Technique Subtitle")
        let _ = String(localized: "Use sound amplification — canyon walls reflect and amplify whistles.", comment: "Step Instruction")
        let _ = String(localized: "A whistle in a canyon can be heard miles further than in open terrain. Sound bounces between walls creating natural amplification.", comment: "Step Detail")
        let _ = String(localized: "Create signals on the canyon rim if possible, not the floor.", comment: "Step Instruction")
        let _ = String(localized: "Canyon floors are invisible from the air and from distance. Any signal on the rim is worth 10 signals on the floor.", comment: "Step Detail")
        let _ = String(localized: "Use smoke — it rises out of canyons and is visible from above.", comment: "Step Instruction")
        let _ = String(localized: "Smoke is the one signal type that works from canyon bottoms. Hot air rises, carrying smoke up and out of the canyon.", comment: "Step Detail")
        let _ = String(localized: "Improvised Flotation Device", comment: "Technique Name")
        let _ = String(localized: "Stay afloat with what you have", comment: "Technique Subtitle")
        let _ = String(localized: "Pants flotation: tie off leg openings, inflate by scooping air.", comment: "Step Instruction")
        let _ = String(localized: "Remove pants, tie each leg end in a knot, hold waist open and scoop over your head to trap air. Provides 15-20 minutes of buoyancy.", comment: "Step Detail")
        let _ = String(localized: "Use any sealed container — water bottles, dry bags, sealed coolers.", comment: "Step Instruction")
        let _ = String(localized: "Two empty 2-liter bottles can support an adult's head above water. Stuff clothing into a garbage bag for a makeshift float.", comment: "Step Detail")
        let _ = String(localized: "Logs, branches, and debris make effective rafts with cordage.", comment: "Step Instruction")
        let _ = String(localized: "Even a single thick log supports significant weight. Green wood floats well. Lash with rope, belts, vines, or torn fabric strips.", comment: "Step Detail")
        let _ = String(localized: "Survival float: face down, lift head only to breathe.", comment: "Step Instruction")
        let _ = String(localized: "Also called 'dead man's float.' Arms and legs hang relaxed. Lift face to inhale, then relax. Uses almost zero energy. Can sustain for hours.", comment: "Step Detail")
        let _ = String(localized: "Ground-to-Air Signal Panel", comment: "Technique Name")
        let _ = String(localized: "Create large visual signals visible from aircraft", comment: "Technique Subtitle")
        let _ = String(localized: "Visual Signaling", comment: "Category")
        let _ = String(localized: "Create a large V (need help), X (need medical), or arrow (traveling this direction).", comment: "Step Instruction")
        let _ = String(localized: "International ground-to-air signals: V = need assistance, X = need medical help, arrow = traveling this direction, I = need supplies, F = need food/water, Y = yes, N = no.", comment: "Step Detail")
        let _ = String(localized: "Make signals at least 10 feet long using contrasting materials.", comment: "Step Instruction")
        let _ = String(localized: "Use branches, rocks, clothing, or dig trenches in soil. CONTRAST is key: dark materials on light ground, light materials on dark ground. Shadows from trenches or piled rocks are visible from high altitude.", comment: "Step Detail")
        let _ = String(localized: "Place in open areas — meadows, beaches, ridgetops. Away from tree canopy.", comment: "Step Instruction")
        let _ = String(localized: "Aircraft cannot see through tree canopy. Place signals in the largest open area available. Multiple signals increase detection probability. Maintain signals daily — wind and weather degrade them.", comment: "Step Detail")
        let _ = String(localized: "Survival Whistle Signaling", comment: "Technique Name")
        let _ = String(localized: "Use standardized whistle patterns for rescue communication", comment: "Technique Subtitle")
        let _ = String(localized: "Audio Signaling", comment: "Category")
        let _ = String(localized: "Three blasts = universal distress signal. Pause. Repeat.", comment: "Step Instruction")
        let _ = String(localized: "Three of anything is the international distress signal: 3 whistle blasts, 3 fires, 3 gunshots. Blow three sharp blasts, pause 1 minute, repeat. A whistle carries 1-2 miles — much farther than shouting.", comment: "Step Detail")
        let _ = String(localized: "Two blasts = 'come to me' or acknowledgment from rescuers.", comment: "Step Instruction")
        let _ = String(localized: "If you hear 2 blasts in response to your 3, rescuers have heard you and are coming. Continue blowing 3 blasts periodically so they can home in on your position.", comment: "Step Detail")
        let _ = String(localized: "One long blast = 'attention' or 'where are you?'", comment: "Step Instruction")
        let _ = String(localized: "Used to get attention or locate group members. A whistle is the single most important signaling device to carry. It works when you're too exhausted to shout. It works in fog, darkness, and wind.", comment: "Step Detail")
        let _ = String(localized: "Water Rescue Throw Line", comment: "Technique Name")
        let _ = String(localized: "Rescue someone from water without entering it yourself", comment: "Technique Subtitle")
        let _ = String(localized: "Water Rescue", comment: "Category")
        let _ = String(localized: "Throw a rope, cord, or improvised line to the person in the water.", comment: "Step Instruction")
        let _ = String(localized: "Rule: REACH, THROW, ROW, GO (in that order of safety). Try to reach with a stick first. Then throw a line. Only enter water as absolute last resort — drowning victims pull rescuers under.", comment: "Step Detail")
        let _ = String(localized: "Attach a flotation device to the line if possible.", comment: "Step Instruction")
        let _ = String(localized: "Tie a water bottle, sealed container, or life jacket to the end. This gives them something to grab and provides buoyancy. Throw PAST the victim and pull line across them.", comment: "Step Detail")
        let _ = String(localized: "Brace yourself firmly and pull them in slowly.", comment: "Step Instruction")
        let _ = String(localized: "Sit down, brace feet against rocks or trees. A panicking victim pulls with surprising force. Pull steadily — don't let them pull you in. Talk calmly and firmly: 'Hold on. I'm pulling you in.'", comment: "Step Detail")
        let _ = String(localized: "Vehicle Emergency Signaling", comment: "Technique Name")
        let _ = String(localized: "Use a disabled vehicle as a rescue beacon", comment: "Technique Subtitle")
        let _ = String(localized: "Stay with the vehicle — it's much easier to spot than a person.", comment: "Step Instruction")
        let _ = String(localized: "A car is visible from aircraft at 10+ miles. A person on foot is visible from less than 1 mile. Your vehicle provides shelter, signaling tools, and materials. The #1 cause of vehicle-stranding deaths is leaving the vehicle.", comment: "Step Detail")
        let _ = String(localized: "Use mirrors, hood, CDs, or any reflective surface to signal aircraft.", comment: "Step Instruction")
        let _ = String(localized: "Side mirrors can be removed for hand-signaling. Open the hood — it's an unusual sight that attracts attention. Hang bright clothing on the antenna. Lay out floor mats in an X pattern nearby.", comment: "Step Detail")
        let _ = String(localized: "If safe, burn the spare tire for black smoke signal (extreme last resort).", comment: "Step Instruction")
        let _ = String(localized: "Tire fires produce thick black smoke visible for 20+ miles. Only burn if rescue is actively being sought and you need rapid attention. Keep fire away from the fuel tank. Flash headlights at night.", comment: "Step Detail")
        let _ = String(localized: "Cold Water Self-Rescue", comment: "Technique Name")
        let _ = String(localized: "Survive cold water immersion using the 1-10-1 principle", comment: "Technique Subtitle")
        let _ = String(localized: "Control your breathing: fight the cold shock gasp reflex.", comment: "Step Instruction")
        let _ = String(localized: "Cold water triggers involuntary gasping (cold shock response). This lasts 1-3 minutes. Focus on slow, deliberate breaths. If you gasp underwater, you will inhale water and drown.", comment: "Step Detail")
        let _ = String(localized: "Float on your back. Do NOT swim unless shore is within 50 meters.", comment: "Step Instruction")
        let _ = String(localized: "Swimming accelerates heat loss 25x faster than floating still. Conserve energy. If wearing a PFD, assume the HELP position (Heat Escape Lessening Posture): knees to chest, arms crossed.", comment: "Step Detail")
        let _ = String(localized: "Keep your head above water at all costs.", comment: "Step Instruction")
        let _ = String(localized: "You lose 40-50% of body heat through your head. Tilt head back, keep face to the sky. If waves are splashing your face, turn your back to the waves.", comment: "Step Detail")
        let _ = String(localized: "Grab onto any floating debris or solid object.", comment: "Step Instruction")
        let _ = String(localized: "Wood, coolers, overturned boats, dock pilings — anything that reduces your effort to stay afloat. Drape arms over it, don't grip (grip strength fails quickly in cold).", comment: "Step Detail")
        let _ = String(localized: "Minimize movement. Wait for rescue or drift to shore.", comment: "Step Instruction")
        let _ = String(localized: "You have 10-15 minutes of meaningful swimming ability in cold water before muscles fail. After that, focused stillness and flotation are your only survival tools. Blow a whistle or yell periodically to attract attention.", comment: "Step Detail")
        let _ = String(localized: "Helicopter Rescue Procedures", comment: "Technique Name")
        let _ = String(localized: "Safely interact with rescue helicopters", comment: "Technique Subtitle")
        let _ = String(localized: "Aircraft Rescue", comment: "Category")
        let _ = String(localized: "Clear a landing zone: 100x100 feet minimum, flat, no loose debris.", comment: "Step Instruction")
        let _ = String(localized: "Remove loose branches, clothing, tarps — rotor wash sends everything flying at high speed. Mark wind direction with smoke or a flag. Helicopter lands INTO the wind. Mark the zone with bright items at corners.", comment: "Step Detail")
        let _ = String(localized: "Signal the helicopter: both arms raised in a Y = need help. One arm up = all OK.", comment: "Step Instruction")
        let _ = String(localized: "Y (both arms raised) = Yes, I need help. One arm raised, one down = all OK / negative. Waving one arm side to side = distress. Do NOT wave both arms wildly — it can mean 'don't land.'", comment: "Step Detail")
        let _ = String(localized: "Approach from the FRONT and DOWNHILL side. NEVER approach from behind (tail rotor).", comment: "Step Instruction")
        let _ = String(localized: "The tail rotor is nearly invisible and instantly lethal. Always approach where the pilot can see you. Stay low — rotor blades dip. On slopes, approach from the downhill side. Wait for crew signal before approaching.", comment: "Step Detail")
        let _ = String(localized: "Smoke Signal Timing & Technique", comment: "Technique Name")
        let _ = String(localized: "Maximize smoke signal effectiveness for aerial detection", comment: "Technique Subtitle")
        let _ = String(localized: "Build three fires in a triangle — three smoke columns = distress signal.", comment: "Step Instruction")
        let _ = String(localized: "Space fires 100-200 feet apart in an equilateral triangle. Three columns of smoke is the international distress signal. One column of smoke looks like a campfire. Three is unmistakably a call for help.", comment: "Step Detail")
        let _ = String(localized: "Use green vegetation for white smoke on dark backgrounds, tires/oil for dark smoke on light backgrounds.", comment: "Step Instruction")
        let _ = String(localized: "Match smoke color to background for contrast. Against dark forest: white smoke (green branches, moss, wet leaves). Against light sky/snow: dark smoke (rubber, oil, plastic). Contrast = visibility.", comment: "Step Detail")
        let _ = String(localized: "Keep signal fires prepared but unlit. Light when you see or hear aircraft.", comment: "Step Instruction")
        let _ = String(localized: "Pre-build signal fires with tinder and kindling ready. Put a cover over them to keep dry. When you detect aircraft, light all three quickly. Keep green branches nearby to throw on for smoke.", comment: "Step Detail")
        let _ = String(localized: "Signal Kite Construction", comment: "Technique Name")
        let _ = String(localized: "Build a kite to increase visual presence above tree canopy", comment: "Technique Subtitle")
        let _ = String(localized: "Build a diamond kite frame from two crossed sticks.", comment: "Step Instruction")
        let _ = String(localized: "Vertical stick: 36 inches. Horizontal stick: 24 inches. Cross them at 1/3 from the top of the vertical stick. Lash the intersection tightly. Notch the ends of each stick.", comment: "Step Detail")
        let _ = String(localized: "Cover with plastic bag, poncho, or large leaves tied to the frame.", comment: "Step Instruction")
        let _ = String(localized: "String cord through the notches to create the outline. Stretch plastic or fabric over the frame and secure. Use the brightest colored material available. A tail of cloth strips helps stability.", comment: "Step Detail")
        let _ = String(localized: "Attach a long line and fly in open area. Tie bright streamers to the line.", comment: "Step Instruction")
        let _ = String(localized: "A kite flying 100+ feet above tree canopy is visible for miles. Attach reflective tape, bright fabric, or foil pieces to the line. Even in moderate wind, a properly built kite extends your visual signature dramatically.", comment: "Step Detail")
        let _ = String(localized: "Urban Search & Rescue Marking", comment: "Technique Name")
        let _ = String(localized: "Use FEMA X-marking to communicate with rescue teams", comment: "Technique Subtitle")
        let _ = String(localized: "Communication", comment: "Category")
        let _ = String(localized: "Draw a large X on the outside of the building entrance.", comment: "Step Instruction")
        let _ = String(localized: "This is the FEMA Disaster Marking System. The X divides into 4 quadrants. Use spray paint, chalk, or marker. Make it large enough to see from the street.", comment: "Step Detail")
        let _ = String(localized: "Fill quadrants: top = team ID, left = date/time, right = hazards, bottom = victims found.", comment: "Step Instruction")
        let _ = String(localized: "Top: your identifier. Left: date and time of search. Right: hazards present (rats, gas leak, structural damage). Bottom: number of live/dead victims (e.g., '2L/1D' = 2 living, 1 dead).", comment: "Step Detail")
        let _ = String(localized: "A single slash means search in progress. Complete X means search finished.", comment: "Step Instruction")
        let _ = String(localized: "When you begin searching: draw one slash (\\). When complete: add the second slash to complete the X and fill in quadrants. This prevents duplicate searches and communicates status to other teams.", comment: "Step Detail")
        let _ = String(localized: "River Self-Rescue Position", comment: "Technique Name")
        let _ = String(localized: "Survive being swept away in river current", comment: "Technique Subtitle")
        let _ = String(localized: "Roll onto your back, feet pointing downstream.", comment: "Step Instruction")
        let _ = String(localized: "This is the defensive swimming position. Your feet act as bumpers against rocks. Keep your hips up and back arched slightly. NEVER swim headfirst downstream.", comment: "Step Detail")
        let _ = String(localized: "Use feet to push off rocks and obstacles.", comment: "Step Instruction")
        let _ = String(localized: "Keep legs slightly bent as shock absorbers. Push off rocks with your feet as you approach them. Never try to stand in fast-moving water — foot entrapment kills.", comment: "Step Detail")
        let _ = String(localized: "Look downstream for eddies (calm water behind rocks).", comment: "Step Instruction")
        let _ = String(localized: "Eddies form behind large rocks and on the inside of river bends. The water circulates upstream in eddies — you can rest there. Swim aggressively toward them.", comment: "Step Detail")
        let _ = String(localized: "To reach shore: ferry angle at 45 degrees across current.", comment: "Step Instruction")
        let _ = String(localized: "Roll onto your stomach (aggressive swim position) and swim at a 45-degree angle toward shore, pointing upstream. The current will push you diagonally toward the bank.", comment: "Step Detail")
        let _ = String(localized: "Avoid strainers (fallen trees, debris piles) at all costs.", comment: "Step Instruction")
        let _ = String(localized: "Strainers let water pass through but trap bodies. If you cannot avoid one, swim TOWARD it aggressively and try to climb up and over it. Never turn your back to a strainer.", comment: "Step Detail")
        let _ = String(localized: "Self-Evacuation Decision Making", comment: "Technique Name")
        let _ = String(localized: "Decide when to stay put vs. self-rescue", comment: "Technique Subtitle")
        let _ = String(localized: "Stay put IF: someone knows your location, you filed a trip plan, you're injured, or terrain is dangerous.", comment: "Step Instruction")
        let _ = String(localized: "Search and rescue finds stationary targets much faster than moving ones. If anyone knows where you are, staying put is almost always the better choice. You're easier to find, you conserve energy, and you reduce injury risk.", comment: "Step Detail")
        let _ = String(localized: "Self-evacuate IF: no one knows you're missing, you know your location, and you're uninjured.", comment: "Step Instruction")
        let _ = String(localized: "If nobody will report you missing, nobody will search for you. In this case, self-rescue is your only option. You must know approximately where you are and which direction leads to help.", comment: "Step Detail")
        let _ = String(localized: "Leave clear signs at your camp indicating direction of travel.", comment: "Step Instruction")
        let _ = String(localized: "If you leave camp: leave a note (under a rock, protected from weather), build arrows pointing your direction, mark trees along your route. This lets rescuers follow you if a search begins after you leave.", comment: "Step Detail")
        let _ = String(localized: "Improvised Litter Carry Techniques", comment: "Technique Name")
        let _ = String(localized: "Transport an injured person without commercial equipment", comment: "Technique Subtitle")
        let _ = String(localized: "Evacuation", comment: "Category")
        let _ = String(localized: "Build a pole litter: two poles + fabric/jacket threaded between them.", comment: "Step Instruction")
        let _ = String(localized: "Two sturdy poles 7-8 feet long. Thread jackets (zipped closed, arms inside) onto the poles. Or use a blanket/tarp folded around the poles. Test with your own weight before loading the patient.", comment: "Step Detail")
        let _ = String(localized: "For one-person carry: use a backpack frame as a seat carry.", comment: "Step Instruction")
        let _ = String(localized: "Patient sits on a large backpack carried on your back. Their legs hang over your hips. Secure with straps. This works for conscious patients with lower extremity injuries.", comment: "Step Detail")
        let _ = String(localized: "Carry team rotation: switch every 200 meters to prevent exhaustion.", comment: "Step Instruction")
        let _ = String(localized: "A 150-lb patient on a litter is exhausting. Rotate carriers every 200 meters or every 5 minutes. Need minimum 4 carriers (2 working, 2 resting). Over rough terrain, 6-8 carriers is ideal.", comment: "Step Detail")
        let _ = String(localized: "Trucker's Hitch", comment: "Technique Name")
